window.BIBLE["Acts"] = {"1":{"chapter":"1","title":"THE ASCENSION","verses":{"1":{"text":"The former treatise have I made, O Theophilus, of all that Jesus began both to do and teach,","ref":"Acts 1:1","synthesized":"In my first book, O Theophilus, I wrote about all that Jesus began to do and to teach,","sources":{"KJV":{"text":"The former treatise have I made, O Theophilus, of all that Jesus began both to do and teach,"},"BSB":{"text":"In my first book, O Theophilus, I wrote about all that Jesus began to do and to teach,"}},"definableWords":[],"peopleInVerse":["Jesus"]},"2":{"text":"Until the day in which he was taken up, after that he through the Holy Ghost had given commandments unto the apostles whom he had chosen:","ref":"Acts 1:2","synthesized":"until the day He was taken up to heaven, after giving instructions through the Holy Spirit to the apostles He had chosen.","sources":{"KJV":{"text":"Until the day in which he was taken up, after that he through the Holy Ghost had given commandments unto the apostles whom he had chosen:"},"BSB":{"text":"until the day He was taken up to heaven, after giving instructions through the Holy Spirit to the apostles He had chosen."}},"definableWords":["day","heaven","holy","Spirit"],"peopleInVerse":[]},"3":{"text":"To whom also he shewed himself alive after his passion by many infallible proofs, being seen of them forty days, and speaking of the things pertaining to the kingdom of God:","ref":"Acts 1:3","synthesized":"After His suffering, He presented Himself to them with many convincing proofs that He was alive. He appeared to them over a span of forty days and spoke about the kingdom of God.","sources":{"KJV":{"text":"To whom also he shewed himself alive after his passion by many infallible proofs, being seen of them forty days, and speaking of the things pertaining to the kingdom of God:"},"BSB":{"text":"After His suffering, He presented Himself to them with many convincing proofs that He was alive. He appeared to them over a span of forty days and spoke about the kingdom of God."}},"definableWords":["days","kingdom","God"],"peopleInVerse":[]},"4":{"text":"And, being assembled together with them, commanded them that they should not depart from Jerusalem, but wait for the promise of the Father, which, saith he, ye have heard of me.","ref":"Acts 1:4","synthesized":"And while they were gathered together, He commanded them: “Do not leave Jerusalem, but wait for the gift the Father promised, which you have heard Me discuss.","sources":{"KJV":{"text":"And, being assembled together with them, commanded them that they should not depart from Jerusalem, but wait for the promise of the Father, which, saith he, ye have heard of me."},"BSB":{"text":"And while they were gathered together, He commanded them: “Do not leave Jerusalem, but wait for the gift the Father promised, which you have heard Me discuss."}},"definableWords":["Jerusalem","wait","Father"],"peopleInVerse":[]},"5":{"text":"For John truly baptized with water; but ye shall be baptized with the Holy Ghost not many days hence.","ref":"Acts 1:5","synthesized":"For John baptized with water, but in a few days you will be baptized with the Holy Spirit.”","sources":{"KJV":{"text":"For John truly baptized with water; but ye shall be baptized with the Holy Ghost not many days hence."},"BSB":{"text":"For John baptized with water, but in a few days you will be baptized with the Holy Spirit.”"}},"definableWords":["water","days","holy","Spirit"],"peopleInVerse":["John"]},"6":{"text":"When they therefore were come together, they asked of him, saying, Lord, wilt thou at this time restore again the kingdom to Israel?","ref":"Acts 1:6","synthesized":"So when they came together, they asked Him, “Lord, will You at this time restore the kingdom to Israel?”","sources":{"KJV":{"text":"When they therefore were come together, they asked of him, saying, Lord, wilt thou at this time restore again the kingdom to Israel?"},"BSB":{"text":"So when they came together, they asked Him, “Lord, will You at this time restore the kingdom to Israel?”"}},"definableWords":["Lord","kingdom","Israel"],"peopleInVerse":[]},"7":{"text":"And he said unto them, It is not for you to know the times or the seasons, which the Father hath put in his own power.","ref":"Acts 1:7","synthesized":"Jesus replied, “It is not for you to know times or seasons that the Father has fixed by His own authority.","sources":{"KJV":{"text":"And he said unto them, It is not for you to know the times or the seasons, which the Father hath put in his own power."},"BSB":{"text":"Jesus replied, “It is not for you to know times or seasons that the Father has fixed by His own authority."}},"definableWords":["or","Father"],"peopleInVerse":["Jesus"]},"8":{"text":"But ye shall receive power, after that the Holy Ghost is come upon you: and ye shall be witnesses unto me both in Jerusalem, and in all Judaea, and in Samaria, and unto the uttermost part of the earth.","ref":"Acts 1:8","synthesized":"But you will receive power when the Holy Spirit comes upon you, and you will be My witnesses in Jerusalem, and in all Judea and Samaria, and to the ends of the earth.”","sources":{"KJV":{"text":"But ye shall receive power, after that the Holy Ghost is come upon you: and ye shall be witnesses unto me both in Jerusalem, and in all Judaea, and in Samaria, and unto the uttermost part of the earth."},"BSB":{"text":"But you will receive power when the Holy Spirit comes upon you, and you will be My witnesses in Jerusalem, and in all Judea and Samaria, and to the ends of the earth.”"}},"definableWords":["holy","Spirit","Jerusalem","Judea","Samaria","earth"],"peopleInVerse":[]},"9":{"text":"And when he had spoken these things, while they beheld, he was taken up; and a cloud received him out of their sight.","ref":"Acts 1:9","synthesized":"After He had said this, they watched as He was taken up, and a cloud hid Him from their sight.","sources":{"KJV":{"text":"And when he had spoken these things, while they beheld, he was taken up; and a cloud received him out of their sight."},"BSB":{"text":"After He had said this, they watched as He was taken up, and a cloud hid Him from their sight."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"And while they looked stedfastly toward heaven as he went up, behold, two men stood by them in white apparel;","ref":"Acts 1:10","synthesized":"They were looking intently into the sky as He was going, when suddenly two men dressed in white stood beside them.","sources":{"KJV":{"text":"And while they looked stedfastly toward heaven as he went up, behold, two men stood by them in white apparel;"},"BSB":{"text":"They were looking intently into the sky as He was going, when suddenly two men dressed in white stood beside them."}},"definableWords":["men"],"peopleInVerse":[]},"11":{"text":"Which also said, Ye men of Galilee, why stand ye gazing up into heaven? this same Jesus, which is taken up from you into heaven, shall so come in like manner as ye have seen him go into heaven.","ref":"Acts 1:11","synthesized":"“Men of Galilee,” they said, “why do you stand here looking into the sky? This same Jesus, who has been taken from you into heaven, will come back in the same way you have seen Him go into heaven.”","sources":{"KJV":{"text":"Which also said, Ye men of Galilee, why stand ye gazing up into heaven? this same Jesus, which is taken up from you into heaven, shall so come in like manner as ye have seen him go into heaven."},"BSB":{"text":"“Men of Galilee,” they said, “why do you stand here looking into the sky? This same Jesus, who has been taken from you into heaven, will come back in the same way you have seen Him go into heaven.”"}},"definableWords":["men","Galilee","stand","heaven","way"],"peopleInVerse":["Jesus"]},"12":{"text":"Then returned they unto Jerusalem from the mount called Olivet, which is from Jerusalem a sabbath day’s journey.","ref":"Acts 1:12","synthesized":"Then they returned to Jerusalem from the Mount of Olives, which is near the city, a Sabbath day’s journey away.","sources":{"KJV":{"text":"Then returned they unto Jerusalem from the mount called Olivet, which is from Jerusalem a sabbath day’s journey."},"BSB":{"text":"Then they returned to Jerusalem from the Mount of Olives, which is near the city, a Sabbath day’s journey away."}},"definableWords":["Jerusalem","Sabbath","day"],"peopleInVerse":[]},"13":{"text":"And when they were come in, they went up into an upper room, where abode both Peter, and James, and John, and Andrew, Philip, and Thomas, Bartholomew, and Matthew, James the son of Alphaeus, and Simon Zelotes, and Judas the brother of James.","ref":"Acts 1:13","synthesized":"When they arrived, they went to the upper room where they were staying: Peter and John, James and Andrew, Philip and Thomas, Bartholomew and Matthew, James son of Alphaeus, Simon the Zealot, and Judas son of James.","sources":{"KJV":{"text":"And when they were come in, they went up into an upper room, where abode both Peter, and James, and John, and Andrew, Philip, and Thomas, Bartholomew, and Matthew, James the son of Alphaeus, and Simon Zelotes, and Judas the brother of James."},"BSB":{"text":"When they arrived, they went to the upper room where they were staying: Peter and John, James and Andrew, Philip and Thomas, Bartholomew and Matthew, James son of Alphaeus, Simon the Zealot, and Judas son of James."}},"definableWords":["son","Son"],"peopleInVerse":["Peter","John","James","Andrew","Matthew"]},"14":{"text":"These all continued with one accord in prayer and supplication, with the women, and Mary the mother of Jesus, and with his brethren.","ref":"Acts 1:14","synthesized":"With one accord they all continued in prayer, along with the women and Mary the mother of Jesus, and with His brothers.","sources":{"KJV":{"text":"These all continued with one accord in prayer and supplication, with the women, and Mary the mother of Jesus, and with his brethren."},"BSB":{"text":"With one accord they all continued in prayer, along with the women and Mary the mother of Jesus, and with His brothers."}},"definableWords":["one","prayer","women","mother"],"peopleInVerse":["Mary","Jesus"]},"15":{"text":"And in those days Peter stood up in the midst of the disciples, and said, (the number of names together were about an hundred and twenty,)","ref":"Acts 1:15","synthesized":"In those days Peter stood up among the brothers (a gathering of about a hundred and twenty) and said,","sources":{"KJV":{"text":"And in those days Peter stood up in the midst of the disciples, and said, (the number of names together were about an hundred and twenty,)"},"BSB":{"text":"In those days Peter stood up among the brothers (a gathering of about a hundred and twenty) and said,"}},"definableWords":["days"],"peopleInVerse":["Peter"]},"16":{"text":"Men and brethren, this scripture must needs have been fulfilled, which the Holy Ghost by the mouth of David spake before concerning Judas, which was guide to them that took Jesus.","ref":"Acts 1:16","synthesized":"“Brothers, the Scripture had to be fulfilled which the Holy Spirit foretold through the mouth of David concerning Judas, who became a guide for those who arrested Jesus.","sources":{"KJV":{"text":"Men and brethren, this scripture must needs have been fulfilled, which the Holy Ghost by the mouth of David spake before concerning Judas, which was guide to them that took Jesus."},"BSB":{"text":"“Brothers, the Scripture had to be fulfilled which the Holy Spirit foretold through the mouth of David concerning Judas, who became a guide for those who arrested Jesus."}},"definableWords":["holy","Spirit"],"peopleInVerse":["David","Jesus"]},"17":{"text":"For he was numbered with us, and had obtained part of this ministry.","ref":"Acts 1:17","synthesized":"He was one of our number and shared in this ministry.”","sources":{"KJV":{"text":"For he was numbered with us, and had obtained part of this ministry."},"BSB":{"text":"He was one of our number and shared in this ministry.”"}},"definableWords":["one"],"peopleInVerse":[]},"18":{"text":"Now this man purchased a field with the reward of iniquity; and falling headlong, he burst asunder in the midst, and all his bowels gushed out.","ref":"Acts 1:18","synthesized":"(Now with the reward for his wickedness Judas bought a field; there he fell headlong and burst open in the middle, and all his intestines spilled out.","sources":{"KJV":{"text":"Now this man purchased a field with the reward of iniquity; and falling headlong, he burst asunder in the midst, and all his bowels gushed out."},"BSB":{"text":"(Now with the reward for his wickedness Judas bought a field; there he fell headlong and burst open in the middle, and all his intestines spilled out."}},"definableWords":["field"],"peopleInVerse":[]},"19":{"text":"And it was known unto all the dwellers at Jerusalem; insomuch as that field is called in their proper tongue, Aceldama, that is to say, The field of blood.","ref":"Acts 1:19","synthesized":"This became known to all who lived in Jerusalem, so they called that field in their own language Akeldama, that is, Field of Blood.)","sources":{"KJV":{"text":"And it was known unto all the dwellers at Jerusalem; insomuch as that field is called in their proper tongue, Aceldama, that is to say, The field of blood."},"BSB":{"text":"This became known to all who lived in Jerusalem, so they called that field in their own language Akeldama, that is, Field of Blood.)"}},"definableWords":["Jerusalem","field","blood"],"peopleInVerse":[]},"20":{"text":"For it is written in the book of Psalms, Let his habitation be desolate, and let no man dwell therein: and his bishoprick let another take.","ref":"Acts 1:20","synthesized":"“For it is written in the book of Psalms:  ‘May his place be deserted; let there be no one to dwell in it,’   and,  ‘May another take his position.’","sources":{"KJV":{"text":"For it is written in the book of Psalms, Let his habitation be desolate, and let no man dwell therein: and his bishoprick let another take."},"BSB":{"text":"“For it is written in the book of Psalms:  ‘May his place be deserted; let there be no one to dwell in it,’   and,  ‘May another take his position.’"}},"definableWords":["one"],"peopleInVerse":[]},"21":{"text":"Wherefore of these men which have companied with us all the time that the Lord Jesus went in and out among us,","ref":"Acts 1:21","synthesized":"Therefore it is necessary to choose one of the men who have accompanied us the whole time the Lord Jesus went in and out among us,","sources":{"KJV":{"text":"Wherefore of these men which have companied with us all the time that the Lord Jesus went in and out among us,"},"BSB":{"text":"Therefore it is necessary to choose one of the men who have accompanied us the whole time the Lord Jesus went in and out among us,"}},"definableWords":["one","men","Lord"],"peopleInVerse":["Jesus"]},"22":{"text":"Beginning from the baptism of John, unto that same day that he was taken up from us, must one be ordained to be a witness with us of his resurrection.","ref":"Acts 1:22","synthesized":"beginning from John’s baptism until the day Jesus was taken up from us. For one of these must become a witness with us of His resurrection.”","sources":{"KJV":{"text":"Beginning from the baptism of John, unto that same day that he was taken up from us, must one be ordained to be a witness with us of his resurrection."},"BSB":{"text":"beginning from John’s baptism until the day Jesus was taken up from us. For one of these must become a witness with us of His resurrection.”"}},"definableWords":["beginning","baptism","day","one","resurrection"],"peopleInVerse":["John","Jesus"]},"23":{"text":"And they appointed two, Joseph called Barsabas, who was surnamed Justus, and Matthias.","ref":"Acts 1:23","synthesized":"So they proposed two men: Joseph called Barsabbas (also known as Justus) and Matthias.","sources":{"KJV":{"text":"And they appointed two, Joseph called Barsabas, who was surnamed Justus, and Matthias."},"BSB":{"text":"So they proposed two men: Joseph called Barsabbas (also known as Justus) and Matthias."}},"definableWords":["men","Joseph"],"peopleInVerse":["Joseph"]},"24":{"text":"And they prayed, and said, Thou, Lord, which knowest the hearts of all men, shew whether of these two thou hast chosen,","ref":"Acts 1:24","synthesized":"And they prayed, “Lord, You know everyone’s heart. Show us which of these two You have chosen","sources":{"KJV":{"text":"And they prayed, and said, Thou, Lord, which knowest the hearts of all men, shew whether of these two thou hast chosen,"},"BSB":{"text":"And they prayed, “Lord, You know everyone’s heart. Show us which of these two You have chosen"}},"definableWords":["Lord","heart"],"peopleInVerse":[]},"25":{"text":"That he may take part of this ministry and apostleship, from which Judas by transgression fell, that he might go to his own place.","ref":"Acts 1:25","synthesized":"to take up this ministry and apostleship, which Judas abandoned to go to his rightful place.”","sources":{"KJV":{"text":"That he may take part of this ministry and apostleship, from which Judas by transgression fell, that he might go to his own place."},"BSB":{"text":"to take up this ministry and apostleship, which Judas abandoned to go to his rightful place.”"}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"And they gave forth their lots; and the lot fell upon Matthias; and he was numbered with the eleven apostles.","ref":"Acts 1:26","synthesized":"Then they cast lots, and the lot fell to Matthias; so he was added to the eleven apostles.","sources":{"KJV":{"text":"And they gave forth their lots; and the lot fell upon Matthias; and he was numbered with the eleven apostles."},"BSB":{"text":"Then they cast lots, and the lot fell to Matthias; so he was added to the eleven apostles."}},"definableWords":["Lot"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"PENTECOST","verses":{"1":{"text":"And when the day of Pentecost was fully come, they were all with one accord in one place.","ref":"Acts 2:1","synthesized":"When the day of Pentecost came, they were all together in one place.","sources":{"KJV":{"text":"And when the day of Pentecost was fully come, they were all with one accord in one place."},"BSB":{"text":"When the day of Pentecost came, they were all together in one place."}},"definableWords":["day","Pentecost","one"],"peopleInVerse":[],"kingdomLens":"Fifty days after Passover, the Holy Spirit falls on 120 disciples with the sound of rushing wind and tongues of fire. They speak in languages they never learned, and Jews from 15+ nations hear the gospel in their own tongue. This reverses Babel (Gen 11) — where languages divided humanity, the Spirit unites them in Christ. The church is born.","cultural":{"title":"Pentecost — the Kingdom goes global","detail":"Pentecost (Hebrew: Shavuot) was the feast celebrating the giving of the Torah at Sinai. So the Spirit comes on the very day Israel commemorated receiving God's word — now God writes the law on hearts, as Jeremiah 31 promised. Peter, who denied Christ three times two months earlier, preaches and 3,000 are baptized.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"And suddenly there came a sound from heaven as of a rushing mighty wind, and it filled all the house where they were sitting.","ref":"Acts 2:2","synthesized":"Suddenly a sound like a mighty rushing wind came from heaven and filled the whole house where they were sitting.","sources":{"KJV":{"text":"And suddenly there came a sound from heaven as of a rushing mighty wind, and it filled all the house where they were sitting."},"BSB":{"text":"Suddenly a sound like a mighty rushing wind came from heaven and filled the whole house where they were sitting."}},"definableWords":["mighty","heaven","house"],"peopleInVerse":[]},"3":{"text":"And there appeared unto them cloven tongues like as of fire, and it sat upon each of them.","ref":"Acts 2:3","synthesized":"They saw tongues like flames of fire that separated and came to rest on each of them.","sources":{"KJV":{"text":"And there appeared unto them cloven tongues like as of fire, and it sat upon each of them."},"BSB":{"text":"They saw tongues like flames of fire that separated and came to rest on each of them."}},"definableWords":["saw","rest"],"peopleInVerse":[]},"4":{"text":"And they were all filled with the Holy Ghost, and began to speak with other tongues, as the Spirit gave them utterance.","ref":"Acts 2:4","synthesized":"And they were all filled with the Holy Spirit and began to speak in other tongues as the Spirit enabled them.","sources":{"KJV":{"text":"And they were all filled with the Holy Ghost, and began to speak with other tongues, as the Spirit gave them utterance."},"BSB":{"text":"And they were all filled with the Holy Spirit and began to speak in other tongues as the Spirit enabled them."}},"definableWords":["holy","Spirit","spirit"],"peopleInVerse":[]},"5":{"text":"And there were dwelling at Jerusalem Jews, devout men, out of every nation under heaven.","ref":"Acts 2:5","synthesized":"Now there were dwelling in Jerusalem God-fearing Jews from every nation under heaven.","sources":{"KJV":{"text":"And there were dwelling at Jerusalem Jews, devout men, out of every nation under heaven."},"BSB":{"text":"Now there were dwelling in Jerusalem God-fearing Jews from every nation under heaven."}},"definableWords":["Jerusalem","God","nation","heaven"],"peopleInVerse":[]},"6":{"text":"Now when this was noised abroad, the multitude came together, and were confounded, because that every man heard them speak in his own language.","ref":"Acts 2:6","synthesized":"And when this sound rang out, a crowd came together in bewilderment, because each one heard them speaking his own language.","sources":{"KJV":{"text":"Now when this was noised abroad, the multitude came together, and were confounded, because that every man heard them speak in his own language."},"BSB":{"text":"And when this sound rang out, a crowd came together in bewilderment, because each one heard them speaking his own language."}},"definableWords":["one"],"peopleInVerse":[]},"7":{"text":"And they were all amazed and marvelled, saying one to another, Behold, are not all these which speak Galilaeans?","ref":"Acts 2:7","synthesized":"Astounded and amazed, they asked, “Are not all these men who are speaking Galileans?","sources":{"KJV":{"text":"And they were all amazed and marvelled, saying one to another, Behold, are not all these which speak Galilaeans?"},"BSB":{"text":"Astounded and amazed, they asked, “Are not all these men who are speaking Galileans?"}},"definableWords":["men"],"peopleInVerse":[]},"8":{"text":"And how hear we every man in our own tongue, wherein we were born?","ref":"Acts 2:8","synthesized":"How is it then that each of us hears them in his own native language?","sources":{"KJV":{"text":"And how hear we every man in our own tongue, wherein we were born?"},"BSB":{"text":"How is it then that each of us hears them in his own native language?"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Parthians, and Medes, and Elamites, and the dwellers in Mesopotamia, and in Judaea, and Cappadocia, in Pontus, and Asia,","ref":"Acts 2:9","synthesized":"Parthians, Medes, and Elamites; residents of Mesopotamia, Judea and Cappadocia, Pontus and Asia,","sources":{"KJV":{"text":"Parthians, and Medes, and Elamites, and the dwellers in Mesopotamia, and in Judaea, and Cappadocia, in Pontus, and Asia,"},"BSB":{"text":"Parthians, Medes, and Elamites; residents of Mesopotamia, Judea and Cappadocia, Pontus and Asia,"}},"definableWords":["Judea"],"peopleInVerse":[]},"10":{"text":"Phrygia, and Pamphylia, in Egypt, and in the parts of Libya about Cyrene, and strangers of Rome, Jews and proselytes,","ref":"Acts 2:10","synthesized":"Phrygia and Pamphylia, Egypt and the parts of Libya near Cyrene; visitors from Rome,","sources":{"KJV":{"text":"Phrygia, and Pamphylia, in Egypt, and in the parts of Libya about Cyrene, and strangers of Rome, Jews and proselytes,"},"BSB":{"text":"Phrygia and Pamphylia, Egypt and the parts of Libya near Cyrene; visitors from Rome,"}},"definableWords":["Egypt"],"peopleInVerse":[]},"11":{"text":"Cretes and Arabians, we do hear them speak in our tongues the wonderful works of God.","ref":"Acts 2:11","synthesized":"both Jews and converts to Judaism; Cretans and Arabs—we hear them declaring the wonders of God in our own tongues!”","sources":{"KJV":{"text":"Cretes and Arabians, we do hear them speak in our tongues the wonderful works of God."},"BSB":{"text":"both Jews and converts to Judaism; Cretans and Arabs—we hear them declaring the wonders of God in our own tongues!”"}},"definableWords":["hear","God"],"peopleInVerse":[]},"12":{"text":"And they were all amazed, and were in doubt, saying one to another, What meaneth this?","ref":"Acts 2:12","synthesized":"Astounded and perplexed, they asked one another, “What does this mean?”","sources":{"KJV":{"text":"And they were all amazed, and were in doubt, saying one to another, What meaneth this?"},"BSB":{"text":"Astounded and perplexed, they asked one another, “What does this mean?”"}},"definableWords":["one"],"peopleInVerse":[]},"13":{"text":"Others mocking said, These men are full of new wine.","ref":"Acts 2:13","synthesized":"But others mocked them and said, “They are drunk on new wine!”","sources":{"KJV":{"text":"Others mocking said, These men are full of new wine."},"BSB":{"text":"But others mocked them and said, “They are drunk on new wine!”"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"But Peter, standing up with the eleven, lifted up his voice, and said unto them, Ye men of Judaea, and all ye that dwell at Jerusalem, be this known unto you, and hearken to my words:","ref":"Acts 2:14","synthesized":"Then Peter stood up with the Eleven, lifted up his voice, and addressed the crowd: “Men of Judea and all who dwell in Jerusalem, let this be known to you, and listen carefully to my words.","sources":{"KJV":{"text":"But Peter, standing up with the eleven, lifted up his voice, and said unto them, Ye men of Judaea, and all ye that dwell at Jerusalem, be this known unto you, and hearken to my words:"},"BSB":{"text":"Then Peter stood up with the Eleven, lifted up his voice, and addressed the crowd: “Men of Judea and all who dwell in Jerusalem, let this be known to you, and listen carefully to my words."}},"definableWords":["voice","men","Judea","Jerusalem"],"peopleInVerse":["Peter"]},"15":{"text":"For these are not drunken, as ye suppose, seeing it is but the third hour of the day.","ref":"Acts 2:15","synthesized":"These men are not drunk, as you suppose. It is only the third hour of the day!","sources":{"KJV":{"text":"For these are not drunken, as ye suppose, seeing it is but the third hour of the day."},"BSB":{"text":"These men are not drunk, as you suppose. It is only the third hour of the day!"}},"definableWords":["men","day"],"peopleInVerse":[]},"16":{"text":"But this is that which was spoken by the prophet Joel;","ref":"Acts 2:16","synthesized":"No, this is what was spoken by the prophet Joel:","sources":{"KJV":{"text":"But this is that which was spoken by the prophet Joel;"},"BSB":{"text":"No, this is what was spoken by the prophet Joel:"}},"definableWords":["prophet"],"peopleInVerse":[]},"17":{"text":"And it shall come to pass in the last days, saith God, I will pour out of my Spirit upon all flesh: and your sons and your daughters shall prophesy, and your young men shall see visions, and your old men shall dream dreams:","ref":"Acts 2:17","synthesized":"‘In the last days, God says, I will pour out My Spirit on all people. Your sons and daughters will prophesy, your young men will see visions, your old men will dream dreams.","sources":{"KJV":{"text":"And it shall come to pass in the last days, saith God, I will pour out of my Spirit upon all flesh: and your sons and your daughters shall prophesy, and your young men shall see visions, and your old men shall dream dreams:"},"BSB":{"text":"‘In the last days, God says, I will pour out My Spirit on all people. Your sons and daughters will prophesy, your young men will see visions, your old men will dream dreams."}},"definableWords":["days","God","Spirit","people","sons","daughters","men","see"],"peopleInVerse":[]},"18":{"text":"And on my servants and on my handmaidens I will pour out in those days of my Spirit; and they shall prophesy:","ref":"Acts 2:18","synthesized":"Even on My menservants and maidservants I will pour out My Spirit in those days, and they will prophesy.","sources":{"KJV":{"text":"And on my servants and on my handmaidens I will pour out in those days of my Spirit; and they shall prophesy:"},"BSB":{"text":"Even on My menservants and maidservants I will pour out My Spirit in those days, and they will prophesy."}},"definableWords":["Spirit","days"],"peopleInVerse":[]},"19":{"text":"And I will shew wonders in heaven above, and signs in the earth beneath; blood, and fire, and vapour of smoke:","ref":"Acts 2:19","synthesized":"I will show wonders in the heavens above and signs on the earth below, blood and fire and billows of smoke.","sources":{"KJV":{"text":"And I will shew wonders in heaven above, and signs in the earth beneath; blood, and fire, and vapour of smoke:"},"BSB":{"text":"I will show wonders in the heavens above and signs on the earth below, blood and fire and billows of smoke."}},"definableWords":["heavens","earth","blood"],"peopleInVerse":[]},"20":{"text":"The sun shall be turned into darkness, and the moon into blood, before that great and notable day of the Lord come:","ref":"Acts 2:20","synthesized":"The sun will be turned to darkness, and the moon to blood, before the coming of the great and glorious Day of the Lord.","sources":{"KJV":{"text":"The sun shall be turned into darkness, and the moon into blood, before that great and notable day of the Lord come:"},"BSB":{"text":"The sun will be turned to darkness, and the moon to blood, before the coming of the great and glorious Day of the Lord."}},"definableWords":["darkness","blood","great","day","Lord"],"peopleInVerse":[]},"21":{"text":"And it shall come to pass, that whosoever shall call on the name of the Lord shall be saved.","ref":"Acts 2:21","synthesized":"And everyone who calls on the name of the Lord will be saved.’","sources":{"KJV":{"text":"And it shall come to pass, that whosoever shall call on the name of the Lord shall be saved."},"BSB":{"text":"And everyone who calls on the name of the Lord will be saved.’"}},"definableWords":["name","Lord"],"peopleInVerse":[]},"22":{"text":"Ye men of Israel, hear these words; Jesus of Nazareth, a man approved of God among you by miracles and wonders and signs, which God did by him in the midst of you, as ye yourselves also know:","ref":"Acts 2:22","synthesized":"Men of Israel, listen to this message: Jesus of Nazareth was a man certified by God to you by miracles, wonders, and signs, which God did among you through Him, as you yourselves know.","sources":{"KJV":{"text":"Ye men of Israel, hear these words; Jesus of Nazareth, a man approved of God among you by miracles and wonders and signs, which God did by him in the midst of you, as ye yourselves also know:"},"BSB":{"text":"Men of Israel, listen to this message: Jesus of Nazareth was a man certified by God to you by miracles, wonders, and signs, which God did among you through Him, as you yourselves know."}},"definableWords":["men","Israel","man","God"],"peopleInVerse":["Jesus"]},"23":{"text":"Him, being delivered by the determinate counsel and foreknowledge of God, ye have taken, and by wicked hands have crucified and slain:","ref":"Acts 2:23","synthesized":"He was delivered up by God’s set plan and foreknowledge, and you, by the hands of the lawless, put Him to death by nailing Him to the cross.","sources":{"KJV":{"text":"Him, being delivered by the determinate counsel and foreknowledge of God, ye have taken, and by wicked hands have crucified and slain:"},"BSB":{"text":"He was delivered up by God’s set plan and foreknowledge, and you, by the hands of the lawless, put Him to death by nailing Him to the cross."}},"definableWords":["God","death"],"peopleInVerse":[]},"24":{"text":"Whom God hath raised up, having loosed the pains of death: because it was not possible that he should be holden of it.","ref":"Acts 2:24","synthesized":"But God raised Him from the dead, releasing Him from the agony of death, because it was impossible for Him to be held in its clutches.","sources":{"KJV":{"text":"Whom God hath raised up, having loosed the pains of death: because it was not possible that he should be holden of it."},"BSB":{"text":"But God raised Him from the dead, releasing Him from the agony of death, because it was impossible for Him to be held in its clutches."}},"definableWords":["God","death"],"peopleInVerse":[]},"25":{"text":"For David speaketh concerning him, I foresaw the Lord always before my face, for he is on my right hand, that I should not be moved:","ref":"Acts 2:25","synthesized":"David says about Him:  ‘I saw the Lord always before me; because He is at my right hand, I will not be shaken.","sources":{"KJV":{"text":"For David speaketh concerning him, I foresaw the Lord always before my face, for he is on my right hand, that I should not be moved:"},"BSB":{"text":"David says about Him:  ‘I saw the Lord always before me; because He is at my right hand, I will not be shaken."}},"definableWords":["saw","Lord"],"peopleInVerse":["David"]},"26":{"text":"Therefore did my heart rejoice, and my tongue was glad; moreover also my flesh shall rest in hope:","ref":"Acts 2:26","synthesized":"Therefore my heart is glad and my tongue rejoices; my body also will dwell in hope,","sources":{"KJV":{"text":"Therefore did my heart rejoice, and my tongue was glad; moreover also my flesh shall rest in hope:"},"BSB":{"text":"Therefore my heart is glad and my tongue rejoices; my body also will dwell in hope,"}},"definableWords":["heart","hope"],"peopleInVerse":[]},"27":{"text":"Because thou wilt not leave my soul in hell, neither wilt thou suffer thine Holy One to see corruption.","ref":"Acts 2:27","synthesized":"because You will not abandon my soul to Hades, nor will You let Your Holy One see decay.","sources":{"KJV":{"text":"Because thou wilt not leave my soul in hell, neither wilt thou suffer thine Holy One to see corruption."},"BSB":{"text":"because You will not abandon my soul to Hades, nor will You let Your Holy One see decay."}},"definableWords":["soul","holy","one","see"],"peopleInVerse":[]},"28":{"text":"Thou hast made known to me the ways of life; thou shalt make me full of joy with thy countenance.","ref":"Acts 2:28","synthesized":"You have made known to me the paths of life; You will fill me with joy in Your presence.’","sources":{"KJV":{"text":"Thou hast made known to me the ways of life; thou shalt make me full of joy with thy countenance."},"BSB":{"text":"You have made known to me the paths of life; You will fill me with joy in Your presence.’"}},"definableWords":["made","life","fill","joy"],"peopleInVerse":[]},"29":{"text":"Men and brethren, let me freely speak unto you of the patriarch David, that he is both dead and buried, and his sepulchre is with us unto this day.","ref":"Acts 2:29","synthesized":"Brothers, I can tell you with confidence that the patriarch David died and was buried, and his tomb is with us to this day.","sources":{"KJV":{"text":"Men and brethren, let me freely speak unto you of the patriarch David, that he is both dead and buried, and his sepulchre is with us unto this day."},"BSB":{"text":"Brothers, I can tell you with confidence that the patriarch David died and was buried, and his tomb is with us to this day."}},"definableWords":["day"],"peopleInVerse":["David"]},"30":{"text":"Therefore being a prophet, and knowing that God had sworn with an oath to him, that of the fruit of his loins, according to the flesh, he would raise up Christ to sit on his throne;","ref":"Acts 2:30","synthesized":"But he was a prophet and knew that God had promised him on oath that He would place one of his descendants on his throne.","sources":{"KJV":{"text":"Therefore being a prophet, and knowing that God had sworn with an oath to him, that of the fruit of his loins, according to the flesh, he would raise up Christ to sit on his throne;"},"BSB":{"text":"But he was a prophet and knew that God had promised him on oath that He would place one of his descendants on his throne."}},"definableWords":["prophet","God","one","throne"],"peopleInVerse":[]},"31":{"text":"He seeing this before spake of the resurrection of Christ, that his soul was not left in hell, neither his flesh did see corruption.","ref":"Acts 2:31","synthesized":"Foreseeing this, David spoke about the resurrection of the Christ, that He was not abandoned to Hades, nor did His body see decay.","sources":{"KJV":{"text":"He seeing this before spake of the resurrection of Christ, that his soul was not left in hell, neither his flesh did see corruption."},"BSB":{"text":"Foreseeing this, David spoke about the resurrection of the Christ, that He was not abandoned to Hades, nor did His body see decay."}},"definableWords":["resurrection","Christ","see"],"peopleInVerse":["David"]},"32":{"text":"This Jesus hath God raised up, whereof we all are witnesses.","ref":"Acts 2:32","synthesized":"God has raised this Jesus to life, to which we are all witnesses.","sources":{"KJV":{"text":"This Jesus hath God raised up, whereof we all are witnesses."},"BSB":{"text":"God has raised this Jesus to life, to which we are all witnesses."}},"definableWords":["God","life"],"peopleInVerse":["Jesus"]},"33":{"text":"Therefore being by the right hand of God exalted, and having received of the Father the promise of the Holy Ghost, he hath shed forth this, which ye now see and hear.","ref":"Acts 2:33","synthesized":"Exalted, then, to the right hand of God, He has received from the Father the promised Holy Spirit and has poured out what you now see and hear.","sources":{"KJV":{"text":"Therefore being by the right hand of God exalted, and having received of the Father the promise of the Holy Ghost, he hath shed forth this, which ye now see and hear."},"BSB":{"text":"Exalted, then, to the right hand of God, He has received from the Father the promised Holy Spirit and has poured out what you now see and hear."}},"definableWords":["God","Father","holy","Spirit","see","hear"],"peopleInVerse":[]},"34":{"text":"For David is not ascended into the heavens: but he saith himself, The Lord said unto my Lord, Sit thou on my right hand,","ref":"Acts 2:34","synthesized":"For David did not ascend into heaven, but he himself says:  ‘The Lord said to my Lord, “Sit at My right hand","sources":{"KJV":{"text":"For David is not ascended into the heavens: but he saith himself, The Lord said unto my Lord, Sit thou on my right hand,"},"BSB":{"text":"For David did not ascend into heaven, but he himself says:  ‘The Lord said to my Lord, “Sit at My right hand"}},"definableWords":["heaven","Lord"],"peopleInVerse":["David"]},"35":{"text":"Until I make thy foes thy footstool.","ref":"Acts 2:35","synthesized":"until I make Your enemies a footstool for Your feet.”’","sources":{"KJV":{"text":"Until I make thy foes thy footstool."},"BSB":{"text":"until I make Your enemies a footstool for Your feet.”’"}},"definableWords":["make"],"peopleInVerse":[]},"36":{"text":"Therefore let all the house of Israel know assuredly, that God hath made that same Jesus, whom ye have crucified, both Lord and Christ.","ref":"Acts 2:36","synthesized":"Therefore let all Israel know with certainty that God has made this Jesus, whom you crucified, both Lord and Christ!”","sources":{"KJV":{"text":"Therefore let all the house of Israel know assuredly, that God hath made that same Jesus, whom ye have crucified, both Lord and Christ."},"BSB":{"text":"Therefore let all Israel know with certainty that God has made this Jesus, whom you crucified, both Lord and Christ!”"}},"definableWords":["Israel","God","made","Lord","Christ"],"peopleInVerse":["Jesus"]},"37":{"text":"Now when they heard this, they were pricked in their heart, and said unto Peter and to the rest of the apostles, Men and brethren, what shall we do?","ref":"Acts 2:37","synthesized":"When the people heard this, they were cut to the heart and asked Peter and the other apostles, “Brothers, what shall we do?”","sources":{"KJV":{"text":"Now when they heard this, they were pricked in their heart, and said unto Peter and to the rest of the apostles, Men and brethren, what shall we do?"},"BSB":{"text":"When the people heard this, they were cut to the heart and asked Peter and the other apostles, “Brothers, what shall we do?”"}},"definableWords":["people","heart"],"peopleInVerse":["Peter"]},"38":{"text":"Then Peter said unto them, Repent, and be baptized every one of you in the name of Jesus Christ for the remission of sins, and ye shall receive the gift of the Holy Ghost.","ref":"Acts 2:38","synthesized":"Peter replied, “Repent and be baptized, every one of you, in the name of Jesus Christ for the forgiveness of your sins, and you will receive the gift of the Holy Spirit.","sources":{"KJV":{"text":"Then Peter said unto them, Repent, and be baptized every one of you in the name of Jesus Christ for the remission of sins, and ye shall receive the gift of the Holy Ghost."},"BSB":{"text":"Peter replied, “Repent and be baptized, every one of you, in the name of Jesus Christ for the forgiveness of your sins, and you will receive the gift of the Holy Spirit."}},"definableWords":["one","name","Christ","holy","Spirit"],"peopleInVerse":["Peter","Jesus"]},"39":{"text":"For the promise is unto you, and to your children, and to all that are afar off, even as many as the LORD our God shall call.","ref":"Acts 2:39","synthesized":"This promise belongs to you and your children and to all who are far off—to all whom the Lord our God will call to Himself.”","sources":{"KJV":{"text":"For the promise is unto you, and to your children, and to all that are afar off, even as many as the LORD our God shall call."},"BSB":{"text":"This promise belongs to you and your children and to all who are far off—to all whom the Lord our God will call to Himself.”"}},"definableWords":["promise","Lord","God"],"peopleInVerse":[]},"40":{"text":"And with many other words did he testify and exhort, saying, Save yourselves from this untoward generation.","ref":"Acts 2:40","synthesized":"With many other words he testified, and he urged them, “Be saved from this corrupt generation.”","sources":{"KJV":{"text":"And with many other words did he testify and exhort, saying, Save yourselves from this untoward generation."},"BSB":{"text":"With many other words he testified, and he urged them, “Be saved from this corrupt generation.”"}},"definableWords":[],"peopleInVerse":[]},"41":{"text":"Then they that gladly received his word were baptized: and the same day there were added unto them about three thousand souls.","ref":"Acts 2:41","synthesized":"Those who embraced his message were baptized, and about three thousand were added to the believers that day.","sources":{"KJV":{"text":"Then they that gladly received his word were baptized: and the same day there were added unto them about three thousand souls."},"BSB":{"text":"Those who embraced his message were baptized, and about three thousand were added to the believers that day."}},"definableWords":["day"],"peopleInVerse":[]},"42":{"text":"And they continued stedfastly in the apostles’ doctrine and fellowship, and in breaking of bread, and in prayers.","ref":"Acts 2:42","synthesized":"They devoted themselves to the apostles’ teaching and to the fellowship, to the breaking of bread and to prayer.","sources":{"KJV":{"text":"And they continued stedfastly in the apostles’ doctrine and fellowship, and in breaking of bread, and in prayers."},"BSB":{"text":"They devoted themselves to the apostles’ teaching and to the fellowship, to the breaking of bread and to prayer."}},"definableWords":["prayer"],"peopleInVerse":[]},"43":{"text":"And fear came upon every soul: and many wonders and signs were done by the apostles.","ref":"Acts 2:43","synthesized":"A sense of awe came over everyone, and the apostles performed many wonders and signs.","sources":{"KJV":{"text":"And fear came upon every soul: and many wonders and signs were done by the apostles."},"BSB":{"text":"A sense of awe came over everyone, and the apostles performed many wonders and signs."}},"definableWords":[],"peopleInVerse":[]},"44":{"text":"And all that believed were together, and had all things common;","ref":"Acts 2:44","synthesized":"All the believers were together and had everything in common.","sources":{"KJV":{"text":"And all that believed were together, and had all things common;"},"BSB":{"text":"All the believers were together and had everything in common."}},"definableWords":[],"peopleInVerse":[]},"45":{"text":"And sold their possessions and goods, and parted them to all men, as every man had need.","ref":"Acts 2:45","synthesized":"Selling their possessions and goods, they shared with anyone who was in need.","sources":{"KJV":{"text":"And sold their possessions and goods, and parted them to all men, as every man had need."},"BSB":{"text":"Selling their possessions and goods, they shared with anyone who was in need."}},"definableWords":[],"peopleInVerse":[]},"46":{"text":"And they, continuing daily with one accord in the temple, and breaking bread from house to house, did eat their meat with gladness and singleness of heart,","ref":"Acts 2:46","synthesized":"With one accord they continued to meet daily in the temple courts and to break bread from house to house, sharing their meals with gladness and sincerity of heart,","sources":{"KJV":{"text":"And they, continuing daily with one accord in the temple, and breaking bread from house to house, did eat their meat with gladness and singleness of heart,"},"BSB":{"text":"With one accord they continued to meet daily in the temple courts and to break bread from house to house, sharing their meals with gladness and sincerity of heart,"}},"definableWords":["one","temple","house","heart"],"peopleInVerse":[]},"47":{"text":"Praising God, and having favour with all the people. And the Lord added to the church daily such as should be saved.","ref":"Acts 2:47","synthesized":"praising God and enjoying the favor of all the people. And the Lord added to their number daily those who were being saved.","sources":{"KJV":{"text":"Praising God, and having favour with all the people. And the Lord added to the church daily such as should be saved."},"BSB":{"text":"praising God and enjoying the favor of all the people. And the Lord added to their number daily those who were being saved."}},"definableWords":["God","people","Lord"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"PETER AND JOHN — HEALING THE LAME MAN","verses":{"1":{"text":"Now Peter and John went up together into the temple at the hour of prayer, being the ninth hour.","ref":"Acts 3:1","synthesized":"One afternoon Peter and John were going up to the temple at the hour of prayer, the ninth hour.","sources":{"KJV":{"text":"Now Peter and John went up together into the temple at the hour of prayer, being the ninth hour."},"BSB":{"text":"One afternoon Peter and John were going up to the temple at the hour of prayer, the ninth hour."}},"definableWords":["one","temple","prayer"],"peopleInVerse":["Peter","John"]},"2":{"text":"And a certain man lame from his mother’s womb was carried, whom they laid daily at the gate of the temple which is called Beautiful, to ask alms of them that entered into the temple;","ref":"Acts 3:2","synthesized":"And a man who was lame from birth was being carried to the temple gate called Beautiful, where he was put every day to beg from those entering the temple courts.","sources":{"KJV":{"text":"And a certain man lame from his mother’s womb was carried, whom they laid daily at the gate of the temple which is called Beautiful, to ask alms of them that entered into the temple;"},"BSB":{"text":"And a man who was lame from birth was being carried to the temple gate called Beautiful, where he was put every day to beg from those entering the temple courts."}},"definableWords":["man","temple","day"],"peopleInVerse":[]},"3":{"text":"Who seeing Peter and John about to go into the temple asked an alms.","ref":"Acts 3:3","synthesized":"When he saw Peter and John about to enter, he asked them for money.","sources":{"KJV":{"text":"Who seeing Peter and John about to go into the temple asked an alms."},"BSB":{"text":"When he saw Peter and John about to enter, he asked them for money."}},"definableWords":["saw"],"peopleInVerse":["Peter","John"]},"4":{"text":"And Peter, fastening his eyes upon him with John, said, Look on us.","ref":"Acts 3:4","synthesized":"Peter looked directly at him, as did John. “Look at us!” said Peter.","sources":{"KJV":{"text":"And Peter, fastening his eyes upon him with John, said, Look on us."},"BSB":{"text":"Peter looked directly at him, as did John. “Look at us!” said Peter."}},"definableWords":[],"peopleInVerse":["Peter","John"]},"5":{"text":"And he gave heed unto them, expecting to receive something of them.","ref":"Acts 3:5","synthesized":"So the man gave them his attention, expecting to receive something from them.","sources":{"KJV":{"text":"And he gave heed unto them, expecting to receive something of them."},"BSB":{"text":"So the man gave them his attention, expecting to receive something from them."}},"definableWords":["man"],"peopleInVerse":[]},"6":{"text":"Then Peter said, Silver and gold have I none; but such as I have give I thee: In the name of Jesus Christ of Nazareth rise up and walk.","ref":"Acts 3:6","synthesized":"But Peter said, “Silver or gold I do not have, but what I have I give you: In the name of Jesus Christ of Nazareth, get up and walk!”","sources":{"KJV":{"text":"Then Peter said, Silver and gold have I none; but such as I have give I thee: In the name of Jesus Christ of Nazareth rise up and walk."},"BSB":{"text":"But Peter said, “Silver or gold I do not have, but what I have I give you: In the name of Jesus Christ of Nazareth, get up and walk!”"}},"definableWords":["or","name","Christ","walk"],"peopleInVerse":["Peter","Jesus"]},"7":{"text":"And he took him by the right hand, and lifted him up: and immediately his feet and ankle bones received strength.","ref":"Acts 3:7","synthesized":"Taking him by the right hand, Peter helped him up, and at once the man’s feet and ankles were made strong.","sources":{"KJV":{"text":"And he took him by the right hand, and lifted him up: and immediately his feet and ankle bones received strength."},"BSB":{"text":"Taking him by the right hand, Peter helped him up, and at once the man’s feet and ankles were made strong."}},"definableWords":["man","made","strong"],"peopleInVerse":["Peter"]},"8":{"text":"And he leaping up stood, and walked, and entered with them into the temple, walking, and leaping, and praising God.","ref":"Acts 3:8","synthesized":"He sprang to his feet and began to walk. Then he went with them into the temple courts, walking and leaping and praising God.","sources":{"KJV":{"text":"And he leaping up stood, and walked, and entered with them into the temple, walking, and leaping, and praising God."},"BSB":{"text":"He sprang to his feet and began to walk. Then he went with them into the temple courts, walking and leaping and praising God."}},"definableWords":["walk","temple","God"],"peopleInVerse":[]},"9":{"text":"And all the people saw him walking and praising God:","ref":"Acts 3:9","synthesized":"When all the people saw him walking and praising God,","sources":{"KJV":{"text":"And all the people saw him walking and praising God:"},"BSB":{"text":"When all the people saw him walking and praising God,"}},"definableWords":["people","saw","God"],"peopleInVerse":[]},"10":{"text":"And they knew that it was he which sat for alms at the Beautiful gate of the temple: and they were filled with wonder and amazement at that which had happened unto him.","ref":"Acts 3:10","synthesized":"they recognized him as the man who used to sit begging at the Beautiful Gate of the temple, and they were filled with wonder and amazement at what had happened to him.","sources":{"KJV":{"text":"And they knew that it was he which sat for alms at the Beautiful gate of the temple: and they were filled with wonder and amazement at that which had happened unto him."},"BSB":{"text":"they recognized him as the man who used to sit begging at the Beautiful Gate of the temple, and they were filled with wonder and amazement at what had happened to him."}},"definableWords":["man","temple"],"peopleInVerse":[]},"11":{"text":"And as the lame man which was healed held Peter and John, all the people ran together unto them in the porch that is called Solomon’s, greatly wondering.","ref":"Acts 3:11","synthesized":"While the man clung to Peter and John, all the people were astonished and ran to them in the walkway called Solomon’s Colonnade.","sources":{"KJV":{"text":"And as the lame man which was healed held Peter and John, all the people ran together unto them in the porch that is called Solomon’s, greatly wondering."},"BSB":{"text":"While the man clung to Peter and John, all the people were astonished and ran to them in the walkway called Solomon’s Colonnade."}},"definableWords":["man","people"],"peopleInVerse":["Peter","John","Solomon"]},"12":{"text":"And when Peter saw it, he answered unto the people, Ye men of Israel, why marvel ye at this? or why look ye so earnestly on us, as though by our own power or holiness we had made this man to walk?","ref":"Acts 3:12","synthesized":"And when Peter saw this, he addressed the people: “Men of Israel, why are you surprised by this? Why do you stare at us as if by our own power or godliness we had made this man walk?","sources":{"KJV":{"text":"And when Peter saw it, he answered unto the people, Ye men of Israel, why marvel ye at this? or why look ye so earnestly on us, as though by our own power or holiness we had made this man to walk?"},"BSB":{"text":"And when Peter saw this, he addressed the people: “Men of Israel, why are you surprised by this? Why do you stare at us as if by our own power or godliness we had made this man walk?"}},"definableWords":["saw","people","men","Israel","or","made","man","walk"],"peopleInVerse":["Peter"]},"13":{"text":"The God of Abraham, and of Isaac, and of Jacob, the God of our fathers, hath glorified his Son Jesus; whom ye delivered up, and denied him in the presence of Pilate, when he was determined to let him go.","ref":"Acts 3:13","synthesized":"The God of Abraham, Isaac, and Jacob, the God of our fathers, has glorified His servant Jesus. You handed Him over and rejected Him before Pilate, even though he had decided to release Him.","sources":{"KJV":{"text":"The God of Abraham, and of Isaac, and of Jacob, the God of our fathers, hath glorified his Son Jesus; whom ye delivered up, and denied him in the presence of Pilate, when he was determined to let him go."},"BSB":{"text":"The God of Abraham, Isaac, and Jacob, the God of our fathers, has glorified His servant Jesus. You handed Him over and rejected Him before Pilate, even though he had decided to release Him."}},"definableWords":["God","Abraham","Isaac","Jacob","fathers","servant"],"peopleInVerse":["Abraham","Isaac","Jacob","Jesus","Pilate"]},"14":{"text":"But ye denied the Holy One and the Just, and desired a murderer to be granted unto you;","ref":"Acts 3:14","synthesized":"You rejected the Holy and Righteous One and asked that a murderer be released to you.","sources":{"KJV":{"text":"But ye denied the Holy One and the Just, and desired a murderer to be granted unto you;"},"BSB":{"text":"You rejected the Holy and Righteous One and asked that a murderer be released to you."}},"definableWords":["holy","righteous","one"],"peopleInVerse":[]},"15":{"text":"And killed the Prince of life, whom God hath raised from the dead; whereof we are witnesses.","ref":"Acts 3:15","synthesized":"You killed the Author of life, but God raised Him from the dead, and we are witnesses of the fact.","sources":{"KJV":{"text":"And killed the Prince of life, whom God hath raised from the dead; whereof we are witnesses."},"BSB":{"text":"You killed the Author of life, but God raised Him from the dead, and we are witnesses of the fact."}},"definableWords":["life","God"],"peopleInVerse":[]},"16":{"text":"And his name through faith in his name hath made this man strong, whom ye see and know: yea, the faith which is by him hath given him this perfect soundness in the presence of you all.","ref":"Acts 3:16","synthesized":"By faith in the name of Jesus, this man whom you see and know has been made strong. It is Jesus’ name and the faith that comes through Him that has given him this complete healing in your presence.","sources":{"KJV":{"text":"And his name through faith in his name hath made this man strong, whom ye see and know: yea, the faith which is by him hath given him this perfect soundness in the presence of you all."},"BSB":{"text":"By faith in the name of Jesus, this man whom you see and know has been made strong. It is Jesus’ name and the faith that comes through Him that has given him this complete healing in your presence."}},"definableWords":["faith","name","man","see","made","strong"],"peopleInVerse":["Jesus"]},"17":{"text":"And now, brethren, I wot that through ignorance ye did it, as did also your rulers.","ref":"Acts 3:17","synthesized":"And now, brothers, I know that you acted in ignorance, as did your leaders.","sources":{"KJV":{"text":"And now, brethren, I wot that through ignorance ye did it, as did also your rulers."},"BSB":{"text":"And now, brothers, I know that you acted in ignorance, as did your leaders."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"But those things, which God before had shewed by the mouth of all his prophets, that Christ should suffer, he hath so fulfilled.","ref":"Acts 3:18","synthesized":"But in this way God has fulfilled what He foretold through all the prophets, saying that His Christ would suffer.","sources":{"KJV":{"text":"But those things, which God before had shewed by the mouth of all his prophets, that Christ should suffer, he hath so fulfilled."},"BSB":{"text":"But in this way God has fulfilled what He foretold through all the prophets, saying that His Christ would suffer."}},"definableWords":["way","God","Christ"],"peopleInVerse":[]},"19":{"text":"Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord;","ref":"Acts 3:19","synthesized":"Repent, then, and turn back, so that your sins may be wiped away,","sources":{"KJV":{"text":"Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord;"},"BSB":{"text":"Repent, then, and turn back, so that your sins may be wiped away,"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"And he shall send Jesus Christ, which before was preached unto you:","ref":"Acts 3:20","synthesized":"that times of refreshing may come from the presence of the Lord, and that He may send Jesus, the Christ, who has been appointed for you.","sources":{"KJV":{"text":"And he shall send Jesus Christ, which before was preached unto you:"},"BSB":{"text":"that times of refreshing may come from the presence of the Lord, and that He may send Jesus, the Christ, who has been appointed for you."}},"definableWords":["Lord","Christ"],"peopleInVerse":["Jesus"]},"21":{"text":"Whom the heaven must receive until the times of restitution of all things, which God hath spoken by the mouth of all his holy prophets since the world began.","ref":"Acts 3:21","synthesized":"Heaven must take Him in until the time comes for the restoration of all things, which God announced long ago through His holy prophets.","sources":{"KJV":{"text":"Whom the heaven must receive until the times of restitution of all things, which God hath spoken by the mouth of all his holy prophets since the world began."},"BSB":{"text":"Heaven must take Him in until the time comes for the restoration of all things, which God announced long ago through His holy prophets."}},"definableWords":["heaven","God","holy"],"peopleInVerse":[]},"22":{"text":"For Moses truly said unto the fathers, A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear in all things whatsoever he shall say unto you.","ref":"Acts 3:22","synthesized":"For Moses said, ‘The Lord your God will raise up for you a prophet like me from among your brothers. You must listen to Him in everything He tells you.","sources":{"KJV":{"text":"For Moses truly said unto the fathers, A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear in all things whatsoever he shall say unto you."},"BSB":{"text":"For Moses said, ‘The Lord your God will raise up for you a prophet like me from among your brothers. You must listen to Him in everything He tells you."}},"definableWords":["Lord","God","prophet"],"peopleInVerse":["Moses"]},"23":{"text":"And it shall come to pass, that every soul, which will not hear that prophet, shall be destroyed from among the people.","ref":"Acts 3:23","synthesized":"Everyone who does not listen to Him will be completely cut off from among his people.’","sources":{"KJV":{"text":"And it shall come to pass, that every soul, which will not hear that prophet, shall be destroyed from among the people."},"BSB":{"text":"Everyone who does not listen to Him will be completely cut off from among his people.’"}},"definableWords":["people"],"peopleInVerse":[]},"24":{"text":"Yea, and all the prophets from Samuel and those that follow after, as many as have spoken, have likewise foretold of these days.","ref":"Acts 3:24","synthesized":"Indeed, all the prophets from Samuel on, as many as have spoken, have proclaimed these days.","sources":{"KJV":{"text":"Yea, and all the prophets from Samuel and those that follow after, as many as have spoken, have likewise foretold of these days."},"BSB":{"text":"Indeed, all the prophets from Samuel on, as many as have spoken, have proclaimed these days."}},"definableWords":["days"],"peopleInVerse":["Samuel"]},"25":{"text":"Ye are the children of the prophets, and of the covenant which God made with our fathers, saying unto Abraham, And in thy seed shall all the kindreds of the earth be blessed.","ref":"Acts 3:25","synthesized":"And you are sons of the prophets and of the covenant God made with your fathers when He said to Abraham, ‘Through your offspring all the families of the earth will be blessed.’","sources":{"KJV":{"text":"Ye are the children of the prophets, and of the covenant which God made with our fathers, saying unto Abraham, And in thy seed shall all the kindreds of the earth be blessed."},"BSB":{"text":"And you are sons of the prophets and of the covenant God made with your fathers when He said to Abraham, ‘Through your offspring all the families of the earth will be blessed.’"}},"definableWords":["sons","covenant","God","made","fathers","Abraham","families","earth","blessed"],"peopleInVerse":["Abraham"]},"26":{"text":"Unto you first God, having raised up his Son Jesus, sent him to bless you, in turning away every one of you from his iniquities.","ref":"Acts 3:26","synthesized":"When God raised up His Servant, He sent Him first to you to bless you by turning each of you from your wicked ways.”","sources":{"KJV":{"text":"Unto you first God, having raised up his Son Jesus, sent him to bless you, in turning away every one of you from his iniquities."},"BSB":{"text":"When God raised up His Servant, He sent Him first to you to bless you by turning each of you from your wicked ways.”"}},"definableWords":["God","servant","bless"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"PETER AND JOHN BEFORE THE SANHEDRIN","verses":{"1":{"text":"And as they spake unto the people, the priests, and the captain of the temple, and the Sadducees, came upon them,","ref":"Acts 4:1","synthesized":"While Peter and John were speaking to the people, the priests and the captain of the temple guard and the Sadducees came up to them,","sources":{"KJV":{"text":"And as they spake unto the people, the priests, and the captain of the temple, and the Sadducees, came upon them,"},"BSB":{"text":"While Peter and John were speaking to the people, the priests and the captain of the temple guard and the Sadducees came up to them,"}},"definableWords":["people","temple"],"peopleInVerse":["Peter","John"]},"2":{"text":"Being grieved that they taught the people, and preached through Jesus the resurrection from the dead.","ref":"Acts 4:2","synthesized":"greatly disturbed that they were teaching the people and proclaiming in Jesus the resurrection of the dead.","sources":{"KJV":{"text":"Being grieved that they taught the people, and preached through Jesus the resurrection from the dead."},"BSB":{"text":"greatly disturbed that they were teaching the people and proclaiming in Jesus the resurrection of the dead."}},"definableWords":["people","resurrection"],"peopleInVerse":["Jesus"]},"3":{"text":"And they laid hands on them, and put them in hold unto the next day: for it was now eventide.","ref":"Acts 4:3","synthesized":"They seized Peter and John, and because it was evening, they put them in custody until the next day.","sources":{"KJV":{"text":"And they laid hands on them, and put them in hold unto the next day: for it was now eventide."},"BSB":{"text":"They seized Peter and John, and because it was evening, they put them in custody until the next day."}},"definableWords":["day"],"peopleInVerse":["Peter","John"]},"4":{"text":"Howbeit many of them which heard the word believed; and the number of the men was about five thousand.","ref":"Acts 4:4","synthesized":"But many who heard the message believed, and the number of men grew to about five thousand.","sources":{"KJV":{"text":"Howbeit many of them which heard the word believed; and the number of the men was about five thousand."},"BSB":{"text":"But many who heard the message believed, and the number of men grew to about five thousand."}},"definableWords":["believed","men"],"peopleInVerse":[]},"5":{"text":"And it came to pass on the morrow, that their rulers, and elders, and scribes,","ref":"Acts 4:5","synthesized":"The next day the rulers, elders, and scribes assembled in Jerusalem,","sources":{"KJV":{"text":"And it came to pass on the morrow, that their rulers, and elders, and scribes,"},"BSB":{"text":"The next day the rulers, elders, and scribes assembled in Jerusalem,"}},"definableWords":["day","Jerusalem"],"peopleInVerse":[]},"6":{"text":"And Annas the high priest, and Caiaphas, and John, and Alexander, and as many as were of the kindred of the high priest, were gathered together at Jerusalem.","ref":"Acts 4:6","synthesized":"along with Annas the high priest, Caiaphas, John, Alexander, and many others from the high priest’s family.","sources":{"KJV":{"text":"And Annas the high priest, and Caiaphas, and John, and Alexander, and as many as were of the kindred of the high priest, were gathered together at Jerusalem."},"BSB":{"text":"along with Annas the high priest, Caiaphas, John, Alexander, and many others from the high priest’s family."}},"definableWords":["priest","family"],"peopleInVerse":["Caiaphas","John"]},"7":{"text":"And when they had set them in the midst, they asked, By what power, or by what name, have ye done this?","ref":"Acts 4:7","synthesized":"They had Peter and John brought in and began to question them: “By what power or what name did you do this?”","sources":{"KJV":{"text":"And when they had set them in the midst, they asked, By what power, or by what name, have ye done this?"},"BSB":{"text":"They had Peter and John brought in and began to question them: “By what power or what name did you do this?”"}},"definableWords":["or","name"],"peopleInVerse":["Peter","John"]},"8":{"text":"Then Peter, filled with the Holy Ghost, said unto them, Ye rulers of the people, and elders of Israel,","ref":"Acts 4:8","synthesized":"Then Peter, filled with the Holy Spirit, said to them, “Rulers and elders of the people!","sources":{"KJV":{"text":"Then Peter, filled with the Holy Ghost, said unto them, Ye rulers of the people, and elders of Israel,"},"BSB":{"text":"Then Peter, filled with the Holy Spirit, said to them, “Rulers and elders of the people!"}},"definableWords":["holy","Spirit","people"],"peopleInVerse":["Peter"]},"9":{"text":"If we this day be examined of the good deed done to the impotent man, by what means he is made whole;","ref":"Acts 4:9","synthesized":"If we are being examined today about a kind service to a man who was lame, to determine how he was healed,","sources":{"KJV":{"text":"If we this day be examined of the good deed done to the impotent man, by what means he is made whole;"},"BSB":{"text":"If we are being examined today about a kind service to a man who was lame, to determine how he was healed,"}},"definableWords":["man"],"peopleInVerse":[]},"10":{"text":"Be it known unto you all, and to all the people of Israel, that by the name of Jesus Christ of Nazareth, whom ye crucified, whom God raised from the dead, even by him doth this man stand here before you whole.","ref":"Acts 4:10","synthesized":"then let this be known to all of you and to all the people of Israel: It is by the name of Jesus Christ of Nazareth, whom you crucified but whom God raised from the dead, that this man stands before you healed.","sources":{"KJV":{"text":"Be it known unto you all, and to all the people of Israel, that by the name of Jesus Christ of Nazareth, whom ye crucified, whom God raised from the dead, even by him doth this man stand here before you whole."},"BSB":{"text":"then let this be known to all of you and to all the people of Israel: It is by the name of Jesus Christ of Nazareth, whom you crucified but whom God raised from the dead, that this man stands before you healed."}},"definableWords":["people","Israel","name","Christ","God","man"],"peopleInVerse":["Jesus"]},"11":{"text":"This is the stone which was set at nought of you builders, which is become the head of the corner.","ref":"Acts 4:11","synthesized":"This Jesus is  ‘the stone you builders rejected, which has become the cornerstone.’","sources":{"KJV":{"text":"This is the stone which was set at nought of you builders, which is become the head of the corner."},"BSB":{"text":"This Jesus is  ‘the stone you builders rejected, which has become the cornerstone.’"}},"definableWords":["stone"],"peopleInVerse":["Jesus"]},"12":{"text":"Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved.","ref":"Acts 4:12","synthesized":"Salvation exists in no one else, for there is no other name under heaven given to men by which we must be saved.”","sources":{"KJV":{"text":"Neither is there salvation in any other: for there is none other name under heaven given among men, whereby we must be saved."},"BSB":{"text":"Salvation exists in no one else, for there is no other name under heaven given to men by which we must be saved.”"}},"definableWords":["salvation","one","name","heaven","men"],"peopleInVerse":[]},"13":{"text":"Now when they saw the boldness of Peter and John, and perceived that they were unlearned and ignorant men, they marvelled; and they took knowledge of them, that they had been with Jesus.","ref":"Acts 4:13","synthesized":"When they saw the boldness of Peter and John and realized that they were unschooled, ordinary men, they marveled and took note that these men had been with Jesus.","sources":{"KJV":{"text":"Now when they saw the boldness of Peter and John, and perceived that they were unlearned and ignorant men, they marvelled; and they took knowledge of them, that they had been with Jesus."},"BSB":{"text":"When they saw the boldness of Peter and John and realized that they were unschooled, ordinary men, they marveled and took note that these men had been with Jesus."}},"definableWords":["saw","men"],"peopleInVerse":["Peter","John","Jesus"]},"14":{"text":"And beholding the man which was healed standing with them, they could say nothing against it.","ref":"Acts 4:14","synthesized":"And seeing the man who had been healed standing there with them, they had nothing to say in response.","sources":{"KJV":{"text":"And beholding the man which was healed standing with them, they could say nothing against it."},"BSB":{"text":"And seeing the man who had been healed standing there with them, they had nothing to say in response."}},"definableWords":["man"],"peopleInVerse":[]},"15":{"text":"But when they had commanded them to go aside out of the council, they conferred among themselves,","ref":"Acts 4:15","synthesized":"So they ordered them to leave the Sanhedrin and then conferred together.","sources":{"KJV":{"text":"But when they had commanded them to go aside out of the council, they conferred among themselves,"},"BSB":{"text":"So they ordered them to leave the Sanhedrin and then conferred together."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Saying, What shall we do to these men? for that indeed a notable miracle hath been done by them is manifest to all them that dwell in Jerusalem; and we cannot deny it.","ref":"Acts 4:16","synthesized":"“What shall we do with these men?” they asked. “It is clear to everyone living in Jerusalem that a remarkable miracle has occurred through them, and we cannot deny it.","sources":{"KJV":{"text":"Saying, What shall we do to these men? for that indeed a notable miracle hath been done by them is manifest to all them that dwell in Jerusalem; and we cannot deny it."},"BSB":{"text":"“What shall we do with these men?” they asked. “It is clear to everyone living in Jerusalem that a remarkable miracle has occurred through them, and we cannot deny it."}},"definableWords":["men","living","Jerusalem"],"peopleInVerse":[]},"17":{"text":"But that it spread no further among the people, let us straitly threaten them, that they speak henceforth to no man in this name.","ref":"Acts 4:17","synthesized":"But to keep this message from spreading any further among the people, we must warn them not to speak to anyone in this name.”","sources":{"KJV":{"text":"But that it spread no further among the people, let us straitly threaten them, that they speak henceforth to no man in this name."},"BSB":{"text":"But to keep this message from spreading any further among the people, we must warn them not to speak to anyone in this name.”"}},"definableWords":["keep","people","name"],"peopleInVerse":[]},"18":{"text":"And they called them, and commanded them not to speak at all nor teach in the name of Jesus.","ref":"Acts 4:18","synthesized":"Then they called them in again and commanded them not to speak or teach at all in the name of Jesus.","sources":{"KJV":{"text":"And they called them, and commanded them not to speak at all nor teach in the name of Jesus."},"BSB":{"text":"Then they called them in again and commanded them not to speak or teach at all in the name of Jesus."}},"definableWords":["or","name"],"peopleInVerse":["Jesus"]},"19":{"text":"But Peter and John answered and said unto them, Whether it be right in the sight of God to hearken unto you more than unto God, judge ye.","ref":"Acts 4:19","synthesized":"But Peter and John replied, “Judge for yourselves whether it is right in God’s sight to listen to you rather than God.","sources":{"KJV":{"text":"But Peter and John answered and said unto them, Whether it be right in the sight of God to hearken unto you more than unto God, judge ye."},"BSB":{"text":"But Peter and John replied, “Judge for yourselves whether it is right in God’s sight to listen to you rather than God."}},"definableWords":["God"],"peopleInVerse":["Peter","John"]},"20":{"text":"For we cannot but speak the things which we have seen and heard.","ref":"Acts 4:20","synthesized":"For we cannot stop speaking about what we have seen and heard.”","sources":{"KJV":{"text":"For we cannot but speak the things which we have seen and heard."},"BSB":{"text":"For we cannot stop speaking about what we have seen and heard.”"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"So when they had further threatened them, they let them go, finding nothing how they might punish them, because of the people: for all men glorified God for that which was done.","ref":"Acts 4:21","synthesized":"After further threats they let them go. They could not find a way to punish them, because all the people were glorifying God for what had happened.","sources":{"KJV":{"text":"So when they had further threatened them, they let them go, finding nothing how they might punish them, because of the people: for all men glorified God for that which was done."},"BSB":{"text":"After further threats they let them go. They could not find a way to punish them, because all the people were glorifying God for what had happened."}},"definableWords":["way","people","God"],"peopleInVerse":[]},"22":{"text":"For the man was above forty years old, on whom this miracle of healing was shewed.","ref":"Acts 4:22","synthesized":"For the man who was miraculously healed was over forty years old.","sources":{"KJV":{"text":"For the man was above forty years old, on whom this miracle of healing was shewed."},"BSB":{"text":"For the man who was miraculously healed was over forty years old."}},"definableWords":["man","years"],"peopleInVerse":[]},"23":{"text":"And being let go, they went to their own company, and reported all that the chief priests and elders had said unto them.","ref":"Acts 4:23","synthesized":"On their release, Peter and John returned to their own people and reported everything that the chief priests and elders had said to them.","sources":{"KJV":{"text":"And being let go, they went to their own company, and reported all that the chief priests and elders had said unto them."},"BSB":{"text":"On their release, Peter and John returned to their own people and reported everything that the chief priests and elders had said to them."}},"definableWords":["people"],"peopleInVerse":["Peter","John"]},"24":{"text":"And when they heard that, they lifted up their voice to God with one accord, and said, Lord, thou art God, which hast made heaven, and earth, and the sea, and all that in them is:","ref":"Acts 4:24","synthesized":"When the believers heard this, they lifted up their voices to God with one accord. “Sovereign Lord,” they said, “You made the heaven and the earth and the sea and everything in them.","sources":{"KJV":{"text":"And when they heard that, they lifted up their voice to God with one accord, and said, Lord, thou art God, which hast made heaven, and earth, and the sea, and all that in them is:"},"BSB":{"text":"When the believers heard this, they lifted up their voices to God with one accord. “Sovereign Lord,” they said, “You made the heaven and the earth and the sea and everything in them."}},"definableWords":["God","one","Lord","made","heaven","earth","sea"],"peopleInVerse":[]},"25":{"text":"Who by the mouth of thy servant David hast said, Why did the heathen rage, and the people imagine vain things?","ref":"Acts 4:25","synthesized":"You spoke by the Holy Spirit through the mouth of Your servant, our father David:  ‘Why do the nations rage and the peoples plot in vain?","sources":{"KJV":{"text":"Who by the mouth of thy servant David hast said, Why did the heathen rage, and the people imagine vain things?"},"BSB":{"text":"You spoke by the Holy Spirit through the mouth of Your servant, our father David:  ‘Why do the nations rage and the peoples plot in vain?"}},"definableWords":["holy","Spirit","servant","father","nations"],"peopleInVerse":["David"]},"26":{"text":"The kings of the earth stood up, and the rulers were gathered together against the Lord, and against his Christ.","ref":"Acts 4:26","synthesized":"The kings of the earth take their stand and the rulers gather together against the Lord and against His Anointed One.’","sources":{"KJV":{"text":"The kings of the earth stood up, and the rulers were gathered together against the Lord, and against his Christ."},"BSB":{"text":"The kings of the earth take their stand and the rulers gather together against the Lord and against His Anointed One.’"}},"definableWords":["kings","earth","stand","Lord","one"],"peopleInVerse":[]},"27":{"text":"For of a truth against thy holy child Jesus, whom thou hast anointed, both Herod, and Pontius Pilate, with the Gentiles, and the people of Israel, were gathered together,","ref":"Acts 4:27","synthesized":"In fact, this is the very city where Herod and Pontius Pilate conspired with the Gentiles and the people of Israel against Your holy servant Jesus, whom You anointed.","sources":{"KJV":{"text":"For of a truth against thy holy child Jesus, whom thou hast anointed, both Herod, and Pontius Pilate, with the Gentiles, and the people of Israel, were gathered together,"},"BSB":{"text":"In fact, this is the very city where Herod and Pontius Pilate conspired with the Gentiles and the people of Israel against Your holy servant Jesus, whom You anointed."}},"definableWords":["people","Israel","holy","servant"],"peopleInVerse":["Herod","Pilate","Jesus"]},"28":{"text":"For to do whatsoever thy hand and thy counsel determined before to be done.","ref":"Acts 4:28","synthesized":"They carried out what Your hand and will had decided beforehand would happen.","sources":{"KJV":{"text":"For to do whatsoever thy hand and thy counsel determined before to be done."},"BSB":{"text":"They carried out what Your hand and will had decided beforehand would happen."}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"And now, Lord, behold their threatenings: and grant unto thy servants, that with all boldness they may speak thy word,","ref":"Acts 4:29","synthesized":"And now, Lord, consider their threats, and enable Your servants to speak Your word with complete boldness,","sources":{"KJV":{"text":"And now, Lord, behold their threatenings: and grant unto thy servants, that with all boldness they may speak thy word,"},"BSB":{"text":"And now, Lord, consider their threats, and enable Your servants to speak Your word with complete boldness,"}},"definableWords":["Lord","servants","word"],"peopleInVerse":[]},"30":{"text":"By stretching forth thine hand to heal; and that signs and wonders may be done by the name of thy holy child Jesus.","ref":"Acts 4:30","synthesized":"as You stretch out Your hand to heal and perform signs and wonders through the name of Your holy servant Jesus.”","sources":{"KJV":{"text":"By stretching forth thine hand to heal; and that signs and wonders may be done by the name of thy holy child Jesus."},"BSB":{"text":"as You stretch out Your hand to heal and perform signs and wonders through the name of Your holy servant Jesus.”"}},"definableWords":["heal","name","holy","servant"],"peopleInVerse":["Jesus"]},"31":{"text":"And when they had prayed, the place was shaken where they were assembled together; and they were all filled with the Holy Ghost, and they spake the word of God with boldness.","ref":"Acts 4:31","synthesized":"After they had prayed, their meeting place was shaken, and they were all filled with the Holy Spirit and spoke the word of God boldly.","sources":{"KJV":{"text":"And when they had prayed, the place was shaken where they were assembled together; and they were all filled with the Holy Ghost, and they spake the word of God with boldness."},"BSB":{"text":"After they had prayed, their meeting place was shaken, and they were all filled with the Holy Spirit and spoke the word of God boldly."}},"definableWords":["holy","Spirit","word","God"],"peopleInVerse":[]},"32":{"text":"And the multitude of them that believed were of one heart and of one soul: neither said any of them that ought of the things which he possessed was his own; but they had all things common.","ref":"Acts 4:32","synthesized":"The multitude of believers was one in heart and soul. No one claimed that any of his possessions was his own, but they shared everything they owned.","sources":{"KJV":{"text":"And the multitude of them that believed were of one heart and of one soul: neither said any of them that ought of the things which he possessed was his own; but they had all things common."},"BSB":{"text":"The multitude of believers was one in heart and soul. No one claimed that any of his possessions was his own, but they shared everything they owned."}},"definableWords":["one","heart","soul"],"peopleInVerse":[]},"33":{"text":"And with great power gave the apostles witness of the resurrection of the Lord Jesus: and great grace was upon them all.","ref":"Acts 4:33","synthesized":"With great power the apostles continued to give their testimony about the resurrection of the Lord Jesus. And abundant grace was upon them all.","sources":{"KJV":{"text":"And with great power gave the apostles witness of the resurrection of the Lord Jesus: and great grace was upon them all."},"BSB":{"text":"With great power the apostles continued to give their testimony about the resurrection of the Lord Jesus. And abundant grace was upon them all."}},"definableWords":["great","resurrection","Lord","grace"],"peopleInVerse":["Jesus"]},"34":{"text":"Neither was there any among them that lacked: for as many as were possessors of lands or houses sold them, and brought the prices of the things that were sold,","ref":"Acts 4:34","synthesized":"There were no needy ones among them, because those who owned lands or houses would sell their property, bring the proceeds from the sales,","sources":{"KJV":{"text":"Neither was there any among them that lacked: for as many as were possessors of lands or houses sold them, and brought the prices of the things that were sold,"},"BSB":{"text":"There were no needy ones among them, because those who owned lands or houses would sell their property, bring the proceeds from the sales,"}},"definableWords":["or"],"peopleInVerse":[]},"35":{"text":"And laid them down at the apostles’ feet: and distribution was made unto every man according as he had need.","ref":"Acts 4:35","synthesized":"and lay them at the apostles’ feet for distribution to anyone as he had need.","sources":{"KJV":{"text":"And laid them down at the apostles’ feet: and distribution was made unto every man according as he had need."},"BSB":{"text":"and lay them at the apostles’ feet for distribution to anyone as he had need."}},"definableWords":[],"peopleInVerse":[]},"36":{"text":"And Joses, who by the apostles was surnamed Barnabas, (which is, being interpreted, The son of consolation,) a Levite, and of the country of Cyprus,","ref":"Acts 4:36","synthesized":"Joseph, a Levite from Cyprus, whom the apostles called Barnabas (meaning Son of Encouragement),","sources":{"KJV":{"text":"And Joses, who by the apostles was surnamed Barnabas, (which is, being interpreted, The son of consolation,) a Levite, and of the country of Cyprus,"},"BSB":{"text":"Joseph, a Levite from Cyprus, whom the apostles called Barnabas (meaning Son of Encouragement),"}},"definableWords":["Joseph","Son"],"peopleInVerse":["Joseph","Barnabas"]},"37":{"text":"Having land, sold it, and brought the money, and laid it at the apostles’ feet.","ref":"Acts 4:37","synthesized":"sold a field he owned, brought the money, and laid it at the apostles’ feet.","sources":{"KJV":{"text":"Having land, sold it, and brought the money, and laid it at the apostles’ feet."},"BSB":{"text":"sold a field he owned, brought the money, and laid it at the apostles’ feet."}},"definableWords":["field"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"ANANIAS AND SAPPHIRA","verses":{"1":{"text":"But a certain man named Ananias, with Sapphira his wife, sold a possession,","ref":"Acts 5:1","synthesized":"Now a man named Ananias, together with his wife Sapphira, also sold a piece of property.","sources":{"KJV":{"text":"But a certain man named Ananias, with Sapphira his wife, sold a possession,"},"BSB":{"text":"Now a man named Ananias, together with his wife Sapphira, also sold a piece of property."}},"definableWords":["man","wife"],"peopleInVerse":[]},"2":{"text":"And kept back part of the price, his wife also being privy to it, and brought a certain part, and laid it at the apostles’ feet.","ref":"Acts 5:2","synthesized":"With his wife’s full knowledge, he kept back some of the proceeds for himself, but brought a portion and laid it at the apostles’ feet.","sources":{"KJV":{"text":"And kept back part of the price, his wife also being privy to it, and brought a certain part, and laid it at the apostles’ feet."},"BSB":{"text":"With his wife’s full knowledge, he kept back some of the proceeds for himself, but brought a portion and laid it at the apostles’ feet."}},"definableWords":["wife","knowledge"],"peopleInVerse":[]},"3":{"text":"But Peter said, Ananias, why hath Satan filled thine heart to lie to the Holy Ghost, and to keep back part of the price of the land?","ref":"Acts 5:3","synthesized":"Then Peter said, “Ananias, how is it that Satan has filled your heart to lie to the Holy Spirit and withhold some of the proceeds from the land?","sources":{"KJV":{"text":"But Peter said, Ananias, why hath Satan filled thine heart to lie to the Holy Ghost, and to keep back part of the price of the land?"},"BSB":{"text":"Then Peter said, “Ananias, how is it that Satan has filled your heart to lie to the Holy Spirit and withhold some of the proceeds from the land?"}},"definableWords":["Satan","heart","holy","Spirit","land"],"peopleInVerse":["Peter"]},"4":{"text":"Whiles it remained, was it not thine own? and after it was sold, was it not in thine own power? why hast thou conceived this thing in thine heart? thou hast not lied unto men, but unto God.","ref":"Acts 5:4","synthesized":"Did it not belong to you before it was sold? And after it was sold, was it not at your disposal? How could you conceive such a deed in your heart? You have not lied to men, but to God!”","sources":{"KJV":{"text":"Whiles it remained, was it not thine own? and after it was sold, was it not in thine own power? why hast thou conceived this thing in thine heart? thou hast not lied unto men, but unto God."},"BSB":{"text":"Did it not belong to you before it was sold? And after it was sold, was it not at your disposal? How could you conceive such a deed in your heart? You have not lied to men, but to God!”"}},"definableWords":["heart","men","God"],"peopleInVerse":[]},"5":{"text":"And Ananias hearing these words fell down, and gave up the ghost: and great fear came on all them that heard these things.","ref":"Acts 5:5","synthesized":"On hearing these words, Ananias fell down and died. And great fear came over all who heard what had happened.","sources":{"KJV":{"text":"And Ananias hearing these words fell down, and gave up the ghost: and great fear came on all them that heard these things."},"BSB":{"text":"On hearing these words, Ananias fell down and died. And great fear came over all who heard what had happened."}},"definableWords":["great","fear"],"peopleInVerse":[]},"6":{"text":"And the young men arose, wound him up, and carried him out, and buried him.","ref":"Acts 5:6","synthesized":"Then the young men stepped forward, wrapped up his body, and carried him out and buried him.","sources":{"KJV":{"text":"And the young men arose, wound him up, and carried him out, and buried him."},"BSB":{"text":"Then the young men stepped forward, wrapped up his body, and carried him out and buried him."}},"definableWords":["men"],"peopleInVerse":[]},"7":{"text":"And it was about the space of three hours after, when his wife, not knowing what was done, came in.","ref":"Acts 5:7","synthesized":"About three hours later his wife also came in, unaware of what had happened.","sources":{"KJV":{"text":"And it was about the space of three hours after, when his wife, not knowing what was done, came in."},"BSB":{"text":"About three hours later his wife also came in, unaware of what had happened."}},"definableWords":["wife"],"peopleInVerse":[]},"8":{"text":"And Peter answered unto her, Tell me whether ye sold the land for so much? And she said, Yea, for so much.","ref":"Acts 5:8","synthesized":"“Tell me,” said Peter, “is this the price you and your husband got for the land?”  “Yes,” she answered, “that is the price.”","sources":{"KJV":{"text":"And Peter answered unto her, Tell me whether ye sold the land for so much? And she said, Yea, for so much."},"BSB":{"text":"“Tell me,” said Peter, “is this the price you and your husband got for the land?”  “Yes,” she answered, “that is the price.”"}},"definableWords":["husband","land"],"peopleInVerse":["Peter"]},"9":{"text":"Then Peter said unto her, How is it that ye have agreed together to tempt the Spirit of the Lord? behold, the feet of them which have buried thy husband are at the door, and shall carry thee out.","ref":"Acts 5:9","synthesized":"“How could you agree to test the Spirit of the Lord?” Peter replied. “Look, the feet of the men who buried your husband are at the door, and they will carry you out also.”","sources":{"KJV":{"text":"Then Peter said unto her, How is it that ye have agreed together to tempt the Spirit of the Lord? behold, the feet of them which have buried thy husband are at the door, and shall carry thee out."},"BSB":{"text":"“How could you agree to test the Spirit of the Lord?” Peter replied. “Look, the feet of the men who buried your husband are at the door, and they will carry you out also.”"}},"definableWords":["Spirit","Lord","men","husband"],"peopleInVerse":["Peter"]},"10":{"text":"Then fell she down straightway at his feet, and yielded up the ghost: and the young men came in, and found her dead, and, carrying her forth, buried her by her husband.","ref":"Acts 5:10","synthesized":"At that instant she fell down at his feet and died. Then the young men came in and, finding her dead, carried her out and buried her beside her husband.","sources":{"KJV":{"text":"Then fell she down straightway at his feet, and yielded up the ghost: and the young men came in, and found her dead, and, carrying her forth, buried her by her husband."},"BSB":{"text":"At that instant she fell down at his feet and died. Then the young men came in and, finding her dead, carried her out and buried her beside her husband."}},"definableWords":["men","husband"],"peopleInVerse":[]},"11":{"text":"And great fear came upon all the church, and upon as many as heard these things.","ref":"Acts 5:11","synthesized":"And great fear came over the whole church and all who heard about these events.","sources":{"KJV":{"text":"And great fear came upon all the church, and upon as many as heard these things."},"BSB":{"text":"And great fear came over the whole church and all who heard about these events."}},"definableWords":["great","fear","church"],"peopleInVerse":[]},"12":{"text":"And by the hands of the apostles were many signs and wonders wrought among the people; (and they were all with one accord in Solomon’s porch.","ref":"Acts 5:12","synthesized":"The apostles performed many signs and wonders among the people, and with one accord the believers gathered together in Solomon’s Colonnade.","sources":{"KJV":{"text":"And by the hands of the apostles were many signs and wonders wrought among the people; (and they were all with one accord in Solomon’s porch."},"BSB":{"text":"The apostles performed many signs and wonders among the people, and with one accord the believers gathered together in Solomon’s Colonnade."}},"definableWords":["people","one"],"peopleInVerse":["Solomon"]},"13":{"text":"And of the rest durst no man join himself to them: but the people magnified them.","ref":"Acts 5:13","synthesized":"Although the people regarded them highly, no one else dared to join them.","sources":{"KJV":{"text":"And of the rest durst no man join himself to them: but the people magnified them."},"BSB":{"text":"Although the people regarded them highly, no one else dared to join them."}},"definableWords":["people","one"],"peopleInVerse":[]},"14":{"text":"And believers were the more added to the Lord, multitudes both of men and women.)","ref":"Acts 5:14","synthesized":"Yet more and more believers were brought to the Lord—large numbers of both men and women.","sources":{"KJV":{"text":"And believers were the more added to the Lord, multitudes both of men and women.)"},"BSB":{"text":"Yet more and more believers were brought to the Lord—large numbers of both men and women."}},"definableWords":["Lord","men","women"],"peopleInVerse":[]},"15":{"text":"Insomuch that they brought forth the sick into the streets, and laid them on beds and couches, that at the least the shadow of Peter passing by might overshadow some of them.","ref":"Acts 5:15","synthesized":"As a result, people brought the sick into the streets and laid them on cots and mats, so that at least Peter’s shadow might fall on some of them as he passed by.","sources":{"KJV":{"text":"Insomuch that they brought forth the sick into the streets, and laid them on beds and couches, that at the least the shadow of Peter passing by might overshadow some of them."},"BSB":{"text":"As a result, people brought the sick into the streets and laid them on cots and mats, so that at least Peter’s shadow might fall on some of them as he passed by."}},"definableWords":["people"],"peopleInVerse":["Peter"]},"16":{"text":"There came also a multitude out of the cities round about unto Jerusalem, bringing sick folks, and them which were vexed with unclean spirits: and they were healed every one.","ref":"Acts 5:16","synthesized":"Crowds also gathered from the towns around Jerusalem, bringing the sick and those tormented by unclean spirits, and all of them were healed.","sources":{"KJV":{"text":"There came also a multitude out of the cities round about unto Jerusalem, bringing sick folks, and them which were vexed with unclean spirits: and they were healed every one."},"BSB":{"text":"Crowds also gathered from the towns around Jerusalem, bringing the sick and those tormented by unclean spirits, and all of them were healed."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"17":{"text":"Then the high priest rose up, and all they that were with him, (which is the sect of the Sadducees,) and were filled with indignation,","ref":"Acts 5:17","synthesized":"Then the high priest and all his associates, who belonged to the party of the Sadducees, were filled with jealousy. They went out","sources":{"KJV":{"text":"Then the high priest rose up, and all they that were with him, (which is the sect of the Sadducees,) and were filled with indignation,"},"BSB":{"text":"Then the high priest and all his associates, who belonged to the party of the Sadducees, were filled with jealousy. They went out"}},"definableWords":["priest"],"peopleInVerse":[]},"18":{"text":"And laid their hands on the apostles, and put them in the common prison.","ref":"Acts 5:18","synthesized":"and arrested the apostles and put them in the public jail.","sources":{"KJV":{"text":"And laid their hands on the apostles, and put them in the common prison."},"BSB":{"text":"and arrested the apostles and put them in the public jail."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"But the angel of the Lord by night opened the prison doors, and brought them forth, and said,","ref":"Acts 5:19","synthesized":"But during the night an angel of the Lord opened the doors of the jail and brought them out, saying,","sources":{"KJV":{"text":"But the angel of the Lord by night opened the prison doors, and brought them forth, and said,"},"BSB":{"text":"But during the night an angel of the Lord opened the doors of the jail and brought them out, saying,"}},"definableWords":["night","angel","Lord"],"peopleInVerse":[]},"20":{"text":"Go, stand and speak in the temple to the people all the words of this life.","ref":"Acts 5:20","synthesized":"“Go, stand in the temple courts and tell the people the full message of this new life.”","sources":{"KJV":{"text":"Go, stand and speak in the temple to the people all the words of this life."},"BSB":{"text":"“Go, stand in the temple courts and tell the people the full message of this new life.”"}},"definableWords":["stand","temple","people","life"],"peopleInVerse":[]},"21":{"text":"And when they heard that, they entered into the temple early in the morning, and taught. But the high priest came, and they that were with him, and called the council together, and all the senate of the children of Israel, and sent to the prison to have them brought.","ref":"Acts 5:21","synthesized":"At daybreak the apostles entered the temple courts as they had been told and began to teach the people.  When the high priest and his associates arrived, they convened the Sanhedrin—the full assembly of the elders of Israel—and sent to the jail for the apostles.","sources":{"KJV":{"text":"And when they heard that, they entered into the temple early in the morning, and taught. But the high priest came, and they that were with him, and called the council together, and all the senate of the children of Israel, and sent to the prison to have them brought."},"BSB":{"text":"At daybreak the apostles entered the temple courts as they had been told and began to teach the people.  When the high priest and his associates arrived, they convened the Sanhedrin—the full assembly of the elders of Israel—and sent to the jail for the apostles."}},"definableWords":["temple","people","priest","Israel"],"peopleInVerse":[]},"22":{"text":"But when the officers came, and found them not in the prison, they returned, and told,","ref":"Acts 5:22","synthesized":"But on arriving at the jail, the officers did not find them there. So they returned with the report:","sources":{"KJV":{"text":"But when the officers came, and found them not in the prison, they returned, and told,"},"BSB":{"text":"But on arriving at the jail, the officers did not find them there. So they returned with the report:"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Saying, The prison truly found we shut with all safety, and the keepers standing without before the doors: but when we had opened, we found no man within.","ref":"Acts 5:23","synthesized":"“We found the jail securely locked, with the guards posted at the doors; but when we opened them, we found no one inside.”","sources":{"KJV":{"text":"Saying, The prison truly found we shut with all safety, and the keepers standing without before the doors: but when we had opened, we found no man within."},"BSB":{"text":"“We found the jail securely locked, with the guards posted at the doors; but when we opened them, we found no one inside.”"}},"definableWords":["one"],"peopleInVerse":[]},"24":{"text":"Now when the high priest and the captain of the temple and the chief priests heard these things, they doubted of them whereunto this would grow.","ref":"Acts 5:24","synthesized":"When the captain of the temple guard and the chief priests heard this account, they were perplexed as to what was happening.","sources":{"KJV":{"text":"Now when the high priest and the captain of the temple and the chief priests heard these things, they doubted of them whereunto this would grow."},"BSB":{"text":"When the captain of the temple guard and the chief priests heard this account, they were perplexed as to what was happening."}},"definableWords":["temple"],"peopleInVerse":[]},"25":{"text":"Then came one and told them, saying, Behold, the men whom ye put in prison are standing in the temple, and teaching the people.","ref":"Acts 5:25","synthesized":"Then someone came in and announced, “Look, the men you put in jail are standing in the temple courts teaching the people!”","sources":{"KJV":{"text":"Then came one and told them, saying, Behold, the men whom ye put in prison are standing in the temple, and teaching the people."},"BSB":{"text":"Then someone came in and announced, “Look, the men you put in jail are standing in the temple courts teaching the people!”"}},"definableWords":["men","temple","people"],"peopleInVerse":[]},"26":{"text":"Then went the captain with the officers, and brought them without violence: for they feared the people, lest they should have been stoned.","ref":"Acts 5:26","synthesized":"At that point, the captain went with the officers and brought the apostles—but not by force, for fear the people would stone them.","sources":{"KJV":{"text":"Then went the captain with the officers, and brought them without violence: for they feared the people, lest they should have been stoned."},"BSB":{"text":"At that point, the captain went with the officers and brought the apostles—but not by force, for fear the people would stone them."}},"definableWords":["fear","people","stone"],"peopleInVerse":[]},"27":{"text":"And when they had brought them, they set them before the council: and the high priest asked them,","ref":"Acts 5:27","synthesized":"They brought them in and made them stand before the Sanhedrin, where the high priest interrogated them.","sources":{"KJV":{"text":"And when they had brought them, they set them before the council: and the high priest asked them,"},"BSB":{"text":"They brought them in and made them stand before the Sanhedrin, where the high priest interrogated them."}},"definableWords":["made","stand","priest"],"peopleInVerse":[]},"28":{"text":"Saying, Did not we straitly command you that ye should not teach in this name? and, behold, ye have filled Jerusalem with your doctrine, and intend to bring this man’s blood upon us.","ref":"Acts 5:28","synthesized":"“We gave you strict orders not to teach in this name,” he said. “Yet you have filled Jerusalem with your teaching and are determined to make us responsible for this man’s blood.”","sources":{"KJV":{"text":"Saying, Did not we straitly command you that ye should not teach in this name? and, behold, ye have filled Jerusalem with your doctrine, and intend to bring this man’s blood upon us."},"BSB":{"text":"“We gave you strict orders not to teach in this name,” he said. “Yet you have filled Jerusalem with your teaching and are determined to make us responsible for this man’s blood.”"}},"definableWords":["name","Jerusalem","make","man","blood"],"peopleInVerse":[]},"29":{"text":"Then Peter and the other apostles answered and said, We ought to obey God rather than men.","ref":"Acts 5:29","synthesized":"But Peter and the other apostles replied, “We must obey God rather than men.","sources":{"KJV":{"text":"Then Peter and the other apostles answered and said, We ought to obey God rather than men."},"BSB":{"text":"But Peter and the other apostles replied, “We must obey God rather than men."}},"definableWords":["God","men"],"peopleInVerse":["Peter"]},"30":{"text":"The God of our fathers raised up Jesus, whom ye slew and hanged on a tree.","ref":"Acts 5:30","synthesized":"The God of our fathers raised up Jesus, whom you had killed by hanging Him on a tree.","sources":{"KJV":{"text":"The God of our fathers raised up Jesus, whom ye slew and hanged on a tree."},"BSB":{"text":"The God of our fathers raised up Jesus, whom you had killed by hanging Him on a tree."}},"definableWords":["God","fathers","tree"],"peopleInVerse":["Jesus"]},"31":{"text":"Him hath God exalted with his right hand to be a Prince and a Saviour, for to give repentance to Israel, and forgiveness of sins.","ref":"Acts 5:31","synthesized":"God exalted Him to His right hand as Prince and Savior, in order to grant repentance and forgiveness of sins to Israel.","sources":{"KJV":{"text":"Him hath God exalted with his right hand to be a Prince and a Saviour, for to give repentance to Israel, and forgiveness of sins."},"BSB":{"text":"God exalted Him to His right hand as Prince and Savior, in order to grant repentance and forgiveness of sins to Israel."}},"definableWords":["God","prince","repentance","Israel"],"peopleInVerse":[]},"32":{"text":"And we are his witnesses of these things; and so is also the Holy Ghost, whom God hath given to them that obey him.","ref":"Acts 5:32","synthesized":"We are witnesses of these things, and so is the Holy Spirit, whom God has given to those who obey Him.”","sources":{"KJV":{"text":"And we are his witnesses of these things; and so is also the Holy Ghost, whom God hath given to them that obey him."},"BSB":{"text":"We are witnesses of these things, and so is the Holy Spirit, whom God has given to those who obey Him.”"}},"definableWords":["holy","Spirit","God"],"peopleInVerse":[]},"33":{"text":"When they heard that, they were cut to the heart, and took counsel to slay them.","ref":"Acts 5:33","synthesized":"When the Council members heard this, they were enraged, and they resolved to put the apostles to death.","sources":{"KJV":{"text":"When they heard that, they were cut to the heart, and took counsel to slay them."},"BSB":{"text":"When the Council members heard this, they were enraged, and they resolved to put the apostles to death."}},"definableWords":["death"],"peopleInVerse":[]},"34":{"text":"Then stood there up one in the council, a Pharisee, named Gamaliel, a doctor of the law, had in reputation among all the people, and commanded to put the apostles forth a little space;","ref":"Acts 5:34","synthesized":"But a Pharisee named Gamaliel, a teacher of the law who was honored by all the people, stood up in the Sanhedrin and ordered that the men be put outside for a short time.","sources":{"KJV":{"text":"Then stood there up one in the council, a Pharisee, named Gamaliel, a doctor of the law, had in reputation among all the people, and commanded to put the apostles forth a little space;"},"BSB":{"text":"But a Pharisee named Gamaliel, a teacher of the law who was honored by all the people, stood up in the Sanhedrin and ordered that the men be put outside for a short time."}},"definableWords":["Pharisee","law","people","men"],"peopleInVerse":[]},"35":{"text":"And said unto them, Ye men of Israel, take heed to yourselves what ye intend to do as touching these men.","ref":"Acts 5:35","synthesized":"“Men of Israel,” he said, “consider carefully what you are about to do to these men.","sources":{"KJV":{"text":"And said unto them, Ye men of Israel, take heed to yourselves what ye intend to do as touching these men."},"BSB":{"text":"“Men of Israel,” he said, “consider carefully what you are about to do to these men."}},"definableWords":["men","Israel"],"peopleInVerse":[]},"36":{"text":"For before these days rose up Theudas, boasting himself to be somebody; to whom a number of men, about four hundred, joined themselves: who was slain; and all, as many as obeyed him, were scattered, and brought to nought.","ref":"Acts 5:36","synthesized":"Some time ago Theudas rose up, claiming to be somebody, and about four hundred men joined him. He was killed, all his followers were dispersed, and it all came to nothing.","sources":{"KJV":{"text":"For before these days rose up Theudas, boasting himself to be somebody; to whom a number of men, about four hundred, joined themselves: who was slain; and all, as many as obeyed him, were scattered, and brought to nought."},"BSB":{"text":"Some time ago Theudas rose up, claiming to be somebody, and about four hundred men joined him. He was killed, all his followers were dispersed, and it all came to nothing."}},"definableWords":["men"],"peopleInVerse":[]},"37":{"text":"After this man rose up Judas of Galilee in the days of the taxing, and drew away much people after him: he also perished; and all, even as many as obeyed him, were dispersed.","ref":"Acts 5:37","synthesized":"After him, Judas the Galilean appeared in the days of the census and drew away people after him. He too perished, and all his followers were scattered.","sources":{"KJV":{"text":"After this man rose up Judas of Galilee in the days of the taxing, and drew away much people after him: he also perished; and all, even as many as obeyed him, were dispersed."},"BSB":{"text":"After him, Judas the Galilean appeared in the days of the census and drew away people after him. He too perished, and all his followers were scattered."}},"definableWords":["days","people"],"peopleInVerse":[]},"38":{"text":"And now I say unto you, Refrain from these men, and let them alone: for if this counsel or this work be of men, it will come to nought:","ref":"Acts 5:38","synthesized":"So in the present case I advise you: Leave these men alone. Let them go! For if their purpose or endeavor is of human origin, it will fail.","sources":{"KJV":{"text":"And now I say unto you, Refrain from these men, and let them alone: for if this counsel or this work be of men, it will come to nought:"},"BSB":{"text":"So in the present case I advise you: Leave these men alone. Let them go! For if their purpose or endeavor is of human origin, it will fail."}},"definableWords":["men","or"],"peopleInVerse":[]},"39":{"text":"But if it be of God, ye cannot overthrow it; lest haply ye be found even to fight against God.","ref":"Acts 5:39","synthesized":"But if it is from God, you will not be able to stop them. You may even find yourselves fighting against God.”","sources":{"KJV":{"text":"But if it be of God, ye cannot overthrow it; lest haply ye be found even to fight against God."},"BSB":{"text":"But if it is from God, you will not be able to stop them. You may even find yourselves fighting against God.”"}},"definableWords":["God"],"peopleInVerse":[]},"40":{"text":"And to him they agreed: and when they had called the apostles, and beaten them, they commanded that they should not speak in the name of Jesus, and let them go.","ref":"Acts 5:40","synthesized":"At this, they yielded to Gamaliel. They called the apostles in and had them flogged. Then they ordered them not to speak in the name of Jesus, and released them.","sources":{"KJV":{"text":"And to him they agreed: and when they had called the apostles, and beaten them, they commanded that they should not speak in the name of Jesus, and let them go."},"BSB":{"text":"At this, they yielded to Gamaliel. They called the apostles in and had them flogged. Then they ordered them not to speak in the name of Jesus, and released them."}},"definableWords":["name"],"peopleInVerse":["Jesus"]},"41":{"text":"And they departed from the presence of the council, rejoicing that they were counted worthy to suffer shame for his name.","ref":"Acts 5:41","synthesized":"The apostles left the Sanhedrin, rejoicing that they had been counted worthy of suffering disgrace for the Name.","sources":{"KJV":{"text":"And they departed from the presence of the council, rejoicing that they were counted worthy to suffer shame for his name."},"BSB":{"text":"The apostles left the Sanhedrin, rejoicing that they had been counted worthy of suffering disgrace for the Name."}},"definableWords":["name"],"peopleInVerse":[]},"42":{"text":"And daily in the temple, and in every house, they ceased not to teach and preach Jesus Christ.","ref":"Acts 5:42","synthesized":"Every day, in the temple courts and from house to house, they did not stop teaching and proclaiming the good news that Jesus is the Christ.","sources":{"KJV":{"text":"And daily in the temple, and in every house, they ceased not to teach and preach Jesus Christ."},"BSB":{"text":"Every day, in the temple courts and from house to house, they did not stop teaching and proclaiming the good news that Jesus is the Christ."}},"definableWords":["day","temple","house","good","Christ"],"peopleInVerse":["Jesus"]}}},"6":{"chapter":"6","title":"THE SEVEN CHOSEN","verses":{"1":{"text":"And in those days, when the number of the disciples was multiplied, there arose a murmuring of the Grecians against the Hebrews, because their widows were neglected in the daily ministration.","ref":"Acts 6:1","synthesized":"In those days when the disciples were increasing in number, the Grecian Jews among them began to grumble against the Hebraic Jews because their widows were being overlooked in the daily distribution of food.","sources":{"KJV":{"text":"And in those days, when the number of the disciples was multiplied, there arose a murmuring of the Grecians against the Hebrews, because their widows were neglected in the daily ministration."},"BSB":{"text":"In those days when the disciples were increasing in number, the Grecian Jews among them began to grumble against the Hebraic Jews because their widows were being overlooked in the daily distribution of food."}},"definableWords":["days"],"peopleInVerse":[]},"2":{"text":"Then the twelve called the multitude of the disciples unto them, and said, It is not reason that we should leave the word of God, and serve tables.","ref":"Acts 6:2","synthesized":"So the Twelve summoned all the disciples and said, “It is unacceptable for us to neglect the word of God in order to wait on tables.","sources":{"KJV":{"text":"Then the twelve called the multitude of the disciples unto them, and said, It is not reason that we should leave the word of God, and serve tables."},"BSB":{"text":"So the Twelve summoned all the disciples and said, “It is unacceptable for us to neglect the word of God in order to wait on tables."}},"definableWords":["word","God","wait"],"peopleInVerse":[]},"3":{"text":"Wherefore, brethren, look ye out among you seven men of honest report, full of the Holy Ghost and wisdom, whom we may appoint over this business.","ref":"Acts 6:3","synthesized":"Therefore, brothers, select from among you seven men confirmed to be full of the Spirit and wisdom. We will appoint this responsibility to them","sources":{"KJV":{"text":"Wherefore, brethren, look ye out among you seven men of honest report, full of the Holy Ghost and wisdom, whom we may appoint over this business."},"BSB":{"text":"Therefore, brothers, select from among you seven men confirmed to be full of the Spirit and wisdom. We will appoint this responsibility to them"}},"definableWords":["men","Spirit","wisdom"],"peopleInVerse":[]},"4":{"text":"But we will give ourselves continually to prayer, and to the ministry of the word.","ref":"Acts 6:4","synthesized":"and will devote ourselves to prayer and to the ministry of the word.”","sources":{"KJV":{"text":"But we will give ourselves continually to prayer, and to the ministry of the word."},"BSB":{"text":"and will devote ourselves to prayer and to the ministry of the word.”"}},"definableWords":["prayer","word"],"peopleInVerse":[]},"5":{"text":"And the saying pleased the whole multitude: and they chose Stephen, a man full of faith and of the Holy Ghost, and Philip, and Prochorus, and Nicanor, and Timon, and Parmenas, and Nicolas a proselyte of Antioch:","ref":"Acts 6:5","synthesized":"This proposal pleased the whole group. They chose Stephen, a man full of faith and of the Holy Spirit, as well as Philip, Prochorus, Nicanor, Timon, Parmenas, and Nicolas from Antioch, a convert to Judaism.","sources":{"KJV":{"text":"And the saying pleased the whole multitude: and they chose Stephen, a man full of faith and of the Holy Ghost, and Philip, and Prochorus, and Nicanor, and Timon, and Parmenas, and Nicolas a proselyte of Antioch:"},"BSB":{"text":"This proposal pleased the whole group. They chose Stephen, a man full of faith and of the Holy Spirit, as well as Philip, Prochorus, Nicanor, Timon, Parmenas, and Nicolas from Antioch, a convert to Judaism."}},"definableWords":["man","faith","holy","Spirit"],"peopleInVerse":["Stephen"]},"6":{"text":"Whom they set before the apostles: and when they had prayed, they laid their hands on them.","ref":"Acts 6:6","synthesized":"They presented these seven to the apostles, who prayed and laid their hands on them.","sources":{"KJV":{"text":"Whom they set before the apostles: and when they had prayed, they laid their hands on them."},"BSB":{"text":"They presented these seven to the apostles, who prayed and laid their hands on them."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And the word of God increased; and the number of the disciples multiplied in Jerusalem greatly; and a great company of the priests were obedient to the faith.","ref":"Acts 6:7","synthesized":"So the word of God continued to spread. The number of disciples in Jerusalem grew rapidly, and a great number of priests became obedient to the faith.","sources":{"KJV":{"text":"And the word of God increased; and the number of the disciples multiplied in Jerusalem greatly; and a great company of the priests were obedient to the faith."},"BSB":{"text":"So the word of God continued to spread. The number of disciples in Jerusalem grew rapidly, and a great number of priests became obedient to the faith."}},"definableWords":["word","God","Jerusalem","great","faith"],"peopleInVerse":[]},"8":{"text":"And Stephen, full of faith and power, did great wonders and miracles among the people.","ref":"Acts 6:8","synthesized":"Now Stephen, who was full of grace and power, was performing great wonders and signs among the people.","sources":{"KJV":{"text":"And Stephen, full of faith and power, did great wonders and miracles among the people."},"BSB":{"text":"Now Stephen, who was full of grace and power, was performing great wonders and signs among the people."}},"definableWords":["grace","great","people"],"peopleInVerse":["Stephen"]},"9":{"text":"Then there arose certain of the synagogue, which is called the synagogue of the Libertines, and Cyrenians, and Alexandrians, and of them of Cilicia and of Asia, disputing with Stephen.","ref":"Acts 6:9","synthesized":"But resistance arose from what was called the Synagogue of the Freedmen, including Cyrenians, Alexandrians, and men from the provinces of Cilicia and Asia. They began to argue with Stephen,","sources":{"KJV":{"text":"Then there arose certain of the synagogue, which is called the synagogue of the Libertines, and Cyrenians, and Alexandrians, and of them of Cilicia and of Asia, disputing with Stephen."},"BSB":{"text":"But resistance arose from what was called the Synagogue of the Freedmen, including Cyrenians, Alexandrians, and men from the provinces of Cilicia and Asia. They began to argue with Stephen,"}},"definableWords":["men"],"peopleInVerse":["Stephen"]},"10":{"text":"And they were not able to resist the wisdom and the spirit by which he spake.","ref":"Acts 6:10","synthesized":"but they could not stand up to his wisdom or the Spirit by whom he spoke.","sources":{"KJV":{"text":"And they were not able to resist the wisdom and the spirit by which he spake."},"BSB":{"text":"but they could not stand up to his wisdom or the Spirit by whom he spoke."}},"definableWords":["stand","wisdom","or","Spirit"],"peopleInVerse":[]},"11":{"text":"Then they suborned men, which said, We have heard him speak blasphemous words against Moses, and against God.","ref":"Acts 6:11","synthesized":"Then they prompted some men to say, “We heard Stephen speak words of blasphemy against Moses and against God.”","sources":{"KJV":{"text":"Then they suborned men, which said, We have heard him speak blasphemous words against Moses, and against God."},"BSB":{"text":"Then they prompted some men to say, “We heard Stephen speak words of blasphemy against Moses and against God.”"}},"definableWords":["men","God"],"peopleInVerse":["Stephen","Moses"]},"12":{"text":"And they stirred up the people, and the elders, and the scribes, and came upon him, and caught him, and brought him to the council,","ref":"Acts 6:12","synthesized":"So they stirred up the people, elders, and scribes and confronted Stephen. They seized him and brought him before the Sanhedrin,","sources":{"KJV":{"text":"And they stirred up the people, and the elders, and the scribes, and came upon him, and caught him, and brought him to the council,"},"BSB":{"text":"So they stirred up the people, elders, and scribes and confronted Stephen. They seized him and brought him before the Sanhedrin,"}},"definableWords":["people"],"peopleInVerse":["Stephen"]},"13":{"text":"And set up false witnesses, which said, This man ceaseth not to speak blasphemous words against this holy place, and the law:","ref":"Acts 6:13","synthesized":"where they presented false witnesses who said, “This man never stops speaking against this holy place and against the law.","sources":{"KJV":{"text":"And set up false witnesses, which said, This man ceaseth not to speak blasphemous words against this holy place, and the law:"},"BSB":{"text":"where they presented false witnesses who said, “This man never stops speaking against this holy place and against the law."}},"definableWords":["man","holy","law"],"peopleInVerse":[]},"14":{"text":"For we have heard him say, that this Jesus of Nazareth shall destroy this place, and shall change the customs which Moses delivered us.","ref":"Acts 6:14","synthesized":"For we have heard him say that Jesus of Nazareth will destroy this place and change the customs that Moses handed down to us.”","sources":{"KJV":{"text":"For we have heard him say, that this Jesus of Nazareth shall destroy this place, and shall change the customs which Moses delivered us."},"BSB":{"text":"For we have heard him say that Jesus of Nazareth will destroy this place and change the customs that Moses handed down to us.”"}},"definableWords":[],"peopleInVerse":["Jesus","Moses"]},"15":{"text":"And all that sat in the council, looking stedfastly on him, saw his face as it had been the face of an angel.","ref":"Acts 6:15","synthesized":"All who were sitting in the Sanhedrin looked intently at Stephen, and they saw that his face was like the face of an angel.","sources":{"KJV":{"text":"And all that sat in the council, looking stedfastly on him, saw his face as it had been the face of an angel."},"BSB":{"text":"All who were sitting in the Sanhedrin looked intently at Stephen, and they saw that his face was like the face of an angel."}},"definableWords":["saw","angel"],"peopleInVerse":["Stephen"]}}},"7":{"chapter":"7","title":"STEPHEN'S MARTYRDOM","verses":{"1":{"text":"Then said the high priest, Are these things so?","ref":"Acts 7:1","synthesized":"Then the high priest asked Stephen, “Are these charges true?”","sources":{"KJV":{"text":"Then said the high priest, Are these things so?"},"BSB":{"text":"Then the high priest asked Stephen, “Are these charges true?”"}},"definableWords":["priest"],"peopleInVerse":["Stephen"]},"2":{"text":"And he said, Men, brethren, and fathers, hearken; The God of glory appeared unto our father Abraham, when he was in Mesopotamia, before he dwelt in Charran,","ref":"Acts 7:2","synthesized":"And Stephen declared: “Brothers and fathers, listen to me! The God of glory appeared to our father Abraham while he was still in Mesopotamia, before he lived in Haran,","sources":{"KJV":{"text":"And he said, Men, brethren, and fathers, hearken; The God of glory appeared unto our father Abraham, when he was in Mesopotamia, before he dwelt in Charran,"},"BSB":{"text":"And Stephen declared: “Brothers and fathers, listen to me! The God of glory appeared to our father Abraham while he was still in Mesopotamia, before he lived in Haran,"}},"definableWords":["fathers","God","glory","father","Abraham"],"peopleInVerse":["Stephen","Abraham"]},"3":{"text":"And said unto him, Get thee out of thy country, and from thy kindred, and come into the land which I shall shew thee.","ref":"Acts 7:3","synthesized":"and told him, ‘Leave your country and your kindred and go to the land I will show you.’","sources":{"KJV":{"text":"And said unto him, Get thee out of thy country, and from thy kindred, and come into the land which I shall shew thee."},"BSB":{"text":"and told him, ‘Leave your country and your kindred and go to the land I will show you.’"}},"definableWords":["land"],"peopleInVerse":[]},"4":{"text":"Then came he out of the land of the Chaldaeans, and dwelt in Charran: and from thence, when his father was dead, he removed him into this land, wherein ye now dwell.","ref":"Acts 7:4","synthesized":"So Abraham left the land of the Chaldeans and settled in Haran. After his father died, God brought him out of that place and into this land where you are now living.","sources":{"KJV":{"text":"Then came he out of the land of the Chaldaeans, and dwelt in Charran: and from thence, when his father was dead, he removed him into this land, wherein ye now dwell."},"BSB":{"text":"So Abraham left the land of the Chaldeans and settled in Haran. After his father died, God brought him out of that place and into this land where you are now living."}},"definableWords":["Abraham","land","father","God","living"],"peopleInVerse":["Abraham"]},"5":{"text":"And he gave him none inheritance in it, no, not so much as to set his foot on: yet he promised that he would give it to him for a possession, and to his seed after him, when as yet he had no child.","ref":"Acts 7:5","synthesized":"He gave him no inheritance here, not even a foot of ground. But God promised to give possession of the land to Abraham and his descendants, even though he did not yet have a child.","sources":{"KJV":{"text":"And he gave him none inheritance in it, no, not so much as to set his foot on: yet he promised that he would give it to him for a possession, and to his seed after him, when as yet he had no child."},"BSB":{"text":"He gave him no inheritance here, not even a foot of ground. But God promised to give possession of the land to Abraham and his descendants, even though he did not yet have a child."}},"definableWords":["ground","God","land","Abraham"],"peopleInVerse":["Abraham"]},"6":{"text":"And God spake on this wise, That his seed should sojourn in a strange land; and that they should bring them into bondage, and entreat them evil four hundred years.","ref":"Acts 7:6","synthesized":"God told him that his descendants would be foreigners in a strange land, and that they would be enslaved and mistreated four hundred years.","sources":{"KJV":{"text":"And God spake on this wise, That his seed should sojourn in a strange land; and that they should bring them into bondage, and entreat them evil four hundred years."},"BSB":{"text":"God told him that his descendants would be foreigners in a strange land, and that they would be enslaved and mistreated four hundred years."}},"definableWords":["God","land","years"],"peopleInVerse":[]},"7":{"text":"And the nation to whom they shall be in bondage will I judge, said God: and after that shall they come forth, and serve me in this place.","ref":"Acts 7:7","synthesized":"‘But I will punish the nation that enslaves them,’ God said, ‘and afterward they will come forth and worship Me in this place.’","sources":{"KJV":{"text":"And the nation to whom they shall be in bondage will I judge, said God: and after that shall they come forth, and serve me in this place."},"BSB":{"text":"‘But I will punish the nation that enslaves them,’ God said, ‘and afterward they will come forth and worship Me in this place.’"}},"definableWords":["nation","God","worship"],"peopleInVerse":[]},"8":{"text":"And he gave him the covenant of circumcision: and so Abraham begat Isaac, and circumcised him the eighth day; and Isaac begat Jacob; and Jacob begat the twelve patriarchs.","ref":"Acts 7:8","synthesized":"Then God gave Abraham the covenant of circumcision, and Abraham became the father of Isaac and circumcised him on the eighth day. And Isaac became the father of Jacob, and Jacob of the twelve patriarchs.","sources":{"KJV":{"text":"And he gave him the covenant of circumcision: and so Abraham begat Isaac, and circumcised him the eighth day; and Isaac begat Jacob; and Jacob begat the twelve patriarchs."},"BSB":{"text":"Then God gave Abraham the covenant of circumcision, and Abraham became the father of Isaac and circumcised him on the eighth day. And Isaac became the father of Jacob, and Jacob of the twelve patriarchs."}},"definableWords":["God","Abraham","covenant","circumcision","father","Isaac","circumcised","day","Father","Jacob"],"peopleInVerse":["Abraham","Isaac","Jacob"]},"9":{"text":"And the patriarchs, moved with envy, sold Joseph into Egypt: but God was with him,","ref":"Acts 7:9","synthesized":"Because the patriarchs were jealous of Joseph, they sold him as a slave into Egypt. But God was with him","sources":{"KJV":{"text":"And the patriarchs, moved with envy, sold Joseph into Egypt: but God was with him,"},"BSB":{"text":"Because the patriarchs were jealous of Joseph, they sold him as a slave into Egypt. But God was with him"}},"definableWords":["Joseph","Egypt","God"],"peopleInVerse":["Joseph"]},"10":{"text":"And delivered him out of all his afflictions, and gave him favour and wisdom in the sight of Pharaoh king of Egypt; and he made him governor over Egypt and all his house.","ref":"Acts 7:10","synthesized":"and rescued him from all his troubles. He granted Joseph favor and wisdom in the sight of Pharaoh king of Egypt, who appointed him ruler over Egypt and all his household.","sources":{"KJV":{"text":"And delivered him out of all his afflictions, and gave him favour and wisdom in the sight of Pharaoh king of Egypt; and he made him governor over Egypt and all his house."},"BSB":{"text":"and rescued him from all his troubles. He granted Joseph favor and wisdom in the sight of Pharaoh king of Egypt, who appointed him ruler over Egypt and all his household."}},"definableWords":["Joseph","wisdom","Pharaoh","king","Egypt","ruler"],"peopleInVerse":["Joseph","Pharaoh"]},"11":{"text":"Now there came a dearth over all the land of Egypt and Chanaan, and great affliction: and our fathers found no sustenance.","ref":"Acts 7:11","synthesized":"Then famine and great suffering swept across Egypt and Canaan, and our fathers could not find food.","sources":{"KJV":{"text":"Now there came a dearth over all the land of Egypt and Chanaan, and great affliction: and our fathers found no sustenance."},"BSB":{"text":"Then famine and great suffering swept across Egypt and Canaan, and our fathers could not find food."}},"definableWords":["great","Egypt","Canaan","fathers"],"peopleInVerse":["Canaan"]},"12":{"text":"But when Jacob heard that there was corn in Egypt, he sent out our fathers first.","ref":"Acts 7:12","synthesized":"When Jacob heard that there was grain in Egypt, he sent our fathers on their first visit.","sources":{"KJV":{"text":"But when Jacob heard that there was corn in Egypt, he sent out our fathers first."},"BSB":{"text":"When Jacob heard that there was grain in Egypt, he sent our fathers on their first visit."}},"definableWords":["Jacob","Egypt","fathers"],"peopleInVerse":["Jacob"]},"13":{"text":"And at the second time Joseph was made known to his brethren; and Joseph’s kindred was made known unto Pharaoh.","ref":"Acts 7:13","synthesized":"On their second visit, Joseph revealed his identity to his brothers, and his family became known to Pharaoh.","sources":{"KJV":{"text":"And at the second time Joseph was made known to his brethren; and Joseph’s kindred was made known unto Pharaoh."},"BSB":{"text":"On their second visit, Joseph revealed his identity to his brothers, and his family became known to Pharaoh."}},"definableWords":["Joseph","family","Pharaoh"],"peopleInVerse":["Joseph","Pharaoh"]},"14":{"text":"Then sent Joseph, and called his father Jacob to him, and all his kindred, threescore and fifteen souls.","ref":"Acts 7:14","synthesized":"Then Joseph sent for his father Jacob and all his relatives, seventy-five in all.","sources":{"KJV":{"text":"Then sent Joseph, and called his father Jacob to him, and all his kindred, threescore and fifteen souls."},"BSB":{"text":"Then Joseph sent for his father Jacob and all his relatives, seventy-five in all."}},"definableWords":["Joseph","father","Jacob"],"peopleInVerse":["Joseph","Jacob"]},"15":{"text":"So Jacob went down into Egypt, and died, he, and our fathers,","ref":"Acts 7:15","synthesized":"So Jacob went down to Egypt, where he and our fathers died.","sources":{"KJV":{"text":"So Jacob went down into Egypt, and died, he, and our fathers,"},"BSB":{"text":"So Jacob went down to Egypt, where he and our fathers died."}},"definableWords":["Jacob","Egypt","fathers"],"peopleInVerse":["Jacob"]},"16":{"text":"And were carried over into Sychem, and laid in the sepulchre that Abraham bought for a sum of money of the sons of Emmor the father of Sychem.","ref":"Acts 7:16","synthesized":"Their bones were carried back to Shechem and placed in the tomb that Abraham had bought from the sons of Hamor at Shechem for a price he paid in silver.","sources":{"KJV":{"text":"And were carried over into Sychem, and laid in the sepulchre that Abraham bought for a sum of money of the sons of Emmor the father of Sychem."},"BSB":{"text":"Their bones were carried back to Shechem and placed in the tomb that Abraham had bought from the sons of Hamor at Shechem for a price he paid in silver."}},"definableWords":["bones","Abraham","sons"],"peopleInVerse":["Abraham"]},"17":{"text":"But when the time of the promise drew nigh, which God had sworn to Abraham, the people grew and multiplied in Egypt,","ref":"Acts 7:17","synthesized":"As the time drew near for God to fulfill His promise to Abraham, our people in Egypt increased greatly in number.","sources":{"KJV":{"text":"But when the time of the promise drew nigh, which God had sworn to Abraham, the people grew and multiplied in Egypt,"},"BSB":{"text":"As the time drew near for God to fulfill His promise to Abraham, our people in Egypt increased greatly in number."}},"definableWords":["God","promise","Abraham","people","Egypt"],"peopleInVerse":["Abraham"]},"18":{"text":"Till another king arose, which knew not Joseph.","ref":"Acts 7:18","synthesized":"Then another king, who knew nothing of Joseph, arose over Egypt.","sources":{"KJV":{"text":"Till another king arose, which knew not Joseph."},"BSB":{"text":"Then another king, who knew nothing of Joseph, arose over Egypt."}},"definableWords":["king","Joseph","Egypt"],"peopleInVerse":["Joseph"]},"19":{"text":"The same dealt subtilly with our kindred, and evil entreated our fathers, so that they cast out their young children, to the end they might not live.","ref":"Acts 7:19","synthesized":"He exploited our people and oppressed our fathers, forcing them to abandon their infants so they would die.","sources":{"KJV":{"text":"The same dealt subtilly with our kindred, and evil entreated our fathers, so that they cast out their young children, to the end they might not live."},"BSB":{"text":"He exploited our people and oppressed our fathers, forcing them to abandon their infants so they would die."}},"definableWords":["people","fathers","die"],"peopleInVerse":[]},"20":{"text":"In which time Moses was born, and was exceeding fair, and nourished up in his father’s house three months:","ref":"Acts 7:20","synthesized":"At that time Moses was born, and he was beautiful in the sight of God. For three months he was nurtured in his father’s house.","sources":{"KJV":{"text":"In which time Moses was born, and was exceeding fair, and nourished up in his father’s house three months:"},"BSB":{"text":"At that time Moses was born, and he was beautiful in the sight of God. For three months he was nurtured in his father’s house."}},"definableWords":["God","father","house"],"peopleInVerse":["Moses"]},"21":{"text":"And when he was cast out, Pharaoh’s daughter took him up, and nourished him for her own son.","ref":"Acts 7:21","synthesized":"When he was set outside, Pharaoh’s daughter took him and brought him up as her own son.","sources":{"KJV":{"text":"And when he was cast out, Pharaoh’s daughter took him up, and nourished him for her own son."},"BSB":{"text":"When he was set outside, Pharaoh’s daughter took him and brought him up as her own son."}},"definableWords":["Pharaoh","daughter","son"],"peopleInVerse":["Pharaoh"]},"22":{"text":"And Moses was learned in all the wisdom of the Egyptians, and was mighty in words and in deeds.","ref":"Acts 7:22","synthesized":"So Moses was educated in all the wisdom of the Egyptians and was powerful in speech and action.","sources":{"KJV":{"text":"And Moses was learned in all the wisdom of the Egyptians, and was mighty in words and in deeds."},"BSB":{"text":"So Moses was educated in all the wisdom of the Egyptians and was powerful in speech and action."}},"definableWords":["wisdom"],"peopleInVerse":["Moses"]},"23":{"text":"And when he was full forty years old, it came into his heart to visit his brethren the children of Israel.","ref":"Acts 7:23","synthesized":"When Moses was forty years old, he decided to visit his brothers, the children of Israel.","sources":{"KJV":{"text":"And when he was full forty years old, it came into his heart to visit his brethren the children of Israel."},"BSB":{"text":"When Moses was forty years old, he decided to visit his brothers, the children of Israel."}},"definableWords":["years","Israel"],"peopleInVerse":["Moses"]},"24":{"text":"And seeing one of them suffer wrong, he defended him, and avenged him that was oppressed, and smote the Egyptian:","ref":"Acts 7:24","synthesized":"And when he saw one of them being mistreated, Moses went to his defense and avenged him by striking down the Egyptian who was oppressing him.","sources":{"KJV":{"text":"And seeing one of them suffer wrong, he defended him, and avenged him that was oppressed, and smote the Egyptian:"},"BSB":{"text":"And when he saw one of them being mistreated, Moses went to his defense and avenged him by striking down the Egyptian who was oppressing him."}},"definableWords":["saw","one"],"peopleInVerse":["Moses"]},"25":{"text":"For he supposed his brethren would have understood how that God by his hand would deliver them: but they understood not.","ref":"Acts 7:25","synthesized":"He assumed his brothers would understand that God was using him to deliver them, but they did not.","sources":{"KJV":{"text":"For he supposed his brethren would have understood how that God by his hand would deliver them: but they understood not."},"BSB":{"text":"He assumed his brothers would understand that God was using him to deliver them, but they did not."}},"definableWords":["God","deliver"],"peopleInVerse":[]},"26":{"text":"And the next day he shewed himself unto them as they strove, and would have set them at one again, saying, Sirs, ye are brethren; why do ye wrong one to another?","ref":"Acts 7:26","synthesized":"The next day he came upon two Israelites who were fighting, and he tried to reconcile them, saying, ‘Men, you are brothers. Why are you mistreating each other?’","sources":{"KJV":{"text":"And the next day he shewed himself unto them as they strove, and would have set them at one again, saying, Sirs, ye are brethren; why do ye wrong one to another?"},"BSB":{"text":"The next day he came upon two Israelites who were fighting, and he tried to reconcile them, saying, ‘Men, you are brothers. Why are you mistreating each other?’"}},"definableWords":["day","Israelites","men"],"peopleInVerse":[]},"27":{"text":"But he that did his neighbour wrong thrust him away, saying, Who made thee a ruler and a judge over us?","ref":"Acts 7:27","synthesized":"But the man who was abusing his neighbor pushed Moses aside and said, ‘Who made you ruler and judge over us?","sources":{"KJV":{"text":"But he that did his neighbour wrong thrust him away, saying, Who made thee a ruler and a judge over us?"},"BSB":{"text":"But the man who was abusing his neighbor pushed Moses aside and said, ‘Who made you ruler and judge over us?"}},"definableWords":["man","made","ruler"],"peopleInVerse":["Moses"]},"28":{"text":"Wilt thou kill me, as thou diddest the Egyptian yesterday?","ref":"Acts 7:28","synthesized":"Do you want to kill me as you killed the Egyptian yesterday?’","sources":{"KJV":{"text":"Wilt thou kill me, as thou diddest the Egyptian yesterday?"},"BSB":{"text":"Do you want to kill me as you killed the Egyptian yesterday?’"}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"Then fled Moses at this saying, and was a stranger in the land of Madian, where he begat two sons.","ref":"Acts 7:29","synthesized":"At this remark, Moses fled to the land of Midian, where he lived as a foreigner and had two sons.","sources":{"KJV":{"text":"Then fled Moses at this saying, and was a stranger in the land of Madian, where he begat two sons."},"BSB":{"text":"At this remark, Moses fled to the land of Midian, where he lived as a foreigner and had two sons."}},"definableWords":["land","sons"],"peopleInVerse":["Moses"]},"30":{"text":"And when forty years were expired, there appeared to him in the wilderness of mount Sina an angel of the Lord in a flame of fire in a bush.","ref":"Acts 7:30","synthesized":"After forty years had passed, an angel appeared to Moses in the flames of a burning bush in the desert near Mount Sinai.","sources":{"KJV":{"text":"And when forty years were expired, there appeared to him in the wilderness of mount Sina an angel of the Lord in a flame of fire in a bush."},"BSB":{"text":"After forty years had passed, an angel appeared to Moses in the flames of a burning bush in the desert near Mount Sinai."}},"definableWords":["years","angel"],"peopleInVerse":["Moses"]},"31":{"text":"When Moses saw it, he wondered at the sight: and as he drew near to behold it, the voice of the LORD came unto him,","ref":"Acts 7:31","synthesized":"When Moses saw it, he marveled at the sight. As he approached to look more closely, the voice of the Lord came to him:","sources":{"KJV":{"text":"When Moses saw it, he wondered at the sight: and as he drew near to behold it, the voice of the LORD came unto him,"},"BSB":{"text":"When Moses saw it, he marveled at the sight. As he approached to look more closely, the voice of the Lord came to him:"}},"definableWords":["saw","voice","Lord"],"peopleInVerse":["Moses"]},"32":{"text":"Saying, I am the God of thy fathers, the God of Abraham, and the God of Isaac, and the God of Jacob. Then Moses trembled, and durst not behold.","ref":"Acts 7:32","synthesized":"‘I am the God of your fathers, the God of Abraham, Isaac, and Jacob.’ Moses trembled with fear and did not dare to look.","sources":{"KJV":{"text":"Saying, I am the God of thy fathers, the God of Abraham, and the God of Isaac, and the God of Jacob. Then Moses trembled, and durst not behold."},"BSB":{"text":"‘I am the God of your fathers, the God of Abraham, Isaac, and Jacob.’ Moses trembled with fear and did not dare to look."}},"definableWords":["God","fathers","Abraham","Isaac","Jacob","fear"],"peopleInVerse":["Abraham","Isaac","Jacob","Moses"]},"33":{"text":"Then said the Lord to him, Put off thy shoes from thy feet: for the place where thou standest is holy ground.","ref":"Acts 7:33","synthesized":"Then the Lord said to him, ‘Take off your sandals, for the place where you are standing is holy ground.","sources":{"KJV":{"text":"Then said the Lord to him, Put off thy shoes from thy feet: for the place where thou standest is holy ground."},"BSB":{"text":"Then the Lord said to him, ‘Take off your sandals, for the place where you are standing is holy ground."}},"definableWords":["Lord","holy","ground"],"peopleInVerse":[]},"34":{"text":"I have seen, I have seen the affliction of my people which is in Egypt, and I have heard their groaning, and am come down to deliver them. And now come, I will send thee into Egypt.","ref":"Acts 7:34","synthesized":"I have indeed seen the oppression of My people in Egypt. I have heard their groaning and have come down to deliver them. Now come, I will send you back to Egypt.’","sources":{"KJV":{"text":"I have seen, I have seen the affliction of my people which is in Egypt, and I have heard their groaning, and am come down to deliver them. And now come, I will send thee into Egypt."},"BSB":{"text":"I have indeed seen the oppression of My people in Egypt. I have heard their groaning and have come down to deliver them. Now come, I will send you back to Egypt.’"}},"definableWords":["people","Egypt","deliver"],"peopleInVerse":[]},"35":{"text":"This Moses whom they refused, saying, Who made thee a ruler and a judge? the same did God send to be a ruler and a deliverer by the hand of the angel which appeared to him in the bush.","ref":"Acts 7:35","synthesized":"This Moses, whom they had rejected with the words, ‘Who made you ruler and judge?’ is the one whom God sent to be their ruler and redeemer through the angel who appeared to him in the bush.","sources":{"KJV":{"text":"This Moses whom they refused, saying, Who made thee a ruler and a judge? the same did God send to be a ruler and a deliverer by the hand of the angel which appeared to him in the bush."},"BSB":{"text":"This Moses, whom they had rejected with the words, ‘Who made you ruler and judge?’ is the one whom God sent to be their ruler and redeemer through the angel who appeared to him in the bush."}},"definableWords":["made","ruler","one","God","Redeemer","angel"],"peopleInVerse":["Moses"]},"36":{"text":"He brought them out, after that he had shewed wonders and signs in the land of Egypt, and in the Red sea, and in the wilderness forty years.","ref":"Acts 7:36","synthesized":"He led them out and performed wonders and signs in the land of Egypt, at the Red Sea, and for forty years in the wilderness.","sources":{"KJV":{"text":"He brought them out, after that he had shewed wonders and signs in the land of Egypt, and in the Red sea, and in the wilderness forty years."},"BSB":{"text":"He led them out and performed wonders and signs in the land of Egypt, at the Red Sea, and for forty years in the wilderness."}},"definableWords":["land","Egypt","sea","years"],"peopleInVerse":[]},"37":{"text":"This is that Moses, which said unto the children of Israel, A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear.","ref":"Acts 7:37","synthesized":"This is the same Moses who told the Israelites, ‘God will raise up for you a prophet like me from among your brothers.’","sources":{"KJV":{"text":"This is that Moses, which said unto the children of Israel, A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear."},"BSB":{"text":"This is the same Moses who told the Israelites, ‘God will raise up for you a prophet like me from among your brothers.’"}},"definableWords":["Israelites","God","prophet"],"peopleInVerse":["Moses"]},"38":{"text":"This is he, that was in the church in the wilderness with the angel which spake to him in the mount Sina, and with our fathers: who received the lively oracles to give unto us:","ref":"Acts 7:38","synthesized":"He was in the assembly in the wilderness with the angel who spoke to him on Mount Sinai, and with our fathers. And he received living words to pass on to us.","sources":{"KJV":{"text":"This is he, that was in the church in the wilderness with the angel which spake to him in the mount Sina, and with our fathers: who received the lively oracles to give unto us:"},"BSB":{"text":"He was in the assembly in the wilderness with the angel who spoke to him on Mount Sinai, and with our fathers. And he received living words to pass on to us."}},"definableWords":["angel","fathers","living"],"peopleInVerse":[]},"39":{"text":"To whom our fathers would not obey, but thrust him from them, and in their hearts turned back again into Egypt,","ref":"Acts 7:39","synthesized":"But our fathers refused to obey him. Instead, they rejected him and in their hearts turned back to Egypt.","sources":{"KJV":{"text":"To whom our fathers would not obey, but thrust him from them, and in their hearts turned back again into Egypt,"},"BSB":{"text":"But our fathers refused to obey him. Instead, they rejected him and in their hearts turned back to Egypt."}},"definableWords":["fathers","Egypt"],"peopleInVerse":[]},"40":{"text":"Saying unto Aaron, Make us gods to go before us: for as for this Moses, which brought us out of the land of Egypt, we wot not what is become of him.","ref":"Acts 7:40","synthesized":"They said to Aaron, ‘Make us gods who will go before us! As for this Moses who led us out of the land of Egypt, we do not know what has happened to him.’","sources":{"KJV":{"text":"Saying unto Aaron, Make us gods to go before us: for as for this Moses, which brought us out of the land of Egypt, we wot not what is become of him."},"BSB":{"text":"They said to Aaron, ‘Make us gods who will go before us! As for this Moses who led us out of the land of Egypt, we do not know what has happened to him.’"}},"definableWords":["make","land","Egypt"],"peopleInVerse":["Aaron","Moses"]},"41":{"text":"And they made a calf in those days, and offered sacrifice unto the idol, and rejoiced in the works of their own hands.","ref":"Acts 7:41","synthesized":"At that time they made a calf and offered a sacrifice to the idol, rejoicing in the works of their hands.","sources":{"KJV":{"text":"And they made a calf in those days, and offered sacrifice unto the idol, and rejoiced in the works of their own hands."},"BSB":{"text":"At that time they made a calf and offered a sacrifice to the idol, rejoicing in the works of their hands."}},"definableWords":["made","sacrifice","works"],"peopleInVerse":[]},"42":{"text":"Then God turned, and gave them up to worship the host of heaven; as it is written in the book of the prophets, O ye house of Israel, have ye offered to me slain beasts and sacrifices by the space of forty years in the wilderness?","ref":"Acts 7:42","synthesized":"But God turned away from them and gave them over to the worship of the host of heaven, as it is written in the book of the prophets:  ‘Did you bring Me sacrifices and offerings forty years in the wilderness, O house of Israel?","sources":{"KJV":{"text":"Then God turned, and gave them up to worship the host of heaven; as it is written in the book of the prophets, O ye house of Israel, have ye offered to me slain beasts and sacrifices by the space of forty years in the wilderness?"},"BSB":{"text":"But God turned away from them and gave them over to the worship of the host of heaven, as it is written in the book of the prophets:  ‘Did you bring Me sacrifices and offerings forty years in the wilderness, O house of Israel?"}},"definableWords":["God","worship","heaven","years","house","Israel"],"peopleInVerse":[]},"43":{"text":"Yea, ye took up the tabernacle of Moloch, and the star of your god Remphan, figures which ye made to worship them: and I will carry you away beyond Babylon.","ref":"Acts 7:43","synthesized":"You have taken along the tabernacle of Molech and the star of your god Rephan, the idols you made to worship. Therefore I will send you into exile beyond Babylon.’","sources":{"KJV":{"text":"Yea, ye took up the tabernacle of Moloch, and the star of your god Remphan, figures which ye made to worship them: and I will carry you away beyond Babylon."},"BSB":{"text":"You have taken along the tabernacle of Molech and the star of your god Rephan, the idols you made to worship. Therefore I will send you into exile beyond Babylon.’"}},"definableWords":["tabernacle","God","made","worship","Babylon"],"peopleInVerse":[]},"44":{"text":"Our fathers had the tabernacle of witness in the wilderness, as he had appointed, speaking unto Moses, that he should make it according to the fashion that he had seen.","ref":"Acts 7:44","synthesized":"Our fathers had the tabernacle of the Testimony with them in the wilderness. It was constructed exactly as God had directed Moses, according to the pattern he had seen.","sources":{"KJV":{"text":"Our fathers had the tabernacle of witness in the wilderness, as he had appointed, speaking unto Moses, that he should make it according to the fashion that he had seen."},"BSB":{"text":"Our fathers had the tabernacle of the Testimony with them in the wilderness. It was constructed exactly as God had directed Moses, according to the pattern he had seen."}},"definableWords":["fathers","tabernacle","God"],"peopleInVerse":["Moses"]},"45":{"text":"Which also our fathers that came after brought in with Jesus into the possession of the Gentiles, whom God drave out before the face of our fathers, unto the days of David;","ref":"Acts 7:45","synthesized":"And our fathers who received it brought it in with Joshua when they dispossessed the nations God drove out before them. It remained until the time of David,","sources":{"KJV":{"text":"Which also our fathers that came after brought in with Jesus into the possession of the Gentiles, whom God drave out before the face of our fathers, unto the days of David;"},"BSB":{"text":"And our fathers who received it brought it in with Joshua when they dispossessed the nations God drove out before them. It remained until the time of David,"}},"definableWords":["fathers","nations","God"],"peopleInVerse":["Joshua","David"]},"46":{"text":"Who found favour before God, and desired to find a tabernacle for the God of Jacob.","ref":"Acts 7:46","synthesized":"who found favor in the sight of God and asked to provide a dwelling place for the God of Jacob.","sources":{"KJV":{"text":"Who found favour before God, and desired to find a tabernacle for the God of Jacob."},"BSB":{"text":"who found favor in the sight of God and asked to provide a dwelling place for the God of Jacob."}},"definableWords":["God","Jacob"],"peopleInVerse":["Jacob"]},"47":{"text":"But Solomon built him an house.","ref":"Acts 7:47","synthesized":"But it was Solomon who built the house for Him.","sources":{"KJV":{"text":"But Solomon built him an house."},"BSB":{"text":"But it was Solomon who built the house for Him."}},"definableWords":["house"],"peopleInVerse":["Solomon"]},"48":{"text":"Howbeit the most High dwelleth not in temples made with hands; as saith the prophet,","ref":"Acts 7:48","synthesized":"However, the Most High does not dwell in houses made by human hands. As the prophet says:","sources":{"KJV":{"text":"Howbeit the most High dwelleth not in temples made with hands; as saith the prophet,"},"BSB":{"text":"However, the Most High does not dwell in houses made by human hands. As the prophet says:"}},"definableWords":["made","prophet"],"peopleInVerse":[]},"49":{"text":"Heaven is my throne, and earth is my footstool: what house will ye build me? saith the Lord: or what is the place of my rest?","ref":"Acts 7:49","synthesized":"‘Heaven is My throne and the earth is My footstool. What kind of house will you build for Me, says the Lord, or where will My place of repose be?","sources":{"KJV":{"text":"Heaven is my throne, and earth is my footstool: what house will ye build me? saith the Lord: or what is the place of my rest?"},"BSB":{"text":"‘Heaven is My throne and the earth is My footstool. What kind of house will you build for Me, says the Lord, or where will My place of repose be?"}},"definableWords":["heaven","throne","earth","house","Lord","or"],"peopleInVerse":[]},"50":{"text":"Hath not my hand made all these things?","ref":"Acts 7:50","synthesized":"Has not My hand made all these things?’","sources":{"KJV":{"text":"Hath not my hand made all these things?"},"BSB":{"text":"Has not My hand made all these things?’"}},"definableWords":["made"],"peopleInVerse":[]},"51":{"text":"Ye stiffnecked and uncircumcised in heart and ears, ye do always resist the Holy Ghost: as your fathers did, so do ye.","ref":"Acts 7:51","synthesized":"You stiff-necked people with uncircumcised hearts and ears! You always resist the Holy Spirit, just as your fathers did.","sources":{"KJV":{"text":"Ye stiffnecked and uncircumcised in heart and ears, ye do always resist the Holy Ghost: as your fathers did, so do ye."},"BSB":{"text":"You stiff-necked people with uncircumcised hearts and ears! You always resist the Holy Spirit, just as your fathers did."}},"definableWords":["people","holy","Spirit","fathers"],"peopleInVerse":[]},"52":{"text":"Which of the prophets have not your fathers persecuted? and they have slain them which shewed before of the coming of the Just One; of whom ye have been now the betrayers and murderers:","ref":"Acts 7:52","synthesized":"Which of the prophets did your fathers fail to persecute? They even killed those who foretold the coming of the Righteous One. And now you are His betrayers and murderers—","sources":{"KJV":{"text":"Which of the prophets have not your fathers persecuted? and they have slain them which shewed before of the coming of the Just One; of whom ye have been now the betrayers and murderers:"},"BSB":{"text":"Which of the prophets did your fathers fail to persecute? They even killed those who foretold the coming of the Righteous One. And now you are His betrayers and murderers—"}},"definableWords":["fathers","righteous","one"],"peopleInVerse":[]},"53":{"text":"Who have received the law by the disposition of angels, and have not kept it.","ref":"Acts 7:53","synthesized":"you who received the law ordained by angels, yet have not kept it.”","sources":{"KJV":{"text":"Who have received the law by the disposition of angels, and have not kept it."},"BSB":{"text":"you who received the law ordained by angels, yet have not kept it.”"}},"definableWords":["law"],"peopleInVerse":[]},"54":{"text":"When they heard these things, they were cut to the heart, and they gnashed on him with their teeth.","ref":"Acts 7:54","synthesized":"On hearing this, the members of the Sanhedrin were enraged, and they gnashed their teeth at him.","sources":{"KJV":{"text":"When they heard these things, they were cut to the heart, and they gnashed on him with their teeth."},"BSB":{"text":"On hearing this, the members of the Sanhedrin were enraged, and they gnashed their teeth at him."}},"definableWords":[],"peopleInVerse":[]},"55":{"text":"But he, being full of the Holy Ghost, looked up stedfastly into heaven, and saw the glory of God, and Jesus standing on the right hand of God,","ref":"Acts 7:55","synthesized":"But Stephen, full of the Holy Spirit, looked intently into heaven and saw the glory of God and Jesus standing at the right hand of God.","sources":{"KJV":{"text":"But he, being full of the Holy Ghost, looked up stedfastly into heaven, and saw the glory of God, and Jesus standing on the right hand of God,"},"BSB":{"text":"But Stephen, full of the Holy Spirit, looked intently into heaven and saw the glory of God and Jesus standing at the right hand of God."}},"definableWords":["holy","Spirit","heaven","saw","glory","God"],"peopleInVerse":["Stephen","Jesus"]},"56":{"text":"And said, Behold, I see the heavens opened, and the Son of man standing on the right hand of God.","ref":"Acts 7:56","synthesized":"“Look,” he said, “I see heaven open and the Son of Man standing at the right hand of God.”","sources":{"KJV":{"text":"And said, Behold, I see the heavens opened, and the Son of man standing on the right hand of God."},"BSB":{"text":"“Look,” he said, “I see heaven open and the Son of Man standing at the right hand of God.”"}},"definableWords":["see","heaven","Son","man","God"],"peopleInVerse":[]},"57":{"text":"Then they cried out with a loud voice, and stopped their ears, and ran upon him with one accord,","ref":"Acts 7:57","synthesized":"At this they covered their ears, cried out in a loud voice, and rushed together at him.","sources":{"KJV":{"text":"Then they cried out with a loud voice, and stopped their ears, and ran upon him with one accord,"},"BSB":{"text":"At this they covered their ears, cried out in a loud voice, and rushed together at him."}},"definableWords":["voice"],"peopleInVerse":[]},"58":{"text":"And cast him out of the city, and stoned him: and the witnesses laid down their clothes at a young man’s feet, whose name was Saul.","ref":"Acts 7:58","synthesized":"They dragged him out of the city and began to stone him. Meanwhile the witnesses laid their garments at the feet of a young man named Saul.","sources":{"KJV":{"text":"And cast him out of the city, and stoned him: and the witnesses laid down their clothes at a young man’s feet, whose name was Saul."},"BSB":{"text":"They dragged him out of the city and began to stone him. Meanwhile the witnesses laid their garments at the feet of a young man named Saul."}},"definableWords":["stone","man"],"peopleInVerse":["Saul"]},"59":{"text":"And they stoned Stephen, calling upon God, and saying, Lord Jesus, receive my spirit.","ref":"Acts 7:59","synthesized":"While they were stoning him, Stephen appealed, “Lord Jesus, receive my spirit.”","sources":{"KJV":{"text":"And they stoned Stephen, calling upon God, and saying, Lord Jesus, receive my spirit."},"BSB":{"text":"While they were stoning him, Stephen appealed, “Lord Jesus, receive my spirit.”"}},"definableWords":["Lord","spirit"],"peopleInVerse":["Stephen","Jesus"]},"60":{"text":"And he kneeled down, and cried with a loud voice, Lord, lay not this sin to their charge. And when he had said this, he fell asleep.","ref":"Acts 7:60","synthesized":"Falling on his knees, he cried out in a loud voice, “Lord, do not hold this sin against them.” And when he had said this, he fell asleep.","sources":{"KJV":{"text":"And he kneeled down, and cried with a loud voice, Lord, lay not this sin to their charge. And when he had said this, he fell asleep."},"BSB":{"text":"Falling on his knees, he cried out in a loud voice, “Lord, do not hold this sin against them.” And when he had said this, he fell asleep."}},"definableWords":["voice","Lord","sin"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"PHILIP AND THE ETHIOPIAN EUNUCH","verses":{"1":{"text":"And Saul was consenting unto his death. And at that time there was a great persecution against the church which was at Jerusalem; and they were all scattered abroad throughout the regions of Judaea and Samaria, except the apostles.","ref":"Acts 8:1","synthesized":"And Saul was there, giving approval to Stephen’s death.  On that day a great persecution broke out against the church in Jerusalem, and all except the apostles were scattered throughout Judea and Samaria.","sources":{"KJV":{"text":"And Saul was consenting unto his death. And at that time there was a great persecution against the church which was at Jerusalem; and they were all scattered abroad throughout the regions of Judaea and Samaria, except the apostles."},"BSB":{"text":"And Saul was there, giving approval to Stephen’s death.  On that day a great persecution broke out against the church in Jerusalem, and all except the apostles were scattered throughout Judea and Samaria."}},"definableWords":["death","day","great","church","Jerusalem","Judea","Samaria"],"peopleInVerse":["Saul","Stephen"]},"2":{"text":"And devout men carried Stephen to his burial, and made great lamentation over him.","ref":"Acts 8:2","synthesized":"God-fearing men buried Stephen and mourned deeply over him.","sources":{"KJV":{"text":"And devout men carried Stephen to his burial, and made great lamentation over him."},"BSB":{"text":"God-fearing men buried Stephen and mourned deeply over him."}},"definableWords":["God","men"],"peopleInVerse":["Stephen"]},"3":{"text":"As for Saul, he made havock of the church, entering into every house, and haling men and women committed them to prison.","ref":"Acts 8:3","synthesized":"But Saul began to destroy the church. Going from house to house, he dragged off men and women and put them in prison.","sources":{"KJV":{"text":"As for Saul, he made havock of the church, entering into every house, and haling men and women committed them to prison."},"BSB":{"text":"But Saul began to destroy the church. Going from house to house, he dragged off men and women and put them in prison."}},"definableWords":["church","house","men","women"],"peopleInVerse":["Saul"]},"4":{"text":"Therefore they that were scattered abroad went every where preaching the word.","ref":"Acts 8:4","synthesized":"Those who had been scattered preached the word wherever they went.","sources":{"KJV":{"text":"Therefore they that were scattered abroad went every where preaching the word."},"BSB":{"text":"Those who had been scattered preached the word wherever they went."}},"definableWords":["word"],"peopleInVerse":[]},"5":{"text":"Then Philip went down to the city of Samaria, and preached Christ unto them.","ref":"Acts 8:5","synthesized":"Philip went down to a city in Samaria and proclaimed the Christ to them.","sources":{"KJV":{"text":"Then Philip went down to the city of Samaria, and preached Christ unto them."},"BSB":{"text":"Philip went down to a city in Samaria and proclaimed the Christ to them."}},"definableWords":["Samaria","Christ"],"peopleInVerse":[]},"6":{"text":"And the people with one accord gave heed unto those things which Philip spake, hearing and seeing the miracles which he did.","ref":"Acts 8:6","synthesized":"The crowds gave their undivided attention to Philip’s message and to the signs they saw him perform.","sources":{"KJV":{"text":"And the people with one accord gave heed unto those things which Philip spake, hearing and seeing the miracles which he did."},"BSB":{"text":"The crowds gave their undivided attention to Philip’s message and to the signs they saw him perform."}},"definableWords":["saw"],"peopleInVerse":[]},"7":{"text":"For unclean spirits, crying with loud voice, came out of many that were possessed with them: and many taken with palsies, and that were lame, were healed.","ref":"Acts 8:7","synthesized":"With loud shrieks, unclean spirits came out of many who were possessed, and many of the paralyzed and lame were healed.","sources":{"KJV":{"text":"For unclean spirits, crying with loud voice, came out of many that were possessed with them: and many taken with palsies, and that were lame, were healed."},"BSB":{"text":"With loud shrieks, unclean spirits came out of many who were possessed, and many of the paralyzed and lame were healed."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"And there was great joy in that city.","ref":"Acts 8:8","synthesized":"So there was great joy in that city.","sources":{"KJV":{"text":"And there was great joy in that city."},"BSB":{"text":"So there was great joy in that city."}},"definableWords":["great","joy"],"peopleInVerse":[]},"9":{"text":"But there was a certain man, called Simon, which beforetime in the same city used sorcery, and bewitched the people of Samaria, giving out that himself was some great one:","ref":"Acts 8:9","synthesized":"Prior to that time, a man named Simon had practiced sorcery in the city and astounded the people of Samaria. He claimed to be someone great,","sources":{"KJV":{"text":"But there was a certain man, called Simon, which beforetime in the same city used sorcery, and bewitched the people of Samaria, giving out that himself was some great one:"},"BSB":{"text":"Prior to that time, a man named Simon had practiced sorcery in the city and astounded the people of Samaria. He claimed to be someone great,"}},"definableWords":["man","people","Samaria","great"],"peopleInVerse":[]},"10":{"text":"To whom they all gave heed, from the least to the greatest, saying, This man is the great power of God.","ref":"Acts 8:10","synthesized":"and all the people, from the least to the greatest, heeded his words and said, “This man is the divine power called the Great Power.”","sources":{"KJV":{"text":"To whom they all gave heed, from the least to the greatest, saying, This man is the great power of God."},"BSB":{"text":"and all the people, from the least to the greatest, heeded his words and said, “This man is the divine power called the Great Power.”"}},"definableWords":["people","man","great"],"peopleInVerse":[]},"11":{"text":"And to him they had regard, because that of long time he had bewitched them with sorceries.","ref":"Acts 8:11","synthesized":"They paid close attention to him because he had astounded them for a long time with his sorcery.","sources":{"KJV":{"text":"And to him they had regard, because that of long time he had bewitched them with sorceries."},"BSB":{"text":"They paid close attention to him because he had astounded them for a long time with his sorcery."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"But when they believed Philip preaching the things concerning the kingdom of God, and the name of Jesus Christ, they were baptized, both men and women.","ref":"Acts 8:12","synthesized":"But when they believed Philip as he preached the gospel of the kingdom of God and the name of Jesus Christ, they were baptized, both men and women.","sources":{"KJV":{"text":"But when they believed Philip preaching the things concerning the kingdom of God, and the name of Jesus Christ, they were baptized, both men and women."},"BSB":{"text":"But when they believed Philip as he preached the gospel of the kingdom of God and the name of Jesus Christ, they were baptized, both men and women."}},"definableWords":["believed","gospel","kingdom","God","name","Christ","men","women"],"peopleInVerse":["Jesus"]},"13":{"text":"Then Simon himself believed also: and when he was baptized, he continued with Philip, and wondered, beholding the miracles and signs which were done.","ref":"Acts 8:13","synthesized":"Even Simon himself believed and was baptized. He followed Philip closely and was astounded by the great signs and miracles he observed.","sources":{"KJV":{"text":"Then Simon himself believed also: and when he was baptized, he continued with Philip, and wondered, beholding the miracles and signs which were done."},"BSB":{"text":"Even Simon himself believed and was baptized. He followed Philip closely and was astounded by the great signs and miracles he observed."}},"definableWords":["believed","great"],"peopleInVerse":[]},"14":{"text":"Now when the apostles which were at Jerusalem heard that Samaria had received the word of God, they sent unto them Peter and John:","ref":"Acts 8:14","synthesized":"When the apostles in Jerusalem heard that Samaria had received the word of God, they sent Peter and John to them.","sources":{"KJV":{"text":"Now when the apostles which were at Jerusalem heard that Samaria had received the word of God, they sent unto them Peter and John:"},"BSB":{"text":"When the apostles in Jerusalem heard that Samaria had received the word of God, they sent Peter and John to them."}},"definableWords":["Jerusalem","Samaria","word","God"],"peopleInVerse":["Peter","John"]},"15":{"text":"Who, when they were come down, prayed for them, that they might receive the Holy Ghost:","ref":"Acts 8:15","synthesized":"On their arrival, they prayed for them to receive the Holy Spirit.","sources":{"KJV":{"text":"Who, when they were come down, prayed for them, that they might receive the Holy Ghost:"},"BSB":{"text":"On their arrival, they prayed for them to receive the Holy Spirit."}},"definableWords":["holy","Spirit"],"peopleInVerse":[]},"16":{"text":"(For as yet he was fallen upon none of them: only they were baptized in the name of the Lord Jesus.)","ref":"Acts 8:16","synthesized":"For the Holy Spirit had not yet fallen upon any of them; they had simply been baptized into the name of the Lord Jesus.","sources":{"KJV":{"text":"(For as yet he was fallen upon none of them: only they were baptized in the name of the Lord Jesus.)"},"BSB":{"text":"For the Holy Spirit had not yet fallen upon any of them; they had simply been baptized into the name of the Lord Jesus."}},"definableWords":["holy","Spirit","name","Lord"],"peopleInVerse":["Jesus"]},"17":{"text":"Then laid they their hands on them, and they received the Holy Ghost.","ref":"Acts 8:17","synthesized":"Then Peter and John laid their hands on them, and they received the Holy Spirit.","sources":{"KJV":{"text":"Then laid they their hands on them, and they received the Holy Ghost."},"BSB":{"text":"Then Peter and John laid their hands on them, and they received the Holy Spirit."}},"definableWords":["holy","Spirit"],"peopleInVerse":["Peter","John"]},"18":{"text":"And when Simon saw that through laying on of the apostles’ hands the Holy Ghost was given, he offered them money,","ref":"Acts 8:18","synthesized":"When Simon saw that the Spirit was given through the laying on of the apostles’ hands, he offered them money.","sources":{"KJV":{"text":"And when Simon saw that through laying on of the apostles’ hands the Holy Ghost was given, he offered them money,"},"BSB":{"text":"When Simon saw that the Spirit was given through the laying on of the apostles’ hands, he offered them money."}},"definableWords":["saw","Spirit"],"peopleInVerse":[]},"19":{"text":"Saying, Give me also this power, that on whomsoever I lay hands, he may receive the Holy Ghost.","ref":"Acts 8:19","synthesized":"“Give me this power as well,” he said, “so that everyone on whom I lay my hands may receive the Holy Spirit.”","sources":{"KJV":{"text":"Saying, Give me also this power, that on whomsoever I lay hands, he may receive the Holy Ghost."},"BSB":{"text":"“Give me this power as well,” he said, “so that everyone on whom I lay my hands may receive the Holy Spirit.”"}},"definableWords":["holy","Spirit"],"peopleInVerse":[]},"20":{"text":"But Peter said unto him, Thy money perish with thee, because thou hast thought that the gift of God may be purchased with money.","ref":"Acts 8:20","synthesized":"But Peter replied, “May your silver perish with you, because you thought you could buy the gift of God with money!","sources":{"KJV":{"text":"But Peter said unto him, Thy money perish with thee, because thou hast thought that the gift of God may be purchased with money."},"BSB":{"text":"But Peter replied, “May your silver perish with you, because you thought you could buy the gift of God with money!"}},"definableWords":["God"],"peopleInVerse":["Peter"]},"21":{"text":"Thou hast neither part nor lot in this matter: for thy heart is not right in the sight of God.","ref":"Acts 8:21","synthesized":"You have no part or share in our ministry, because your heart is not right before God.","sources":{"KJV":{"text":"Thou hast neither part nor lot in this matter: for thy heart is not right in the sight of God."},"BSB":{"text":"You have no part or share in our ministry, because your heart is not right before God."}},"definableWords":["or","heart","God"],"peopleInVerse":[]},"22":{"text":"Repent therefore of this thy wickedness, and pray God, if perhaps the thought of thine heart may be forgiven thee.","ref":"Acts 8:22","synthesized":"Repent, therefore, of your wickedness, and pray to the Lord. Perhaps He will forgive you for the intent of your heart.","sources":{"KJV":{"text":"Repent therefore of this thy wickedness, and pray God, if perhaps the thought of thine heart may be forgiven thee."},"BSB":{"text":"Repent, therefore, of your wickedness, and pray to the Lord. Perhaps He will forgive you for the intent of your heart."}},"definableWords":["Lord","forgive","heart"],"peopleInVerse":[]},"23":{"text":"For I perceive that thou art in the gall of bitterness, and in the bond of iniquity.","ref":"Acts 8:23","synthesized":"For I see that you are poisoned by bitterness and captive to iniquity.”","sources":{"KJV":{"text":"For I perceive that thou art in the gall of bitterness, and in the bond of iniquity."},"BSB":{"text":"For I see that you are poisoned by bitterness and captive to iniquity.”"}},"definableWords":["see","iniquity"],"peopleInVerse":[]},"24":{"text":"Then answered Simon, and said, Pray ye to the LORD for me, that none of these things which ye have spoken come upon me.","ref":"Acts 8:24","synthesized":"Then Simon answered, “Pray to the Lord for me, so that nothing you have said may happen to me.”","sources":{"KJV":{"text":"Then answered Simon, and said, Pray ye to the LORD for me, that none of these things which ye have spoken come upon me."},"BSB":{"text":"Then Simon answered, “Pray to the Lord for me, so that nothing you have said may happen to me.”"}},"definableWords":["Lord"],"peopleInVerse":[]},"25":{"text":"And they, when they had testified and preached the word of the Lord, returned to Jerusalem, and preached the gospel in many villages of the Samaritans.","ref":"Acts 8:25","synthesized":"And after Peter and John had testified and spoken the word of the Lord, they returned to Jerusalem, preaching the gospel in many of the Samaritan villages.","sources":{"KJV":{"text":"And they, when they had testified and preached the word of the Lord, returned to Jerusalem, and preached the gospel in many villages of the Samaritans."},"BSB":{"text":"And after Peter and John had testified and spoken the word of the Lord, they returned to Jerusalem, preaching the gospel in many of the Samaritan villages."}},"definableWords":["word","Lord","Jerusalem","gospel"],"peopleInVerse":["Peter","John"]},"26":{"text":"And the angel of the Lord spake unto Philip, saying, Arise, and go toward the south unto the way that goeth down from Jerusalem unto Gaza, which is desert.","ref":"Acts 8:26","synthesized":"Now an angel of the Lord said to Philip, “Get up and go south to the desert road that goes down from Jerusalem to Gaza.”","sources":{"KJV":{"text":"And the angel of the Lord spake unto Philip, saying, Arise, and go toward the south unto the way that goeth down from Jerusalem unto Gaza, which is desert."},"BSB":{"text":"Now an angel of the Lord said to Philip, “Get up and go south to the desert road that goes down from Jerusalem to Gaza.”"}},"definableWords":["angel","Lord","Jerusalem"],"peopleInVerse":[]},"27":{"text":"And he arose and went: and, behold, a man of Ethiopia, an eunuch of great authority under Candace queen of the Ethiopians, who had the charge of all her treasure, and had come to Jerusalem for to worship,","ref":"Acts 8:27","synthesized":"So he started out, and on his way he met an Ethiopian eunuch, a court official in charge of the entire treasury of Candace, queen of the Ethiopians. He had gone to Jerusalem to worship,","sources":{"KJV":{"text":"And he arose and went: and, behold, a man of Ethiopia, an eunuch of great authority under Candace queen of the Ethiopians, who had the charge of all her treasure, and had come to Jerusalem for to worship,"},"BSB":{"text":"So he started out, and on his way he met an Ethiopian eunuch, a court official in charge of the entire treasury of Candace, queen of the Ethiopians. He had gone to Jerusalem to worship,"}},"definableWords":["way","charge","Jerusalem","worship"],"peopleInVerse":[]},"28":{"text":"Was returning, and sitting in his chariot read Esaias the prophet.","ref":"Acts 8:28","synthesized":"and on his return was sitting in his chariot reading Isaiah the prophet.","sources":{"KJV":{"text":"Was returning, and sitting in his chariot read Esaias the prophet."},"BSB":{"text":"and on his return was sitting in his chariot reading Isaiah the prophet."}},"definableWords":["prophet"],"peopleInVerse":["Isaiah"]},"29":{"text":"Then the Spirit said unto Philip, Go near, and join thyself to this chariot.","ref":"Acts 8:29","synthesized":"The Spirit said to Philip, “Go over to that chariot and stay by it.”","sources":{"KJV":{"text":"Then the Spirit said unto Philip, Go near, and join thyself to this chariot."},"BSB":{"text":"The Spirit said to Philip, “Go over to that chariot and stay by it.”"}},"definableWords":["Spirit"],"peopleInVerse":[]},"30":{"text":"And Philip ran thither to him, and heard him read the prophet Esaias, and said, Understandest thou what thou readest?","ref":"Acts 8:30","synthesized":"So Philip ran up and heard the man reading Isaiah the prophet. “Do you understand what you are reading?” Philip asked.","sources":{"KJV":{"text":"And Philip ran thither to him, and heard him read the prophet Esaias, and said, Understandest thou what thou readest?"},"BSB":{"text":"So Philip ran up and heard the man reading Isaiah the prophet. “Do you understand what you are reading?” Philip asked."}},"definableWords":["man","prophet"],"peopleInVerse":["Isaiah"]},"31":{"text":"And he said, How can I, except some man should guide me? And he desired Philip that he would come up and sit with him.","ref":"Acts 8:31","synthesized":"“How can I,” he said, “unless someone guides me?” And he invited Philip to come up and sit with him.","sources":{"KJV":{"text":"And he said, How can I, except some man should guide me? And he desired Philip that he would come up and sit with him."},"BSB":{"text":"“How can I,” he said, “unless someone guides me?” And he invited Philip to come up and sit with him."}},"definableWords":[],"peopleInVerse":[]},"32":{"text":"The place of the scripture which he read was this, He was led as a sheep to the slaughter; and like a lamb dumb before his shearer, so opened he not his mouth:","ref":"Acts 8:32","synthesized":"The eunuch was reading this passage of Scripture:  “He was led like a sheep to the slaughter, and as a lamb before the shearer is silent, so He did not open His mouth.","sources":{"KJV":{"text":"The place of the scripture which he read was this, He was led as a sheep to the slaughter; and like a lamb dumb before his shearer, so opened he not his mouth:"},"BSB":{"text":"The eunuch was reading this passage of Scripture:  “He was led like a sheep to the slaughter, and as a lamb before the shearer is silent, so He did not open His mouth."}},"definableWords":["Lamb"],"peopleInVerse":[]},"33":{"text":"In his humiliation his judgment was taken away: and who shall declare his generation? for his life is taken from the earth.","ref":"Acts 8:33","synthesized":"In His humiliation He was deprived of justice. Who can recount His descendants? For His life was removed from the earth.”","sources":{"KJV":{"text":"In his humiliation his judgment was taken away: and who shall declare his generation? for his life is taken from the earth."},"BSB":{"text":"In His humiliation He was deprived of justice. Who can recount His descendants? For His life was removed from the earth.”"}},"definableWords":["justice","life","earth"],"peopleInVerse":[]},"34":{"text":"And the eunuch answered Philip, and said, I pray thee, of whom speaketh the prophet this? of himself, or of some other man?","ref":"Acts 8:34","synthesized":"“Tell me,” said the eunuch, “who is the prophet talking about, himself or someone else?”","sources":{"KJV":{"text":"And the eunuch answered Philip, and said, I pray thee, of whom speaketh the prophet this? of himself, or of some other man?"},"BSB":{"text":"“Tell me,” said the eunuch, “who is the prophet talking about, himself or someone else?”"}},"definableWords":["prophet","or"],"peopleInVerse":[]},"35":{"text":"Then Philip opened his mouth, and began at the same scripture, and preached unto him Jesus.","ref":"Acts 8:35","synthesized":"Then Philip began with this very Scripture and told him the good news about Jesus.","sources":{"KJV":{"text":"Then Philip opened his mouth, and began at the same scripture, and preached unto him Jesus."},"BSB":{"text":"Then Philip began with this very Scripture and told him the good news about Jesus."}},"definableWords":["good"],"peopleInVerse":["Jesus"]},"36":{"text":"And as they went on their way, they came unto a certain water: and the eunuch said, See, here is water; what doth hinder me to be baptized?","ref":"Acts 8:36","synthesized":"As they traveled along the road and came to some water, the eunuch said, “Look, here is water! What is there to prevent me from being baptized?”","sources":{"KJV":{"text":"And as they went on their way, they came unto a certain water: and the eunuch said, See, here is water; what doth hinder me to be baptized?"},"BSB":{"text":"As they traveled along the road and came to some water, the eunuch said, “Look, here is water! What is there to prevent me from being baptized?”"}},"definableWords":["water"],"peopleInVerse":[]},"37":{"text":"And Philip said, If thou believest with all thine heart, thou mayest. And he answered and said, I believe that Jesus Christ is the Son of God.","ref":"Acts 8:37","synthesized":"And Philip said, If thou believest with all thine heart, thou mayest. And he answered and said, I believe that Jesus Christ is the Son of God.","sources":{"KJV":{"text":"And Philip said, If thou believest with all thine heart, thou mayest. And he answered and said, I believe that Jesus Christ is the Son of God."}},"definableWords":["heart","Christ","Son","God"],"peopleInVerse":["Jesus"]},"38":{"text":"And he commanded the chariot to stand still: and they went down both into the water, both Philip and the eunuch; and he baptized him.","ref":"Acts 8:38","synthesized":"And he gave orders to stop the chariot. Then both Philip and the eunuch went down into the water, and Philip baptized him.","sources":{"KJV":{"text":"And he commanded the chariot to stand still: and they went down both into the water, both Philip and the eunuch; and he baptized him."},"BSB":{"text":"And he gave orders to stop the chariot. Then both Philip and the eunuch went down into the water, and Philip baptized him."}},"definableWords":["water"],"peopleInVerse":[]},"39":{"text":"And when they were come up out of the water, the Spirit of the Lord caught away Philip, that the eunuch saw him no more: and he went on his way rejoicing.","ref":"Acts 8:39","synthesized":"When they came up out of the water, the Spirit of the Lord carried Philip away, and the eunuch saw him no more, but went on his way rejoicing.","sources":{"KJV":{"text":"And when they were come up out of the water, the Spirit of the Lord caught away Philip, that the eunuch saw him no more: and he went on his way rejoicing."},"BSB":{"text":"When they came up out of the water, the Spirit of the Lord carried Philip away, and the eunuch saw him no more, but went on his way rejoicing."}},"definableWords":["water","Spirit","Lord","saw","way"],"peopleInVerse":[]},"40":{"text":"But Philip was found at Azotus: and passing through he preached in all the cities, till he came to Caesarea.","ref":"Acts 8:40","synthesized":"But Philip appeared at Azotus and traveled through that region, preaching the gospel in all the towns until he came to Caesarea.","sources":{"KJV":{"text":"But Philip was found at Azotus: and passing through he preached in all the cities, till he came to Caesarea."},"BSB":{"text":"But Philip appeared at Azotus and traveled through that region, preaching the gospel in all the towns until he came to Caesarea."}},"definableWords":["gospel"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"PAUL'S CONVERSION ON THE DAMASCUS ROAD","verses":{"1":{"text":"And Saul, yet breathing out threatenings and slaughter against the disciples of the Lord, went unto the high priest,","ref":"Acts 9:1","synthesized":"Meanwhile, Saul was still breathing out murderous threats against the disciples of the Lord. He approached the high priest","sources":{"KJV":{"text":"And Saul, yet breathing out threatenings and slaughter against the disciples of the Lord, went unto the high priest,"},"BSB":{"text":"Meanwhile, Saul was still breathing out murderous threats against the disciples of the Lord. He approached the high priest"}},"definableWords":["Lord","priest"],"peopleInVerse":["Saul"],"kingdomLens":"Saul of Tarsus — the chief persecutor of the church — is on his way to Damascus to arrest Christians. A blinding light strikes him to the ground. A voice: 'Saul, Saul, why persecutest thou ME?' Jesus identifies WITH his church. The persecutor becomes the apostle to the Gentiles. The author of half the NT. Christianity's most dramatic conversion.","cultural":{"title":"The Damascus Road conversion","detail":"Damascus is one of the oldest continuously inhabited cities on earth (mentioned in Genesis 14). The street called Straight (Acts 9:11) still exists in Damascus today as the main east-west road through the Old City. The historicity of this account is geographically verifiable.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"And desired of him letters to Damascus to the synagogues, that if he found any of this way, whether they were men or women, he might bring them bound unto Jerusalem.","ref":"Acts 9:2","synthesized":"and requested letters to the synagogues in Damascus, so that if he found any men or women belonging to the Way, he could bring them as prisoners to Jerusalem.","sources":{"KJV":{"text":"And desired of him letters to Damascus to the synagogues, that if he found any of this way, whether they were men or women, he might bring them bound unto Jerusalem."},"BSB":{"text":"and requested letters to the synagogues in Damascus, so that if he found any men or women belonging to the Way, he could bring them as prisoners to Jerusalem."}},"definableWords":["men","or","women","way","Jerusalem"],"peopleInVerse":[]},"3":{"text":"And as he journeyed, he came near Damascus: and suddenly there shined round about him a light from heaven:","ref":"Acts 9:3","synthesized":"As Saul drew near to Damascus on his journey, suddenly a light from heaven flashed around him.","sources":{"KJV":{"text":"And as he journeyed, he came near Damascus: and suddenly there shined round about him a light from heaven:"},"BSB":{"text":"As Saul drew near to Damascus on his journey, suddenly a light from heaven flashed around him."}},"definableWords":["light","heaven"],"peopleInVerse":["Saul"]},"4":{"text":"And he fell to the earth, and heard a voice saying unto him, Saul, Saul, why persecutest thou me?","ref":"Acts 9:4","synthesized":"He fell to the ground and heard a voice say to him, “Saul, Saul, why do you persecute Me?”","sources":{"KJV":{"text":"And he fell to the earth, and heard a voice saying unto him, Saul, Saul, why persecutest thou me?"},"BSB":{"text":"He fell to the ground and heard a voice say to him, “Saul, Saul, why do you persecute Me?”"}},"definableWords":["ground","voice"],"peopleInVerse":["Saul"]},"5":{"text":"And he said, Who art thou, Lord? And the Lord said, I am Jesus whom thou persecutest: it is hard for thee to kick against the pricks.","ref":"Acts 9:5","synthesized":"“Who are You, Lord?” Saul asked.  “I am Jesus, whom you are persecuting,” He replied.","sources":{"KJV":{"text":"And he said, Who art thou, Lord? And the Lord said, I am Jesus whom thou persecutest: it is hard for thee to kick against the pricks."},"BSB":{"text":"“Who are You, Lord?” Saul asked.  “I am Jesus, whom you are persecuting,” He replied."}},"definableWords":["Lord"],"peopleInVerse":["Saul","Jesus"]},"6":{"text":"And he trembling and astonished said, Lord, what wilt thou have me to do? And the Lord said unto him, Arise, and go into the city, and it shall be told thee what thou must do.","ref":"Acts 9:6","synthesized":"“Now get up and go into the city, and you will be told what you must do.”","sources":{"KJV":{"text":"And he trembling and astonished said, Lord, what wilt thou have me to do? And the Lord said unto him, Arise, and go into the city, and it shall be told thee what thou must do."},"BSB":{"text":"“Now get up and go into the city, and you will be told what you must do.”"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And the men which journeyed with him stood speechless, hearing a voice, but seeing no man.","ref":"Acts 9:7","synthesized":"The men traveling with Saul stood there speechless. They heard the voice but did not see anyone.","sources":{"KJV":{"text":"And the men which journeyed with him stood speechless, hearing a voice, but seeing no man."},"BSB":{"text":"The men traveling with Saul stood there speechless. They heard the voice but did not see anyone."}},"definableWords":["men","voice","see"],"peopleInVerse":["Saul"]},"8":{"text":"And Saul arose from the earth; and when his eyes were opened, he saw no man: but they led him by the hand, and brought him into Damascus.","ref":"Acts 9:8","synthesized":"Saul got up from the ground, but when he opened his eyes he could not see a thing. So they led him by the hand into Damascus.","sources":{"KJV":{"text":"And Saul arose from the earth; and when his eyes were opened, he saw no man: but they led him by the hand, and brought him into Damascus."},"BSB":{"text":"Saul got up from the ground, but when he opened his eyes he could not see a thing. So they led him by the hand into Damascus."}},"definableWords":["ground","see"],"peopleInVerse":["Saul"]},"9":{"text":"And he was three days without sight, and neither did eat nor drink.","ref":"Acts 9:9","synthesized":"For three days he was without sight, and he did not eat or drink anything.","sources":{"KJV":{"text":"And he was three days without sight, and neither did eat nor drink."},"BSB":{"text":"For three days he was without sight, and he did not eat or drink anything."}},"definableWords":["days","or"],"peopleInVerse":[]},"10":{"text":"And there was a certain disciple at Damascus, named Ananias; and to him said the Lord in a vision, Ananias. And he said, Behold, I am here, Lord.","ref":"Acts 9:10","synthesized":"In Damascus there was a disciple named Ananias. The Lord spoke to him in a vision, “Ananias!”  “Here I am, Lord,” he answered.","sources":{"KJV":{"text":"And there was a certain disciple at Damascus, named Ananias; and to him said the Lord in a vision, Ananias. And he said, Behold, I am here, Lord."},"BSB":{"text":"In Damascus there was a disciple named Ananias. The Lord spoke to him in a vision, “Ananias!”  “Here I am, Lord,” he answered."}},"definableWords":["disciple","Lord"],"peopleInVerse":[]},"11":{"text":"And the Lord said unto him, Arise, and go into the street which is called Straight, and enquire in the house of Judas for one called Saul, of Tarsus: for, behold, he prayeth,","ref":"Acts 9:11","synthesized":"“Get up!” the Lord told him. “Go to the house of Judas on Straight Street and ask for a man from Tarsus named Saul, for he is praying.","sources":{"KJV":{"text":"And the Lord said unto him, Arise, and go into the street which is called Straight, and enquire in the house of Judas for one called Saul, of Tarsus: for, behold, he prayeth,"},"BSB":{"text":"“Get up!” the Lord told him. “Go to the house of Judas on Straight Street and ask for a man from Tarsus named Saul, for he is praying."}},"definableWords":["Lord","house","man"],"peopleInVerse":["Saul"]},"12":{"text":"And hath seen in a vision a man named Ananias coming in, and putting his hand on him, that he might receive his sight.","ref":"Acts 9:12","synthesized":"In a vision he has seen a man named Ananias come and place his hands on him to restore his sight.”","sources":{"KJV":{"text":"And hath seen in a vision a man named Ananias coming in, and putting his hand on him, that he might receive his sight."},"BSB":{"text":"In a vision he has seen a man named Ananias come and place his hands on him to restore his sight.”"}},"definableWords":["man"],"peopleInVerse":[]},"13":{"text":"Then Ananias answered, Lord, I have heard by many of this man, how much evil he hath done to thy saints at Jerusalem:","ref":"Acts 9:13","synthesized":"But Ananias answered, “Lord, many people have told me about this man and all the harm he has done to Your saints in Jerusalem.","sources":{"KJV":{"text":"Then Ananias answered, Lord, I have heard by many of this man, how much evil he hath done to thy saints at Jerusalem:"},"BSB":{"text":"But Ananias answered, “Lord, many people have told me about this man and all the harm he has done to Your saints in Jerusalem."}},"definableWords":["Lord","people","man","Jerusalem"],"peopleInVerse":[]},"14":{"text":"And here he hath authority from the chief priests to bind all that call on thy name.","ref":"Acts 9:14","synthesized":"And now he is here with authority from the chief priests to arrest all who call on Your name.”","sources":{"KJV":{"text":"And here he hath authority from the chief priests to bind all that call on thy name."},"BSB":{"text":"And now he is here with authority from the chief priests to arrest all who call on Your name.”"}},"definableWords":["name"],"peopleInVerse":[]},"15":{"text":"But the Lord said unto him, Go thy way: for he is a chosen vessel unto me, to bear my name before the Gentiles, and kings, and the children of Israel:","ref":"Acts 9:15","synthesized":"“Go!” said the Lord. “This man is My chosen instrument to carry My name before the Gentiles and their kings, and before the people of Israel.","sources":{"KJV":{"text":"But the Lord said unto him, Go thy way: for he is a chosen vessel unto me, to bear my name before the Gentiles, and kings, and the children of Israel:"},"BSB":{"text":"“Go!” said the Lord. “This man is My chosen instrument to carry My name before the Gentiles and their kings, and before the people of Israel."}},"definableWords":["Lord","man","name","kings","people","Israel"],"peopleInVerse":[]},"16":{"text":"For I will shew him how great things he must suffer for my name’s sake.","ref":"Acts 9:16","synthesized":"I will show him how much he must suffer for My name.”","sources":{"KJV":{"text":"For I will shew him how great things he must suffer for my name’s sake."},"BSB":{"text":"I will show him how much he must suffer for My name.”"}},"definableWords":["name"],"peopleInVerse":[]},"17":{"text":"And Ananias went his way, and entered into the house; and putting his hands on him said, Brother Saul, the Lord, even Jesus, that appeared unto thee in the way as thou camest, hath sent me, that thou mightest receive thy sight, and be filled with the Holy Ghost.","ref":"Acts 9:17","synthesized":"So Ananias went to the house, and when he arrived, he placed his hands on Saul. “Brother Saul,” he said, “the Lord Jesus, who appeared to you on the road as you were coming here, has sent me so that you may see again and be filled with the Holy Spirit.”","sources":{"KJV":{"text":"And Ananias went his way, and entered into the house; and putting his hands on him said, Brother Saul, the Lord, even Jesus, that appeared unto thee in the way as thou camest, hath sent me, that thou mightest receive thy sight, and be filled with the Holy Ghost."},"BSB":{"text":"So Ananias went to the house, and when he arrived, he placed his hands on Saul. “Brother Saul,” he said, “the Lord Jesus, who appeared to you on the road as you were coming here, has sent me so that you may see again and be filled with the Holy Spirit.”"}},"definableWords":["house","brother","Lord","see","holy","Spirit"],"peopleInVerse":["Saul","Jesus"]},"18":{"text":"And immediately there fell from his eyes as it had been scales: and he received sight forthwith, and arose, and was baptized.","ref":"Acts 9:18","synthesized":"At that instant, something like scales fell from Saul’s eyes, and his sight was restored. He got up and was baptized,","sources":{"KJV":{"text":"And immediately there fell from his eyes as it had been scales: and he received sight forthwith, and arose, and was baptized."},"BSB":{"text":"At that instant, something like scales fell from Saul’s eyes, and his sight was restored. He got up and was baptized,"}},"definableWords":[],"peopleInVerse":["Saul"]},"19":{"text":"And when he had received meat, he was strengthened. Then was Saul certain days with the disciples which were at Damascus.","ref":"Acts 9:19","synthesized":"and after taking some food, he regained his strength. And he spent several days with the disciples in Damascus.","sources":{"KJV":{"text":"And when he had received meat, he was strengthened. Then was Saul certain days with the disciples which were at Damascus."},"BSB":{"text":"and after taking some food, he regained his strength. And he spent several days with the disciples in Damascus."}},"definableWords":["days"],"peopleInVerse":[]},"20":{"text":"And straightway he preached Christ in the synagogues, that he is the Son of God.","ref":"Acts 9:20","synthesized":"Saul promptly began to proclaim Jesus in the synagogues, declaring, “He is the Son of God.”","sources":{"KJV":{"text":"And straightway he preached Christ in the synagogues, that he is the Son of God."},"BSB":{"text":"Saul promptly began to proclaim Jesus in the synagogues, declaring, “He is the Son of God.”"}},"definableWords":["Son","God"],"peopleInVerse":["Saul","Jesus"]},"21":{"text":"But all that heard him were amazed, and said; Is not this he that destroyed them which called on this name in Jerusalem, and came hither for that intent, that he might bring them bound unto the chief priests?","ref":"Acts 9:21","synthesized":"All who heard him were astounded and asked, “Isn’t this the man who wreaked havoc in Jerusalem on those who call on this name? And hasn’t he come here to take them as prisoners to the chief priests?”","sources":{"KJV":{"text":"But all that heard him were amazed, and said; Is not this he that destroyed them which called on this name in Jerusalem, and came hither for that intent, that he might bring them bound unto the chief priests?"},"BSB":{"text":"All who heard him were astounded and asked, “Isn’t this the man who wreaked havoc in Jerusalem on those who call on this name? And hasn’t he come here to take them as prisoners to the chief priests?”"}},"definableWords":["man","Jerusalem","name"],"peopleInVerse":[]},"22":{"text":"But Saul increased the more in strength, and confounded the Jews which dwelt at Damascus, proving that this is very Christ.","ref":"Acts 9:22","synthesized":"But Saul was empowered all the more, and he confounded the Jews living in Damascus by proving that Jesus is the Christ.","sources":{"KJV":{"text":"But Saul increased the more in strength, and confounded the Jews which dwelt at Damascus, proving that this is very Christ."},"BSB":{"text":"But Saul was empowered all the more, and he confounded the Jews living in Damascus by proving that Jesus is the Christ."}},"definableWords":["living","Christ"],"peopleInVerse":["Saul","Jesus"]},"23":{"text":"And after that many days were fulfilled, the Jews took counsel to kill him:","ref":"Acts 9:23","synthesized":"After many days had passed, the Jews conspired to kill him,","sources":{"KJV":{"text":"And after that many days were fulfilled, the Jews took counsel to kill him:"},"BSB":{"text":"After many days had passed, the Jews conspired to kill him,"}},"definableWords":["days"],"peopleInVerse":[]},"24":{"text":"But their laying await was known of Saul. And they watched the gates day and night to kill him.","ref":"Acts 9:24","synthesized":"but Saul learned of their plot. Day and night they watched the city gates in order to kill him.","sources":{"KJV":{"text":"But their laying await was known of Saul. And they watched the gates day and night to kill him."},"BSB":{"text":"but Saul learned of their plot. Day and night they watched the city gates in order to kill him."}},"definableWords":["day","night"],"peopleInVerse":["Saul"]},"25":{"text":"Then the disciples took him by night, and let him down by the wall in a basket.","ref":"Acts 9:25","synthesized":"One night, however, his disciples took him and lowered him in a basket through a window in the wall.","sources":{"KJV":{"text":"Then the disciples took him by night, and let him down by the wall in a basket."},"BSB":{"text":"One night, however, his disciples took him and lowered him in a basket through a window in the wall."}},"definableWords":["one","night"],"peopleInVerse":[]},"26":{"text":"And when Saul was come to Jerusalem, he assayed to join himself to the disciples: but they were all afraid of him, and believed not that he was a disciple.","ref":"Acts 9:26","synthesized":"When Saul arrived in Jerusalem, he tried to join the disciples, but they were all afraid of him, not believing that he was a disciple.","sources":{"KJV":{"text":"And when Saul was come to Jerusalem, he assayed to join himself to the disciples: but they were all afraid of him, and believed not that he was a disciple."},"BSB":{"text":"When Saul arrived in Jerusalem, he tried to join the disciples, but they were all afraid of him, not believing that he was a disciple."}},"definableWords":["Jerusalem","disciple"],"peopleInVerse":["Saul"]},"27":{"text":"But Barnabas took him, and brought him to the apostles, and declared unto them how he had seen the Lord in the way, and that he had spoken to him, and how he had preached boldly at Damascus in the name of Jesus.","ref":"Acts 9:27","synthesized":"Then Barnabas brought him to the apostles and described how Saul had seen the Lord, who spoke to him on the road to Damascus, and how Saul had spoken boldly in that city in the name of Jesus.","sources":{"KJV":{"text":"But Barnabas took him, and brought him to the apostles, and declared unto them how he had seen the Lord in the way, and that he had spoken to him, and how he had preached boldly at Damascus in the name of Jesus."},"BSB":{"text":"Then Barnabas brought him to the apostles and described how Saul had seen the Lord, who spoke to him on the road to Damascus, and how Saul had spoken boldly in that city in the name of Jesus."}},"definableWords":["Lord","name"],"peopleInVerse":["Barnabas","Saul","Jesus"]},"28":{"text":"And he was with them coming in and going out at Jerusalem.","ref":"Acts 9:28","synthesized":"So Saul stayed with them, moving about freely in Jerusalem and speaking boldly in the name of the Lord.","sources":{"KJV":{"text":"And he was with them coming in and going out at Jerusalem."},"BSB":{"text":"So Saul stayed with them, moving about freely in Jerusalem and speaking boldly in the name of the Lord."}},"definableWords":["Jerusalem","name","Lord"],"peopleInVerse":["Saul"]},"29":{"text":"And he spake boldly in the name of the Lord Jesus, and disputed against the Grecians: but they went about to slay him.","ref":"Acts 9:29","synthesized":"He talked and debated with the Grecian Jews, but they tried to kill him.","sources":{"KJV":{"text":"And he spake boldly in the name of the Lord Jesus, and disputed against the Grecians: but they went about to slay him."},"BSB":{"text":"He talked and debated with the Grecian Jews, but they tried to kill him."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"Which when the brethren knew, they brought him down to Caesarea, and sent him forth to Tarsus.","ref":"Acts 9:30","synthesized":"When the brothers learned of this, they took him down to Caesarea and sent him off to Tarsus.","sources":{"KJV":{"text":"Which when the brethren knew, they brought him down to Caesarea, and sent him forth to Tarsus."},"BSB":{"text":"When the brothers learned of this, they took him down to Caesarea and sent him off to Tarsus."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"Then had the churches rest throughout all Judaea and Galilee and Samaria, and were edified; and walking in the fear of the Lord, and in the comfort of the Holy Ghost, were multiplied.","ref":"Acts 9:31","synthesized":"Then the church throughout Judea, Galilee, and Samaria experienced a time of peace. It grew in strength and numbers, living in the fear of the Lord and the encouragement of the Holy Spirit.","sources":{"KJV":{"text":"Then had the churches rest throughout all Judaea and Galilee and Samaria, and were edified; and walking in the fear of the Lord, and in the comfort of the Holy Ghost, were multiplied."},"BSB":{"text":"Then the church throughout Judea, Galilee, and Samaria experienced a time of peace. It grew in strength and numbers, living in the fear of the Lord and the encouragement of the Holy Spirit."}},"definableWords":["church","Judea","Galilee","Samaria","peace","living","fear","Lord","holy","Spirit"],"peopleInVerse":[]},"32":{"text":"And it came to pass, as Peter passed throughout all quarters, he came down also to the saints which dwelt at Lydda.","ref":"Acts 9:32","synthesized":"As Peter traveled throughout the area, he went to visit the saints in Lydda.","sources":{"KJV":{"text":"And it came to pass, as Peter passed throughout all quarters, he came down also to the saints which dwelt at Lydda."},"BSB":{"text":"As Peter traveled throughout the area, he went to visit the saints in Lydda."}},"definableWords":[],"peopleInVerse":["Peter"]},"33":{"text":"And there he found a certain man named Aeneas, which had kept his bed eight years, and was sick of the palsy.","ref":"Acts 9:33","synthesized":"There he found a man named Aeneas, who had been paralyzed and bedridden for eight years.","sources":{"KJV":{"text":"And there he found a certain man named Aeneas, which had kept his bed eight years, and was sick of the palsy."},"BSB":{"text":"There he found a man named Aeneas, who had been paralyzed and bedridden for eight years."}},"definableWords":["man","years"],"peopleInVerse":[]},"34":{"text":"And Peter said unto him, Aeneas, Jesus Christ maketh thee whole: arise, and make thy bed. And he arose immediately.","ref":"Acts 9:34","synthesized":"“Aeneas,” Peter said to him, “Jesus Christ heals you! Get up and put away your mat.” Immediately Aeneas got up,","sources":{"KJV":{"text":"And Peter said unto him, Aeneas, Jesus Christ maketh thee whole: arise, and make thy bed. And he arose immediately."},"BSB":{"text":"“Aeneas,” Peter said to him, “Jesus Christ heals you! Get up and put away your mat.” Immediately Aeneas got up,"}},"definableWords":["Christ"],"peopleInVerse":["Peter","Jesus"]},"35":{"text":"And all that dwelt at Lydda and Saron saw him, and turned to the Lord.","ref":"Acts 9:35","synthesized":"and all who lived in Lydda and Sharon saw him and turned to the Lord.","sources":{"KJV":{"text":"And all that dwelt at Lydda and Saron saw him, and turned to the Lord."},"BSB":{"text":"and all who lived in Lydda and Sharon saw him and turned to the Lord."}},"definableWords":["saw","Lord"],"peopleInVerse":[]},"36":{"text":"Now there was at Joppa a certain disciple named Tabitha, which by interpretation is called Dorcas: this woman was full of good works and almsdeeds which she did.","ref":"Acts 9:36","synthesized":"In Joppa there was a disciple named Tabitha (which is translated as Dorcas), who was always occupied with works of kindness and charity.","sources":{"KJV":{"text":"Now there was at Joppa a certain disciple named Tabitha, which by interpretation is called Dorcas: this woman was full of good works and almsdeeds which she did."},"BSB":{"text":"In Joppa there was a disciple named Tabitha (which is translated as Dorcas), who was always occupied with works of kindness and charity."}},"definableWords":["disciple","works","kindness"],"peopleInVerse":[]},"37":{"text":"And it came to pass in those days, that she was sick, and died: whom when they had washed, they laid her in an upper chamber.","ref":"Acts 9:37","synthesized":"At that time, however, she became sick and died, and her body was washed and placed in an upper room.","sources":{"KJV":{"text":"And it came to pass in those days, that she was sick, and died: whom when they had washed, they laid her in an upper chamber."},"BSB":{"text":"At that time, however, she became sick and died, and her body was washed and placed in an upper room."}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"And forasmuch as Lydda was nigh to Joppa, and the disciples had heard that Peter was there, they sent unto him two men, desiring him that he would not delay to come to them.","ref":"Acts 9:38","synthesized":"Since Lydda was near Joppa, the disciples heard that Peter was there and sent two men to urge him, “Come to us without delay.”","sources":{"KJV":{"text":"And forasmuch as Lydda was nigh to Joppa, and the disciples had heard that Peter was there, they sent unto him two men, desiring him that he would not delay to come to them."},"BSB":{"text":"Since Lydda was near Joppa, the disciples heard that Peter was there and sent two men to urge him, “Come to us without delay.”"}},"definableWords":["men"],"peopleInVerse":["Peter"]},"39":{"text":"Then Peter arose and went with them. When he was come, they brought him into the upper chamber: and all the widows stood by him weeping, and shewing the coats and garments which Dorcas made, while she was with them.","ref":"Acts 9:39","synthesized":"So Peter got up and went with them. On his arrival, they took him to the upper room. All the widows stood around him, weeping and showing him the tunics and other clothing that Dorcas had made while she was still with them.","sources":{"KJV":{"text":"Then Peter arose and went with them. When he was come, they brought him into the upper chamber: and all the widows stood by him weeping, and shewing the coats and garments which Dorcas made, while she was with them."},"BSB":{"text":"So Peter got up and went with them. On his arrival, they took him to the upper room. All the widows stood around him, weeping and showing him the tunics and other clothing that Dorcas had made while she was still with them."}},"definableWords":["made"],"peopleInVerse":["Peter"]},"40":{"text":"But Peter put them all forth, and kneeled down, and prayed; and turning him to the body said, Tabitha, arise. And she opened her eyes: and when she saw Peter, she sat up.","ref":"Acts 9:40","synthesized":"Then Peter sent them all out of the room. He knelt down and prayed, and turning toward her body, he said, “Tabitha, get up!” She opened her eyes, and seeing Peter, she sat up.","sources":{"KJV":{"text":"But Peter put them all forth, and kneeled down, and prayed; and turning him to the body said, Tabitha, arise. And she opened her eyes: and when she saw Peter, she sat up."},"BSB":{"text":"Then Peter sent them all out of the room. He knelt down and prayed, and turning toward her body, he said, “Tabitha, get up!” She opened her eyes, and seeing Peter, she sat up."}},"definableWords":[],"peopleInVerse":["Peter"]},"41":{"text":"And he gave her his hand, and lifted her up, and when he had called the saints and widows, presented her alive.","ref":"Acts 9:41","synthesized":"Peter took her by the hand and helped her up. Then he called the saints and widows and presented her to them alive.","sources":{"KJV":{"text":"And he gave her his hand, and lifted her up, and when he had called the saints and widows, presented her alive."},"BSB":{"text":"Peter took her by the hand and helped her up. Then he called the saints and widows and presented her to them alive."}},"definableWords":[],"peopleInVerse":["Peter"]},"42":{"text":"And it was known throughout all Joppa; and many believed in the Lord.","ref":"Acts 9:42","synthesized":"This became known all over Joppa, and many people believed in the Lord.","sources":{"KJV":{"text":"And it was known throughout all Joppa; and many believed in the Lord."},"BSB":{"text":"This became known all over Joppa, and many people believed in the Lord."}},"definableWords":["people","believed","Lord"],"peopleInVerse":[]},"43":{"text":"And it came to pass, that he tarried many days in Joppa with one Simon a tanner.","ref":"Acts 9:43","synthesized":"And Peter stayed for several days in Joppa with a tanner named Simon.","sources":{"KJV":{"text":"And it came to pass, that he tarried many days in Joppa with one Simon a tanner."},"BSB":{"text":"And Peter stayed for several days in Joppa with a tanner named Simon."}},"definableWords":["days"],"peopleInVerse":["Peter"]}}},"10":{"chapter":"10","title":"CORNELIUS — GENTILES RECEIVE THE SPIRIT","verses":{"1":{"text":"There was a certain man in Caesarea called Cornelius, a centurion of the band called the Italian band,","ref":"Acts 10:1","synthesized":"At Caesarea there was a man named Cornelius, a centurion in what was called the Italian Regiment.","sources":{"KJV":{"text":"There was a certain man in Caesarea called Cornelius, a centurion of the band called the Italian band,"},"BSB":{"text":"At Caesarea there was a man named Cornelius, a centurion in what was called the Italian Regiment."}},"definableWords":["man"],"peopleInVerse":[]},"2":{"text":"A devout man, and one that feared God with all his house, which gave much alms to the people, and prayed to God alway.","ref":"Acts 10:2","synthesized":"He and all his household were devout and God-fearing. He gave generously to the people and prayed to God regularly.","sources":{"KJV":{"text":"A devout man, and one that feared God with all his house, which gave much alms to the people, and prayed to God alway."},"BSB":{"text":"He and all his household were devout and God-fearing. He gave generously to the people and prayed to God regularly."}},"definableWords":["God","people"],"peopleInVerse":[]},"3":{"text":"He saw in a vision evidently about the ninth hour of the day an angel of God coming in to him, and saying unto him, Cornelius.","ref":"Acts 10:3","synthesized":"One day at about the ninth hour, he had a clear vision of an angel of God who came to him and said, “Cornelius!”","sources":{"KJV":{"text":"He saw in a vision evidently about the ninth hour of the day an angel of God coming in to him, and saying unto him, Cornelius."},"BSB":{"text":"One day at about the ninth hour, he had a clear vision of an angel of God who came to him and said, “Cornelius!”"}},"definableWords":["one","day","angel","God"],"peopleInVerse":[]},"4":{"text":"And when he looked on him, he was afraid, and said, What is it, Lord? And he said unto him, Thy prayers and thine alms are come up for a memorial before God.","ref":"Acts 10:4","synthesized":"Cornelius stared at him in fear and asked, “What is it, Lord?”  The angel answered, “Your prayers and gifts to the poor have ascended as a memorial offering before God.","sources":{"KJV":{"text":"And when he looked on him, he was afraid, and said, What is it, Lord? And he said unto him, Thy prayers and thine alms are come up for a memorial before God."},"BSB":{"text":"Cornelius stared at him in fear and asked, “What is it, Lord?”  The angel answered, “Your prayers and gifts to the poor have ascended as a memorial offering before God."}},"definableWords":["fear","Lord","angel","offering","God"],"peopleInVerse":[]},"5":{"text":"And now send men to Joppa, and call for one Simon, whose surname is Peter:","ref":"Acts 10:5","synthesized":"Now send men to Joppa to call for a man named Simon who is called Peter.","sources":{"KJV":{"text":"And now send men to Joppa, and call for one Simon, whose surname is Peter:"},"BSB":{"text":"Now send men to Joppa to call for a man named Simon who is called Peter."}},"definableWords":["men","man"],"peopleInVerse":["Peter"]},"6":{"text":"He lodgeth with one Simon a tanner, whose house is by the sea side: he shall tell thee what thou oughtest to do.","ref":"Acts 10:6","synthesized":"He is staying with Simon the tanner, whose house is by the sea.”","sources":{"KJV":{"text":"He lodgeth with one Simon a tanner, whose house is by the sea side: he shall tell thee what thou oughtest to do."},"BSB":{"text":"He is staying with Simon the tanner, whose house is by the sea.”"}},"definableWords":["house","sea"],"peopleInVerse":[]},"7":{"text":"And when the angel which spake unto Cornelius was departed, he called two of his household servants, and a devout soldier of them that waited on him continually;","ref":"Acts 10:7","synthesized":"When the angel who spoke to him had gone, Cornelius called two of his servants and a devout soldier from among his attendants.","sources":{"KJV":{"text":"And when the angel which spake unto Cornelius was departed, he called two of his household servants, and a devout soldier of them that waited on him continually;"},"BSB":{"text":"When the angel who spoke to him had gone, Cornelius called two of his servants and a devout soldier from among his attendants."}},"definableWords":["angel","servants"],"peopleInVerse":[]},"8":{"text":"And when he had declared all these things unto them, he sent them to Joppa.","ref":"Acts 10:8","synthesized":"He explained what had happened and sent them to Joppa.","sources":{"KJV":{"text":"And when he had declared all these things unto them, he sent them to Joppa."},"BSB":{"text":"He explained what had happened and sent them to Joppa."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"On the morrow, as they went on their journey, and drew nigh unto the city, Peter went up upon the housetop to pray about the sixth hour:","ref":"Acts 10:9","synthesized":"The next day at about the sixth hour, as the men were approaching the city on their journey, Peter went up on the roof to pray.","sources":{"KJV":{"text":"On the morrow, as they went on their journey, and drew nigh unto the city, Peter went up upon the housetop to pray about the sixth hour:"},"BSB":{"text":"The next day at about the sixth hour, as the men were approaching the city on their journey, Peter went up on the roof to pray."}},"definableWords":["day","men"],"peopleInVerse":["Peter"]},"10":{"text":"And he became very hungry, and would have eaten: but while they made ready, he fell into a trance,","ref":"Acts 10:10","synthesized":"He became hungry and wanted something to eat, but while the meal was being prepared, he fell into a trance.","sources":{"KJV":{"text":"And he became very hungry, and would have eaten: but while they made ready, he fell into a trance,"},"BSB":{"text":"He became hungry and wanted something to eat, but while the meal was being prepared, he fell into a trance."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And saw heaven opened, and a certain vessel descending unto him, as it had been a great sheet knit at the four corners, and let down to the earth:","ref":"Acts 10:11","synthesized":"He saw heaven open and something like a large sheet being let down to earth by its four corners.","sources":{"KJV":{"text":"And saw heaven opened, and a certain vessel descending unto him, as it had been a great sheet knit at the four corners, and let down to the earth:"},"BSB":{"text":"He saw heaven open and something like a large sheet being let down to earth by its four corners."}},"definableWords":["saw","heaven","earth"],"peopleInVerse":[]},"12":{"text":"Wherein were all manner of fourfooted beasts of the earth, and wild beasts, and creeping things, and fowls of the air.","ref":"Acts 10:12","synthesized":"It contained all kinds of four-footed animals and reptiles of the earth, as well as birds of the air.","sources":{"KJV":{"text":"Wherein were all manner of fourfooted beasts of the earth, and wild beasts, and creeping things, and fowls of the air."},"BSB":{"text":"It contained all kinds of four-footed animals and reptiles of the earth, as well as birds of the air."}},"definableWords":["earth","birds"],"peopleInVerse":[]},"13":{"text":"And there came a voice to him, Rise, Peter; kill, and eat.","ref":"Acts 10:13","synthesized":"Then a voice said to him: “Get up, Peter, kill and eat!”","sources":{"KJV":{"text":"And there came a voice to him, Rise, Peter; kill, and eat."},"BSB":{"text":"Then a voice said to him: “Get up, Peter, kill and eat!”"}},"definableWords":["voice"],"peopleInVerse":["Peter"]},"14":{"text":"But Peter said, Not so, Lord; for I have never eaten any thing that is common or unclean.","ref":"Acts 10:14","synthesized":"“No, Lord!” Peter answered. “I have never eaten anything impure or unclean.”","sources":{"KJV":{"text":"But Peter said, Not so, Lord; for I have never eaten any thing that is common or unclean."},"BSB":{"text":"“No, Lord!” Peter answered. “I have never eaten anything impure or unclean.”"}},"definableWords":["Lord","or"],"peopleInVerse":["Peter"]},"15":{"text":"And the voice spake unto him again the second time, What God hath cleansed, that call not thou common.","ref":"Acts 10:15","synthesized":"The voice spoke to him a second time: “Do not call anything impure that God has made clean.”","sources":{"KJV":{"text":"And the voice spake unto him again the second time, What God hath cleansed, that call not thou common."},"BSB":{"text":"The voice spoke to him a second time: “Do not call anything impure that God has made clean.”"}},"definableWords":["voice","God","made"],"peopleInVerse":[]},"16":{"text":"This was done thrice: and the vessel was received up again into heaven.","ref":"Acts 10:16","synthesized":"This happened three times, and all at once the sheet was taken back up into heaven.","sources":{"KJV":{"text":"This was done thrice: and the vessel was received up again into heaven."},"BSB":{"text":"This happened three times, and all at once the sheet was taken back up into heaven."}},"definableWords":["heaven"],"peopleInVerse":[]},"17":{"text":"Now while Peter doubted in himself what this vision which he had seen should mean, behold, the men which were sent from Cornelius had made enquiry for Simon’s house, and stood before the gate,","ref":"Acts 10:17","synthesized":"While Peter was puzzling over the meaning of the vision, the men sent by Cornelius found Simon’s house and approached the gate.","sources":{"KJV":{"text":"Now while Peter doubted in himself what this vision which he had seen should mean, behold, the men which were sent from Cornelius had made enquiry for Simon’s house, and stood before the gate,"},"BSB":{"text":"While Peter was puzzling over the meaning of the vision, the men sent by Cornelius found Simon’s house and approached the gate."}},"definableWords":["men","house"],"peopleInVerse":["Peter"]},"18":{"text":"And called, and asked whether Simon, which was surnamed Peter, were lodged there.","ref":"Acts 10:18","synthesized":"They called out to ask if Simon called Peter was staying there.","sources":{"KJV":{"text":"And called, and asked whether Simon, which was surnamed Peter, were lodged there."},"BSB":{"text":"They called out to ask if Simon called Peter was staying there."}},"definableWords":[],"peopleInVerse":["Peter"]},"19":{"text":"While Peter thought on the vision, the Spirit said unto him, Behold, three men seek thee.","ref":"Acts 10:19","synthesized":"As Peter continued to reflect on the vision, the Spirit said to him, “Behold, three men are looking for you.","sources":{"KJV":{"text":"While Peter thought on the vision, the Spirit said unto him, Behold, three men seek thee."},"BSB":{"text":"As Peter continued to reflect on the vision, the Spirit said to him, “Behold, three men are looking for you."}},"definableWords":["Spirit","men"],"peopleInVerse":["Peter"]},"20":{"text":"Arise therefore, and get thee down, and go with them, doubting nothing: for I have sent them.","ref":"Acts 10:20","synthesized":"So get up! Go downstairs and accompany them without hesitation, because I have sent them.”","sources":{"KJV":{"text":"Arise therefore, and get thee down, and go with them, doubting nothing: for I have sent them."},"BSB":{"text":"So get up! Go downstairs and accompany them without hesitation, because I have sent them.”"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Then Peter went down to the men which were sent unto him from Cornelius; and said, Behold, I am he whom ye seek: what is the cause wherefore ye are come?","ref":"Acts 10:21","synthesized":"So Peter went down to the men and said, “Here am I, the one you are looking for. Why have you come?”","sources":{"KJV":{"text":"Then Peter went down to the men which were sent unto him from Cornelius; and said, Behold, I am he whom ye seek: what is the cause wherefore ye are come?"},"BSB":{"text":"So Peter went down to the men and said, “Here am I, the one you are looking for. Why have you come?”"}},"definableWords":["men","one"],"peopleInVerse":["Peter"]},"22":{"text":"And they said, Cornelius the centurion, a just man, and one that feareth God, and of good report among all the nation of the Jews, was warned from God by an holy angel to send for thee into his house, and to hear words of thee.","ref":"Acts 10:22","synthesized":"“Cornelius the centurion has sent us,” they said. “He is a righteous and God-fearing man with a good reputation among the whole Jewish nation. A holy angel instructed him to request your presence in his home so he could hear a message from you.”","sources":{"KJV":{"text":"And they said, Cornelius the centurion, a just man, and one that feareth God, and of good report among all the nation of the Jews, was warned from God by an holy angel to send for thee into his house, and to hear words of thee."},"BSB":{"text":"“Cornelius the centurion has sent us,” they said. “He is a righteous and God-fearing man with a good reputation among the whole Jewish nation. A holy angel instructed him to request your presence in his home so he could hear a message from you.”"}},"definableWords":["righteous","God","man","good","nation","holy","angel","hear"],"peopleInVerse":[]},"23":{"text":"Then called he them in, and lodged them. And on the morrow Peter went away with them, and certain brethren from Joppa accompanied him.","ref":"Acts 10:23","synthesized":"So Peter invited them in as his guests. And the next day he got ready and went with them, accompanied by some of the brothers from Joppa.","sources":{"KJV":{"text":"Then called he them in, and lodged them. And on the morrow Peter went away with them, and certain brethren from Joppa accompanied him."},"BSB":{"text":"So Peter invited them in as his guests. And the next day he got ready and went with them, accompanied by some of the brothers from Joppa."}},"definableWords":["day"],"peopleInVerse":["Peter"]},"24":{"text":"And the morrow after they entered into Caesarea. And Cornelius waited for them, and had called together his kinsmen and near friends.","ref":"Acts 10:24","synthesized":"The following day he arrived in Caesarea, where Cornelius was expecting them and had called together his relatives and close friends.","sources":{"KJV":{"text":"And the morrow after they entered into Caesarea. And Cornelius waited for them, and had called together his kinsmen and near friends."},"BSB":{"text":"The following day he arrived in Caesarea, where Cornelius was expecting them and had called together his relatives and close friends."}},"definableWords":["day"],"peopleInVerse":[]},"25":{"text":"And as Peter was coming in, Cornelius met him, and fell down at his feet, and worshipped him.","ref":"Acts 10:25","synthesized":"As Peter was about to enter, Cornelius met him and fell at his feet to worship him.","sources":{"KJV":{"text":"And as Peter was coming in, Cornelius met him, and fell down at his feet, and worshipped him."},"BSB":{"text":"As Peter was about to enter, Cornelius met him and fell at his feet to worship him."}},"definableWords":["worship"],"peopleInVerse":["Peter"]},"26":{"text":"But Peter took him up, saying, Stand up; I myself also am a man.","ref":"Acts 10:26","synthesized":"But Peter helped him up. “Stand up,” he said, “I am only a man myself.”","sources":{"KJV":{"text":"But Peter took him up, saying, Stand up; I myself also am a man."},"BSB":{"text":"But Peter helped him up. “Stand up,” he said, “I am only a man myself.”"}},"definableWords":["stand","man"],"peopleInVerse":["Peter"]},"27":{"text":"And as he talked with him, he went in, and found many that were come together.","ref":"Acts 10:27","synthesized":"As Peter talked with him, he went inside and found many people gathered together.","sources":{"KJV":{"text":"And as he talked with him, he went in, and found many that were come together."},"BSB":{"text":"As Peter talked with him, he went inside and found many people gathered together."}},"definableWords":["people"],"peopleInVerse":["Peter"]},"28":{"text":"And he said unto them, Ye know how that it is an unlawful thing for a man that is a Jew to keep company, or come unto one of another nation; but God hath shewed me that I should not call any man common or unclean.","ref":"Acts 10:28","synthesized":"He said to them, “You know how unlawful it is for a Jew to associate with a foreigner or visit him. But God has shown me that I should not call any man impure or unclean.","sources":{"KJV":{"text":"And he said unto them, Ye know how that it is an unlawful thing for a man that is a Jew to keep company, or come unto one of another nation; but God hath shewed me that I should not call any man common or unclean."},"BSB":{"text":"He said to them, “You know how unlawful it is for a Jew to associate with a foreigner or visit him. But God has shown me that I should not call any man impure or unclean."}},"definableWords":["Jew","or","God","man"],"peopleInVerse":[]},"29":{"text":"Therefore came I unto you without gainsaying, as soon as I was sent for: I ask therefore for what intent ye have sent for me?","ref":"Acts 10:29","synthesized":"So when I was invited, I came without objection. I ask, then, why have you sent for me?”","sources":{"KJV":{"text":"Therefore came I unto you without gainsaying, as soon as I was sent for: I ask therefore for what intent ye have sent for me?"},"BSB":{"text":"So when I was invited, I came without objection. I ask, then, why have you sent for me?”"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"And Cornelius said, Four days ago I was fasting until this hour; and at the ninth hour I prayed in my house, and, behold, a man stood before me in bright clothing,","ref":"Acts 10:30","synthesized":"Cornelius answered: “Four days ago I was in my house praying at this, the ninth hour. Suddenly a man in radiant clothing stood before me","sources":{"KJV":{"text":"And Cornelius said, Four days ago I was fasting until this hour; and at the ninth hour I prayed in my house, and, behold, a man stood before me in bright clothing,"},"BSB":{"text":"Cornelius answered: “Four days ago I was in my house praying at this, the ninth hour. Suddenly a man in radiant clothing stood before me"}},"definableWords":["days","house","man"],"peopleInVerse":[]},"31":{"text":"And said, Cornelius, thy prayer is heard, and thine alms are had in remembrance in the sight of God.","ref":"Acts 10:31","synthesized":"and said, ‘Cornelius, your prayer has been heard, and your gifts to the poor have been remembered before God.","sources":{"KJV":{"text":"And said, Cornelius, thy prayer is heard, and thine alms are had in remembrance in the sight of God."},"BSB":{"text":"and said, ‘Cornelius, your prayer has been heard, and your gifts to the poor have been remembered before God."}},"definableWords":["prayer","remembered","God"],"peopleInVerse":[]},"32":{"text":"Send therefore to Joppa, and call hither Simon, whose surname is Peter; he is lodged in the house of one Simon a tanner by the sea side: who, when he cometh, shall speak unto thee.","ref":"Acts 10:32","synthesized":"Therefore send to Joppa for Simon, who is called Peter. He is a guest in the home of Simon the tanner, by the sea.’","sources":{"KJV":{"text":"Send therefore to Joppa, and call hither Simon, whose surname is Peter; he is lodged in the house of one Simon a tanner by the sea side: who, when he cometh, shall speak unto thee."},"BSB":{"text":"Therefore send to Joppa for Simon, who is called Peter. He is a guest in the home of Simon the tanner, by the sea.’"}},"definableWords":["sea"],"peopleInVerse":["Peter"]},"33":{"text":"Immediately therefore I sent to thee; and thou hast well done that thou art come. Now therefore are we all here present before God, to hear all things that are commanded thee of God.","ref":"Acts 10:33","synthesized":"So I sent for you immediately, and you were kind enough to come. Now then, we are all here in the presence of God to listen to everything the Lord has instructed you to tell us.”","sources":{"KJV":{"text":"Immediately therefore I sent to thee; and thou hast well done that thou art come. Now therefore are we all here present before God, to hear all things that are commanded thee of God."},"BSB":{"text":"So I sent for you immediately, and you were kind enough to come. Now then, we are all here in the presence of God to listen to everything the Lord has instructed you to tell us.”"}},"definableWords":["God","Lord"],"peopleInVerse":[]},"34":{"text":"Then Peter opened his mouth, and said, Of a truth I perceive that God is no respecter of persons:","ref":"Acts 10:34","synthesized":"Then Peter began to speak: “I now truly understand that God does not show favoritism,","sources":{"KJV":{"text":"Then Peter opened his mouth, and said, Of a truth I perceive that God is no respecter of persons:"},"BSB":{"text":"Then Peter began to speak: “I now truly understand that God does not show favoritism,"}},"definableWords":["God"],"peopleInVerse":["Peter"]},"35":{"text":"But in every nation he that feareth him, and worketh righteousness, is accepted with him.","ref":"Acts 10:35","synthesized":"but welcomes those from every nation who fear Him and do what is right.","sources":{"KJV":{"text":"But in every nation he that feareth him, and worketh righteousness, is accepted with him."},"BSB":{"text":"but welcomes those from every nation who fear Him and do what is right."}},"definableWords":["nation","fear"],"peopleInVerse":[]},"36":{"text":"The word which God sent unto the children of Israel, preaching peace by Jesus Christ: (he is Lord of all:)","ref":"Acts 10:36","synthesized":"He has sent this message to the people of Israel, proclaiming the gospel of peace through Jesus Christ, who is Lord of all.","sources":{"KJV":{"text":"The word which God sent unto the children of Israel, preaching peace by Jesus Christ: (he is Lord of all:)"},"BSB":{"text":"He has sent this message to the people of Israel, proclaiming the gospel of peace through Jesus Christ, who is Lord of all."}},"definableWords":["people","Israel","gospel","peace","Christ","Lord"],"peopleInVerse":["Jesus"]},"37":{"text":"That word, I say, ye know, which was published throughout all Judaea, and began from Galilee, after the baptism which John preached;","ref":"Acts 10:37","synthesized":"You yourselves know what has happened throughout Judea, beginning in Galilee with the baptism that John proclaimed:","sources":{"KJV":{"text":"That word, I say, ye know, which was published throughout all Judaea, and began from Galilee, after the baptism which John preached;"},"BSB":{"text":"You yourselves know what has happened throughout Judea, beginning in Galilee with the baptism that John proclaimed:"}},"definableWords":["Judea","beginning","Galilee","baptism"],"peopleInVerse":["John"]},"38":{"text":"How God anointed Jesus of Nazareth with the Holy Ghost and with power: who went about doing good, and healing all that were oppressed of the devil; for God was with him.","ref":"Acts 10:38","synthesized":"how God anointed Jesus of Nazareth with the Holy Spirit and with power, and how Jesus went around doing good and healing all who were oppressed by the devil, because God was with Him.","sources":{"KJV":{"text":"How God anointed Jesus of Nazareth with the Holy Ghost and with power: who went about doing good, and healing all that were oppressed of the devil; for God was with him."},"BSB":{"text":"how God anointed Jesus of Nazareth with the Holy Spirit and with power, and how Jesus went around doing good and healing all who were oppressed by the devil, because God was with Him."}},"definableWords":["God","holy","Spirit","good","devil"],"peopleInVerse":["Jesus"]},"39":{"text":"And we are witnesses of all things which he did both in the land of the Jews, and in Jerusalem; whom they slew and hanged on a tree:","ref":"Acts 10:39","synthesized":"We are witnesses of all that He did, both in the land of the Jews and in Jerusalem. And although they put Him to death by hanging Him on a tree,","sources":{"KJV":{"text":"And we are witnesses of all things which he did both in the land of the Jews, and in Jerusalem; whom they slew and hanged on a tree:"},"BSB":{"text":"We are witnesses of all that He did, both in the land of the Jews and in Jerusalem. And although they put Him to death by hanging Him on a tree,"}},"definableWords":["land","Jerusalem","death","tree"],"peopleInVerse":[]},"40":{"text":"Him God raised up the third day, and shewed him openly;","ref":"Acts 10:40","synthesized":"God raised Him up on the third day and caused Him to be seen—","sources":{"KJV":{"text":"Him God raised up the third day, and shewed him openly;"},"BSB":{"text":"God raised Him up on the third day and caused Him to be seen—"}},"definableWords":["God","day"],"peopleInVerse":[]},"41":{"text":"Not to all the people, but unto witnesses chosen before of God, even to us, who did eat and drink with him after he rose from the dead.","ref":"Acts 10:41","synthesized":"not by all the people, but by the witnesses God had chosen beforehand, by us who ate and drank with Him after He rose from the dead.","sources":{"KJV":{"text":"Not to all the people, but unto witnesses chosen before of God, even to us, who did eat and drink with him after he rose from the dead."},"BSB":{"text":"not by all the people, but by the witnesses God had chosen beforehand, by us who ate and drank with Him after He rose from the dead."}},"definableWords":["people","God"],"peopleInVerse":[]},"42":{"text":"And he commanded us to preach unto the people, and to testify that it is he which was ordained of God to be the Judge of quick and dead.","ref":"Acts 10:42","synthesized":"And He commanded us to preach to the people and to testify that He is the One appointed by God to judge the living and the dead.","sources":{"KJV":{"text":"And he commanded us to preach unto the people, and to testify that it is he which was ordained of God to be the Judge of quick and dead."},"BSB":{"text":"And He commanded us to preach to the people and to testify that He is the One appointed by God to judge the living and the dead."}},"definableWords":["people","one","God","living"],"peopleInVerse":[]},"43":{"text":"To him give all the prophets witness, that through his name whosoever believeth in him shall receive remission of sins.","ref":"Acts 10:43","synthesized":"All the prophets testify about Him that everyone who believes in Him receives forgiveness of sins through His name.”","sources":{"KJV":{"text":"To him give all the prophets witness, that through his name whosoever believeth in him shall receive remission of sins."},"BSB":{"text":"All the prophets testify about Him that everyone who believes in Him receives forgiveness of sins through His name.”"}},"definableWords":["name"],"peopleInVerse":[]},"44":{"text":"While Peter yet spake these words, the Holy Ghost fell on all them which heard the word.","ref":"Acts 10:44","synthesized":"While Peter was still speaking these words, the Holy Spirit fell upon all who heard his message.","sources":{"KJV":{"text":"While Peter yet spake these words, the Holy Ghost fell on all them which heard the word."},"BSB":{"text":"While Peter was still speaking these words, the Holy Spirit fell upon all who heard his message."}},"definableWords":["holy","Spirit"],"peopleInVerse":["Peter"]},"45":{"text":"And they of the circumcision which believed were astonished, as many as came with Peter, because that on the Gentiles also was poured out the gift of the Holy Ghost.","ref":"Acts 10:45","synthesized":"All the circumcised believers who had accompanied Peter were astounded that the gift of the Holy Spirit had been poured out even on the Gentiles.","sources":{"KJV":{"text":"And they of the circumcision which believed were astonished, as many as came with Peter, because that on the Gentiles also was poured out the gift of the Holy Ghost."},"BSB":{"text":"All the circumcised believers who had accompanied Peter were astounded that the gift of the Holy Spirit had been poured out even on the Gentiles."}},"definableWords":["circumcised","holy","Spirit"],"peopleInVerse":["Peter"]},"46":{"text":"For they heard them speak with tongues, and magnify God. Then answered Peter,","ref":"Acts 10:46","synthesized":"For they heard them speaking in tongues and exalting God.  Then Peter said,","sources":{"KJV":{"text":"For they heard them speak with tongues, and magnify God. Then answered Peter,"},"BSB":{"text":"For they heard them speaking in tongues and exalting God.  Then Peter said,"}},"definableWords":["God"],"peopleInVerse":["Peter"]},"47":{"text":"Can any man forbid water, that these should not be baptized, which have received the Holy Ghost as well as we?","ref":"Acts 10:47","synthesized":"“Can anyone withhold the water to baptize these people? They have received the Holy Spirit just as we have!”","sources":{"KJV":{"text":"Can any man forbid water, that these should not be baptized, which have received the Holy Ghost as well as we?"},"BSB":{"text":"“Can anyone withhold the water to baptize these people? They have received the Holy Spirit just as we have!”"}},"definableWords":["water","people","holy","Spirit"],"peopleInVerse":[]},"48":{"text":"And he commanded them to be baptized in the name of the Lord. Then prayed they him to tarry certain days.","ref":"Acts 10:48","synthesized":"So he ordered that they be baptized in the name of Jesus Christ. Then they asked him to stay for a few days.","sources":{"KJV":{"text":"And he commanded them to be baptized in the name of the Lord. Then prayed they him to tarry certain days."},"BSB":{"text":"So he ordered that they be baptized in the name of Jesus Christ. Then they asked him to stay for a few days."}},"definableWords":["name","Christ","days"],"peopleInVerse":["Jesus"]}}},"11":{"chapter":"11","title":"THE CHURCH AT ANTIOCH","verses":{"1":{"text":"And the apostles and brethren that were in Judaea heard that the Gentiles had also received the word of God.","ref":"Acts 11:1","synthesized":"The apostles and brothers throughout Judea soon heard that the Gentiles also had received the word of God.","sources":{"KJV":{"text":"And the apostles and brethren that were in Judaea heard that the Gentiles had also received the word of God."},"BSB":{"text":"The apostles and brothers throughout Judea soon heard that the Gentiles also had received the word of God."}},"definableWords":["Judea","word","God"],"peopleInVerse":[]},"2":{"text":"And when Peter was come up to Jerusalem, they that were of the circumcision contended with him,","ref":"Acts 11:2","synthesized":"So when Peter went up to Jerusalem, the circumcised believers took issue with him","sources":{"KJV":{"text":"And when Peter was come up to Jerusalem, they that were of the circumcision contended with him,"},"BSB":{"text":"So when Peter went up to Jerusalem, the circumcised believers took issue with him"}},"definableWords":["Jerusalem","circumcised"],"peopleInVerse":["Peter"]},"3":{"text":"Saying, Thou wentest in to men uncircumcised, and didst eat with them.","ref":"Acts 11:3","synthesized":"and said, “You visited uncircumcised men and ate with them.”","sources":{"KJV":{"text":"Saying, Thou wentest in to men uncircumcised, and didst eat with them."},"BSB":{"text":"and said, “You visited uncircumcised men and ate with them.”"}},"definableWords":["men"],"peopleInVerse":[]},"4":{"text":"But Peter rehearsed the matter from the beginning, and expounded it by order unto them, saying,","ref":"Acts 11:4","synthesized":"But Peter began and explained to them the whole sequence of events:","sources":{"KJV":{"text":"But Peter rehearsed the matter from the beginning, and expounded it by order unto them, saying,"},"BSB":{"text":"But Peter began and explained to them the whole sequence of events:"}},"definableWords":[],"peopleInVerse":["Peter"]},"5":{"text":"I was in the city of Joppa praying: and in a trance I saw a vision, A certain vessel descend, as it had been a great sheet, let down from heaven by four corners; and it came even to me:","ref":"Acts 11:5","synthesized":"“I was in the city of Joppa praying, and in a trance I saw a vision of something like a large sheet being let down from heaven by its four corners, and it came right down to me.","sources":{"KJV":{"text":"I was in the city of Joppa praying: and in a trance I saw a vision, A certain vessel descend, as it had been a great sheet, let down from heaven by four corners; and it came even to me:"},"BSB":{"text":"“I was in the city of Joppa praying, and in a trance I saw a vision of something like a large sheet being let down from heaven by its four corners, and it came right down to me."}},"definableWords":["saw","heaven"],"peopleInVerse":[]},"6":{"text":"Upon the which when I had fastened mine eyes, I considered, and saw fourfooted beasts of the earth, and wild beasts, and creeping things, and fowls of the air.","ref":"Acts 11:6","synthesized":"I looked at it closely and saw four-footed animals of the earth, wild beasts, reptiles, and birds of the air.","sources":{"KJV":{"text":"Upon the which when I had fastened mine eyes, I considered, and saw fourfooted beasts of the earth, and wild beasts, and creeping things, and fowls of the air."},"BSB":{"text":"I looked at it closely and saw four-footed animals of the earth, wild beasts, reptiles, and birds of the air."}},"definableWords":["saw","earth","birds"],"peopleInVerse":[]},"7":{"text":"And I heard a voice saying unto me, Arise, Peter; slay and eat.","ref":"Acts 11:7","synthesized":"Then I heard a voice saying to me, ‘Get up, Peter, kill and eat.’","sources":{"KJV":{"text":"And I heard a voice saying unto me, Arise, Peter; slay and eat."},"BSB":{"text":"Then I heard a voice saying to me, ‘Get up, Peter, kill and eat.’"}},"definableWords":["voice"],"peopleInVerse":["Peter"]},"8":{"text":"But I said, Not so, Lord: for nothing common or unclean hath at any time entered into my mouth.","ref":"Acts 11:8","synthesized":"‘No, Lord,’ I said, ‘for nothing impure or unclean has ever entered my mouth.’","sources":{"KJV":{"text":"But I said, Not so, Lord: for nothing common or unclean hath at any time entered into my mouth."},"BSB":{"text":"‘No, Lord,’ I said, ‘for nothing impure or unclean has ever entered my mouth.’"}},"definableWords":["Lord","or"],"peopleInVerse":[]},"9":{"text":"But the voice answered me again from heaven, What God hath cleansed, that call not thou common.","ref":"Acts 11:9","synthesized":"But the voice spoke from heaven a second time, ‘Do not call anything impure that God has made clean.’","sources":{"KJV":{"text":"But the voice answered me again from heaven, What God hath cleansed, that call not thou common."},"BSB":{"text":"But the voice spoke from heaven a second time, ‘Do not call anything impure that God has made clean.’"}},"definableWords":["voice","heaven","God","made"],"peopleInVerse":[]},"10":{"text":"And this was done three times: and all were drawn up again into heaven.","ref":"Acts 11:10","synthesized":"This happened three times, and everything was drawn back up into heaven.","sources":{"KJV":{"text":"And this was done three times: and all were drawn up again into heaven."},"BSB":{"text":"This happened three times, and everything was drawn back up into heaven."}},"definableWords":["heaven"],"peopleInVerse":[]},"11":{"text":"And, behold, immediately there were three men already come unto the house where I was, sent from Caesarea unto me.","ref":"Acts 11:11","synthesized":"Just then three men sent to me from Caesarea stopped at the house where I was staying.","sources":{"KJV":{"text":"And, behold, immediately there were three men already come unto the house where I was, sent from Caesarea unto me."},"BSB":{"text":"Just then three men sent to me from Caesarea stopped at the house where I was staying."}},"definableWords":["men","house"],"peopleInVerse":[]},"12":{"text":"And the Spirit bade me go with them, nothing doubting. Moreover these six brethren accompanied me, and we entered into the man’s house:","ref":"Acts 11:12","synthesized":"The Spirit told me to accompany them without hesitation. These six brothers also went with me, and we entered the man’s home.","sources":{"KJV":{"text":"And the Spirit bade me go with them, nothing doubting. Moreover these six brethren accompanied me, and we entered into the man’s house:"},"BSB":{"text":"The Spirit told me to accompany them without hesitation. These six brothers also went with me, and we entered the man’s home."}},"definableWords":["Spirit","man"],"peopleInVerse":[]},"13":{"text":"And he shewed us how he had seen an angel in his house, which stood and said unto him, Send men to Joppa, and call for Simon, whose surname is Peter;","ref":"Acts 11:13","synthesized":"He told us how he had seen an angel standing in his house and saying, ‘Send to Joppa for Simon who is called Peter.","sources":{"KJV":{"text":"And he shewed us how he had seen an angel in his house, which stood and said unto him, Send men to Joppa, and call for Simon, whose surname is Peter;"},"BSB":{"text":"He told us how he had seen an angel standing in his house and saying, ‘Send to Joppa for Simon who is called Peter."}},"definableWords":["angel","house"],"peopleInVerse":["Peter"]},"14":{"text":"Who shall tell thee words, whereby thou and all thy house shall be saved.","ref":"Acts 11:14","synthesized":"He will convey to you a message by which you and all your household will be saved.’","sources":{"KJV":{"text":"Who shall tell thee words, whereby thou and all thy house shall be saved."},"BSB":{"text":"He will convey to you a message by which you and all your household will be saved.’"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And as I began to speak, the Holy Ghost fell on them, as on us at the beginning.","ref":"Acts 11:15","synthesized":"As I began to speak, the Holy Spirit fell upon them, just as He had fallen upon us at the beginning.","sources":{"KJV":{"text":"And as I began to speak, the Holy Ghost fell on them, as on us at the beginning."},"BSB":{"text":"As I began to speak, the Holy Spirit fell upon them, just as He had fallen upon us at the beginning."}},"definableWords":["holy","Spirit","beginning"],"peopleInVerse":[]},"16":{"text":"Then remembered I the word of the Lord, how that he said, John indeed baptized with water; but ye shall be baptized with the Holy Ghost.","ref":"Acts 11:16","synthesized":"Then I remembered the word of the Lord, as He used to say, ‘John baptized with water, but you will be baptized with the Holy Spirit.’","sources":{"KJV":{"text":"Then remembered I the word of the Lord, how that he said, John indeed baptized with water; but ye shall be baptized with the Holy Ghost."},"BSB":{"text":"Then I remembered the word of the Lord, as He used to say, ‘John baptized with water, but you will be baptized with the Holy Spirit.’"}},"definableWords":["remembered","word","Lord","water","holy","Spirit"],"peopleInVerse":["John"]},"17":{"text":"Forasmuch then as God gave them the like gift as he did unto us, who believed on the Lord Jesus Christ; what was I, that I could withstand God?","ref":"Acts 11:17","synthesized":"So if God gave them the same gift He gave us who believed in the Lord Jesus Christ, who was I to hinder the work of God?”","sources":{"KJV":{"text":"Forasmuch then as God gave them the like gift as he did unto us, who believed on the Lord Jesus Christ; what was I, that I could withstand God?"},"BSB":{"text":"So if God gave them the same gift He gave us who believed in the Lord Jesus Christ, who was I to hinder the work of God?”"}},"definableWords":["God","believed","Lord","Christ","work"],"peopleInVerse":["Jesus"]},"18":{"text":"When they heard these things, they held their peace, and glorified God, saying, Then hath God also to the Gentiles granted repentance unto life.","ref":"Acts 11:18","synthesized":"When they heard this, their objections were put to rest, and they glorified God, saying, “So then, God has granted even the Gentiles repentance unto life.”","sources":{"KJV":{"text":"When they heard these things, they held their peace, and glorified God, saying, Then hath God also to the Gentiles granted repentance unto life."},"BSB":{"text":"When they heard this, their objections were put to rest, and they glorified God, saying, “So then, God has granted even the Gentiles repentance unto life.”"}},"definableWords":["rest","God","repentance","life"],"peopleInVerse":[]},"19":{"text":"Now they which were scattered abroad upon the persecution that arose about Stephen travelled as far as Phenice, and Cyprus, and Antioch, preaching the word to none but unto the Jews only.","ref":"Acts 11:19","synthesized":"Meanwhile those scattered by the persecution that began with Stephen traveled as far as Phoenicia, Cyprus, and Antioch, speaking the message only to Jews.","sources":{"KJV":{"text":"Now they which were scattered abroad upon the persecution that arose about Stephen travelled as far as Phenice, and Cyprus, and Antioch, preaching the word to none but unto the Jews only."},"BSB":{"text":"Meanwhile those scattered by the persecution that began with Stephen traveled as far as Phoenicia, Cyprus, and Antioch, speaking the message only to Jews."}},"definableWords":[],"peopleInVerse":["Stephen"]},"20":{"text":"And some of them were men of Cyprus and Cyrene, which, when they were come to Antioch, spake unto the Grecians, preaching the LORD Jesus.","ref":"Acts 11:20","synthesized":"But some of them, men from Cyprus and Cyrene, went to Antioch and began speaking to the Greeks as well, proclaiming the good news about the Lord Jesus.","sources":{"KJV":{"text":"And some of them were men of Cyprus and Cyrene, which, when they were come to Antioch, spake unto the Grecians, preaching the LORD Jesus."},"BSB":{"text":"But some of them, men from Cyprus and Cyrene, went to Antioch and began speaking to the Greeks as well, proclaiming the good news about the Lord Jesus."}},"definableWords":["men","good","Lord"],"peopleInVerse":["Jesus"]},"21":{"text":"And the hand of the Lord was with them: and a great number believed, and turned unto the Lord.","ref":"Acts 11:21","synthesized":"The hand of the Lord was with them, and a great number of people believed and turned to the Lord.","sources":{"KJV":{"text":"And the hand of the Lord was with them: and a great number believed, and turned unto the Lord."},"BSB":{"text":"The hand of the Lord was with them, and a great number of people believed and turned to the Lord."}},"definableWords":["Lord","great","people","believed"],"peopleInVerse":[]},"22":{"text":"Then tidings of these things came unto the ears of the church which was in Jerusalem: and they sent forth Barnabas, that he should go as far as Antioch.","ref":"Acts 11:22","synthesized":"When news of this reached the ears of the church in Jerusalem, they sent Barnabas to Antioch.","sources":{"KJV":{"text":"Then tidings of these things came unto the ears of the church which was in Jerusalem: and they sent forth Barnabas, that he should go as far as Antioch."},"BSB":{"text":"When news of this reached the ears of the church in Jerusalem, they sent Barnabas to Antioch."}},"definableWords":["church","Jerusalem"],"peopleInVerse":["Barnabas"]},"23":{"text":"Who, when he came, and had seen the grace of God, was glad, and exhorted them all, that with purpose of heart they would cleave unto the Lord.","ref":"Acts 11:23","synthesized":"When he arrived and saw the grace of God, he rejoiced and encouraged them all to abide in the Lord with all their hearts.","sources":{"KJV":{"text":"Who, when he came, and had seen the grace of God, was glad, and exhorted them all, that with purpose of heart they would cleave unto the Lord."},"BSB":{"text":"When he arrived and saw the grace of God, he rejoiced and encouraged them all to abide in the Lord with all their hearts."}},"definableWords":["saw","grace","God","abide","Lord"],"peopleInVerse":[]},"24":{"text":"For he was a good man, and full of the Holy Ghost and of faith: and much people was added unto the Lord.","ref":"Acts 11:24","synthesized":"Barnabas was a good man, full of the Holy Spirit and faith, and a great number of people were brought to the Lord.","sources":{"KJV":{"text":"For he was a good man, and full of the Holy Ghost and of faith: and much people was added unto the Lord."},"BSB":{"text":"Barnabas was a good man, full of the Holy Spirit and faith, and a great number of people were brought to the Lord."}},"definableWords":["good","man","holy","Spirit","faith","great","people","Lord"],"peopleInVerse":["Barnabas"]},"25":{"text":"Then departed Barnabas to Tarsus, for to seek Saul:","ref":"Acts 11:25","synthesized":"Then Barnabas went to Tarsus to look for Saul,","sources":{"KJV":{"text":"Then departed Barnabas to Tarsus, for to seek Saul:"},"BSB":{"text":"Then Barnabas went to Tarsus to look for Saul,"}},"definableWords":[],"peopleInVerse":["Barnabas","Saul"]},"26":{"text":"And when he had found him, he brought him unto Antioch. And it came to pass, that a whole year they assembled themselves with the church, and taught much people. And the disciples were called Christians first in Antioch.","ref":"Acts 11:26","synthesized":"and when he found him, he brought him back to Antioch. So for a full year they met together with the church and taught large numbers of people. The disciples were first called Christians at Antioch.","sources":{"KJV":{"text":"And when he had found him, he brought him unto Antioch. And it came to pass, that a whole year they assembled themselves with the church, and taught much people. And the disciples were called Christians first in Antioch."},"BSB":{"text":"and when he found him, he brought him back to Antioch. So for a full year they met together with the church and taught large numbers of people. The disciples were first called Christians at Antioch."}},"definableWords":["year","church","people"],"peopleInVerse":[]},"27":{"text":"And in these days came prophets from Jerusalem unto Antioch.","ref":"Acts 11:27","synthesized":"In those days some prophets came down from Jerusalem to Antioch.","sources":{"KJV":{"text":"And in these days came prophets from Jerusalem unto Antioch."},"BSB":{"text":"In those days some prophets came down from Jerusalem to Antioch."}},"definableWords":["days","Jerusalem"],"peopleInVerse":[]},"28":{"text":"And there stood up one of them named Agabus, and signified by the Spirit that there should be great dearth throughout all the world: which came to pass in the days of Claudius Caesar.","ref":"Acts 11:28","synthesized":"One of them named Agabus stood up and predicted through the Spirit that a great famine would sweep across the whole world. (This happened under Claudius.)","sources":{"KJV":{"text":"And there stood up one of them named Agabus, and signified by the Spirit that there should be great dearth throughout all the world: which came to pass in the days of Claudius Caesar."},"BSB":{"text":"One of them named Agabus stood up and predicted through the Spirit that a great famine would sweep across the whole world. (This happened under Claudius.)"}},"definableWords":["one","Spirit","great"],"peopleInVerse":[]},"29":{"text":"Then the disciples, every man according to his ability, determined to send relief unto the brethren which dwelt in Judaea:","ref":"Acts 11:29","synthesized":"So the disciples, each according to his ability, decided to send relief to the brothers living in Judea.","sources":{"KJV":{"text":"Then the disciples, every man according to his ability, determined to send relief unto the brethren which dwelt in Judaea:"},"BSB":{"text":"So the disciples, each according to his ability, decided to send relief to the brothers living in Judea."}},"definableWords":["living","Judea"],"peopleInVerse":[]},"30":{"text":"Which also they did, and sent it to the elders by the hands of Barnabas and Saul.","ref":"Acts 11:30","synthesized":"This they did, sending their gifts to the elders with Barnabas and Saul.","sources":{"KJV":{"text":"Which also they did, and sent it to the elders by the hands of Barnabas and Saul."},"BSB":{"text":"This they did, sending their gifts to the elders with Barnabas and Saul."}},"definableWords":[],"peopleInVerse":["Barnabas","Saul"]}}},"12":{"chapter":"12","title":"PETER'S MIRACULOUS ESCAPE — HEROD'S DEATH","verses":{"1":{"text":"Now about that time Herod the king stretched forth his hands to vex certain of the church.","ref":"Acts 12:1","synthesized":"About that time, King Herod reached out to harm some who belonged to the church.","sources":{"KJV":{"text":"Now about that time Herod the king stretched forth his hands to vex certain of the church."},"BSB":{"text":"About that time, King Herod reached out to harm some who belonged to the church."}},"definableWords":["King","church"],"peopleInVerse":["Herod"]},"2":{"text":"And he killed James the brother of John with the sword.","ref":"Acts 12:2","synthesized":"He had James, the brother of John, put to death with the sword.","sources":{"KJV":{"text":"And he killed James the brother of John with the sword."},"BSB":{"text":"He had James, the brother of John, put to death with the sword."}},"definableWords":["brother","death"],"peopleInVerse":["James","John"]},"3":{"text":"And because he saw it pleased the Jews, he proceeded further to take Peter also. (Then were the days of unleavened bread.)","ref":"Acts 12:3","synthesized":"And seeing that this pleased the Jews, Herod proceeded to seize Peter during the Feast of Unleavened Bread.","sources":{"KJV":{"text":"And because he saw it pleased the Jews, he proceeded further to take Peter also. (Then were the days of unleavened bread.)"},"BSB":{"text":"And seeing that this pleased the Jews, Herod proceeded to seize Peter during the Feast of Unleavened Bread."}},"definableWords":[],"peopleInVerse":["Herod","Peter"]},"4":{"text":"And when he had apprehended him, he put him in prison, and delivered him to four quaternions of soldiers to keep him; intending after Easter to bring him forth to the people.","ref":"Acts 12:4","synthesized":"He arrested him and put him in prison, handing him over to be guarded by four squads of four soldiers each. Herod intended to bring him out to the people after the Passover.","sources":{"KJV":{"text":"And when he had apprehended him, he put him in prison, and delivered him to four quaternions of soldiers to keep him; intending after Easter to bring him forth to the people."},"BSB":{"text":"He arrested him and put him in prison, handing him over to be guarded by four squads of four soldiers each. Herod intended to bring him out to the people after the Passover."}},"definableWords":["people","Passover"],"peopleInVerse":["Herod"]},"5":{"text":"Peter therefore was kept in prison: but prayer was made without ceasing of the church unto God for him.","ref":"Acts 12:5","synthesized":"So Peter was kept in prison, but the church was fervently praying to God for him.","sources":{"KJV":{"text":"Peter therefore was kept in prison: but prayer was made without ceasing of the church unto God for him."},"BSB":{"text":"So Peter was kept in prison, but the church was fervently praying to God for him."}},"definableWords":["church","God"],"peopleInVerse":["Peter"]},"6":{"text":"And when Herod would have brought him forth, the same night Peter was sleeping between two soldiers, bound with two chains: and the keepers before the door kept the prison.","ref":"Acts 12:6","synthesized":"On the night before Herod was to bring him to trial, Peter was sleeping between two soldiers, bound with two chains, with sentries standing guard at the entrance to the prison.","sources":{"KJV":{"text":"And when Herod would have brought him forth, the same night Peter was sleeping between two soldiers, bound with two chains: and the keepers before the door kept the prison."},"BSB":{"text":"On the night before Herod was to bring him to trial, Peter was sleeping between two soldiers, bound with two chains, with sentries standing guard at the entrance to the prison."}},"definableWords":["night"],"peopleInVerse":["Herod","Peter"]},"7":{"text":"And, behold, the angel of the Lord came upon him, and a light shined in the prison: and he smote Peter on the side, and raised him up, saying, Arise up quickly. And his chains fell off from his hands.","ref":"Acts 12:7","synthesized":"Suddenly an angel of the Lord appeared and a light shone in the cell. He tapped Peter on the side and woke him up, saying, “Get up quickly.” And the chains fell off his wrists.","sources":{"KJV":{"text":"And, behold, the angel of the Lord came upon him, and a light shined in the prison: and he smote Peter on the side, and raised him up, saying, Arise up quickly. And his chains fell off from his hands."},"BSB":{"text":"Suddenly an angel of the Lord appeared and a light shone in the cell. He tapped Peter on the side and woke him up, saying, “Get up quickly.” And the chains fell off his wrists."}},"definableWords":["angel","Lord","light"],"peopleInVerse":["Peter"]},"8":{"text":"And the angel said unto him, Gird thyself, and bind on thy sandals. And so he did. And he saith unto him, Cast thy garment about thee, and follow me.","ref":"Acts 12:8","synthesized":"“Get dressed and put on your sandals,” said the angel. Peter did so, and the angel told him, “Wrap your cloak around you and follow me.”","sources":{"KJV":{"text":"And the angel said unto him, Gird thyself, and bind on thy sandals. And so he did. And he saith unto him, Cast thy garment about thee, and follow me."},"BSB":{"text":"“Get dressed and put on your sandals,” said the angel. Peter did so, and the angel told him, “Wrap your cloak around you and follow me.”"}},"definableWords":["angel"],"peopleInVerse":["Peter"]},"9":{"text":"And he went out, and followed him; and wist not that it was true which was done by the angel; but thought he saw a vision.","ref":"Acts 12:9","synthesized":"So Peter followed him out, but he was unaware that what the angel was doing was real. He thought he was only seeing a vision.","sources":{"KJV":{"text":"And he went out, and followed him; and wist not that it was true which was done by the angel; but thought he saw a vision."},"BSB":{"text":"So Peter followed him out, but he was unaware that what the angel was doing was real. He thought he was only seeing a vision."}},"definableWords":["angel"],"peopleInVerse":["Peter"]},"10":{"text":"When they were past the first and the second ward, they came unto the iron gate that leadeth unto the city; which opened to them of his own accord: and they went out, and passed on through one street; and forthwith the angel departed from him.","ref":"Acts 12:10","synthesized":"They passed the first and second guards and came to the iron gate leading to the city, which opened for them by itself. When they had gone outside and walked the length of one block, the angel suddenly left him.","sources":{"KJV":{"text":"When they were past the first and the second ward, they came unto the iron gate that leadeth unto the city; which opened to them of his own accord: and they went out, and passed on through one street; and forthwith the angel departed from him."},"BSB":{"text":"They passed the first and second guards and came to the iron gate leading to the city, which opened for them by itself. When they had gone outside and walked the length of one block, the angel suddenly left him."}},"definableWords":["walked","one","angel"],"peopleInVerse":[]},"11":{"text":"And when Peter was come to himself, he said, Now I know of a surety, that the LORD hath sent his angel, and hath delivered me out of the hand of Herod, and from all the expectation of the people of the Jews.","ref":"Acts 12:11","synthesized":"Then Peter came to himself and said, “Now I know for sure that the Lord has sent His angel and rescued me from Herod’s grasp and from everything the Jewish people were anticipating.”","sources":{"KJV":{"text":"And when Peter was come to himself, he said, Now I know of a surety, that the LORD hath sent his angel, and hath delivered me out of the hand of Herod, and from all the expectation of the people of the Jews."},"BSB":{"text":"Then Peter came to himself and said, “Now I know for sure that the Lord has sent His angel and rescued me from Herod’s grasp and from everything the Jewish people were anticipating.”"}},"definableWords":["Lord","angel","people"],"peopleInVerse":["Peter","Herod"]},"12":{"text":"And when he had considered the thing, he came to the house of Mary the mother of John, whose surname was Mark; where many were gathered together praying.","ref":"Acts 12:12","synthesized":"And when he had realized this, he went to the house of Mary the mother of John, also called Mark, where many people had gathered together and were praying.","sources":{"KJV":{"text":"And when he had considered the thing, he came to the house of Mary the mother of John, whose surname was Mark; where many were gathered together praying."},"BSB":{"text":"And when he had realized this, he went to the house of Mary the mother of John, also called Mark, where many people had gathered together and were praying."}},"definableWords":["house","mother","people"],"peopleInVerse":["Mary","John"]},"13":{"text":"And as Peter knocked at the door of the gate, a damsel came to hearken, named Rhoda.","ref":"Acts 12:13","synthesized":"He knocked at the outer gate, and a servant girl named Rhoda came to answer it.","sources":{"KJV":{"text":"And as Peter knocked at the door of the gate, a damsel came to hearken, named Rhoda."},"BSB":{"text":"He knocked at the outer gate, and a servant girl named Rhoda came to answer it."}},"definableWords":["servant"],"peopleInVerse":[]},"14":{"text":"And when she knew Peter’s voice, she opened not the gate for gladness, but ran in, and told how Peter stood before the gate.","ref":"Acts 12:14","synthesized":"When she recognized Peter’s voice, she was so overjoyed that she forgot to open the gate, but ran inside and announced, “Peter is standing at the gate!”","sources":{"KJV":{"text":"And when she knew Peter’s voice, she opened not the gate for gladness, but ran in, and told how Peter stood before the gate."},"BSB":{"text":"When she recognized Peter’s voice, she was so overjoyed that she forgot to open the gate, but ran inside and announced, “Peter is standing at the gate!”"}},"definableWords":["voice"],"peopleInVerse":["Peter"]},"15":{"text":"And they said unto her, Thou art mad. But she constantly affirmed that it was even so. Then said they, It is his angel.","ref":"Acts 12:15","synthesized":"“You are out of your mind,” they told her. But when she kept insisting it was so, they said, “It must be his angel.”","sources":{"KJV":{"text":"And they said unto her, Thou art mad. But she constantly affirmed that it was even so. Then said they, It is his angel."},"BSB":{"text":"“You are out of your mind,” they told her. But when she kept insisting it was so, they said, “It must be his angel.”"}},"definableWords":["mind","angel"],"peopleInVerse":[]},"16":{"text":"But Peter continued knocking: and when they had opened the door, and saw him, they were astonished.","ref":"Acts 12:16","synthesized":"But Peter kept on knocking, and when they opened the door and saw him, they were astounded.","sources":{"KJV":{"text":"But Peter continued knocking: and when they had opened the door, and saw him, they were astonished."},"BSB":{"text":"But Peter kept on knocking, and when they opened the door and saw him, they were astounded."}},"definableWords":["saw"],"peopleInVerse":["Peter"]},"17":{"text":"But he, beckoning unto them with the hand to hold their peace, declared unto them how the Lord had brought him out of the prison. And he said, Go shew these things unto James, and to the brethren. And he departed, and went into another place.","ref":"Acts 12:17","synthesized":"Peter motioned with his hand for silence, and he described how the Lord had brought him out of the prison. “Send word to James and to the brothers,” he said, and he left for another place.","sources":{"KJV":{"text":"But he, beckoning unto them with the hand to hold their peace, declared unto them how the Lord had brought him out of the prison. And he said, Go shew these things unto James, and to the brethren. And he departed, and went into another place."},"BSB":{"text":"Peter motioned with his hand for silence, and he described how the Lord had brought him out of the prison. “Send word to James and to the brothers,” he said, and he left for another place."}},"definableWords":["Lord","word"],"peopleInVerse":["Peter","James"]},"18":{"text":"Now as soon as it was day, there was no small stir among the soldiers, what was become of Peter.","ref":"Acts 12:18","synthesized":"At daybreak there was no small commotion among the soldiers as to what had become of Peter.","sources":{"KJV":{"text":"Now as soon as it was day, there was no small stir among the soldiers, what was become of Peter."},"BSB":{"text":"At daybreak there was no small commotion among the soldiers as to what had become of Peter."}},"definableWords":[],"peopleInVerse":["Peter"]},"19":{"text":"And when Herod had sought for him, and found him not, he examined the keepers, and commanded that they should be put to death. And he went down from Judaea to Caesarea, and there abode.","ref":"Acts 12:19","synthesized":"After Herod had searched for him unsuccessfully, he examined the guards and ordered that they be executed. Then he went down from Judea to Caesarea and spent some time there.","sources":{"KJV":{"text":"And when Herod had sought for him, and found him not, he examined the keepers, and commanded that they should be put to death. And he went down from Judaea to Caesarea, and there abode."},"BSB":{"text":"After Herod had searched for him unsuccessfully, he examined the guards and ordered that they be executed. Then he went down from Judea to Caesarea and spent some time there."}},"definableWords":["Judea"],"peopleInVerse":["Herod"]},"20":{"text":"And Herod was highly displeased with them of Tyre and Sidon: but they came with one accord to him, and, having made Blastus the king’s chamberlain their friend, desired peace; because their country was nourished by the king’s country.","ref":"Acts 12:20","synthesized":"Now Herod was in a furious dispute with the people of Tyre and Sidon, and they convened before him. Having secured the support of Blastus, the king’s chamberlain, they asked for peace, because their region depended on the king’s country for food.","sources":{"KJV":{"text":"And Herod was highly displeased with them of Tyre and Sidon: but they came with one accord to him, and, having made Blastus the king’s chamberlain their friend, desired peace; because their country was nourished by the king’s country."},"BSB":{"text":"Now Herod was in a furious dispute with the people of Tyre and Sidon, and they convened before him. Having secured the support of Blastus, the king’s chamberlain, they asked for peace, because their region depended on the king’s country for food."}},"definableWords":["people","king","peace","King"],"peopleInVerse":["Herod"]},"21":{"text":"And upon a set day Herod, arrayed in royal apparel, sat upon his throne, and made an oration unto them.","ref":"Acts 12:21","synthesized":"On the appointed day, Herod donned his royal robes, sat on his throne, and addressed the people.","sources":{"KJV":{"text":"And upon a set day Herod, arrayed in royal apparel, sat upon his throne, and made an oration unto them."},"BSB":{"text":"On the appointed day, Herod donned his royal robes, sat on his throne, and addressed the people."}},"definableWords":["day","throne","people"],"peopleInVerse":["Herod"]},"22":{"text":"And the people gave a shout, saying, It is the voice of a god, and not of a man.","ref":"Acts 12:22","synthesized":"And they began to shout, “This is the voice of a god, not a man!”","sources":{"KJV":{"text":"And the people gave a shout, saying, It is the voice of a god, and not of a man."},"BSB":{"text":"And they began to shout, “This is the voice of a god, not a man!”"}},"definableWords":["voice","God","man"],"peopleInVerse":[]},"23":{"text":"And immediately the angel of the Lord smote him, because he gave not God the glory: and he was eaten of worms, and gave up the ghost.","ref":"Acts 12:23","synthesized":"Immediately, because Herod did not give glory to God, an angel of the Lord struck him down, and he was eaten by worms and died.","sources":{"KJV":{"text":"And immediately the angel of the Lord smote him, because he gave not God the glory: and he was eaten of worms, and gave up the ghost."},"BSB":{"text":"Immediately, because Herod did not give glory to God, an angel of the Lord struck him down, and he was eaten by worms and died."}},"definableWords":["glory","God","angel","Lord"],"peopleInVerse":["Herod"]},"24":{"text":"But the word of God grew and multiplied.","ref":"Acts 12:24","synthesized":"But the word of God continued to spread and multiply.","sources":{"KJV":{"text":"But the word of God grew and multiplied."},"BSB":{"text":"But the word of God continued to spread and multiply."}},"definableWords":["word","God","multiply"],"peopleInVerse":[]},"25":{"text":"And Barnabas and Saul returned from Jerusalem, when they had fulfilled their ministry, and took with them John, whose surname was Mark.","ref":"Acts 12:25","synthesized":"When Barnabas and Saul had fulfilled their mission to Jerusalem, they returned, bringing with them John, also called Mark.","sources":{"KJV":{"text":"And Barnabas and Saul returned from Jerusalem, when they had fulfilled their ministry, and took with them John, whose surname was Mark."},"BSB":{"text":"When Barnabas and Saul had fulfilled their mission to Jerusalem, they returned, bringing with them John, also called Mark."}},"definableWords":["Jerusalem"],"peopleInVerse":["Barnabas","Saul","John"]}}},"13":{"chapter":"13","title":"PAUL'S FIRST MISSIONARY JOURNEY BEGINS","verses":{"1":{"text":"Now there were in the church that was at Antioch certain prophets and teachers; as Barnabas, and Simeon that was called Niger, and Lucius of Cyrene, and Manaen, which had been brought up with Herod the tetrarch, and Saul.","ref":"Acts 13:1","synthesized":"Now in the church at Antioch there were prophets and teachers: Barnabas, Simeon called Niger, Lucius of Cyrene, Manaen (who had been brought up with Herod the tetrarch), and Saul.","sources":{"KJV":{"text":"Now there were in the church that was at Antioch certain prophets and teachers; as Barnabas, and Simeon that was called Niger, and Lucius of Cyrene, and Manaen, which had been brought up with Herod the tetrarch, and Saul."},"BSB":{"text":"Now in the church at Antioch there were prophets and teachers: Barnabas, Simeon called Niger, Lucius of Cyrene, Manaen (who had been brought up with Herod the tetrarch), and Saul."}},"definableWords":["church","Simeon"],"peopleInVerse":["Barnabas","Herod","Saul"]},"2":{"text":"As they ministered to the Lord, and fasted, the Holy Ghost said, Separate me Barnabas and Saul for the work whereunto I have called them.","ref":"Acts 13:2","synthesized":"While they were worshiping the Lord and fasting, the Holy Spirit said, “Set apart for Me Barnabas and Saul for the work to which I have called them.”","sources":{"KJV":{"text":"As they ministered to the Lord, and fasted, the Holy Ghost said, Separate me Barnabas and Saul for the work whereunto I have called them."},"BSB":{"text":"While they were worshiping the Lord and fasting, the Holy Spirit said, “Set apart for Me Barnabas and Saul for the work to which I have called them.”"}},"definableWords":["Lord","holy","Spirit","work"],"peopleInVerse":["Barnabas","Saul"]},"3":{"text":"And when they had fasted and prayed, and laid their hands on them, they sent them away.","ref":"Acts 13:3","synthesized":"And after they had fasted and prayed, they laid their hands on them and sent them off.","sources":{"KJV":{"text":"And when they had fasted and prayed, and laid their hands on them, they sent them away."},"BSB":{"text":"And after they had fasted and prayed, they laid their hands on them and sent them off."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"So they, being sent forth by the Holy Ghost, departed unto Seleucia; and from thence they sailed to Cyprus.","ref":"Acts 13:4","synthesized":"So Barnabas and Saul, sent forth by the Holy Spirit, went down to Seleucia and sailed from there to Cyprus.","sources":{"KJV":{"text":"So they, being sent forth by the Holy Ghost, departed unto Seleucia; and from thence they sailed to Cyprus."},"BSB":{"text":"So Barnabas and Saul, sent forth by the Holy Spirit, went down to Seleucia and sailed from there to Cyprus."}},"definableWords":["holy","Spirit"],"peopleInVerse":["Barnabas","Saul"]},"5":{"text":"And when they were at Salamis, they preached the word of God in the synagogues of the Jews: and they had also John to their minister.","ref":"Acts 13:5","synthesized":"When they arrived at Salamis, they proclaimed the word of God in the Jewish synagogues. And John was with them as their helper.","sources":{"KJV":{"text":"And when they were at Salamis, they preached the word of God in the synagogues of the Jews: and they had also John to their minister."},"BSB":{"text":"When they arrived at Salamis, they proclaimed the word of God in the Jewish synagogues. And John was with them as their helper."}},"definableWords":["word","God","helper"],"peopleInVerse":["John"]},"6":{"text":"And when they had gone through the isle unto Paphos, they found a certain sorcerer, a false prophet, a Jew, whose name was Barjesus:","ref":"Acts 13:6","synthesized":"They traveled through the whole island as far as Paphos, where they found a Jewish sorcerer and false prophet named Bar-Jesus,","sources":{"KJV":{"text":"And when they had gone through the isle unto Paphos, they found a certain sorcerer, a false prophet, a Jew, whose name was Barjesus:"},"BSB":{"text":"They traveled through the whole island as far as Paphos, where they found a Jewish sorcerer and false prophet named Bar-Jesus,"}},"definableWords":["prophet"],"peopleInVerse":["Jesus"]},"7":{"text":"Which was with the deputy of the country, Sergius Paulus, a prudent man; who called for Barnabas and Saul, and desired to hear the word of God.","ref":"Acts 13:7","synthesized":"an attendant of the proconsul, Sergius Paulus. The proconsul, a man of intelligence, summoned Barnabas and Saul because he wanted to hear the word of God.","sources":{"KJV":{"text":"Which was with the deputy of the country, Sergius Paulus, a prudent man; who called for Barnabas and Saul, and desired to hear the word of God."},"BSB":{"text":"an attendant of the proconsul, Sergius Paulus. The proconsul, a man of intelligence, summoned Barnabas and Saul because he wanted to hear the word of God."}},"definableWords":["man","hear","word","God"],"peopleInVerse":["Barnabas","Saul"]},"8":{"text":"But Elymas the sorcerer (for so is his name by interpretation) withstood them, seeking to turn away the deputy from the faith.","ref":"Acts 13:8","synthesized":"But Elymas the sorcerer (for that is what his name means) opposed them and tried to turn the proconsul from the faith.","sources":{"KJV":{"text":"But Elymas the sorcerer (for so is his name by interpretation) withstood them, seeking to turn away the deputy from the faith."},"BSB":{"text":"But Elymas the sorcerer (for that is what his name means) opposed them and tried to turn the proconsul from the faith."}},"definableWords":["name","faith"],"peopleInVerse":[]},"9":{"text":"Then Saul, (who also is called Paul,) filled with the Holy Ghost, set his eyes on him,","ref":"Acts 13:9","synthesized":"Then Saul, who was also called Paul, filled with the Holy Spirit, looked directly at Elymas","sources":{"KJV":{"text":"Then Saul, (who also is called Paul,) filled with the Holy Ghost, set his eyes on him,"},"BSB":{"text":"Then Saul, who was also called Paul, filled with the Holy Spirit, looked directly at Elymas"}},"definableWords":["holy","Spirit"],"peopleInVerse":["Saul","Paul"]},"10":{"text":"And said, O full of all subtilty and all mischief, thou child of the devil, thou enemy of all righteousness, wilt thou not cease to pervert the right ways of the Lord?","ref":"Acts 13:10","synthesized":"and said, “O child of the devil and enemy of all righteousness, you are full of all kinds of deceit and trickery! Will you never stop perverting the straight ways of the Lord?","sources":{"KJV":{"text":"And said, O full of all subtilty and all mischief, thou child of the devil, thou enemy of all righteousness, wilt thou not cease to pervert the right ways of the Lord?"},"BSB":{"text":"and said, “O child of the devil and enemy of all righteousness, you are full of all kinds of deceit and trickery! Will you never stop perverting the straight ways of the Lord?"}},"definableWords":["devil","righteousness","Lord"],"peopleInVerse":[]},"11":{"text":"And now, behold, the hand of the Lord is upon thee, and thou shalt be blind, not seeing the sun for a season. And immediately there fell on him a mist and a darkness; and he went about seeking some to lead him by the hand.","ref":"Acts 13:11","synthesized":"Now look, the hand of the Lord is against you, and for a time you will be blind and unable to see the light of the sun.” Immediately mist and darkness came over him, and he groped about, seeking someone to lead him by the hand.","sources":{"KJV":{"text":"And now, behold, the hand of the Lord is upon thee, and thou shalt be blind, not seeing the sun for a season. And immediately there fell on him a mist and a darkness; and he went about seeking some to lead him by the hand."},"BSB":{"text":"Now look, the hand of the Lord is against you, and for a time you will be blind and unable to see the light of the sun.” Immediately mist and darkness came over him, and he groped about, seeking someone to lead him by the hand."}},"definableWords":["Lord","see","light","darkness"],"peopleInVerse":[]},"12":{"text":"Then the deputy, when he saw what was done, believed, being astonished at the doctrine of the Lord.","ref":"Acts 13:12","synthesized":"When the proconsul saw what had happened, he believed, for he was astonished at the teaching about the Lord.","sources":{"KJV":{"text":"Then the deputy, when he saw what was done, believed, being astonished at the doctrine of the Lord."},"BSB":{"text":"When the proconsul saw what had happened, he believed, for he was astonished at the teaching about the Lord."}},"definableWords":["saw","believed","Lord"],"peopleInVerse":[]},"13":{"text":"Now when Paul and his company loosed from Paphos, they came to Perga in Pamphylia: and John departing from them returned to Jerusalem.","ref":"Acts 13:13","synthesized":"After setting sail from Paphos, Paul and his companions came to Perga in Pamphylia, where John left them to return to Jerusalem.","sources":{"KJV":{"text":"Now when Paul and his company loosed from Paphos, they came to Perga in Pamphylia: and John departing from them returned to Jerusalem."},"BSB":{"text":"After setting sail from Paphos, Paul and his companions came to Perga in Pamphylia, where John left them to return to Jerusalem."}},"definableWords":["Jerusalem"],"peopleInVerse":["Paul","John"]},"14":{"text":"But when they departed from Perga, they came to Antioch in Pisidia, and went into the synagogue on the sabbath day, and sat down.","ref":"Acts 13:14","synthesized":"And from Perga, they traveled inland to Pisidian Antioch, where they entered the synagogue on the Sabbath and sat down.","sources":{"KJV":{"text":"But when they departed from Perga, they came to Antioch in Pisidia, and went into the synagogue on the sabbath day, and sat down."},"BSB":{"text":"And from Perga, they traveled inland to Pisidian Antioch, where they entered the synagogue on the Sabbath and sat down."}},"definableWords":["Sabbath"],"peopleInVerse":[]},"15":{"text":"And after the reading of the law and the prophets the rulers of the synagogue sent unto them, saying, Ye men and brethren, if ye have any word of exhortation for the people, say on.","ref":"Acts 13:15","synthesized":"After the reading from the Law and the Prophets, the synagogue leaders sent word to them: “Brothers, if you have a word of encouragement for the people, please speak.”","sources":{"KJV":{"text":"And after the reading of the law and the prophets the rulers of the synagogue sent unto them, saying, Ye men and brethren, if ye have any word of exhortation for the people, say on."},"BSB":{"text":"After the reading from the Law and the Prophets, the synagogue leaders sent word to them: “Brothers, if you have a word of encouragement for the people, please speak.”"}},"definableWords":["law","word","people"],"peopleInVerse":[]},"16":{"text":"Then Paul stood up, and beckoning with his hand said, Men of Israel, and ye that fear God, give audience.","ref":"Acts 13:16","synthesized":"Paul stood up, motioned with his hand, and began to speak: “Men of Israel and you Gentiles who fear God, listen to me!","sources":{"KJV":{"text":"Then Paul stood up, and beckoning with his hand said, Men of Israel, and ye that fear God, give audience."},"BSB":{"text":"Paul stood up, motioned with his hand, and began to speak: “Men of Israel and you Gentiles who fear God, listen to me!"}},"definableWords":["men","Israel","fear","God"],"peopleInVerse":["Paul"]},"17":{"text":"The God of this people of Israel chose our fathers, and exalted the people when they dwelt as strangers in the land of Egypt, and with an high arm brought he them out of it.","ref":"Acts 13:17","synthesized":"The God of the people of Israel chose our fathers. He made them into a great people during their stay in Egypt, and with an uplifted arm He led them out of that land.","sources":{"KJV":{"text":"The God of this people of Israel chose our fathers, and exalted the people when they dwelt as strangers in the land of Egypt, and with an high arm brought he them out of it."},"BSB":{"text":"The God of the people of Israel chose our fathers. He made them into a great people during their stay in Egypt, and with an uplifted arm He led them out of that land."}},"definableWords":["God","people","Israel","fathers","made","great","Egypt","land"],"peopleInVerse":[]},"18":{"text":"And about the time of forty years suffered he their manners in the wilderness.","ref":"Acts 13:18","synthesized":"He endured their conduct for about forty years in the wilderness.","sources":{"KJV":{"text":"And about the time of forty years suffered he their manners in the wilderness."},"BSB":{"text":"He endured their conduct for about forty years in the wilderness."}},"definableWords":["years"],"peopleInVerse":[]},"19":{"text":"And when he had destroyed seven nations in the land of Chanaan, he divided their land to them by lot.","ref":"Acts 13:19","synthesized":"And having vanquished seven nations in Canaan, He gave their land to His people as an inheritance.","sources":{"KJV":{"text":"And when he had destroyed seven nations in the land of Chanaan, he divided their land to them by lot."},"BSB":{"text":"And having vanquished seven nations in Canaan, He gave their land to His people as an inheritance."}},"definableWords":["nations","Canaan","land","people"],"peopleInVerse":["Canaan"]},"20":{"text":"And after that he gave unto them judges about the space of four hundred and fifty years, until Samuel the prophet.","ref":"Acts 13:20","synthesized":"All this took about 450 years.  After this, God gave them judges until the time of Samuel the prophet.","sources":{"KJV":{"text":"And after that he gave unto them judges about the space of four hundred and fifty years, until Samuel the prophet."},"BSB":{"text":"All this took about 450 years.  After this, God gave them judges until the time of Samuel the prophet."}},"definableWords":["years","God","prophet"],"peopleInVerse":["Samuel"]},"21":{"text":"And afterward they desired a king: and God gave unto them Saul the son of Cis, a man of the tribe of Benjamin, by the space of forty years.","ref":"Acts 13:21","synthesized":"Then the people asked for a king, and God gave them forty years under Saul son of Kish, from the tribe of Benjamin.","sources":{"KJV":{"text":"And afterward they desired a king: and God gave unto them Saul the son of Cis, a man of the tribe of Benjamin, by the space of forty years."},"BSB":{"text":"Then the people asked for a king, and God gave them forty years under Saul son of Kish, from the tribe of Benjamin."}},"definableWords":["people","king","God","years","son","tribe","Benjamin"],"peopleInVerse":["Saul"]},"22":{"text":"And when he had removed him, he raised up unto them David to be their king; to whom also he gave testimony, and said, I have found David the son of Jesse, a man after mine own heart, which shall fulfil all my will.","ref":"Acts 13:22","synthesized":"After removing Saul, He raised up David as their king and testified about him: ‘I have found David son of Jesse a man after My own heart; he will carry out My will in its entirety.’","sources":{"KJV":{"text":"And when he had removed him, he raised up unto them David to be their king; to whom also he gave testimony, and said, I have found David the son of Jesse, a man after mine own heart, which shall fulfil all my will."},"BSB":{"text":"After removing Saul, He raised up David as their king and testified about him: ‘I have found David son of Jesse a man after My own heart; he will carry out My will in its entirety.’"}},"definableWords":["king","son","man","heart"],"peopleInVerse":["Saul","David"]},"23":{"text":"Of this man’s seed hath God according to his promise raised unto Israel a Saviour, Jesus:","ref":"Acts 13:23","synthesized":"From the descendants of this man, God has brought to Israel the Savior Jesus, as He promised.","sources":{"KJV":{"text":"Of this man’s seed hath God according to his promise raised unto Israel a Saviour, Jesus:"},"BSB":{"text":"From the descendants of this man, God has brought to Israel the Savior Jesus, as He promised."}},"definableWords":["man","God","Israel"],"peopleInVerse":["Jesus"]},"24":{"text":"When John had first preached before his coming the baptism of repentance to all the people of Israel.","ref":"Acts 13:24","synthesized":"Before the arrival of Jesus, John preached a baptism of repentance to all the people of Israel.","sources":{"KJV":{"text":"When John had first preached before his coming the baptism of repentance to all the people of Israel."},"BSB":{"text":"Before the arrival of Jesus, John preached a baptism of repentance to all the people of Israel."}},"definableWords":["baptism","repentance","people","Israel"],"peopleInVerse":["Jesus","John"]},"25":{"text":"And as John fulfilled his course, he said, Whom think ye that I am? I am not he. But, behold, there cometh one after me, whose shoes of his feet I am not worthy to loose.","ref":"Acts 13:25","synthesized":"As John was completing his course, he said, ‘Who do you suppose I am? I am not that One. But He is coming after me whose sandals I am not worthy to untie.’","sources":{"KJV":{"text":"And as John fulfilled his course, he said, Whom think ye that I am? I am not he. But, behold, there cometh one after me, whose shoes of his feet I am not worthy to loose."},"BSB":{"text":"As John was completing his course, he said, ‘Who do you suppose I am? I am not that One. But He is coming after me whose sandals I am not worthy to untie.’"}},"definableWords":["one"],"peopleInVerse":["John"]},"26":{"text":"Men and brethren, children of the stock of Abraham, and whosoever among you feareth God, to you is the word of this salvation sent.","ref":"Acts 13:26","synthesized":"Brothers, children of Abraham, and you Gentiles who fear God, it is to us that this message of salvation has been sent.","sources":{"KJV":{"text":"Men and brethren, children of the stock of Abraham, and whosoever among you feareth God, to you is the word of this salvation sent."},"BSB":{"text":"Brothers, children of Abraham, and you Gentiles who fear God, it is to us that this message of salvation has been sent."}},"definableWords":["Abraham","fear","God","salvation"],"peopleInVerse":["Abraham"]},"27":{"text":"For they that dwell at Jerusalem, and their rulers, because they knew him not, nor yet the voices of the prophets which are read every sabbath day, they have fulfilled them in condemning him.","ref":"Acts 13:27","synthesized":"The people of Jerusalem and their rulers did not recognize Jesus, yet in condemning Him they fulfilled the words of the prophets that are read every Sabbath.","sources":{"KJV":{"text":"For they that dwell at Jerusalem, and their rulers, because they knew him not, nor yet the voices of the prophets which are read every sabbath day, they have fulfilled them in condemning him."},"BSB":{"text":"The people of Jerusalem and their rulers did not recognize Jesus, yet in condemning Him they fulfilled the words of the prophets that are read every Sabbath."}},"definableWords":["people","Jerusalem","Sabbath"],"peopleInVerse":["Jesus"]},"28":{"text":"And though they found no cause of death in him, yet desired they Pilate that he should be slain.","ref":"Acts 13:28","synthesized":"And though they found no ground for a death sentence, they asked Pilate to have Him executed.","sources":{"KJV":{"text":"And though they found no cause of death in him, yet desired they Pilate that he should be slain."},"BSB":{"text":"And though they found no ground for a death sentence, they asked Pilate to have Him executed."}},"definableWords":["ground","death"],"peopleInVerse":["Pilate"]},"29":{"text":"And when they had fulfilled all that was written of him, they took him down from the tree, and laid him in a sepulchre.","ref":"Acts 13:29","synthesized":"When they had carried out all that was written about Him, they took Him down from the tree and laid Him in a tomb.","sources":{"KJV":{"text":"And when they had fulfilled all that was written of him, they took him down from the tree, and laid him in a sepulchre."},"BSB":{"text":"When they had carried out all that was written about Him, they took Him down from the tree and laid Him in a tomb."}},"definableWords":["tree"],"peopleInVerse":[]},"30":{"text":"But God raised him from the dead:","ref":"Acts 13:30","synthesized":"But God raised Him from the dead,","sources":{"KJV":{"text":"But God raised him from the dead:"},"BSB":{"text":"But God raised Him from the dead,"}},"definableWords":["God"],"peopleInVerse":[]},"31":{"text":"And he was seen many days of them which came up with him from Galilee to Jerusalem, who are his witnesses unto the people.","ref":"Acts 13:31","synthesized":"and for many days He was seen by those who had accompanied Him from Galilee to Jerusalem. They are now His witnesses to our people.","sources":{"KJV":{"text":"And he was seen many days of them which came up with him from Galilee to Jerusalem, who are his witnesses unto the people."},"BSB":{"text":"and for many days He was seen by those who had accompanied Him from Galilee to Jerusalem. They are now His witnesses to our people."}},"definableWords":["days","Galilee","Jerusalem","people"],"peopleInVerse":[]},"32":{"text":"And we declare unto you glad tidings, how that the promise which was made unto the fathers,","ref":"Acts 13:32","synthesized":"And now we proclaim to you the good news: What God promised our fathers","sources":{"KJV":{"text":"And we declare unto you glad tidings, how that the promise which was made unto the fathers,"},"BSB":{"text":"And now we proclaim to you the good news: What God promised our fathers"}},"definableWords":["good","God","fathers"],"peopleInVerse":[]},"33":{"text":"God hath fulfilled the same unto us their children, in that he hath raised up Jesus again; as it is also written in the second psalm, Thou art my Son, this day have I begotten thee.","ref":"Acts 13:33","synthesized":"He has fulfilled for us, their children, by raising up Jesus. As it is written in the second Psalm:  ‘You are My Son; today I have become Your Father.’","sources":{"KJV":{"text":"God hath fulfilled the same unto us their children, in that he hath raised up Jesus again; as it is also written in the second psalm, Thou art my Son, this day have I begotten thee."},"BSB":{"text":"He has fulfilled for us, their children, by raising up Jesus. As it is written in the second Psalm:  ‘You are My Son; today I have become Your Father.’"}},"definableWords":["Son","Father"],"peopleInVerse":["Jesus"]},"34":{"text":"And as concerning that he raised him up from the dead, now no more to return to corruption, he said on this wise, I will give you the sure mercies of David.","ref":"Acts 13:34","synthesized":"In fact, God raised Him from the dead, never to see decay. As He has said:  ‘I will give you the holy and sure blessings promised to David.’","sources":{"KJV":{"text":"And as concerning that he raised him up from the dead, now no more to return to corruption, he said on this wise, I will give you the sure mercies of David."},"BSB":{"text":"In fact, God raised Him from the dead, never to see decay. As He has said:  ‘I will give you the holy and sure blessings promised to David.’"}},"definableWords":["God","see","holy"],"peopleInVerse":["David"]},"35":{"text":"Wherefore he saith also in another psalm, Thou shalt not suffer thine Holy One to see corruption.","ref":"Acts 13:35","synthesized":"So also, He says in another Psalm:  ‘You will not let Your Holy One see decay.’","sources":{"KJV":{"text":"Wherefore he saith also in another psalm, Thou shalt not suffer thine Holy One to see corruption."},"BSB":{"text":"So also, He says in another Psalm:  ‘You will not let Your Holy One see decay.’"}},"definableWords":["holy","one","see"],"peopleInVerse":[]},"36":{"text":"For David, after he had served his own generation by the will of God, fell on sleep, and was laid unto his fathers, and saw corruption:","ref":"Acts 13:36","synthesized":"For when David had served God’s purpose in his own generation, he fell asleep. His body was buried with his fathers and saw decay.","sources":{"KJV":{"text":"For David, after he had served his own generation by the will of God, fell on sleep, and was laid unto his fathers, and saw corruption:"},"BSB":{"text":"For when David had served God’s purpose in his own generation, he fell asleep. His body was buried with his fathers and saw decay."}},"definableWords":["God","fathers","saw"],"peopleInVerse":["David"]},"37":{"text":"But he, whom God raised again, saw no corruption.","ref":"Acts 13:37","synthesized":"But the One whom God raised from the dead did not see decay.","sources":{"KJV":{"text":"But he, whom God raised again, saw no corruption."},"BSB":{"text":"But the One whom God raised from the dead did not see decay."}},"definableWords":["one","God","see"],"peopleInVerse":[]},"38":{"text":"Be it known unto you therefore, men and brethren, that through this man is preached unto you the forgiveness of sins:","ref":"Acts 13:38","synthesized":"Therefore let it be known to you, brothers, that through Jesus the forgiveness of sins is proclaimed to you.","sources":{"KJV":{"text":"Be it known unto you therefore, men and brethren, that through this man is preached unto you the forgiveness of sins:"},"BSB":{"text":"Therefore let it be known to you, brothers, that through Jesus the forgiveness of sins is proclaimed to you."}},"definableWords":[],"peopleInVerse":["Jesus"]},"39":{"text":"And by him all that believe are justified from all things, from which ye could not be justified by the law of Moses.","ref":"Acts 13:39","synthesized":"Through Him everyone who believes is justified from everything you could not be justified from by the law of Moses.","sources":{"KJV":{"text":"And by him all that believe are justified from all things, from which ye could not be justified by the law of Moses."},"BSB":{"text":"Through Him everyone who believes is justified from everything you could not be justified from by the law of Moses."}},"definableWords":["law"],"peopleInVerse":["Moses"]},"40":{"text":"Beware therefore, lest that come upon you, which is spoken of in the prophets;","ref":"Acts 13:40","synthesized":"Watch out, then, that what was spoken by the prophets does not happen to you:","sources":{"KJV":{"text":"Beware therefore, lest that come upon you, which is spoken of in the prophets;"},"BSB":{"text":"Watch out, then, that what was spoken by the prophets does not happen to you:"}},"definableWords":[],"peopleInVerse":[]},"41":{"text":"Behold, ye despisers, and wonder, and perish: for I work a work in your days, a work which ye shall in no wise believe, though a man declare it unto you.","ref":"Acts 13:41","synthesized":"‘Look, you scoffers, wonder and perish! For I am doing a work in your days that you would never believe, even if someone told you.’”","sources":{"KJV":{"text":"Behold, ye despisers, and wonder, and perish: for I work a work in your days, a work which ye shall in no wise believe, though a man declare it unto you."},"BSB":{"text":"‘Look, you scoffers, wonder and perish! For I am doing a work in your days that you would never believe, even if someone told you.’”"}},"definableWords":["work","days"],"peopleInVerse":[]},"42":{"text":"And when the Jews were gone out of the synagogue, the Gentiles besought that these words might be preached to them the next sabbath.","ref":"Acts 13:42","synthesized":"As Paul and Barnabas were leaving the synagogue, the people urged them to continue this message on the next Sabbath.","sources":{"KJV":{"text":"And when the Jews were gone out of the synagogue, the Gentiles besought that these words might be preached to them the next sabbath."},"BSB":{"text":"As Paul and Barnabas were leaving the synagogue, the people urged them to continue this message on the next Sabbath."}},"definableWords":["people","Sabbath"],"peopleInVerse":["Paul","Barnabas"]},"43":{"text":"Now when the congregation was broken up, many of the Jews and religious proselytes followed Paul and Barnabas: who, speaking to them, persuaded them to continue in the grace of God.","ref":"Acts 13:43","synthesized":"After the synagogue was dismissed, many of the Jews and devout converts to Judaism followed Paul and Barnabas, who spoke to them and urged them to continue in the grace of God.","sources":{"KJV":{"text":"Now when the congregation was broken up, many of the Jews and religious proselytes followed Paul and Barnabas: who, speaking to them, persuaded them to continue in the grace of God."},"BSB":{"text":"After the synagogue was dismissed, many of the Jews and devout converts to Judaism followed Paul and Barnabas, who spoke to them and urged them to continue in the grace of God."}},"definableWords":["grace","God"],"peopleInVerse":["Paul","Barnabas"]},"44":{"text":"And the next sabbath day came almost the whole city together to hear the word of God.","ref":"Acts 13:44","synthesized":"On the following Sabbath, nearly the whole city gathered to hear the word of the Lord.","sources":{"KJV":{"text":"And the next sabbath day came almost the whole city together to hear the word of God."},"BSB":{"text":"On the following Sabbath, nearly the whole city gathered to hear the word of the Lord."}},"definableWords":["Sabbath","hear","word","Lord"],"peopleInVerse":[]},"45":{"text":"But when the Jews saw the multitudes, they were filled with envy, and spake against those things which were spoken by Paul, contradicting and blaspheming.","ref":"Acts 13:45","synthesized":"But when the Jews saw the crowds, they were filled with jealousy, and they blasphemously contradicted what Paul was saying.","sources":{"KJV":{"text":"But when the Jews saw the multitudes, they were filled with envy, and spake against those things which were spoken by Paul, contradicting and blaspheming."},"BSB":{"text":"But when the Jews saw the crowds, they were filled with jealousy, and they blasphemously contradicted what Paul was saying."}},"definableWords":["saw"],"peopleInVerse":["Paul"]},"46":{"text":"Then Paul and Barnabas waxed bold, and said, It was necessary that the word of God should first have been spoken to you: but seeing ye put it from you, and judge yourselves unworthy of everlasting life, lo, we turn to the Gentiles.","ref":"Acts 13:46","synthesized":"Then Paul and Barnabas answered them boldly: “It was necessary to speak the word of God to you first. But since you reject it and do not consider yourselves worthy of eternal life, we now turn to the Gentiles.","sources":{"KJV":{"text":"Then Paul and Barnabas waxed bold, and said, It was necessary that the word of God should first have been spoken to you: but seeing ye put it from you, and judge yourselves unworthy of everlasting life, lo, we turn to the Gentiles."},"BSB":{"text":"Then Paul and Barnabas answered them boldly: “It was necessary to speak the word of God to you first. But since you reject it and do not consider yourselves worthy of eternal life, we now turn to the Gentiles."}},"definableWords":["word","God","eternal","life"],"peopleInVerse":["Paul","Barnabas"]},"47":{"text":"For so hath the Lord commanded us, saying, I have set thee to be a light of the Gentiles, that thou shouldest be for salvation unto the ends of the earth.","ref":"Acts 13:47","synthesized":"For this is what the Lord has commanded us:  ‘I have made you a light for the Gentiles, to bring salvation to the ends of the earth.’”","sources":{"KJV":{"text":"For so hath the Lord commanded us, saying, I have set thee to be a light of the Gentiles, that thou shouldest be for salvation unto the ends of the earth."},"BSB":{"text":"For this is what the Lord has commanded us:  ‘I have made you a light for the Gentiles, to bring salvation to the ends of the earth.’”"}},"definableWords":["Lord","made","light","salvation","earth"],"peopleInVerse":[]},"48":{"text":"And when the Gentiles heard this, they were glad, and glorified the word of the Lord: and as many as were ordained to eternal life believed.","ref":"Acts 13:48","synthesized":"When the Gentiles heard this, they rejoiced and glorified the word of the Lord, and all who were appointed for eternal life believed.","sources":{"KJV":{"text":"And when the Gentiles heard this, they were glad, and glorified the word of the Lord: and as many as were ordained to eternal life believed."},"BSB":{"text":"When the Gentiles heard this, they rejoiced and glorified the word of the Lord, and all who were appointed for eternal life believed."}},"definableWords":["word","Lord","eternal","life","believed"],"peopleInVerse":[]},"49":{"text":"And the word of the Lord was published throughout all the region.","ref":"Acts 13:49","synthesized":"And the word of the Lord spread throughout that region.","sources":{"KJV":{"text":"And the word of the Lord was published throughout all the region."},"BSB":{"text":"And the word of the Lord spread throughout that region."}},"definableWords":["word","Lord"],"peopleInVerse":[]},"50":{"text":"But the Jews stirred up the devout and honourable women, and the chief men of the city, and raised persecution against Paul and Barnabas, and expelled them out of their coasts.","ref":"Acts 13:50","synthesized":"The Jews, however, incited the religious women of prominence and the leading men of the city. They stirred up persecution against Paul and Barnabas and drove them out of their district.","sources":{"KJV":{"text":"But the Jews stirred up the devout and honourable women, and the chief men of the city, and raised persecution against Paul and Barnabas, and expelled them out of their coasts."},"BSB":{"text":"The Jews, however, incited the religious women of prominence and the leading men of the city. They stirred up persecution against Paul and Barnabas and drove them out of their district."}},"definableWords":["women","men"],"peopleInVerse":["Paul","Barnabas"]},"51":{"text":"But they shook off the dust of their feet against them, and came unto Iconium.","ref":"Acts 13:51","synthesized":"So they shook the dust off their feet in protest against them and went to Iconium.","sources":{"KJV":{"text":"But they shook off the dust of their feet against them, and came unto Iconium."},"BSB":{"text":"So they shook the dust off their feet in protest against them and went to Iconium."}},"definableWords":[],"peopleInVerse":[]},"52":{"text":"And the disciples were filled with joy, and with the Holy Ghost.","ref":"Acts 13:52","synthesized":"And the disciples were filled with joy and with the Holy Spirit.","sources":{"KJV":{"text":"And the disciples were filled with joy, and with the Holy Ghost."},"BSB":{"text":"And the disciples were filled with joy and with the Holy Spirit."}},"definableWords":["joy","holy","Spirit"],"peopleInVerse":[]}}},"14":{"chapter":"14","title":"PAUL STONED AT LYSTRA — RECOVERS","verses":{"1":{"text":"And it came to pass in Iconium, that they went both together into the synagogue of the Jews, and so spake, that a great multitude both of the Jews and also of the Greeks believed.","ref":"Acts 14:1","synthesized":"At Iconium, Paul and Barnabas went as usual into the Jewish synagogue, where they spoke so well that a great number of Jews and Greeks believed.","sources":{"KJV":{"text":"And it came to pass in Iconium, that they went both together into the synagogue of the Jews, and so spake, that a great multitude both of the Jews and also of the Greeks believed."},"BSB":{"text":"At Iconium, Paul and Barnabas went as usual into the Jewish synagogue, where they spoke so well that a great number of Jews and Greeks believed."}},"definableWords":["great","believed"],"peopleInVerse":["Paul","Barnabas"]},"2":{"text":"But the unbelieving Jews stirred up the Gentiles, and made their minds evil affected against the brethren.","ref":"Acts 14:2","synthesized":"But the unbelieving Jews stirred up the Gentiles and poisoned their minds against the brothers.","sources":{"KJV":{"text":"But the unbelieving Jews stirred up the Gentiles, and made their minds evil affected against the brethren."},"BSB":{"text":"But the unbelieving Jews stirred up the Gentiles and poisoned their minds against the brothers."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Long time therefore abode they speaking boldly in the Lord, which gave testimony unto the word of his grace, and granted signs and wonders to be done by their hands.","ref":"Acts 14:3","synthesized":"So Paul and Barnabas spent considerable time there, speaking boldly for the Lord, who affirmed the message of His grace by enabling them to perform signs and wonders.","sources":{"KJV":{"text":"Long time therefore abode they speaking boldly in the Lord, which gave testimony unto the word of his grace, and granted signs and wonders to be done by their hands."},"BSB":{"text":"So Paul and Barnabas spent considerable time there, speaking boldly for the Lord, who affirmed the message of His grace by enabling them to perform signs and wonders."}},"definableWords":["Lord","grace"],"peopleInVerse":["Paul","Barnabas"]},"4":{"text":"But the multitude of the city was divided: and part held with the Jews, and part with the apostles.","ref":"Acts 14:4","synthesized":"The people of the city were divided. Some sided with the Jews, and others with the apostles.","sources":{"KJV":{"text":"But the multitude of the city was divided: and part held with the Jews, and part with the apostles."},"BSB":{"text":"The people of the city were divided. Some sided with the Jews, and others with the apostles."}},"definableWords":["people"],"peopleInVerse":[]},"5":{"text":"And when there was an assault made both of the Gentiles, and also of the Jews with their rulers, to use them despitefully, and to stone them,","ref":"Acts 14:5","synthesized":"But when the Gentiles and Jews, together with their rulers, set out to mistreat and stone them,","sources":{"KJV":{"text":"And when there was an assault made both of the Gentiles, and also of the Jews with their rulers, to use them despitefully, and to stone them,"},"BSB":{"text":"But when the Gentiles and Jews, together with their rulers, set out to mistreat and stone them,"}},"definableWords":["stone"],"peopleInVerse":[]},"6":{"text":"They were ware of it, and fled unto Lystra and Derbe, cities of Lycaonia, and unto the region that lieth round about:","ref":"Acts 14:6","synthesized":"they found out about it and fled to the Lycaonian cities of Lystra and Derbe and to the surrounding region,","sources":{"KJV":{"text":"They were ware of it, and fled unto Lystra and Derbe, cities of Lycaonia, and unto the region that lieth round about:"},"BSB":{"text":"they found out about it and fled to the Lycaonian cities of Lystra and Derbe and to the surrounding region,"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And there they preached the gospel.","ref":"Acts 14:7","synthesized":"where they continued to preach the gospel.","sources":{"KJV":{"text":"And there they preached the gospel."},"BSB":{"text":"where they continued to preach the gospel."}},"definableWords":["gospel"],"peopleInVerse":[]},"8":{"text":"And there sat a certain man at Lystra, impotent in his feet, being a cripple from his mother’s womb, who never had walked:","ref":"Acts 14:8","synthesized":"In Lystra there sat a man crippled in his feet, who was lame from birth and had never walked.","sources":{"KJV":{"text":"And there sat a certain man at Lystra, impotent in his feet, being a cripple from his mother’s womb, who never had walked:"},"BSB":{"text":"In Lystra there sat a man crippled in his feet, who was lame from birth and had never walked."}},"definableWords":["man","walked"],"peopleInVerse":[]},"9":{"text":"The same heard Paul speak: who stedfastly beholding him, and perceiving that he had faith to be healed,","ref":"Acts 14:9","synthesized":"This man was listening to the words of Paul, who looked intently at him and saw that he had faith to be healed.","sources":{"KJV":{"text":"The same heard Paul speak: who stedfastly beholding him, and perceiving that he had faith to be healed,"},"BSB":{"text":"This man was listening to the words of Paul, who looked intently at him and saw that he had faith to be healed."}},"definableWords":["man","saw","faith"],"peopleInVerse":["Paul"]},"10":{"text":"Said with a loud voice, Stand upright on thy feet. And he leaped and walked.","ref":"Acts 14:10","synthesized":"In a loud voice Paul called out, “Stand up on your feet!” And the man jumped up and began to walk.","sources":{"KJV":{"text":"Said with a loud voice, Stand upright on thy feet. And he leaped and walked."},"BSB":{"text":"In a loud voice Paul called out, “Stand up on your feet!” And the man jumped up and began to walk."}},"definableWords":["voice","stand","man","walk"],"peopleInVerse":["Paul"]},"11":{"text":"And when the people saw what Paul had done, they lifted up their voices, saying in the speech of Lycaonia, The gods are come down to us in the likeness of men.","ref":"Acts 14:11","synthesized":"When the crowds saw what Paul had done, they lifted up their voices in the Lycaonian language: “The gods have come down to us in human form!”","sources":{"KJV":{"text":"And when the people saw what Paul had done, they lifted up their voices, saying in the speech of Lycaonia, The gods are come down to us in the likeness of men."},"BSB":{"text":"When the crowds saw what Paul had done, they lifted up their voices in the Lycaonian language: “The gods have come down to us in human form!”"}},"definableWords":["saw","form"],"peopleInVerse":["Paul"]},"12":{"text":"And they called Barnabas, Jupiter; and Paul, Mercurius, because he was the chief speaker.","ref":"Acts 14:12","synthesized":"Barnabas they called Zeus, and Paul they called Hermes, because he was the chief speaker.","sources":{"KJV":{"text":"And they called Barnabas, Jupiter; and Paul, Mercurius, because he was the chief speaker."},"BSB":{"text":"Barnabas they called Zeus, and Paul they called Hermes, because he was the chief speaker."}},"definableWords":[],"peopleInVerse":["Barnabas","Paul"]},"13":{"text":"Then the priest of Jupiter, which was before their city, brought oxen and garlands unto the gates, and would have done sacrifice with the people.","ref":"Acts 14:13","synthesized":"The priest of Zeus, whose temple was just outside the city, brought bulls and wreaths to the city gates, hoping to offer a sacrifice along with the crowds.","sources":{"KJV":{"text":"Then the priest of Jupiter, which was before their city, brought oxen and garlands unto the gates, and would have done sacrifice with the people."},"BSB":{"text":"The priest of Zeus, whose temple was just outside the city, brought bulls and wreaths to the city gates, hoping to offer a sacrifice along with the crowds."}},"definableWords":["priest","temple","sacrifice"],"peopleInVerse":[]},"14":{"text":"Which when the apostles, Barnabas and Paul, heard of, they rent their clothes, and ran in among the people, crying out,","ref":"Acts 14:14","synthesized":"But when the apostles Barnabas and Paul found out about this, they tore their clothes and rushed into the crowd, shouting,","sources":{"KJV":{"text":"Which when the apostles, Barnabas and Paul, heard of, they rent their clothes, and ran in among the people, crying out,"},"BSB":{"text":"But when the apostles Barnabas and Paul found out about this, they tore their clothes and rushed into the crowd, shouting,"}},"definableWords":[],"peopleInVerse":["Barnabas","Paul"]},"15":{"text":"And saying, Sirs, why do ye these things? We also are men of like passions with you, and preach unto you that ye should turn from these vanities unto the living God, which made heaven, and earth, and the sea, and all things that are therein:","ref":"Acts 14:15","synthesized":"“Men, why are you doing this? We too are only men, human like you. We are bringing you good news that you should turn from these worthless things to the living God, who made heaven and earth and sea and everything in them.","sources":{"KJV":{"text":"And saying, Sirs, why do ye these things? We also are men of like passions with you, and preach unto you that ye should turn from these vanities unto the living God, which made heaven, and earth, and the sea, and all things that are therein:"},"BSB":{"text":"“Men, why are you doing this? We too are only men, human like you. We are bringing you good news that you should turn from these worthless things to the living God, who made heaven and earth and sea and everything in them."}},"definableWords":["men","good","living","God","made","heaven","earth","sea"],"peopleInVerse":[]},"16":{"text":"Who in times past suffered all nations to walk in their own ways.","ref":"Acts 14:16","synthesized":"In past generations, He let all nations go their own way.","sources":{"KJV":{"text":"Who in times past suffered all nations to walk in their own ways."},"BSB":{"text":"In past generations, He let all nations go their own way."}},"definableWords":["nations","way"],"peopleInVerse":[]},"17":{"text":"Nevertheless he left not himself without witness, in that he did good, and gave us rain from heaven, and fruitful seasons, filling our hearts with food and gladness.","ref":"Acts 14:17","synthesized":"Yet He has not left Himself without testimony to His goodness: He gives you rain from heaven and fruitful seasons, filling your hearts with food and gladness.”","sources":{"KJV":{"text":"Nevertheless he left not himself without witness, in that he did good, and gave us rain from heaven, and fruitful seasons, filling our hearts with food and gladness."},"BSB":{"text":"Yet He has not left Himself without testimony to His goodness: He gives you rain from heaven and fruitful seasons, filling your hearts with food and gladness.”"}},"definableWords":["heaven","fruitful"],"peopleInVerse":[]},"18":{"text":"And with these sayings scarce restrained they the people, that they had not done sacrifice unto them.","ref":"Acts 14:18","synthesized":"Even with these words, Paul and Barnabas could hardly stop the crowds from sacrificing to them.","sources":{"KJV":{"text":"And with these sayings scarce restrained they the people, that they had not done sacrifice unto them."},"BSB":{"text":"Even with these words, Paul and Barnabas could hardly stop the crowds from sacrificing to them."}},"definableWords":[],"peopleInVerse":["Paul","Barnabas"]},"19":{"text":"And there came thither certain Jews from Antioch and Iconium, who persuaded the people, and, having stoned Paul, drew him out of the city, supposing he had been dead.","ref":"Acts 14:19","synthesized":"Then some Jews arrived from Antioch and Iconium and won over the crowds. They stoned Paul and dragged him outside the city, presuming he was dead.","sources":{"KJV":{"text":"And there came thither certain Jews from Antioch and Iconium, who persuaded the people, and, having stoned Paul, drew him out of the city, supposing he had been dead."},"BSB":{"text":"Then some Jews arrived from Antioch and Iconium and won over the crowds. They stoned Paul and dragged him outside the city, presuming he was dead."}},"definableWords":[],"peopleInVerse":["Paul"]},"20":{"text":"Howbeit, as the disciples stood round about him, he rose up, and came into the city: and the next day he departed with Barnabas to Derbe.","ref":"Acts 14:20","synthesized":"But after the disciples had gathered around him, he got up and went back into the city. And the next day he left with Barnabas for Derbe.","sources":{"KJV":{"text":"Howbeit, as the disciples stood round about him, he rose up, and came into the city: and the next day he departed with Barnabas to Derbe."},"BSB":{"text":"But after the disciples had gathered around him, he got up and went back into the city. And the next day he left with Barnabas for Derbe."}},"definableWords":["day"],"peopleInVerse":["Barnabas"]},"21":{"text":"And when they had preached the gospel to that city, and had taught many, they returned again to Lystra, and to Iconium, and Antioch,","ref":"Acts 14:21","synthesized":"They preached the gospel to that city and made many disciples. Then they returned to Lystra, Iconium, and Antioch,","sources":{"KJV":{"text":"And when they had preached the gospel to that city, and had taught many, they returned again to Lystra, and to Iconium, and Antioch,"},"BSB":{"text":"They preached the gospel to that city and made many disciples. Then they returned to Lystra, Iconium, and Antioch,"}},"definableWords":["gospel","made"],"peopleInVerse":[]},"22":{"text":"Confirming the souls of the disciples, and exhorting them to continue in the faith, and that we must through much tribulation enter into the kingdom of God.","ref":"Acts 14:22","synthesized":"strengthening the souls of the disciples and encouraging them to continue in the faith. “We must endure many hardships to enter the kingdom of God,” they said.","sources":{"KJV":{"text":"Confirming the souls of the disciples, and exhorting them to continue in the faith, and that we must through much tribulation enter into the kingdom of God."},"BSB":{"text":"strengthening the souls of the disciples and encouraging them to continue in the faith. “We must endure many hardships to enter the kingdom of God,” they said."}},"definableWords":["faith","kingdom","God"],"peopleInVerse":[]},"23":{"text":"And when they had ordained them elders in every church, and had prayed with fasting, they commended them to the Lord, on whom they believed.","ref":"Acts 14:23","synthesized":"Paul and Barnabas appointed elders for them in each church, praying and fasting as they entrusted them to the Lord, in whom they had believed.","sources":{"KJV":{"text":"And when they had ordained them elders in every church, and had prayed with fasting, they commended them to the Lord, on whom they believed."},"BSB":{"text":"Paul and Barnabas appointed elders for them in each church, praying and fasting as they entrusted them to the Lord, in whom they had believed."}},"definableWords":["church","Lord","believed"],"peopleInVerse":["Paul","Barnabas"]},"24":{"text":"And after they had passed throughout Pisidia, they came to Pamphylia.","ref":"Acts 14:24","synthesized":"After passing through Pisidia, they came to Pamphylia.","sources":{"KJV":{"text":"And after they had passed throughout Pisidia, they came to Pamphylia."},"BSB":{"text":"After passing through Pisidia, they came to Pamphylia."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"And when they had preached the word in Perga, they went down into Attalia:","ref":"Acts 14:25","synthesized":"And when they had spoken the word in Perga, they went down to Attalia.","sources":{"KJV":{"text":"And when they had preached the word in Perga, they went down into Attalia:"},"BSB":{"text":"And when they had spoken the word in Perga, they went down to Attalia."}},"definableWords":["word"],"peopleInVerse":[]},"26":{"text":"And thence sailed to Antioch, from whence they had been recommended to the grace of God for the work which they fulfilled.","ref":"Acts 14:26","synthesized":"From Attalia they sailed to Antioch, where they had been commended to the grace of God for the work they had just completed.","sources":{"KJV":{"text":"And thence sailed to Antioch, from whence they had been recommended to the grace of God for the work which they fulfilled."},"BSB":{"text":"From Attalia they sailed to Antioch, where they had been commended to the grace of God for the work they had just completed."}},"definableWords":["grace","God","work"],"peopleInVerse":[]},"27":{"text":"And when they were come, and had gathered the church together, they rehearsed all that God had done with them, and how he had opened the door of faith unto the Gentiles.","ref":"Acts 14:27","synthesized":"When they arrived, they gathered the church together and reported all that God had done through them, and how He had opened the door of faith to the Gentiles.","sources":{"KJV":{"text":"And when they were come, and had gathered the church together, they rehearsed all that God had done with them, and how he had opened the door of faith unto the Gentiles."},"BSB":{"text":"When they arrived, they gathered the church together and reported all that God had done through them, and how He had opened the door of faith to the Gentiles."}},"definableWords":["church","God","faith"],"peopleInVerse":[]},"28":{"text":"And there they abode long time with the disciples.","ref":"Acts 14:28","synthesized":"And they spent a long time there with the disciples.","sources":{"KJV":{"text":"And there they abode long time with the disciples."},"BSB":{"text":"And they spent a long time there with the disciples."}},"definableWords":[],"peopleInVerse":[]}}},"15":{"chapter":"15","title":"THE JERUSALEM COUNCIL","verses":{"1":{"text":"And certain men which came down from Judaea taught the brethren, and said, Except ye be circumcised after the manner of Moses, ye cannot be saved.","ref":"Acts 15:1","synthesized":"Then some men came down from Judea and were teaching the brothers, “Unless you are circumcised according to the custom of Moses, you cannot be saved.”","sources":{"KJV":{"text":"And certain men which came down from Judaea taught the brethren, and said, Except ye be circumcised after the manner of Moses, ye cannot be saved."},"BSB":{"text":"Then some men came down from Judea and were teaching the brothers, “Unless you are circumcised according to the custom of Moses, you cannot be saved.”"}},"definableWords":["men","Judea","circumcised"],"peopleInVerse":["Moses"]},"2":{"text":"When therefore Paul and Barnabas had no small dissension and disputation with them, they determined that Paul and Barnabas, and certain other of them, should go up to Jerusalem unto the apostles and elders about this question.","ref":"Acts 15:2","synthesized":"And after engaging these men in sharp debate, Paul and Barnabas were appointed, along with some other believers, to go up to Jerusalem to see the apostles and elders about this question.","sources":{"KJV":{"text":"When therefore Paul and Barnabas had no small dissension and disputation with them, they determined that Paul and Barnabas, and certain other of them, should go up to Jerusalem unto the apostles and elders about this question."},"BSB":{"text":"And after engaging these men in sharp debate, Paul and Barnabas were appointed, along with some other believers, to go up to Jerusalem to see the apostles and elders about this question."}},"definableWords":["men","Jerusalem","see"],"peopleInVerse":["Paul","Barnabas"]},"3":{"text":"And being brought on their way by the church, they passed through Phenice and Samaria, declaring the conversion of the Gentiles: and they caused great joy unto all the brethren.","ref":"Acts 15:3","synthesized":"Sent on their way by the church, they passed through Phoenicia and Samaria, recounting the conversion of the Gentiles and bringing great joy to all the brothers.","sources":{"KJV":{"text":"And being brought on their way by the church, they passed through Phenice and Samaria, declaring the conversion of the Gentiles: and they caused great joy unto all the brethren."},"BSB":{"text":"Sent on their way by the church, they passed through Phoenicia and Samaria, recounting the conversion of the Gentiles and bringing great joy to all the brothers."}},"definableWords":["way","church","Samaria","great","joy"],"peopleInVerse":[]},"4":{"text":"And when they were come to Jerusalem, they were received of the church, and of the apostles and elders, and they declared all things that God had done with them.","ref":"Acts 15:4","synthesized":"On their arrival in Jerusalem, they were welcomed by the church and apostles and elders, to whom they reported all that God had done through them.","sources":{"KJV":{"text":"And when they were come to Jerusalem, they were received of the church, and of the apostles and elders, and they declared all things that God had done with them."},"BSB":{"text":"On their arrival in Jerusalem, they were welcomed by the church and apostles and elders, to whom they reported all that God had done through them."}},"definableWords":["Jerusalem","church","God"],"peopleInVerse":[]},"5":{"text":"But there rose up certain of the sect of the Pharisees which believed, saying, That it was needful to circumcise them, and to command them to keep the law of Moses.","ref":"Acts 15:5","synthesized":"But some believers from the party of the Pharisees stood up and declared, “The Gentiles must be circumcised and required to obey the law of Moses.”","sources":{"KJV":{"text":"But there rose up certain of the sect of the Pharisees which believed, saying, That it was needful to circumcise them, and to command them to keep the law of Moses."},"BSB":{"text":"But some believers from the party of the Pharisees stood up and declared, “The Gentiles must be circumcised and required to obey the law of Moses.”"}},"definableWords":["circumcised","law"],"peopleInVerse":["Moses"]},"6":{"text":"And the apostles and elders came together for to consider of this matter.","ref":"Acts 15:6","synthesized":"So the apostles and elders met to look into this matter.","sources":{"KJV":{"text":"And the apostles and elders came together for to consider of this matter."},"BSB":{"text":"So the apostles and elders met to look into this matter."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And when there had been much disputing, Peter rose up, and said unto them, Men and brethren, ye know how that a good while ago God made choice among us, that the Gentiles by my mouth should hear the word of the gospel, and believe.","ref":"Acts 15:7","synthesized":"After much discussion, Peter got up and said to them, “Brothers, you know that in the early days God made a choice among you that the Gentiles would hear from my lips the message of the gospel and believe.","sources":{"KJV":{"text":"And when there had been much disputing, Peter rose up, and said unto them, Men and brethren, ye know how that a good while ago God made choice among us, that the Gentiles by my mouth should hear the word of the gospel, and believe."},"BSB":{"text":"After much discussion, Peter got up and said to them, “Brothers, you know that in the early days God made a choice among you that the Gentiles would hear from my lips the message of the gospel and believe."}},"definableWords":["days","God","made","hear","gospel"],"peopleInVerse":["Peter"]},"8":{"text":"And God, which knoweth the hearts, bare them witness, giving them the Holy Ghost, even as he did unto us;","ref":"Acts 15:8","synthesized":"And God, who knows the heart, showed His approval by giving the Holy Spirit to them, just as He did to us.","sources":{"KJV":{"text":"And God, which knoweth the hearts, bare them witness, giving them the Holy Ghost, even as he did unto us;"},"BSB":{"text":"And God, who knows the heart, showed His approval by giving the Holy Spirit to them, just as He did to us."}},"definableWords":["God","heart","holy","Spirit"],"peopleInVerse":[]},"9":{"text":"And put no difference between us and them, purifying their hearts by faith.","ref":"Acts 15:9","synthesized":"He made no distinction between us and them, for He cleansed their hearts by faith.","sources":{"KJV":{"text":"And put no difference between us and them, purifying their hearts by faith."},"BSB":{"text":"He made no distinction between us and them, for He cleansed their hearts by faith."}},"definableWords":["made","faith"],"peopleInVerse":[]},"10":{"text":"Now therefore why tempt ye God, to put a yoke upon the neck of the disciples, which neither our fathers nor we were able to bear?","ref":"Acts 15:10","synthesized":"Now then, why do you test God by placing on the necks of the disciples a yoke that neither we nor our fathers have been able to bear?","sources":{"KJV":{"text":"Now therefore why tempt ye God, to put a yoke upon the neck of the disciples, which neither our fathers nor we were able to bear?"},"BSB":{"text":"Now then, why do you test God by placing on the necks of the disciples a yoke that neither we nor our fathers have been able to bear?"}},"definableWords":["God","fathers"],"peopleInVerse":[]},"11":{"text":"But we believe that through the grace of the LORD Jesus Christ we shall be saved, even as they.","ref":"Acts 15:11","synthesized":"On the contrary, we believe it is through the grace of the Lord Jesus that we are saved, just as they are.”","sources":{"KJV":{"text":"But we believe that through the grace of the LORD Jesus Christ we shall be saved, even as they."},"BSB":{"text":"On the contrary, we believe it is through the grace of the Lord Jesus that we are saved, just as they are.”"}},"definableWords":["grace","Lord"],"peopleInVerse":["Jesus"]},"12":{"text":"Then all the multitude kept silence, and gave audience to Barnabas and Paul, declaring what miracles and wonders God had wrought among the Gentiles by them.","ref":"Acts 15:12","synthesized":"The whole assembly fell silent as they listened to Barnabas and Paul describing the signs and wonders God had done among the Gentiles through them.","sources":{"KJV":{"text":"Then all the multitude kept silence, and gave audience to Barnabas and Paul, declaring what miracles and wonders God had wrought among the Gentiles by them."},"BSB":{"text":"The whole assembly fell silent as they listened to Barnabas and Paul describing the signs and wonders God had done among the Gentiles through them."}},"definableWords":["God"],"peopleInVerse":["Barnabas","Paul"]},"13":{"text":"And after they had held their peace, James answered, saying, Men and brethren, hearken unto me:","ref":"Acts 15:13","synthesized":"When they had finished speaking, James declared, “Brothers, listen to me!","sources":{"KJV":{"text":"And after they had held their peace, James answered, saying, Men and brethren, hearken unto me:"},"BSB":{"text":"When they had finished speaking, James declared, “Brothers, listen to me!"}},"definableWords":[],"peopleInVerse":["James"]},"14":{"text":"Simeon hath declared how God at the first did visit the Gentiles, to take out of them a people for his name.","ref":"Acts 15:14","synthesized":"Simon has told us how God first visited the Gentiles to take from them a people to be His own.","sources":{"KJV":{"text":"Simeon hath declared how God at the first did visit the Gentiles, to take out of them a people for his name."},"BSB":{"text":"Simon has told us how God first visited the Gentiles to take from them a people to be His own."}},"definableWords":["God","people"],"peopleInVerse":[]},"15":{"text":"And to this agree the words of the prophets; as it is written,","ref":"Acts 15:15","synthesized":"The words of the prophets agree with this, as it is written:","sources":{"KJV":{"text":"And to this agree the words of the prophets; as it is written,"},"BSB":{"text":"The words of the prophets agree with this, as it is written:"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"After this I will return, and will build again the tabernacle of David, which is fallen down; and I will build again the ruins thereof, and I will set it up:","ref":"Acts 15:16","synthesized":"‘After this I will return and rebuild the fallen tent of David. Its ruins I will rebuild, and I will restore it,","sources":{"KJV":{"text":"After this I will return, and will build again the tabernacle of David, which is fallen down; and I will build again the ruins thereof, and I will set it up:"},"BSB":{"text":"‘After this I will return and rebuild the fallen tent of David. Its ruins I will rebuild, and I will restore it,"}},"definableWords":[],"peopleInVerse":["David"]},"17":{"text":"That the residue of men might seek after the Lord, and all the Gentiles, upon whom my name is called, saith the Lord, who doeth all these things.","ref":"Acts 15:17","synthesized":"so that the remnant of men may seek the Lord, and all the Gentiles who are called by My name, says the Lord who does these things","sources":{"KJV":{"text":"That the residue of men might seek after the Lord, and all the Gentiles, upon whom my name is called, saith the Lord, who doeth all these things."},"BSB":{"text":"so that the remnant of men may seek the Lord, and all the Gentiles who are called by My name, says the Lord who does these things"}},"definableWords":["remnant","men","seek","Lord","name"],"peopleInVerse":[]},"18":{"text":"Known unto God are all his works from the beginning of the world.","ref":"Acts 15:18","synthesized":"that have been known for ages.’","sources":{"KJV":{"text":"Known unto God are all his works from the beginning of the world."},"BSB":{"text":"that have been known for ages.’"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Wherefore my sentence is, that we trouble not them, which from among the Gentiles are turned to God:","ref":"Acts 15:19","synthesized":"It is my judgment, therefore, that we should not cause trouble for the Gentiles who are turning to God.","sources":{"KJV":{"text":"Wherefore my sentence is, that we trouble not them, which from among the Gentiles are turned to God:"},"BSB":{"text":"It is my judgment, therefore, that we should not cause trouble for the Gentiles who are turning to God."}},"definableWords":["judgment","God"],"peopleInVerse":[]},"20":{"text":"But that we write unto them, that they abstain from pollutions of idols, and from fornication, and from things strangled, and from blood.","ref":"Acts 15:20","synthesized":"Instead, we should write and tell them to abstain from food polluted by idols, from sexual immorality, from the meat of strangled animals, and from blood.","sources":{"KJV":{"text":"But that we write unto them, that they abstain from pollutions of idols, and from fornication, and from things strangled, and from blood."},"BSB":{"text":"Instead, we should write and tell them to abstain from food polluted by idols, from sexual immorality, from the meat of strangled animals, and from blood."}},"definableWords":["blood"],"peopleInVerse":[]},"21":{"text":"For Moses of old time hath in every city them that preach him, being read in the synagogues every sabbath day.","ref":"Acts 15:21","synthesized":"For Moses has been proclaimed in every city from ancient times and is read in the synagogues on every Sabbath.”","sources":{"KJV":{"text":"For Moses of old time hath in every city them that preach him, being read in the synagogues every sabbath day."},"BSB":{"text":"For Moses has been proclaimed in every city from ancient times and is read in the synagogues on every Sabbath.”"}},"definableWords":["Sabbath"],"peopleInVerse":["Moses"]},"22":{"text":"Then pleased it the apostles and elders, with the whole church, to send chosen men of their own company to Antioch with Paul and Barnabas; namely, Judas surnamed Barsabas, and Silas, chief men among the brethren:","ref":"Acts 15:22","synthesized":"Then the apostles and elders, with the whole church, decided to select men from among them to send to Antioch with Paul and Barnabas. They chose Judas called Barsabbas and Silas, two leaders among the brothers,","sources":{"KJV":{"text":"Then pleased it the apostles and elders, with the whole church, to send chosen men of their own company to Antioch with Paul and Barnabas; namely, Judas surnamed Barsabas, and Silas, chief men among the brethren:"},"BSB":{"text":"Then the apostles and elders, with the whole church, decided to select men from among them to send to Antioch with Paul and Barnabas. They chose Judas called Barsabbas and Silas, two leaders among the brothers,"}},"definableWords":["church","men"],"peopleInVerse":["Paul","Barnabas"]},"23":{"text":"And they wrote letters by them after this manner; The apostles and elders and brethren send greeting unto the brethren which are of the Gentiles in Antioch and Syria and Cilicia:","ref":"Acts 15:23","synthesized":"and sent them with this letter:  The apostles and the elders, your brothers,  To the brothers among the Gentiles in Antioch, Syria, and Cilicia:  Greetings.","sources":{"KJV":{"text":"And they wrote letters by them after this manner; The apostles and elders and brethren send greeting unto the brethren which are of the Gentiles in Antioch and Syria and Cilicia:"},"BSB":{"text":"and sent them with this letter:  The apostles and the elders, your brothers,  To the brothers among the Gentiles in Antioch, Syria, and Cilicia:  Greetings."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Forasmuch as we have heard, that certain which went out from us have troubled you with words, subverting your souls, saying, Ye must be circumcised, and keep the law: to whom we gave no such commandment:","ref":"Acts 15:24","synthesized":"It has come to our attention that some went out from us without our authorization and unsettled you, troubling your minds by what they said.","sources":{"KJV":{"text":"Forasmuch as we have heard, that certain which went out from us have troubled you with words, subverting your souls, saying, Ye must be circumcised, and keep the law: to whom we gave no such commandment:"},"BSB":{"text":"It has come to our attention that some went out from us without our authorization and unsettled you, troubling your minds by what they said."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"It seemed good unto us, being assembled with one accord, to send chosen men unto you with our beloved Barnabas and Paul,","ref":"Acts 15:25","synthesized":"So we all agreed to choose men to send to you along with our beloved Barnabas and Paul,","sources":{"KJV":{"text":"It seemed good unto us, being assembled with one accord, to send chosen men unto you with our beloved Barnabas and Paul,"},"BSB":{"text":"So we all agreed to choose men to send to you along with our beloved Barnabas and Paul,"}},"definableWords":["men"],"peopleInVerse":["Barnabas","Paul"]},"26":{"text":"Men that have hazarded their lives for the name of our Lord Jesus Christ.","ref":"Acts 15:26","synthesized":"men who have risked their lives for the name of our Lord Jesus Christ.","sources":{"KJV":{"text":"Men that have hazarded their lives for the name of our Lord Jesus Christ."},"BSB":{"text":"men who have risked their lives for the name of our Lord Jesus Christ."}},"definableWords":["men","name","Lord","Christ"],"peopleInVerse":["Jesus"]},"27":{"text":"We have sent therefore Judas and Silas, who shall also tell you the same things by mouth.","ref":"Acts 15:27","synthesized":"Therefore we are sending Judas and Silas to tell you in person the same things we are writing.","sources":{"KJV":{"text":"We have sent therefore Judas and Silas, who shall also tell you the same things by mouth."},"BSB":{"text":"Therefore we are sending Judas and Silas to tell you in person the same things we are writing."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"For it seemed good to the Holy Ghost, and to us, to lay upon you no greater burden than these necessary things;","ref":"Acts 15:28","synthesized":"It seemed good to the Holy Spirit and to us not to burden you with anything beyond these essential requirements:","sources":{"KJV":{"text":"For it seemed good to the Holy Ghost, and to us, to lay upon you no greater burden than these necessary things;"},"BSB":{"text":"It seemed good to the Holy Spirit and to us not to burden you with anything beyond these essential requirements:"}},"definableWords":["good","holy","Spirit"],"peopleInVerse":[]},"29":{"text":"That ye abstain from meats offered to idols, and from blood, and from things strangled, and from fornication: from which if ye keep yourselves, ye shall do well. Fare ye well.","ref":"Acts 15:29","synthesized":"You must abstain from food sacrificed to idols, from blood, from the meat of strangled animals, and from sexual immorality. You will do well to avoid these things.  Farewell.","sources":{"KJV":{"text":"That ye abstain from meats offered to idols, and from blood, and from things strangled, and from fornication: from which if ye keep yourselves, ye shall do well. Fare ye well."},"BSB":{"text":"You must abstain from food sacrificed to idols, from blood, from the meat of strangled animals, and from sexual immorality. You will do well to avoid these things.  Farewell."}},"definableWords":["blood"],"peopleInVerse":[]},"30":{"text":"So when they were dismissed, they came to Antioch: and when they had gathered the multitude together, they delivered the epistle:","ref":"Acts 15:30","synthesized":"So the men were sent off and went down to Antioch, where they assembled the congregation and delivered the letter.","sources":{"KJV":{"text":"So when they were dismissed, they came to Antioch: and when they had gathered the multitude together, they delivered the epistle:"},"BSB":{"text":"So the men were sent off and went down to Antioch, where they assembled the congregation and delivered the letter."}},"definableWords":["men"],"peopleInVerse":[]},"31":{"text":"Which when they had read, they rejoiced for the consolation.","ref":"Acts 15:31","synthesized":"When the people read it, they rejoiced at its encouraging message.","sources":{"KJV":{"text":"Which when they had read, they rejoiced for the consolation."},"BSB":{"text":"When the people read it, they rejoiced at its encouraging message."}},"definableWords":["people"],"peopleInVerse":[]},"32":{"text":"And Judas and Silas, being prophets also themselves, exhorted the brethren with many words, and confirmed them.","ref":"Acts 15:32","synthesized":"Judas and Silas, who themselves were prophets, said much to encourage and strengthen the brothers.","sources":{"KJV":{"text":"And Judas and Silas, being prophets also themselves, exhorted the brethren with many words, and confirmed them."},"BSB":{"text":"Judas and Silas, who themselves were prophets, said much to encourage and strengthen the brothers."}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"And after they had tarried there a space, they were let go in peace from the brethren unto the apostles.","ref":"Acts 15:33","synthesized":"After spending some time there, they were sent off by the brothers in peace to return to those who had sent them.","sources":{"KJV":{"text":"And after they had tarried there a space, they were let go in peace from the brethren unto the apostles."},"BSB":{"text":"After spending some time there, they were sent off by the brothers in peace to return to those who had sent them."}},"definableWords":["peace"],"peopleInVerse":[]},"34":{"text":"Notwithstanding it pleased Silas to abide there still.","ref":"Acts 15:34","synthesized":"Notwithstanding it pleased Silas to abide there still.","sources":{"KJV":{"text":"Notwithstanding it pleased Silas to abide there still."}},"definableWords":["abide"],"peopleInVerse":[]},"35":{"text":"Paul also and Barnabas continued in Antioch, teaching and preaching the word of the Lord, with many others also.","ref":"Acts 15:35","synthesized":"But Paul and Barnabas remained at Antioch, along with many others, teaching and preaching the word of the Lord.","sources":{"KJV":{"text":"Paul also and Barnabas continued in Antioch, teaching and preaching the word of the Lord, with many others also."},"BSB":{"text":"But Paul and Barnabas remained at Antioch, along with many others, teaching and preaching the word of the Lord."}},"definableWords":["word","Lord"],"peopleInVerse":["Paul","Barnabas"]},"36":{"text":"And some days after Paul said unto Barnabas, Let us go again and visit our brethren in every city where we have preached the word of the LORD, and see how they do.","ref":"Acts 15:36","synthesized":"Some time later Paul said to Barnabas, “Let us go back and visit the brothers in every town where we proclaimed the word of the Lord, to see how they are doing.”","sources":{"KJV":{"text":"And some days after Paul said unto Barnabas, Let us go again and visit our brethren in every city where we have preached the word of the LORD, and see how they do."},"BSB":{"text":"Some time later Paul said to Barnabas, “Let us go back and visit the brothers in every town where we proclaimed the word of the Lord, to see how they are doing.”"}},"definableWords":["word","Lord","see"],"peopleInVerse":["Paul","Barnabas"]},"37":{"text":"And Barnabas determined to take with them John, whose surname was Mark.","ref":"Acts 15:37","synthesized":"Barnabas wanted to take John, also called Mark.","sources":{"KJV":{"text":"And Barnabas determined to take with them John, whose surname was Mark."},"BSB":{"text":"Barnabas wanted to take John, also called Mark."}},"definableWords":[],"peopleInVerse":["Barnabas","John"]},"38":{"text":"But Paul thought not good to take him with them, who departed from them from Pamphylia, and went not with them to the work.","ref":"Acts 15:38","synthesized":"But Paul thought it best not to take him, because he had deserted them in Pamphylia and had not accompanied them in the work.","sources":{"KJV":{"text":"But Paul thought not good to take him with them, who departed from them from Pamphylia, and went not with them to the work."},"BSB":{"text":"But Paul thought it best not to take him, because he had deserted them in Pamphylia and had not accompanied them in the work."}},"definableWords":["work"],"peopleInVerse":["Paul"]},"39":{"text":"And the contention was so sharp between them, that they departed asunder one from the other: and so Barnabas took Mark, and sailed unto Cyprus;","ref":"Acts 15:39","synthesized":"Their disagreement was so sharp that they parted company. Barnabas took Mark and sailed for Cyprus,","sources":{"KJV":{"text":"And the contention was so sharp between them, that they departed asunder one from the other: and so Barnabas took Mark, and sailed unto Cyprus;"},"BSB":{"text":"Their disagreement was so sharp that they parted company. Barnabas took Mark and sailed for Cyprus,"}},"definableWords":[],"peopleInVerse":["Barnabas"]},"40":{"text":"And Paul chose Silas, and departed, being recommended by the brethren unto the grace of God.","ref":"Acts 15:40","synthesized":"but Paul chose Silas and left, commended by the brothers to the grace of the Lord.","sources":{"KJV":{"text":"And Paul chose Silas, and departed, being recommended by the brethren unto the grace of God."},"BSB":{"text":"but Paul chose Silas and left, commended by the brothers to the grace of the Lord."}},"definableWords":["grace","Lord"],"peopleInVerse":["Paul"]},"41":{"text":"And he went through Syria and Cilicia, confirming the churches.","ref":"Acts 15:41","synthesized":"And he traveled through Syria and Cilicia, strengthening the churches.","sources":{"KJV":{"text":"And he went through Syria and Cilicia, confirming the churches."},"BSB":{"text":"And he traveled through Syria and Cilicia, strengthening the churches."}},"definableWords":[],"peopleInVerse":[]}}},"16":{"chapter":"16","title":"THE PHILIPPIAN JAILER","verses":{"1":{"text":"Then came he to Derbe and Lystra: and, behold, a certain disciple was there, named Timotheus, the son of a certain woman, which was a Jewess, and believed; but his father was a Greek:","ref":"Acts 16:1","synthesized":"Paul came to Derbe and then to Lystra, where he found a disciple named Timothy, the son of a believing Jewish woman and a Greek father.","sources":{"KJV":{"text":"Then came he to Derbe and Lystra: and, behold, a certain disciple was there, named Timotheus, the son of a certain woman, which was a Jewess, and believed; but his father was a Greek:"},"BSB":{"text":"Paul came to Derbe and then to Lystra, where he found a disciple named Timothy, the son of a believing Jewish woman and a Greek father."}},"definableWords":["disciple","son","woman","Greek","father"],"peopleInVerse":["Paul"]},"2":{"text":"Which was well reported of by the brethren that were at Lystra and Iconium.","ref":"Acts 16:2","synthesized":"The brothers in Lystra and Iconium spoke well of him.","sources":{"KJV":{"text":"Which was well reported of by the brethren that were at Lystra and Iconium."},"BSB":{"text":"The brothers in Lystra and Iconium spoke well of him."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Him would Paul have to go forth with him; and took and circumcised him because of the Jews which were in those quarters: for they knew all that his father was a Greek.","ref":"Acts 16:3","synthesized":"Paul wanted Timothy to accompany him, so he took him and circumcised him on account of the Jews in that area, for they all knew that his father was a Greek.","sources":{"KJV":{"text":"Him would Paul have to go forth with him; and took and circumcised him because of the Jews which were in those quarters: for they knew all that his father was a Greek."},"BSB":{"text":"Paul wanted Timothy to accompany him, so he took him and circumcised him on account of the Jews in that area, for they all knew that his father was a Greek."}},"definableWords":["circumcised","father","Greek"],"peopleInVerse":["Paul"]},"4":{"text":"And as they went through the cities, they delivered them the decrees for to keep, that were ordained of the apostles and elders which were at Jerusalem.","ref":"Acts 16:4","synthesized":"As they went from town to town, they delivered the decisions handed down by the apostles and elders in Jerusalem for the people to obey.","sources":{"KJV":{"text":"And as they went through the cities, they delivered them the decrees for to keep, that were ordained of the apostles and elders which were at Jerusalem."},"BSB":{"text":"As they went from town to town, they delivered the decisions handed down by the apostles and elders in Jerusalem for the people to obey."}},"definableWords":["Jerusalem","people"],"peopleInVerse":[]},"5":{"text":"And so were the churches established in the faith, and increased in number daily.","ref":"Acts 16:5","synthesized":"So the churches were strengthened in the faith and grew daily in numbers.","sources":{"KJV":{"text":"And so were the churches established in the faith, and increased in number daily."},"BSB":{"text":"So the churches were strengthened in the faith and grew daily in numbers."}},"definableWords":["faith"],"peopleInVerse":[]},"6":{"text":"Now when they had gone throughout Phrygia and the region of Galatia, and were forbidden of the Holy Ghost to preach the word in Asia,","ref":"Acts 16:6","synthesized":"After the Holy Spirit had prevented them from speaking the word in the province of Asia, they traveled through the region of Phrygia and Galatia.","sources":{"KJV":{"text":"Now when they had gone throughout Phrygia and the region of Galatia, and were forbidden of the Holy Ghost to preach the word in Asia,"},"BSB":{"text":"After the Holy Spirit had prevented them from speaking the word in the province of Asia, they traveled through the region of Phrygia and Galatia."}},"definableWords":["holy","Spirit","word"],"peopleInVerse":[]},"7":{"text":"After they were come to Mysia, they assayed to go into Bithynia: but the Spirit suffered them not.","ref":"Acts 16:7","synthesized":"And when they came to the border of Mysia, they tried to enter Bithynia, but the Spirit of Jesus would not permit them.","sources":{"KJV":{"text":"After they were come to Mysia, they assayed to go into Bithynia: but the Spirit suffered them not."},"BSB":{"text":"And when they came to the border of Mysia, they tried to enter Bithynia, but the Spirit of Jesus would not permit them."}},"definableWords":["Spirit"],"peopleInVerse":["Jesus"]},"8":{"text":"And they passing by Mysia came down to Troas.","ref":"Acts 16:8","synthesized":"So they passed by Mysia and went down to Troas.","sources":{"KJV":{"text":"And they passing by Mysia came down to Troas."},"BSB":{"text":"So they passed by Mysia and went down to Troas."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And a vision appeared to Paul in the night; There stood a man of Macedonia, and prayed him, saying, Come over into Macedonia, and help us.","ref":"Acts 16:9","synthesized":"During the night, Paul had a vision of a man of Macedonia standing and pleading with him, “Come over to Macedonia and help us.”","sources":{"KJV":{"text":"And a vision appeared to Paul in the night; There stood a man of Macedonia, and prayed him, saying, Come over into Macedonia, and help us."},"BSB":{"text":"During the night, Paul had a vision of a man of Macedonia standing and pleading with him, “Come over to Macedonia and help us.”"}},"definableWords":["night","man"],"peopleInVerse":["Paul"]},"10":{"text":"And after he had seen the vision, immediately we endeavoured to go into Macedonia, assuredly gathering that the Lord had called us for to preach the gospel unto them.","ref":"Acts 16:10","synthesized":"As soon as Paul had seen the vision, we got ready to leave for Macedonia, concluding that God had called us to preach the gospel to them.","sources":{"KJV":{"text":"And after he had seen the vision, immediately we endeavoured to go into Macedonia, assuredly gathering that the Lord had called us for to preach the gospel unto them."},"BSB":{"text":"As soon as Paul had seen the vision, we got ready to leave for Macedonia, concluding that God had called us to preach the gospel to them."}},"definableWords":["God","gospel"],"peopleInVerse":["Paul"]},"11":{"text":"Therefore loosing from Troas, we came with a straight course to Samothracia, and the next day to Neapolis;","ref":"Acts 16:11","synthesized":"We sailed from Troas straight to Samothrace, and the following day on to Neapolis.","sources":{"KJV":{"text":"Therefore loosing from Troas, we came with a straight course to Samothracia, and the next day to Neapolis;"},"BSB":{"text":"We sailed from Troas straight to Samothrace, and the following day on to Neapolis."}},"definableWords":["day"],"peopleInVerse":[]},"12":{"text":"And from thence to Philippi, which is the chief city of that part of Macedonia, and a colony: and we were in that city abiding certain days.","ref":"Acts 16:12","synthesized":"From there we went to the Roman colony of Philippi, the leading city of that district of Macedonia. And we stayed there several days.","sources":{"KJV":{"text":"And from thence to Philippi, which is the chief city of that part of Macedonia, and a colony: and we were in that city abiding certain days."},"BSB":{"text":"From there we went to the Roman colony of Philippi, the leading city of that district of Macedonia. And we stayed there several days."}},"definableWords":["days"],"peopleInVerse":[]},"13":{"text":"And on the sabbath we went out of the city by a river side, where prayer was wont to be made; and we sat down, and spake unto the women which resorted thither.","ref":"Acts 16:13","synthesized":"On the Sabbath we went outside the city gate along the river, where it was customary to find a place of prayer. After sitting down, we spoke to the women who had gathered there.","sources":{"KJV":{"text":"And on the sabbath we went out of the city by a river side, where prayer was wont to be made; and we sat down, and spake unto the women which resorted thither."},"BSB":{"text":"On the Sabbath we went outside the city gate along the river, where it was customary to find a place of prayer. After sitting down, we spoke to the women who had gathered there."}},"definableWords":["Sabbath","prayer","women"],"peopleInVerse":[]},"14":{"text":"And a certain woman named Lydia, a seller of purple, of the city of Thyatira, which worshipped God, heard us: whose heart the Lord opened, that she attended unto the things which were spoken of Paul.","ref":"Acts 16:14","synthesized":"Among those listening was a woman named Lydia, a dealer in purple cloth from the city of Thyatira, who was a worshiper of God. The Lord opened her heart to respond to Paul’s message.","sources":{"KJV":{"text":"And a certain woman named Lydia, a seller of purple, of the city of Thyatira, which worshipped God, heard us: whose heart the Lord opened, that she attended unto the things which were spoken of Paul."},"BSB":{"text":"Among those listening was a woman named Lydia, a dealer in purple cloth from the city of Thyatira, who was a worshiper of God. The Lord opened her heart to respond to Paul’s message."}},"definableWords":["woman","God","Lord","heart"],"peopleInVerse":["Paul"]},"15":{"text":"And when she was baptized, and her household, she besought us, saying, If ye have judged me to be faithful to the Lord, come into my house, and abide there. And she constrained us.","ref":"Acts 16:15","synthesized":"And when she and her household had been baptized, she urged us, “If you consider me a believer in the Lord, come and stay at my house.” And she persuaded us.","sources":{"KJV":{"text":"And when she was baptized, and her household, she besought us, saying, If ye have judged me to be faithful to the Lord, come into my house, and abide there. And she constrained us."},"BSB":{"text":"And when she and her household had been baptized, she urged us, “If you consider me a believer in the Lord, come and stay at my house.” And she persuaded us."}},"definableWords":["Lord","house"],"peopleInVerse":[]},"16":{"text":"And it came to pass, as we went to prayer, a certain damsel possessed with a spirit of divination met us, which brought her masters much gain by soothsaying:","ref":"Acts 16:16","synthesized":"One day as we were going to the place of prayer, we were met by a slave girl with a spirit of divination, who earned a large income for her masters by fortune-telling.","sources":{"KJV":{"text":"And it came to pass, as we went to prayer, a certain damsel possessed with a spirit of divination met us, which brought her masters much gain by soothsaying:"},"BSB":{"text":"One day as we were going to the place of prayer, we were met by a slave girl with a spirit of divination, who earned a large income for her masters by fortune-telling."}},"definableWords":["one","day","prayer","spirit"],"peopleInVerse":[]},"17":{"text":"The same followed Paul and us, and cried, saying, These men are the servants of the most high God, which shew unto us the way of salvation.","ref":"Acts 16:17","synthesized":"This girl followed Paul and the rest of us, shouting, “These men are servants of the Most High God, who are proclaiming to you the way of salvation!”","sources":{"KJV":{"text":"The same followed Paul and us, and cried, saying, These men are the servants of the most high God, which shew unto us the way of salvation."},"BSB":{"text":"This girl followed Paul and the rest of us, shouting, “These men are servants of the Most High God, who are proclaiming to you the way of salvation!”"}},"definableWords":["rest","men","servants","God","way","salvation"],"peopleInVerse":["Paul"]},"18":{"text":"And this did she many days. But Paul, being grieved, turned and said to the spirit, I command thee in the name of Jesus Christ to come out of her. And he came out the same hour.","ref":"Acts 16:18","synthesized":"She continued this for many days. Eventually Paul grew so aggravated that he turned and said to the spirit, “In the name of Jesus Christ I command you to come out of her!” And the spirit left her at that very moment.","sources":{"KJV":{"text":"And this did she many days. But Paul, being grieved, turned and said to the spirit, I command thee in the name of Jesus Christ to come out of her. And he came out the same hour."},"BSB":{"text":"She continued this for many days. Eventually Paul grew so aggravated that he turned and said to the spirit, “In the name of Jesus Christ I command you to come out of her!” And the spirit left her at that very moment."}},"definableWords":["days","spirit","name","Christ"],"peopleInVerse":["Paul","Jesus"]},"19":{"text":"And when her masters saw that the hope of their gains was gone, they caught Paul and Silas, and drew them into the marketplace unto the rulers,","ref":"Acts 16:19","synthesized":"When the girl’s owners saw that their hope of making money was gone, they seized Paul and Silas and dragged them before the authorities in the marketplace.","sources":{"KJV":{"text":"And when her masters saw that the hope of their gains was gone, they caught Paul and Silas, and drew them into the marketplace unto the rulers,"},"BSB":{"text":"When the girl’s owners saw that their hope of making money was gone, they seized Paul and Silas and dragged them before the authorities in the marketplace."}},"definableWords":["saw","hope"],"peopleInVerse":["Paul"]},"20":{"text":"And brought them to the magistrates, saying, These men, being Jews, do exceedingly trouble our city,","ref":"Acts 16:20","synthesized":"They brought them to the magistrates and said, “These men are Jews and are throwing our city into turmoil","sources":{"KJV":{"text":"And brought them to the magistrates, saying, These men, being Jews, do exceedingly trouble our city,"},"BSB":{"text":"They brought them to the magistrates and said, “These men are Jews and are throwing our city into turmoil"}},"definableWords":["men"],"peopleInVerse":[]},"21":{"text":"And teach customs, which are not lawful for us to receive, neither to observe, being Romans.","ref":"Acts 16:21","synthesized":"by promoting customs that are unlawful for us Romans to adopt or practice.”","sources":{"KJV":{"text":"And teach customs, which are not lawful for us to receive, neither to observe, being Romans."},"BSB":{"text":"by promoting customs that are unlawful for us Romans to adopt or practice.”"}},"definableWords":["or"],"peopleInVerse":[]},"22":{"text":"And the multitude rose up together against them: and the magistrates rent off their clothes, and commanded to beat them.","ref":"Acts 16:22","synthesized":"The crowd joined in the attack against Paul and Silas, and the magistrates ordered that they be stripped and beaten with rods.","sources":{"KJV":{"text":"And the multitude rose up together against them: and the magistrates rent off their clothes, and commanded to beat them."},"BSB":{"text":"The crowd joined in the attack against Paul and Silas, and the magistrates ordered that they be stripped and beaten with rods."}},"definableWords":[],"peopleInVerse":["Paul"]},"23":{"text":"And when they had laid many stripes upon them, they cast them into prison, charging the jailor to keep them safely:","ref":"Acts 16:23","synthesized":"And after striking them with many blows, they threw them into prison and ordered the jailer to guard them securely.","sources":{"KJV":{"text":"And when they had laid many stripes upon them, they cast them into prison, charging the jailor to keep them safely:"},"BSB":{"text":"And after striking them with many blows, they threw them into prison and ordered the jailer to guard them securely."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Who, having received such a charge, thrust them into the inner prison, and made their feet fast in the stocks.","ref":"Acts 16:24","synthesized":"On receiving this order, he placed them in the inner cell and fastened their feet in the stocks.","sources":{"KJV":{"text":"Who, having received such a charge, thrust them into the inner prison, and made their feet fast in the stocks."},"BSB":{"text":"On receiving this order, he placed them in the inner cell and fastened their feet in the stocks."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"And at midnight Paul and Silas prayed, and sang praises unto God: and the prisoners heard them.","ref":"Acts 16:25","synthesized":"About midnight Paul and Silas were praying and singing hymns to God, and the other prisoners were listening to them.","sources":{"KJV":{"text":"And at midnight Paul and Silas prayed, and sang praises unto God: and the prisoners heard them."},"BSB":{"text":"About midnight Paul and Silas were praying and singing hymns to God, and the other prisoners were listening to them."}},"definableWords":["God"],"peopleInVerse":["Paul"]},"26":{"text":"And suddenly there was a great earthquake, so that the foundations of the prison were shaken: and immediately all the doors were opened, and every one’s bands were loosed.","ref":"Acts 16:26","synthesized":"Suddenly a strong earthquake shook the foundations of the prison. At once all the doors flew open and everyone’s chains came loose.","sources":{"KJV":{"text":"And suddenly there was a great earthquake, so that the foundations of the prison were shaken: and immediately all the doors were opened, and every one’s bands were loosed."},"BSB":{"text":"Suddenly a strong earthquake shook the foundations of the prison. At once all the doors flew open and everyone’s chains came loose."}},"definableWords":["strong"],"peopleInVerse":[]},"27":{"text":"And the keeper of the prison awaking out of his sleep, and seeing the prison doors open, he drew out his sword, and would have killed himself, supposing that the prisoners had been fled.","ref":"Acts 16:27","synthesized":"When the jailer woke up and saw the prison doors open, he drew his sword and was about to kill himself, presuming that the prisoners had escaped.","sources":{"KJV":{"text":"And the keeper of the prison awaking out of his sleep, and seeing the prison doors open, he drew out his sword, and would have killed himself, supposing that the prisoners had been fled."},"BSB":{"text":"When the jailer woke up and saw the prison doors open, he drew his sword and was about to kill himself, presuming that the prisoners had escaped."}},"definableWords":["saw"],"peopleInVerse":[]},"28":{"text":"But Paul cried with a loud voice, saying, Do thyself no harm: for we are all here.","ref":"Acts 16:28","synthesized":"But Paul called out in a loud voice, “Do not harm yourself! We are all here!”","sources":{"KJV":{"text":"But Paul cried with a loud voice, saying, Do thyself no harm: for we are all here."},"BSB":{"text":"But Paul called out in a loud voice, “Do not harm yourself! We are all here!”"}},"definableWords":["voice"],"peopleInVerse":["Paul"]},"29":{"text":"Then he called for a light, and sprang in, and came trembling, and fell down before Paul and Silas,","ref":"Acts 16:29","synthesized":"Calling for lights, the jailer rushed in and fell trembling before Paul and Silas.","sources":{"KJV":{"text":"Then he called for a light, and sprang in, and came trembling, and fell down before Paul and Silas,"},"BSB":{"text":"Calling for lights, the jailer rushed in and fell trembling before Paul and Silas."}},"definableWords":[],"peopleInVerse":["Paul"]},"30":{"text":"And brought them out, and said, Sirs, what must I do to be saved?","ref":"Acts 16:30","synthesized":"Then he brought them out and asked, “Sirs, what must I do to be saved?”","sources":{"KJV":{"text":"And brought them out, and said, Sirs, what must I do to be saved?"},"BSB":{"text":"Then he brought them out and asked, “Sirs, what must I do to be saved?”"}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"And they said, Believe on the Lord Jesus Christ, and thou shalt be saved, and thy house.","ref":"Acts 16:31","synthesized":"They replied, “Believe in the Lord Jesus and you will be saved, you and your household.”","sources":{"KJV":{"text":"And they said, Believe on the Lord Jesus Christ, and thou shalt be saved, and thy house."},"BSB":{"text":"They replied, “Believe in the Lord Jesus and you will be saved, you and your household.”"}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"32":{"text":"And they spake unto him the word of the Lord, and to all that were in his house.","ref":"Acts 16:32","synthesized":"Then Paul and Silas spoke the word of the Lord to him and to everyone in his house.","sources":{"KJV":{"text":"And they spake unto him the word of the Lord, and to all that were in his house."},"BSB":{"text":"Then Paul and Silas spoke the word of the Lord to him and to everyone in his house."}},"definableWords":["word","Lord","house"],"peopleInVerse":["Paul"]},"33":{"text":"And he took them the same hour of the night, and washed their stripes; and was baptized, he and all his, straightway.","ref":"Acts 16:33","synthesized":"At that hour of the night, the jailer took them and washed their wounds. And without delay, he and all his household were baptized.","sources":{"KJV":{"text":"And he took them the same hour of the night, and washed their stripes; and was baptized, he and all his, straightway."},"BSB":{"text":"At that hour of the night, the jailer took them and washed their wounds. And without delay, he and all his household were baptized."}},"definableWords":["night"],"peopleInVerse":[]},"34":{"text":"And when he had brought them into his house, he set meat before them, and rejoiced, believing in God with all his house.","ref":"Acts 16:34","synthesized":"Then he brought them into his home and set a meal before them. So he and all his household rejoiced that they had come to believe in God.","sources":{"KJV":{"text":"And when he had brought them into his house, he set meat before them, and rejoiced, believing in God with all his house."},"BSB":{"text":"Then he brought them into his home and set a meal before them. So he and all his household rejoiced that they had come to believe in God."}},"definableWords":["God"],"peopleInVerse":[]},"35":{"text":"And when it was day, the magistrates sent the serjeants, saying, Let those men go.","ref":"Acts 16:35","synthesized":"When daylight came, the magistrates sent their officers with the order: “Release those men.”","sources":{"KJV":{"text":"And when it was day, the magistrates sent the serjeants, saying, Let those men go."},"BSB":{"text":"When daylight came, the magistrates sent their officers with the order: “Release those men.”"}},"definableWords":["men"],"peopleInVerse":[]},"36":{"text":"And the keeper of the prison told this saying to Paul, The magistrates have sent to let you go: now therefore depart, and go in peace.","ref":"Acts 16:36","synthesized":"The jailer informed Paul: “The magistrates have sent orders to release you. Now you may go on your way in peace.”","sources":{"KJV":{"text":"And the keeper of the prison told this saying to Paul, The magistrates have sent to let you go: now therefore depart, and go in peace."},"BSB":{"text":"The jailer informed Paul: “The magistrates have sent orders to release you. Now you may go on your way in peace.”"}},"definableWords":["way","peace"],"peopleInVerse":["Paul"]},"37":{"text":"But Paul said unto them, They have beaten us openly uncondemned, being Romans, and have cast us into prison; and now do they thrust us out privily? nay verily; but let them come themselves and fetch us out.","ref":"Acts 16:37","synthesized":"But Paul said to the officers, “They beat us publicly without a trial and threw us into prison, even though we are Roman citizens. And now do they want to send us away secretly? Absolutely not! Let them come themselves and escort us out!”","sources":{"KJV":{"text":"But Paul said unto them, They have beaten us openly uncondemned, being Romans, and have cast us into prison; and now do they thrust us out privily? nay verily; but let them come themselves and fetch us out."},"BSB":{"text":"But Paul said to the officers, “They beat us publicly without a trial and threw us into prison, even though we are Roman citizens. And now do they want to send us away secretly? Absolutely not! Let them come themselves and escort us out!”"}},"definableWords":[],"peopleInVerse":["Paul"]},"38":{"text":"And the serjeants told these words unto the magistrates: and they feared, when they heard that they were Romans.","ref":"Acts 16:38","synthesized":"So the officers relayed this message to the magistrates, who were alarmed to hear that Paul and Silas were Roman citizens.","sources":{"KJV":{"text":"And the serjeants told these words unto the magistrates: and they feared, when they heard that they were Romans."},"BSB":{"text":"So the officers relayed this message to the magistrates, who were alarmed to hear that Paul and Silas were Roman citizens."}},"definableWords":["hear"],"peopleInVerse":["Paul"]},"39":{"text":"And they came and besought them, and brought them out, and desired them to depart out of the city.","ref":"Acts 16:39","synthesized":"They came to appease them and led them out, requesting that they leave the city.","sources":{"KJV":{"text":"And they came and besought them, and brought them out, and desired them to depart out of the city."},"BSB":{"text":"They came to appease them and led them out, requesting that they leave the city."}},"definableWords":[],"peopleInVerse":[]},"40":{"text":"And they went out of the prison, and entered into the house of Lydia: and when they had seen the brethren, they comforted them, and departed.","ref":"Acts 16:40","synthesized":"After Paul and Silas came out of the prison, they went to Lydia’s house to see the brothers and encourage them. Then they left the city.","sources":{"KJV":{"text":"And they went out of the prison, and entered into the house of Lydia: and when they had seen the brethren, they comforted them, and departed."},"BSB":{"text":"After Paul and Silas came out of the prison, they went to Lydia’s house to see the brothers and encourage them. Then they left the city."}},"definableWords":["house","see"],"peopleInVerse":["Paul"]}}},"17":{"chapter":"17","title":"PAUL ON MARS HILL","verses":{"1":{"text":"Now when they had passed through Amphipolis and Apollonia, they came to Thessalonica, where was a synagogue of the Jews:","ref":"Acts 17:1","synthesized":"When they had passed through Amphipolis and Apollonia, they came to Thessalonica, where there was a Jewish synagogue.","sources":{"KJV":{"text":"Now when they had passed through Amphipolis and Apollonia, they came to Thessalonica, where was a synagogue of the Jews:"},"BSB":{"text":"When they had passed through Amphipolis and Apollonia, they came to Thessalonica, where there was a Jewish synagogue."}},"definableWords":[],"peopleInVerse":[],"kingdomLens":"Paul stands on Mars Hill (Areopagus) in Athens — the intellectual capital of the ancient world. Surrounded by Stoic and Epicurean philosophers. He points to their altar 'TO THE UNKNOWN GOD' and declares 'Whom therefore ye ignorantly worship, him declare I unto you' (17:23). Quotes Greek poets. Explains the resurrection. Some mock, some join — including Dionysius the Areopagite.","cultural":{"title":"Paul on Mars Hill","detail":"The Areopagus was THE seat of intellectual debate. The Bible records Paul using natural revelation (creation, conscience, even pagan poetry) to bridge to special revelation. Acts 17:28 quotes the Greek poet Aratus directly: 'for we are also his offspring.'","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"And Paul, as his manner was, went in unto them, and three sabbath days reasoned with them out of the scriptures,","ref":"Acts 17:2","synthesized":"As was his custom, Paul went into the synagogue, and on three Sabbaths he reasoned with them from the Scriptures,","sources":{"KJV":{"text":"And Paul, as his manner was, went in unto them, and three sabbath days reasoned with them out of the scriptures,"},"BSB":{"text":"As was his custom, Paul went into the synagogue, and on three Sabbaths he reasoned with them from the Scriptures,"}},"definableWords":[],"peopleInVerse":["Paul"]},"3":{"text":"Opening and alleging, that Christ must needs have suffered, and risen again from the dead; and that this Jesus, whom I preach unto you, is Christ.","ref":"Acts 17:3","synthesized":"explaining and proving that the Christ had to suffer and rise from the dead. “This Jesus I am proclaiming to you is the Christ,” he declared.","sources":{"KJV":{"text":"Opening and alleging, that Christ must needs have suffered, and risen again from the dead; and that this Jesus, whom I preach unto you, is Christ."},"BSB":{"text":"explaining and proving that the Christ had to suffer and rise from the dead. “This Jesus I am proclaiming to you is the Christ,” he declared."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"4":{"text":"And some of them believed, and consorted with Paul and Silas; and of the devout Greeks a great multitude, and of the chief women not a few.","ref":"Acts 17:4","synthesized":"Some of the Jews were persuaded and joined Paul and Silas, along with a large number of God-fearing Greeks and quite a few leading women.","sources":{"KJV":{"text":"And some of them believed, and consorted with Paul and Silas; and of the devout Greeks a great multitude, and of the chief women not a few."},"BSB":{"text":"Some of the Jews were persuaded and joined Paul and Silas, along with a large number of God-fearing Greeks and quite a few leading women."}},"definableWords":["God","women"],"peopleInVerse":["Paul"]},"5":{"text":"But the Jews which believed not, moved with envy, took unto them certain lewd fellows of the baser sort, and gathered a company, and set all the city on an uproar, and assaulted the house of Jason, and sought to bring them out to the people.","ref":"Acts 17:5","synthesized":"The Jews, however, became jealous. So they brought in some troublemakers from the marketplace, formed a mob, and sent the city into an uproar. They raided Jason’s house in search of Paul and Silas, hoping to bring them out to the people.","sources":{"KJV":{"text":"But the Jews which believed not, moved with envy, took unto them certain lewd fellows of the baser sort, and gathered a company, and set all the city on an uproar, and assaulted the house of Jason, and sought to bring them out to the people."},"BSB":{"text":"The Jews, however, became jealous. So they brought in some troublemakers from the marketplace, formed a mob, and sent the city into an uproar. They raided Jason’s house in search of Paul and Silas, hoping to bring them out to the people."}},"definableWords":["formed","house","people"],"peopleInVerse":["Paul"]},"6":{"text":"And when they found them not, they drew Jason and certain brethren unto the rulers of the city, crying, These that have turned the world upside down are come hither also;","ref":"Acts 17:6","synthesized":"But when they could not find them, they dragged Jason and some other brothers before the city officials, shouting, “These men who have turned the world upside down have now come here,","sources":{"KJV":{"text":"And when they found them not, they drew Jason and certain brethren unto the rulers of the city, crying, These that have turned the world upside down are come hither also;"},"BSB":{"text":"But when they could not find them, they dragged Jason and some other brothers before the city officials, shouting, “These men who have turned the world upside down have now come here,"}},"definableWords":["men"],"peopleInVerse":[]},"7":{"text":"Whom Jason hath received: and these all do contrary to the decrees of Caesar, saying that there is another king, one Jesus.","ref":"Acts 17:7","synthesized":"and Jason has welcomed them into his home. They are all defying Caesar’s decrees, saying that there is another king, named Jesus!”","sources":{"KJV":{"text":"Whom Jason hath received: and these all do contrary to the decrees of Caesar, saying that there is another king, one Jesus."},"BSB":{"text":"and Jason has welcomed them into his home. They are all defying Caesar’s decrees, saying that there is another king, named Jesus!”"}},"definableWords":["king"],"peopleInVerse":["Jesus"]},"8":{"text":"And they troubled the people and the rulers of the city, when they heard these things.","ref":"Acts 17:8","synthesized":"On hearing this, the crowd and city officials were greatly disturbed.","sources":{"KJV":{"text":"And they troubled the people and the rulers of the city, when they heard these things."},"BSB":{"text":"On hearing this, the crowd and city officials were greatly disturbed."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And when they had taken security of Jason, and of the other, they let them go.","ref":"Acts 17:9","synthesized":"And they collected bond from Jason and the others, and then released them.","sources":{"KJV":{"text":"And when they had taken security of Jason, and of the other, they let them go."},"BSB":{"text":"And they collected bond from Jason and the others, and then released them."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"And the brethren immediately sent away Paul and Silas by night unto Berea: who coming thither went into the synagogue of the Jews.","ref":"Acts 17:10","synthesized":"As soon as night had fallen, the brothers sent Paul and Silas away to Berea. On arriving there, they went into the Jewish synagogue.","sources":{"KJV":{"text":"And the brethren immediately sent away Paul and Silas by night unto Berea: who coming thither went into the synagogue of the Jews."},"BSB":{"text":"As soon as night had fallen, the brothers sent Paul and Silas away to Berea. On arriving there, they went into the Jewish synagogue."}},"definableWords":["night"],"peopleInVerse":["Paul"]},"11":{"text":"These were more noble than those in Thessalonica, in that they received the word with all readiness of mind, and searched the scriptures daily, whether those things were so.","ref":"Acts 17:11","synthesized":"Now the Bereans were more noble-minded than the Thessalonians, for they received the message with great eagerness and examined the Scriptures every day to see if these teachings were true.","sources":{"KJV":{"text":"These were more noble than those in Thessalonica, in that they received the word with all readiness of mind, and searched the scriptures daily, whether those things were so."},"BSB":{"text":"Now the Bereans were more noble-minded than the Thessalonians, for they received the message with great eagerness and examined the Scriptures every day to see if these teachings were true."}},"definableWords":["great","day","see"],"peopleInVerse":[]},"12":{"text":"Therefore many of them believed; also of honourable women which were Greeks, and of men, not a few.","ref":"Acts 17:12","synthesized":"As a result, many of them believed, along with quite a few prominent Greek women and men.","sources":{"KJV":{"text":"Therefore many of them believed; also of honourable women which were Greeks, and of men, not a few."},"BSB":{"text":"As a result, many of them believed, along with quite a few prominent Greek women and men."}},"definableWords":["believed","Greek","women","men"],"peopleInVerse":[]},"13":{"text":"But when the Jews of Thessalonica had knowledge that the word of God was preached of Paul at Berea, they came thither also, and stirred up the people.","ref":"Acts 17:13","synthesized":"But when the Jews from Thessalonica learned that Paul was also proclaiming the word of God in Berea, they went there themselves to incite and agitate the crowds.","sources":{"KJV":{"text":"But when the Jews of Thessalonica had knowledge that the word of God was preached of Paul at Berea, they came thither also, and stirred up the people."},"BSB":{"text":"But when the Jews from Thessalonica learned that Paul was also proclaiming the word of God in Berea, they went there themselves to incite and agitate the crowds."}},"definableWords":["word","God"],"peopleInVerse":["Paul"]},"14":{"text":"And then immediately the brethren sent away Paul to go as it were to the sea: but Silas and Timotheus abode there still.","ref":"Acts 17:14","synthesized":"The brothers immediately sent Paul to the coast, but Silas and Timothy remained in Berea.","sources":{"KJV":{"text":"And then immediately the brethren sent away Paul to go as it were to the sea: but Silas and Timotheus abode there still."},"BSB":{"text":"The brothers immediately sent Paul to the coast, but Silas and Timothy remained in Berea."}},"definableWords":[],"peopleInVerse":["Paul"]},"15":{"text":"And they that conducted Paul brought him unto Athens: and receiving a commandment unto Silas and Timotheus for to come to him with all speed, they departed.","ref":"Acts 17:15","synthesized":"Those who escorted Paul brought him to Athens and then returned with instructions for Silas and Timothy to join him as soon as possible.","sources":{"KJV":{"text":"And they that conducted Paul brought him unto Athens: and receiving a commandment unto Silas and Timotheus for to come to him with all speed, they departed."},"BSB":{"text":"Those who escorted Paul brought him to Athens and then returned with instructions for Silas and Timothy to join him as soon as possible."}},"definableWords":[],"peopleInVerse":["Paul"]},"16":{"text":"Now while Paul waited for them at Athens, his spirit was stirred in him, when he saw the city wholly given to idolatry.","ref":"Acts 17:16","synthesized":"While Paul was waiting for them in Athens, he was deeply disturbed in his spirit to see that the city was full of idols.","sources":{"KJV":{"text":"Now while Paul waited for them at Athens, his spirit was stirred in him, when he saw the city wholly given to idolatry."},"BSB":{"text":"While Paul was waiting for them in Athens, he was deeply disturbed in his spirit to see that the city was full of idols."}},"definableWords":["spirit","see"],"peopleInVerse":["Paul"]},"17":{"text":"Therefore disputed he in the synagogue with the Jews, and with the devout persons, and in the market daily with them that met with him.","ref":"Acts 17:17","synthesized":"So he reasoned in the synagogue with the Jews and God-fearing Gentiles, and in the marketplace with those he met each day.","sources":{"KJV":{"text":"Therefore disputed he in the synagogue with the Jews, and with the devout persons, and in the market daily with them that met with him."},"BSB":{"text":"So he reasoned in the synagogue with the Jews and God-fearing Gentiles, and in the marketplace with those he met each day."}},"definableWords":["God","day"],"peopleInVerse":[]},"18":{"text":"Then certain philosophers of the Epicureans, and of the Stoicks, encountered him. And some said, What will this babbler say? other some, He seemeth to be a setter forth of strange gods: because he preached unto them Jesus, and the resurrection.","ref":"Acts 17:18","synthesized":"Some Epicurean and Stoic philosophers also began to debate with him. Some of them asked, “What is this babbler trying to say?” Others said, “He seems to be advocating foreign gods.” They said this because Paul was proclaiming the good news of Jesus and the resurrection.","sources":{"KJV":{"text":"Then certain philosophers of the Epicureans, and of the Stoicks, encountered him. And some said, What will this babbler say? other some, He seemeth to be a setter forth of strange gods: because he preached unto them Jesus, and the resurrection."},"BSB":{"text":"Some Epicurean and Stoic philosophers also began to debate with him. Some of them asked, “What is this babbler trying to say?” Others said, “He seems to be advocating foreign gods.” They said this because Paul was proclaiming the good news of Jesus and the resurrection."}},"definableWords":["good","resurrection"],"peopleInVerse":["Paul","Jesus"]},"19":{"text":"And they took him, and brought him unto Areopagus, saying, May we know what this new doctrine, whereof thou speakest, is?","ref":"Acts 17:19","synthesized":"So they took Paul and brought him to the Areopagus, where they asked him, “May we know what this new teaching is that you are presenting?","sources":{"KJV":{"text":"And they took him, and brought him unto Areopagus, saying, May we know what this new doctrine, whereof thou speakest, is?"},"BSB":{"text":"So they took Paul and brought him to the Areopagus, where they asked him, “May we know what this new teaching is that you are presenting?"}},"definableWords":[],"peopleInVerse":["Paul"]},"20":{"text":"For thou bringest certain strange things to our ears: we would know therefore what these things mean.","ref":"Acts 17:20","synthesized":"For you are bringing some strange notions to our ears, and we want to know what they mean.”","sources":{"KJV":{"text":"For thou bringest certain strange things to our ears: we would know therefore what these things mean."},"BSB":{"text":"For you are bringing some strange notions to our ears, and we want to know what they mean.”"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"(For all the Athenians and strangers which were there spent their time in nothing else, but either to tell, or to hear some new thing.)","ref":"Acts 17:21","synthesized":"Now all the Athenians and foreigners who lived there spent their time doing nothing more than hearing and articulating new ideas.","sources":{"KJV":{"text":"(For all the Athenians and strangers which were there spent their time in nothing else, but either to tell, or to hear some new thing.)"},"BSB":{"text":"Now all the Athenians and foreigners who lived there spent their time doing nothing more than hearing and articulating new ideas."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Then Paul stood in the midst of Mars’ hill, and said, Ye men of Athens, I perceive that in all things ye are too superstitious.","ref":"Acts 17:22","synthesized":"Then Paul stood up in the meeting of the Areopagus and said, “Men of Athens, I see that in every way you are very religious.","sources":{"KJV":{"text":"Then Paul stood in the midst of Mars’ hill, and said, Ye men of Athens, I perceive that in all things ye are too superstitious."},"BSB":{"text":"Then Paul stood up in the meeting of the Areopagus and said, “Men of Athens, I see that in every way you are very religious."}},"definableWords":["men","see","way"],"peopleInVerse":["Paul"]},"23":{"text":"For as I passed by, and beheld your devotions, I found an altar with this inscription, TO THE UNKNOWN GOD. Whom therefore ye ignorantly worship, him declare I unto you.","ref":"Acts 17:23","synthesized":"For as I walked around and examined your objects of worship, I even found an altar with this inscription:  TO AN UNKNOWN GOD.  Therefore what you worship as something unknown, I now proclaim to you.","sources":{"KJV":{"text":"For as I passed by, and beheld your devotions, I found an altar with this inscription, TO THE UNKNOWN GOD. Whom therefore ye ignorantly worship, him declare I unto you."},"BSB":{"text":"For as I walked around and examined your objects of worship, I even found an altar with this inscription:  TO AN UNKNOWN GOD.  Therefore what you worship as something unknown, I now proclaim to you."}},"definableWords":["walked","worship","altar","God"],"peopleInVerse":[]},"24":{"text":"God that made the world and all things therein, seeing that he is Lord of heaven and earth, dwelleth not in temples made with hands;","ref":"Acts 17:24","synthesized":"The God who made the world and everything in it is the Lord of heaven and earth and does not live in temples made by human hands.","sources":{"KJV":{"text":"God that made the world and all things therein, seeing that he is Lord of heaven and earth, dwelleth not in temples made with hands;"},"BSB":{"text":"The God who made the world and everything in it is the Lord of heaven and earth and does not live in temples made by human hands."}},"definableWords":["God","made","Lord","heaven","earth","live"],"peopleInVerse":[]},"25":{"text":"Neither is worshipped with men’s hands, as though he needed any thing, seeing he giveth to all life, and breath, and all things;","ref":"Acts 17:25","synthesized":"Nor is He served by human hands, as if He needed anything, because He Himself gives everyone life and breath and everything else.","sources":{"KJV":{"text":"Neither is worshipped with men’s hands, as though he needed any thing, seeing he giveth to all life, and breath, and all things;"},"BSB":{"text":"Nor is He served by human hands, as if He needed anything, because He Himself gives everyone life and breath and everything else."}},"definableWords":["life","breath"],"peopleInVerse":[]},"26":{"text":"And hath made of one blood all nations of men for to dwell on all the face of the earth, and hath determined the times before appointed, and the bounds of their habitation;","ref":"Acts 17:26","synthesized":"From one man He made every nation of men, that they should inhabit the whole earth; and He determined their appointed times and the boundaries of their lands.","sources":{"KJV":{"text":"And hath made of one blood all nations of men for to dwell on all the face of the earth, and hath determined the times before appointed, and the bounds of their habitation;"},"BSB":{"text":"From one man He made every nation of men, that they should inhabit the whole earth; and He determined their appointed times and the boundaries of their lands."}},"definableWords":["one","man","made","nation","men","earth"],"peopleInVerse":[]},"27":{"text":"That they should seek the Lord, if haply they might feel after him, and find him, though he be not far from every one of us:","ref":"Acts 17:27","synthesized":"God intended that they would seek Him and perhaps reach out for Him and find Him, though He is not far from each one of us.","sources":{"KJV":{"text":"That they should seek the Lord, if haply they might feel after him, and find him, though he be not far from every one of us:"},"BSB":{"text":"God intended that they would seek Him and perhaps reach out for Him and find Him, though He is not far from each one of us."}},"definableWords":["God","seek","one"],"peopleInVerse":[]},"28":{"text":"For in him we live, and move, and have our being; as certain also of your own poets have said, For we are also his offspring.","ref":"Acts 17:28","synthesized":"‘For in Him we live and move and have our being.’ As some of your own poets have said, ‘We are His offspring.’","sources":{"KJV":{"text":"For in him we live, and move, and have our being; as certain also of your own poets have said, For we are also his offspring."},"BSB":{"text":"‘For in Him we live and move and have our being.’ As some of your own poets have said, ‘We are His offspring.’"}},"definableWords":["live"],"peopleInVerse":[]},"29":{"text":"Forasmuch then as we are the offspring of God, we ought not to think that the Godhead is like unto gold, or silver, or stone, graven by art and man’s device.","ref":"Acts 17:29","synthesized":"Therefore, being offspring of God, we should not think that the Divine Being is like gold or silver or stone, an image formed by man’s skill and imagination.","sources":{"KJV":{"text":"Forasmuch then as we are the offspring of God, we ought not to think that the Godhead is like unto gold, or silver, or stone, graven by art and man’s device."},"BSB":{"text":"Therefore, being offspring of God, we should not think that the Divine Being is like gold or silver or stone, an image formed by man’s skill and imagination."}},"definableWords":["God","or","stone","image","formed","man"],"peopleInVerse":[]},"30":{"text":"And the times of this ignorance God winked at; but now commandeth all men every where to repent:","ref":"Acts 17:30","synthesized":"Although God overlooked the ignorance of earlier times, He now commands all people everywhere to repent.","sources":{"KJV":{"text":"And the times of this ignorance God winked at; but now commandeth all men every where to repent:"},"BSB":{"text":"Although God overlooked the ignorance of earlier times, He now commands all people everywhere to repent."}},"definableWords":["God","people"],"peopleInVerse":[]},"31":{"text":"Because he hath appointed a day, in the which he will judge the world in righteousness by that man whom he hath ordained; whereof he hath given assurance unto all men, in that he hath raised him from the dead.","ref":"Acts 17:31","synthesized":"For He has set a day when He will judge the world with justice by the Man He has appointed. He has given proof of this to everyone by raising Him from the dead.”","sources":{"KJV":{"text":"Because he hath appointed a day, in the which he will judge the world in righteousness by that man whom he hath ordained; whereof he hath given assurance unto all men, in that he hath raised him from the dead."},"BSB":{"text":"For He has set a day when He will judge the world with justice by the Man He has appointed. He has given proof of this to everyone by raising Him from the dead.”"}},"definableWords":["day","justice","man"],"peopleInVerse":[]},"32":{"text":"And when they heard of the resurrection of the dead, some mocked: and others said, We will hear thee again of this matter.","ref":"Acts 17:32","synthesized":"When they heard about the resurrection of the dead, some began to mock him, but others said, “We want to hear you again on this topic.”","sources":{"KJV":{"text":"And when they heard of the resurrection of the dead, some mocked: and others said, We will hear thee again of this matter."},"BSB":{"text":"When they heard about the resurrection of the dead, some began to mock him, but others said, “We want to hear you again on this topic.”"}},"definableWords":["resurrection","hear"],"peopleInVerse":[]},"33":{"text":"So Paul departed from among them.","ref":"Acts 17:33","synthesized":"At that, Paul left the Areopagus.","sources":{"KJV":{"text":"So Paul departed from among them."},"BSB":{"text":"At that, Paul left the Areopagus."}},"definableWords":[],"peopleInVerse":["Paul"]},"34":{"text":"Howbeit certain men clave unto him, and believed: among the which was Dionysius the Areopagite, and a woman named Damaris, and others with them.","ref":"Acts 17:34","synthesized":"But some joined him and believed, including Dionysius the Areopagite, a woman named Damaris, and others who were with them.","sources":{"KJV":{"text":"Howbeit certain men clave unto him, and believed: among the which was Dionysius the Areopagite, and a woman named Damaris, and others with them."},"BSB":{"text":"But some joined him and believed, including Dionysius the Areopagite, a woman named Damaris, and others who were with them."}},"definableWords":["believed","woman"],"peopleInVerse":[]}}},"18":{"chapter":"18","title":"PAUL AT CORINTH","verses":{"1":{"text":"After these things Paul departed from Athens, and came to Corinth;","ref":"Acts 18:1","synthesized":"After this, Paul left Athens and went to Corinth.","sources":{"KJV":{"text":"After these things Paul departed from Athens, and came to Corinth;"},"BSB":{"text":"After this, Paul left Athens and went to Corinth."}},"definableWords":[],"peopleInVerse":["Paul"]},"2":{"text":"And found a certain Jew named Aquila, born in Pontus, lately come from Italy, with his wife Priscilla; (because that Claudius had commanded all Jews to depart from Rome:) and came unto them.","ref":"Acts 18:2","synthesized":"There he found a Jew named Aquila, a native of Pontus, who had recently come from Italy with his wife Priscilla because Claudius had ordered all the Jews to leave Rome. Paul went to visit them,","sources":{"KJV":{"text":"And found a certain Jew named Aquila, born in Pontus, lately come from Italy, with his wife Priscilla; (because that Claudius had commanded all Jews to depart from Rome:) and came unto them."},"BSB":{"text":"There he found a Jew named Aquila, a native of Pontus, who had recently come from Italy with his wife Priscilla because Claudius had ordered all the Jews to leave Rome. Paul went to visit them,"}},"definableWords":["Jew","wife"],"peopleInVerse":["Paul"]},"3":{"text":"And because he was of the same craft, he abode with them, and wrought: for by their occupation they were tentmakers.","ref":"Acts 18:3","synthesized":"and he stayed and worked with them because they were tentmakers by trade, just as he was.","sources":{"KJV":{"text":"And because he was of the same craft, he abode with them, and wrought: for by their occupation they were tentmakers."},"BSB":{"text":"and he stayed and worked with them because they were tentmakers by trade, just as he was."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"And he reasoned in the synagogue every sabbath, and persuaded the Jews and the Greeks.","ref":"Acts 18:4","synthesized":"Every Sabbath he reasoned in the synagogue, trying to persuade Jews and Greeks alike.","sources":{"KJV":{"text":"And he reasoned in the synagogue every sabbath, and persuaded the Jews and the Greeks."},"BSB":{"text":"Every Sabbath he reasoned in the synagogue, trying to persuade Jews and Greeks alike."}},"definableWords":["Sabbath"],"peopleInVerse":[]},"5":{"text":"And when Silas and Timotheus were come from Macedonia, Paul was pressed in the spirit, and testified to the Jews that Jesus was Christ.","ref":"Acts 18:5","synthesized":"And when Silas and Timothy came down from Macedonia, Paul devoted himself fully to the word, testifying to the Jews that Jesus is the Christ.","sources":{"KJV":{"text":"And when Silas and Timotheus were come from Macedonia, Paul was pressed in the spirit, and testified to the Jews that Jesus was Christ."},"BSB":{"text":"And when Silas and Timothy came down from Macedonia, Paul devoted himself fully to the word, testifying to the Jews that Jesus is the Christ."}},"definableWords":["word","Christ"],"peopleInVerse":["Paul","Jesus"]},"6":{"text":"And when they opposed themselves, and blasphemed, he shook his raiment, and said unto them, Your blood be upon your own heads; I am clean: from henceforth I will go unto the Gentiles.","ref":"Acts 18:6","synthesized":"But when they opposed and insulted him, he shook out his garments and told them, “Your blood be on your own heads! I am innocent of it. From now on I will go to the Gentiles.”","sources":{"KJV":{"text":"And when they opposed themselves, and blasphemed, he shook his raiment, and said unto them, Your blood be upon your own heads; I am clean: from henceforth I will go unto the Gentiles."},"BSB":{"text":"But when they opposed and insulted him, he shook out his garments and told them, “Your blood be on your own heads! I am innocent of it. From now on I will go to the Gentiles.”"}},"definableWords":["blood"],"peopleInVerse":[]},"7":{"text":"And he departed thence, and entered into a certain man’s house, named Justus, one that worshipped God, whose house joined hard to the synagogue.","ref":"Acts 18:7","synthesized":"So Paul left the synagogue and went next door to the house of Titus Justus, a worshiper of God.","sources":{"KJV":{"text":"And he departed thence, and entered into a certain man’s house, named Justus, one that worshipped God, whose house joined hard to the synagogue."},"BSB":{"text":"So Paul left the synagogue and went next door to the house of Titus Justus, a worshiper of God."}},"definableWords":["house","God"],"peopleInVerse":["Paul"]},"8":{"text":"And Crispus, the chief ruler of the synagogue, believed on the Lord with all his house; and many of the Corinthians hearing believed, and were baptized.","ref":"Acts 18:8","synthesized":"Crispus, the synagogue leader, and his whole household believed in the Lord. And many of the Corinthians who heard the message believed and were baptized.","sources":{"KJV":{"text":"And Crispus, the chief ruler of the synagogue, believed on the Lord with all his house; and many of the Corinthians hearing believed, and were baptized."},"BSB":{"text":"Crispus, the synagogue leader, and his whole household believed in the Lord. And many of the Corinthians who heard the message believed and were baptized."}},"definableWords":["believed","Lord"],"peopleInVerse":[]},"9":{"text":"Then spake the Lord to Paul in the night by a vision, Be not afraid, but speak, and hold not thy peace:","ref":"Acts 18:9","synthesized":"One night the Lord spoke to Paul in a vision: “Do not be afraid; keep on speaking; do not be silent.","sources":{"KJV":{"text":"Then spake the Lord to Paul in the night by a vision, Be not afraid, but speak, and hold not thy peace:"},"BSB":{"text":"One night the Lord spoke to Paul in a vision: “Do not be afraid; keep on speaking; do not be silent."}},"definableWords":["one","night","Lord","keep"],"peopleInVerse":["Paul"]},"10":{"text":"For I am with thee, and no man shall set on thee to hurt thee: for I have much people in this city.","ref":"Acts 18:10","synthesized":"For I am with you and no one will lay a hand on you, because I have many people in this city.”","sources":{"KJV":{"text":"For I am with thee, and no man shall set on thee to hurt thee: for I have much people in this city."},"BSB":{"text":"For I am with you and no one will lay a hand on you, because I have many people in this city.”"}},"definableWords":["one","people"],"peopleInVerse":[]},"11":{"text":"And he continued there a year and six months, teaching the word of God among them.","ref":"Acts 18:11","synthesized":"So Paul stayed for a year and a half, teaching the word of God among the Corinthians.","sources":{"KJV":{"text":"And he continued there a year and six months, teaching the word of God among them."},"BSB":{"text":"So Paul stayed for a year and a half, teaching the word of God among the Corinthians."}},"definableWords":["year","word","God"],"peopleInVerse":["Paul"]},"12":{"text":"And when Gallio was the deputy of Achaia, the Jews made insurrection with one accord against Paul, and brought him to the judgment seat,","ref":"Acts 18:12","synthesized":"While Gallio was proconsul of Achaia, the Jews coordinated an attack on Paul and brought him before the judgment seat.","sources":{"KJV":{"text":"And when Gallio was the deputy of Achaia, the Jews made insurrection with one accord against Paul, and brought him to the judgment seat,"},"BSB":{"text":"While Gallio was proconsul of Achaia, the Jews coordinated an attack on Paul and brought him before the judgment seat."}},"definableWords":["judgment"],"peopleInVerse":["Paul"]},"13":{"text":"Saying, This fellow persuadeth men to worship God contrary to the law.","ref":"Acts 18:13","synthesized":"“This man is persuading the people to worship God in ways contrary to the law,” they said.","sources":{"KJV":{"text":"Saying, This fellow persuadeth men to worship God contrary to the law."},"BSB":{"text":"“This man is persuading the people to worship God in ways contrary to the law,” they said."}},"definableWords":["man","people","worship","God","law"],"peopleInVerse":[]},"14":{"text":"And when Paul was now about to open his mouth, Gallio said unto the Jews, If it were a matter of wrong or wicked lewdness, O ye Jews, reason would that I should bear with you:","ref":"Acts 18:14","synthesized":"But just as Paul was about to speak, Gallio told the Jews, “If this matter involved a wrongdoing or vicious crime, O Jews, it would be reasonable for me to hear your complaint.","sources":{"KJV":{"text":"And when Paul was now about to open his mouth, Gallio said unto the Jews, If it were a matter of wrong or wicked lewdness, O ye Jews, reason would that I should bear with you:"},"BSB":{"text":"But just as Paul was about to speak, Gallio told the Jews, “If this matter involved a wrongdoing or vicious crime, O Jews, it would be reasonable for me to hear your complaint."}},"definableWords":["or","hear"],"peopleInVerse":["Paul"]},"15":{"text":"But if it be a question of words and names, and of your law, look ye to it; for I will be no judge of such matters.","ref":"Acts 18:15","synthesized":"But since it is a dispute about words and names and your own law, settle it yourselves. I refuse to be a judge of such things.”","sources":{"KJV":{"text":"But if it be a question of words and names, and of your law, look ye to it; for I will be no judge of such matters."},"BSB":{"text":"But since it is a dispute about words and names and your own law, settle it yourselves. I refuse to be a judge of such things.”"}},"definableWords":["law"],"peopleInVerse":[]},"16":{"text":"And he drave them from the judgment seat.","ref":"Acts 18:16","synthesized":"And he drove them away from the judgment seat.","sources":{"KJV":{"text":"And he drave them from the judgment seat."},"BSB":{"text":"And he drove them away from the judgment seat."}},"definableWords":["judgment"],"peopleInVerse":[]},"17":{"text":"Then all the Greeks took Sosthenes, the chief ruler of the synagogue, and beat him before the judgment seat. And Gallio cared for none of those things.","ref":"Acts 18:17","synthesized":"At this, the crowd seized Sosthenes the synagogue leader and beat him in front of the judgment seat. But none of this was of concern to Gallio.","sources":{"KJV":{"text":"Then all the Greeks took Sosthenes, the chief ruler of the synagogue, and beat him before the judgment seat. And Gallio cared for none of those things."},"BSB":{"text":"At this, the crowd seized Sosthenes the synagogue leader and beat him in front of the judgment seat. But none of this was of concern to Gallio."}},"definableWords":["judgment"],"peopleInVerse":[]},"18":{"text":"And Paul after this tarried there yet a good while, and then took his leave of the brethren, and sailed thence into Syria, and with him Priscilla and Aquila; having shorn his head in Cenchrea: for he had a vow.","ref":"Acts 18:18","synthesized":"Paul remained in Corinth for quite some time before saying goodbye to the brothers. He had his head shaved in Cenchrea to keep a vow he had made, and then he sailed for Syria, accompanied by Priscilla and Aquila.","sources":{"KJV":{"text":"And Paul after this tarried there yet a good while, and then took his leave of the brethren, and sailed thence into Syria, and with him Priscilla and Aquila; having shorn his head in Cenchrea: for he had a vow."},"BSB":{"text":"Paul remained in Corinth for quite some time before saying goodbye to the brothers. He had his head shaved in Cenchrea to keep a vow he had made, and then he sailed for Syria, accompanied by Priscilla and Aquila."}},"definableWords":["keep","made"],"peopleInVerse":["Paul"]},"19":{"text":"And he came to Ephesus, and left them there: but he himself entered into the synagogue, and reasoned with the Jews.","ref":"Acts 18:19","synthesized":"When they reached Ephesus, Paul parted ways with Priscilla and Aquila. He himself went into the synagogue there and reasoned with the Jews.","sources":{"KJV":{"text":"And he came to Ephesus, and left them there: but he himself entered into the synagogue, and reasoned with the Jews."},"BSB":{"text":"When they reached Ephesus, Paul parted ways with Priscilla and Aquila. He himself went into the synagogue there and reasoned with the Jews."}},"definableWords":[],"peopleInVerse":["Paul"]},"20":{"text":"When they desired him to tarry longer time with them, he consented not;","ref":"Acts 18:20","synthesized":"When they asked him to stay for a while longer, he declined.","sources":{"KJV":{"text":"When they desired him to tarry longer time with them, he consented not;"},"BSB":{"text":"When they asked him to stay for a while longer, he declined."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"But bade them farewell, saying, I must by all means keep this feast that cometh in Jerusalem: but I will return again unto you, if God will. And he sailed from Ephesus.","ref":"Acts 18:21","synthesized":"But as he left, he said, “I will come back to you if God is willing.” And he set sail from Ephesus.","sources":{"KJV":{"text":"But bade them farewell, saying, I must by all means keep this feast that cometh in Jerusalem: but I will return again unto you, if God will. And he sailed from Ephesus."},"BSB":{"text":"But as he left, he said, “I will come back to you if God is willing.” And he set sail from Ephesus."}},"definableWords":["God"],"peopleInVerse":[]},"22":{"text":"And when he had landed at Caesarea, and gone up, and saluted the church, he went down to Antioch.","ref":"Acts 18:22","synthesized":"When Paul had landed at Caesarea, he went up and greeted the church at Jerusalem. Then he went down to Antioch.","sources":{"KJV":{"text":"And when he had landed at Caesarea, and gone up, and saluted the church, he went down to Antioch."},"BSB":{"text":"When Paul had landed at Caesarea, he went up and greeted the church at Jerusalem. Then he went down to Antioch."}},"definableWords":["church","Jerusalem"],"peopleInVerse":["Paul"]},"23":{"text":"And after he had spent some time there, he departed, and went over all the country of Galatia and Phrygia in order, strengthening all the disciples.","ref":"Acts 18:23","synthesized":"After Paul had spent some time in Antioch, he traveled from place to place throughout the region of Galatia and Phrygia, strengthening all the disciples.","sources":{"KJV":{"text":"And after he had spent some time there, he departed, and went over all the country of Galatia and Phrygia in order, strengthening all the disciples."},"BSB":{"text":"After Paul had spent some time in Antioch, he traveled from place to place throughout the region of Galatia and Phrygia, strengthening all the disciples."}},"definableWords":[],"peopleInVerse":["Paul"]},"24":{"text":"And a certain Jew named Apollos, born at Alexandria, an eloquent man, and mighty in the scriptures, came to Ephesus.","ref":"Acts 18:24","synthesized":"Meanwhile a Jew named Apollos, a native of Alexandria, came to Ephesus. He was an eloquent man, well versed in the Scriptures.","sources":{"KJV":{"text":"And a certain Jew named Apollos, born at Alexandria, an eloquent man, and mighty in the scriptures, came to Ephesus."},"BSB":{"text":"Meanwhile a Jew named Apollos, a native of Alexandria, came to Ephesus. He was an eloquent man, well versed in the Scriptures."}},"definableWords":["Jew","man"],"peopleInVerse":[]},"25":{"text":"This man was instructed in the way of the Lord; and being fervent in the spirit, he spake and taught diligently the things of the Lord, knowing only the baptism of John.","ref":"Acts 18:25","synthesized":"He had been instructed in the way of the Lord and was fervent in spirit. He spoke and taught accurately about Jesus, though he knew only the baptism of John.","sources":{"KJV":{"text":"This man was instructed in the way of the Lord; and being fervent in the spirit, he spake and taught diligently the things of the Lord, knowing only the baptism of John."},"BSB":{"text":"He had been instructed in the way of the Lord and was fervent in spirit. He spoke and taught accurately about Jesus, though he knew only the baptism of John."}},"definableWords":["way","Lord","spirit","baptism"],"peopleInVerse":["Jesus","John"]},"26":{"text":"And he began to speak boldly in the synagogue: whom when Aquila and Priscilla had heard, they took him unto them, and expounded unto him the way of God more perfectly.","ref":"Acts 18:26","synthesized":"And he began to speak boldly in the synagogue. When Priscilla and Aquila heard him, they took him in and explained to him the way of God more accurately.","sources":{"KJV":{"text":"And he began to speak boldly in the synagogue: whom when Aquila and Priscilla had heard, they took him unto them, and expounded unto him the way of God more perfectly."},"BSB":{"text":"And he began to speak boldly in the synagogue. When Priscilla and Aquila heard him, they took him in and explained to him the way of God more accurately."}},"definableWords":["way","God"],"peopleInVerse":[]},"27":{"text":"And when he was disposed to pass into Achaia, the brethren wrote, exhorting the disciples to receive him: who, when he was come, helped them much which had believed through grace:","ref":"Acts 18:27","synthesized":"When Apollos resolved to cross over to Achaia, the brothers encouraged him and wrote to the disciples there to welcome him. On his arrival, he was a great help to those who by grace had believed.","sources":{"KJV":{"text":"And when he was disposed to pass into Achaia, the brethren wrote, exhorting the disciples to receive him: who, when he was come, helped them much which had believed through grace:"},"BSB":{"text":"When Apollos resolved to cross over to Achaia, the brothers encouraged him and wrote to the disciples there to welcome him. On his arrival, he was a great help to those who by grace had believed."}},"definableWords":["great","grace","believed"],"peopleInVerse":[]},"28":{"text":"For he mightily convinced the Jews, and that publickly, shewing by the scriptures that Jesus was Christ.","ref":"Acts 18:28","synthesized":"For he powerfully refuted the Jews in public debate, proving from the Scriptures that Jesus is the Christ.","sources":{"KJV":{"text":"For he mightily convinced the Jews, and that publickly, shewing by the scriptures that Jesus was Christ."},"BSB":{"text":"For he powerfully refuted the Jews in public debate, proving from the Scriptures that Jesus is the Christ."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]}}},"19":{"chapter":"19","title":"PAUL AT EPHESUS — RIOT OF THE SILVERSMITHS","verses":{"1":{"text":"And it came to pass, that, while Apollos was at Corinth, Paul having passed through the upper coasts came to Ephesus: and finding certain disciples,","ref":"Acts 19:1","synthesized":"While Apollos was at Corinth, Paul passed through the interior and came to Ephesus. There he found some disciples","sources":{"KJV":{"text":"And it came to pass, that, while Apollos was at Corinth, Paul having passed through the upper coasts came to Ephesus: and finding certain disciples,"},"BSB":{"text":"While Apollos was at Corinth, Paul passed through the interior and came to Ephesus. There he found some disciples"}},"definableWords":[],"peopleInVerse":["Paul"]},"2":{"text":"He said unto them, Have ye received the Holy Ghost since ye believed? And they said unto him, We have not so much as heard whether there be any Holy Ghost.","ref":"Acts 19:2","synthesized":"and asked them, “Did you receive the Holy Spirit when you became believers?”  “No,” they answered, “we have not even heard that there is a Holy Spirit.”","sources":{"KJV":{"text":"He said unto them, Have ye received the Holy Ghost since ye believed? And they said unto him, We have not so much as heard whether there be any Holy Ghost."},"BSB":{"text":"and asked them, “Did you receive the Holy Spirit when you became believers?”  “No,” they answered, “we have not even heard that there is a Holy Spirit.”"}},"definableWords":["holy","Spirit","spirit"],"peopleInVerse":[]},"3":{"text":"And he said unto them, Unto what then were ye baptized? And they said, Unto John’s baptism.","ref":"Acts 19:3","synthesized":"“Into what, then, were you baptized?” Paul asked.  “The baptism of John,” they replied.","sources":{"KJV":{"text":"And he said unto them, Unto what then were ye baptized? And they said, Unto John’s baptism."},"BSB":{"text":"“Into what, then, were you baptized?” Paul asked.  “The baptism of John,” they replied."}},"definableWords":["baptism"],"peopleInVerse":["Paul","John"]},"4":{"text":"Then said Paul, John verily baptized with the baptism of repentance, saying unto the people, that they should believe on him which should come after him, that is, on Christ Jesus.","ref":"Acts 19:4","synthesized":"Paul explained: “John’s baptism was a baptism of repentance. He told the people to believe in the One coming after him, that is, in Jesus.”","sources":{"KJV":{"text":"Then said Paul, John verily baptized with the baptism of repentance, saying unto the people, that they should believe on him which should come after him, that is, on Christ Jesus."},"BSB":{"text":"Paul explained: “John’s baptism was a baptism of repentance. He told the people to believe in the One coming after him, that is, in Jesus.”"}},"definableWords":["baptism","repentance","people","one"],"peopleInVerse":["Paul","John","Jesus"]},"5":{"text":"When they heard this, they were baptized in the name of the Lord Jesus.","ref":"Acts 19:5","synthesized":"On hearing this, they were baptized into the name of the Lord Jesus.","sources":{"KJV":{"text":"When they heard this, they were baptized in the name of the Lord Jesus."},"BSB":{"text":"On hearing this, they were baptized into the name of the Lord Jesus."}},"definableWords":["name","Lord"],"peopleInVerse":["Jesus"]},"6":{"text":"And when Paul had laid his hands upon them, the Holy Ghost came on them; and they spake with tongues, and prophesied.","ref":"Acts 19:6","synthesized":"And when Paul laid his hands on them, the Holy Spirit came upon them, and they spoke in tongues and prophesied.","sources":{"KJV":{"text":"And when Paul had laid his hands upon them, the Holy Ghost came on them; and they spake with tongues, and prophesied."},"BSB":{"text":"And when Paul laid his hands on them, the Holy Spirit came upon them, and they spoke in tongues and prophesied."}},"definableWords":["holy","Spirit"],"peopleInVerse":["Paul"]},"7":{"text":"And all the men were about twelve.","ref":"Acts 19:7","synthesized":"There were about twelve men in all.","sources":{"KJV":{"text":"And all the men were about twelve."},"BSB":{"text":"There were about twelve men in all."}},"definableWords":["men"],"peopleInVerse":[]},"8":{"text":"And he went into the synagogue, and spake boldly for the space of three months, disputing and persuading the things concerning the kingdom of God.","ref":"Acts 19:8","synthesized":"Then Paul went into the synagogue and spoke boldly there for three months, arguing persuasively about the kingdom of God.","sources":{"KJV":{"text":"And he went into the synagogue, and spake boldly for the space of three months, disputing and persuading the things concerning the kingdom of God."},"BSB":{"text":"Then Paul went into the synagogue and spoke boldly there for three months, arguing persuasively about the kingdom of God."}},"definableWords":["kingdom","God"],"peopleInVerse":["Paul"]},"9":{"text":"But when divers were hardened, and believed not, but spake evil of that way before the multitude, he departed from them, and separated the disciples, disputing daily in the school of one Tyrannus.","ref":"Acts 19:9","synthesized":"But when some of them stubbornly refused to believe and publicly maligned the Way, Paul took his disciples and left the synagogue to conduct daily discussions in the lecture hall of Tyrannus.","sources":{"KJV":{"text":"But when divers were hardened, and believed not, but spake evil of that way before the multitude, he departed from them, and separated the disciples, disputing daily in the school of one Tyrannus."},"BSB":{"text":"But when some of them stubbornly refused to believe and publicly maligned the Way, Paul took his disciples and left the synagogue to conduct daily discussions in the lecture hall of Tyrannus."}},"definableWords":["way"],"peopleInVerse":["Paul"]},"10":{"text":"And this continued by the space of two years; so that all they which dwelt in Asia heard the word of the Lord Jesus, both Jews and Greeks.","ref":"Acts 19:10","synthesized":"This continued for two years, so that everyone who lived in the province of Asia, Jews and Greeks alike, heard the word of the Lord.","sources":{"KJV":{"text":"And this continued by the space of two years; so that all they which dwelt in Asia heard the word of the Lord Jesus, both Jews and Greeks."},"BSB":{"text":"This continued for two years, so that everyone who lived in the province of Asia, Jews and Greeks alike, heard the word of the Lord."}},"definableWords":["years","word","Lord"],"peopleInVerse":[]},"11":{"text":"And God wrought special miracles by the hands of Paul:","ref":"Acts 19:11","synthesized":"God did extraordinary miracles through the hands of Paul,","sources":{"KJV":{"text":"And God wrought special miracles by the hands of Paul:"},"BSB":{"text":"God did extraordinary miracles through the hands of Paul,"}},"definableWords":["God"],"peopleInVerse":["Paul"]},"12":{"text":"So that from his body were brought unto the sick handkerchiefs or aprons, and the diseases departed from them, and the evil spirits went out of them.","ref":"Acts 19:12","synthesized":"so that even handkerchiefs and aprons that had touched him were taken to the sick, and the diseases and evil spirits left them.","sources":{"KJV":{"text":"So that from his body were brought unto the sick handkerchiefs or aprons, and the diseases departed from them, and the evil spirits went out of them."},"BSB":{"text":"so that even handkerchiefs and aprons that had touched him were taken to the sick, and the diseases and evil spirits left them."}},"definableWords":["evil"],"peopleInVerse":[]},"13":{"text":"Then certain of the vagabond Jews, exorcists, took upon them to call over them which had evil spirits the name of the LORD Jesus, saying, We adjure you by Jesus whom Paul preacheth.","ref":"Acts 19:13","synthesized":"Now there were some itinerant Jewish exorcists who tried to invoke the name of the Lord Jesus over those with evil spirits. They would say, “I bind you by Jesus, whom Paul proclaims.”","sources":{"KJV":{"text":"Then certain of the vagabond Jews, exorcists, took upon them to call over them which had evil spirits the name of the LORD Jesus, saying, We adjure you by Jesus whom Paul preacheth."},"BSB":{"text":"Now there were some itinerant Jewish exorcists who tried to invoke the name of the Lord Jesus over those with evil spirits. They would say, “I bind you by Jesus, whom Paul proclaims.”"}},"definableWords":["name","Lord","evil"],"peopleInVerse":["Jesus","Paul"]},"14":{"text":"And there were seven sons of one Sceva, a Jew, and chief of the priests, which did so.","ref":"Acts 19:14","synthesized":"Seven sons of Sceva, a Jewish chief priest, were doing this.","sources":{"KJV":{"text":"And there were seven sons of one Sceva, a Jew, and chief of the priests, which did so."},"BSB":{"text":"Seven sons of Sceva, a Jewish chief priest, were doing this."}},"definableWords":["sons","priest"],"peopleInVerse":[]},"15":{"text":"And the evil spirit answered and said, Jesus I know, and Paul I know; but who are ye?","ref":"Acts 19:15","synthesized":"Eventually, one of the evil spirits answered them, “Jesus I know, and I know about Paul, but who are you?”","sources":{"KJV":{"text":"And the evil spirit answered and said, Jesus I know, and Paul I know; but who are ye?"},"BSB":{"text":"Eventually, one of the evil spirits answered them, “Jesus I know, and I know about Paul, but who are you?”"}},"definableWords":["one","evil"],"peopleInVerse":["Jesus","Paul"]},"16":{"text":"And the man in whom the evil spirit was leaped on them, and overcame them, and prevailed against them, so that they fled out of that house naked and wounded.","ref":"Acts 19:16","synthesized":"Then the man with the evil spirit jumped on them and overpowered them all. The attack was so violent that they ran out of the house naked and wounded.","sources":{"KJV":{"text":"And the man in whom the evil spirit was leaped on them, and overcame them, and prevailed against them, so that they fled out of that house naked and wounded."},"BSB":{"text":"Then the man with the evil spirit jumped on them and overpowered them all. The attack was so violent that they ran out of the house naked and wounded."}},"definableWords":["man","evil","spirit","house","naked"],"peopleInVerse":[]},"17":{"text":"And this was known to all the Jews and Greeks also dwelling at Ephesus; and fear fell on them all, and the name of the Lord Jesus was magnified.","ref":"Acts 19:17","synthesized":"This became known to all the Jews and Greeks living in Ephesus, and fear came over all of them. So the name of the Lord Jesus was held in high honor.","sources":{"KJV":{"text":"And this was known to all the Jews and Greeks also dwelling at Ephesus; and fear fell on them all, and the name of the Lord Jesus was magnified."},"BSB":{"text":"This became known to all the Jews and Greeks living in Ephesus, and fear came over all of them. So the name of the Lord Jesus was held in high honor."}},"definableWords":["living","fear","name","Lord"],"peopleInVerse":["Jesus"]},"18":{"text":"And many that believed came, and confessed, and shewed their deeds.","ref":"Acts 19:18","synthesized":"Many who had believed now came forward, confessing and disclosing their deeds.","sources":{"KJV":{"text":"And many that believed came, and confessed, and shewed their deeds."},"BSB":{"text":"Many who had believed now came forward, confessing and disclosing their deeds."}},"definableWords":["believed"],"peopleInVerse":[]},"19":{"text":"Many of them also which used curious arts brought their books together, and burned them before all men: and they counted the price of them, and found it fifty thousand pieces of silver.","ref":"Acts 19:19","synthesized":"And a number of those who had practiced magic arts brought their books and burned them in front of everyone. When the value of the books was calculated, the total came to fifty thousand drachmas.","sources":{"KJV":{"text":"Many of them also which used curious arts brought their books together, and burned them before all men: and they counted the price of them, and found it fifty thousand pieces of silver."},"BSB":{"text":"And a number of those who had practiced magic arts brought their books and burned them in front of everyone. When the value of the books was calculated, the total came to fifty thousand drachmas."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"So mightily grew the word of God and prevailed.","ref":"Acts 19:20","synthesized":"So the word of the Lord powerfully continued to spread and prevail.","sources":{"KJV":{"text":"So mightily grew the word of God and prevailed."},"BSB":{"text":"So the word of the Lord powerfully continued to spread and prevail."}},"definableWords":["word","Lord"],"peopleInVerse":[]},"21":{"text":"After these things were ended, Paul purposed in the spirit, when he had passed through Macedonia and Achaia, to go to Jerusalem, saying, After I have been there, I must also see Rome.","ref":"Acts 19:21","synthesized":"After these things had happened, Paul resolved in the Spirit to go to Jerusalem after he had passed through Macedonia and Achaia. “After I have been there,” he said, “I must see Rome as well.”","sources":{"KJV":{"text":"After these things were ended, Paul purposed in the spirit, when he had passed through Macedonia and Achaia, to go to Jerusalem, saying, After I have been there, I must also see Rome."},"BSB":{"text":"After these things had happened, Paul resolved in the Spirit to go to Jerusalem after he had passed through Macedonia and Achaia. “After I have been there,” he said, “I must see Rome as well.”"}},"definableWords":["Spirit","Jerusalem","see"],"peopleInVerse":["Paul"]},"22":{"text":"So he sent into Macedonia two of them that ministered unto him, Timotheus and Erastus; but he himself stayed in Asia for a season.","ref":"Acts 19:22","synthesized":"He sent two of his helpers, Timothy and Erastus, to Macedonia, while he stayed for a time in the province of Asia.","sources":{"KJV":{"text":"So he sent into Macedonia two of them that ministered unto him, Timotheus and Erastus; but he himself stayed in Asia for a season."},"BSB":{"text":"He sent two of his helpers, Timothy and Erastus, to Macedonia, while he stayed for a time in the province of Asia."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"And the same time there arose no small stir about that way.","ref":"Acts 19:23","synthesized":"About that time there arose a great disturbance about the Way.","sources":{"KJV":{"text":"And the same time there arose no small stir about that way."},"BSB":{"text":"About that time there arose a great disturbance about the Way."}},"definableWords":["great","way"],"peopleInVerse":[]},"24":{"text":"For a certain man named Demetrius, a silversmith, which made silver shrines for Diana, brought no small gain unto the craftsmen;","ref":"Acts 19:24","synthesized":"It began with a silversmith named Demetrius who made silver shrines of Artemis, bringing much business to the craftsmen.","sources":{"KJV":{"text":"For a certain man named Demetrius, a silversmith, which made silver shrines for Diana, brought no small gain unto the craftsmen;"},"BSB":{"text":"It began with a silversmith named Demetrius who made silver shrines of Artemis, bringing much business to the craftsmen."}},"definableWords":["made"],"peopleInVerse":[]},"25":{"text":"Whom he called together with the workmen of like occupation, and said, Sirs, ye know that by this craft we have our wealth.","ref":"Acts 19:25","synthesized":"Demetrius assembled the craftsmen, along with the workmen in related trades. “Men,” he said, “you know that this business is our source of prosperity.","sources":{"KJV":{"text":"Whom he called together with the workmen of like occupation, and said, Sirs, ye know that by this craft we have our wealth."},"BSB":{"text":"Demetrius assembled the craftsmen, along with the workmen in related trades. “Men,” he said, “you know that this business is our source of prosperity."}},"definableWords":["men"],"peopleInVerse":[]},"26":{"text":"Moreover ye see and hear, that not alone at Ephesus, but almost throughout all Asia, this Paul hath persuaded and turned away much people, saying that they be no gods, which are made with hands:","ref":"Acts 19:26","synthesized":"And you can see and hear that not only in Ephesus, but in nearly the whole province of Asia, Paul has persuaded a great number of people to turn away. He says that man-made gods are no gods at all.","sources":{"KJV":{"text":"Moreover ye see and hear, that not alone at Ephesus, but almost throughout all Asia, this Paul hath persuaded and turned away much people, saying that they be no gods, which are made with hands:"},"BSB":{"text":"And you can see and hear that not only in Ephesus, but in nearly the whole province of Asia, Paul has persuaded a great number of people to turn away. He says that man-made gods are no gods at all."}},"definableWords":["see","hear","great","people","man","made"],"peopleInVerse":["Paul"]},"27":{"text":"So that not only this our craft is in danger to be set at nought; but also that the temple of the great goddess Diana should be despised, and her magnificence should be destroyed, whom all Asia and the world worshippeth.","ref":"Acts 19:27","synthesized":"There is danger not only that our business will fall into disrepute, but also that the temple of the great goddess Artemis will be discredited and her majesty deposed—she who is worshiped by all the province of Asia and the whole world.”","sources":{"KJV":{"text":"So that not only this our craft is in danger to be set at nought; but also that the temple of the great goddess Diana should be despised, and her magnificence should be destroyed, whom all Asia and the world worshippeth."},"BSB":{"text":"There is danger not only that our business will fall into disrepute, but also that the temple of the great goddess Artemis will be discredited and her majesty deposed—she who is worshiped by all the province of Asia and the whole world.”"}},"definableWords":["temple","great"],"peopleInVerse":[]},"28":{"text":"And when they heard these sayings, they were full of wrath, and cried out, saying, Great is Diana of the Ephesians.","ref":"Acts 19:28","synthesized":"When the men heard this, they were enraged and began shouting, “Great is Artemis of the Ephesians!”","sources":{"KJV":{"text":"And when they heard these sayings, they were full of wrath, and cried out, saying, Great is Diana of the Ephesians."},"BSB":{"text":"When the men heard this, they were enraged and began shouting, “Great is Artemis of the Ephesians!”"}},"definableWords":["men","great"],"peopleInVerse":[]},"29":{"text":"And the whole city was filled with confusion: and having caught Gaius and Aristarchus, men of Macedonia, Paul’s companions in travel, they rushed with one accord into the theatre.","ref":"Acts 19:29","synthesized":"Soon the whole city was in disarray. They rushed together into the theatre, dragging with them Gaius and Aristarchus, Paul’s traveling companions from Macedonia.","sources":{"KJV":{"text":"And the whole city was filled with confusion: and having caught Gaius and Aristarchus, men of Macedonia, Paul’s companions in travel, they rushed with one accord into the theatre."},"BSB":{"text":"Soon the whole city was in disarray. They rushed together into the theatre, dragging with them Gaius and Aristarchus, Paul’s traveling companions from Macedonia."}},"definableWords":[],"peopleInVerse":["Paul"]},"30":{"text":"And when Paul would have entered in unto the people, the disciples suffered him not.","ref":"Acts 19:30","synthesized":"Paul wanted to go before the assembly, but the disciples would not allow him.","sources":{"KJV":{"text":"And when Paul would have entered in unto the people, the disciples suffered him not."},"BSB":{"text":"Paul wanted to go before the assembly, but the disciples would not allow him."}},"definableWords":[],"peopleInVerse":["Paul"]},"31":{"text":"And certain of the chief of Asia, which were his friends, sent unto him, desiring him that he would not adventure himself into the theatre.","ref":"Acts 19:31","synthesized":"Even some of Paul’s friends who were officials of the province of Asia sent word to him, begging him not to venture into the theatre.","sources":{"KJV":{"text":"And certain of the chief of Asia, which were his friends, sent unto him, desiring him that he would not adventure himself into the theatre."},"BSB":{"text":"Even some of Paul’s friends who were officials of the province of Asia sent word to him, begging him not to venture into the theatre."}},"definableWords":["word"],"peopleInVerse":["Paul"]},"32":{"text":"Some therefore cried one thing, and some another: for the assembly was confused; and the more part knew not wherefore they were come together.","ref":"Acts 19:32","synthesized":"Meanwhile the assembly was in turmoil. Some were shouting one thing and some another, and most of them did not even know why they were there.","sources":{"KJV":{"text":"Some therefore cried one thing, and some another: for the assembly was confused; and the more part knew not wherefore they were come together."},"BSB":{"text":"Meanwhile the assembly was in turmoil. Some were shouting one thing and some another, and most of them did not even know why they were there."}},"definableWords":["one"],"peopleInVerse":[]},"33":{"text":"And they drew Alexander out of the multitude, the Jews putting him forward. And Alexander beckoned with the hand, and would have made his defence unto the people.","ref":"Acts 19:33","synthesized":"The Jews in the crowd pushed Alexander forward to explain himself, and he motioned for silence so he could make his defense to the people.","sources":{"KJV":{"text":"And they drew Alexander out of the multitude, the Jews putting him forward. And Alexander beckoned with the hand, and would have made his defence unto the people."},"BSB":{"text":"The Jews in the crowd pushed Alexander forward to explain himself, and he motioned for silence so he could make his defense to the people."}},"definableWords":["make","people"],"peopleInVerse":[]},"34":{"text":"But when they knew that he was a Jew, all with one voice about the space of two hours cried out, Great is Diana of the Ephesians.","ref":"Acts 19:34","synthesized":"But when they realized that he was a Jew, they all shouted in unison for about two hours: “Great is Artemis of the Ephesians!”","sources":{"KJV":{"text":"But when they knew that he was a Jew, all with one voice about the space of two hours cried out, Great is Diana of the Ephesians."},"BSB":{"text":"But when they realized that he was a Jew, they all shouted in unison for about two hours: “Great is Artemis of the Ephesians!”"}},"definableWords":["Jew","great"],"peopleInVerse":[]},"35":{"text":"And when the townclerk had appeased the people, he said, Ye men of Ephesus, what man is there that knoweth not how that the city of the Ephesians is a worshipper of the great goddess Diana, and of the image which fell down from Jupiter?","ref":"Acts 19:35","synthesized":"Finally the city clerk quieted the crowd and declared, “Men of Ephesus, doesn’t everyone know that the city of Ephesus is guardian of the temple of the great Artemis and of her image, which fell from heaven?","sources":{"KJV":{"text":"And when the townclerk had appeased the people, he said, Ye men of Ephesus, what man is there that knoweth not how that the city of the Ephesians is a worshipper of the great goddess Diana, and of the image which fell down from Jupiter?"},"BSB":{"text":"Finally the city clerk quieted the crowd and declared, “Men of Ephesus, doesn’t everyone know that the city of Ephesus is guardian of the temple of the great Artemis and of her image, which fell from heaven?"}},"definableWords":["men","temple","great","image","heaven"],"peopleInVerse":[]},"36":{"text":"Seeing then that these things cannot be spoken against, ye ought to be quiet, and to do nothing rashly.","ref":"Acts 19:36","synthesized":"Since these things are undeniable, you ought to be calm and not do anything rash.","sources":{"KJV":{"text":"Seeing then that these things cannot be spoken against, ye ought to be quiet, and to do nothing rashly."},"BSB":{"text":"Since these things are undeniable, you ought to be calm and not do anything rash."}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"For ye have brought hither these men, which are neither robbers of churches, nor yet blasphemers of your goddess.","ref":"Acts 19:37","synthesized":"For you have brought these men here, though they have neither robbed our temple nor blasphemed our goddess.","sources":{"KJV":{"text":"For ye have brought hither these men, which are neither robbers of churches, nor yet blasphemers of your goddess."},"BSB":{"text":"For you have brought these men here, though they have neither robbed our temple nor blasphemed our goddess."}},"definableWords":["men","temple"],"peopleInVerse":[]},"38":{"text":"Wherefore if Demetrius, and the craftsmen which are with him, have a matter against any man, the law is open, and there are deputies: let them implead one another.","ref":"Acts 19:38","synthesized":"So if Demetrius and his fellow craftsmen have a complaint against anyone, the courts are open and proconsuls are available. Let them bring charges against one another there.","sources":{"KJV":{"text":"Wherefore if Demetrius, and the craftsmen which are with him, have a matter against any man, the law is open, and there are deputies: let them implead one another."},"BSB":{"text":"So if Demetrius and his fellow craftsmen have a complaint against anyone, the courts are open and proconsuls are available. Let them bring charges against one another there."}},"definableWords":["one"],"peopleInVerse":[]},"39":{"text":"But if ye enquire any thing concerning other matters, it shall be determined in a lawful assembly.","ref":"Acts 19:39","synthesized":"But if you are seeking anything beyond this, it must be settled in a legal assembly.","sources":{"KJV":{"text":"But if ye enquire any thing concerning other matters, it shall be determined in a lawful assembly."},"BSB":{"text":"But if you are seeking anything beyond this, it must be settled in a legal assembly."}},"definableWords":[],"peopleInVerse":[]},"40":{"text":"For we are in danger to be called in question for this day’s uproar, there being no cause whereby we may give an account of this concourse.","ref":"Acts 19:40","synthesized":"For we are in jeopardy of being charged with rioting for today’s events, and we have no justification to account for this commotion.”","sources":{"KJV":{"text":"For we are in danger to be called in question for this day’s uproar, there being no cause whereby we may give an account of this concourse."},"BSB":{"text":"For we are in jeopardy of being charged with rioting for today’s events, and we have no justification to account for this commotion.”"}},"definableWords":["justification"],"peopleInVerse":[]},"41":{"text":"And when he had thus spoken, he dismissed the assembly.","ref":"Acts 19:41","synthesized":"After he had said this, he dismissed the assembly.","sources":{"KJV":{"text":"And when he had thus spoken, he dismissed the assembly."},"BSB":{"text":"After he had said this, he dismissed the assembly."}},"definableWords":[],"peopleInVerse":[]}}},"20":{"chapter":"20","title":"PAUL AT TROAS — EUTYCHUS","verses":{"1":{"text":"And after the uproar was ceased, Paul called unto him the disciples, and embraced them, and departed for to go into Macedonia.","ref":"Acts 20:1","synthesized":"When the uproar had ended, Paul sent for the disciples. And after encouraging them, he said goodbye to them and left for Macedonia.","sources":{"KJV":{"text":"And after the uproar was ceased, Paul called unto him the disciples, and embraced them, and departed for to go into Macedonia."},"BSB":{"text":"When the uproar had ended, Paul sent for the disciples. And after encouraging them, he said goodbye to them and left for Macedonia."}},"definableWords":[],"peopleInVerse":["Paul"]},"2":{"text":"And when he had gone over those parts, and had given them much exhortation, he came into Greece,","ref":"Acts 20:2","synthesized":"After traveling through that area and speaking many words of encouragement, he arrived in Greece,","sources":{"KJV":{"text":"And when he had gone over those parts, and had given them much exhortation, he came into Greece,"},"BSB":{"text":"After traveling through that area and speaking many words of encouragement, he arrived in Greece,"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"And there abode three months. And when the Jews laid wait for him, as he was about to sail into Syria, he purposed to return through Macedonia.","ref":"Acts 20:3","synthesized":"where he stayed three months. And when the Jews formed a plot against him as he was about to sail for Syria, he decided to go back through Macedonia.","sources":{"KJV":{"text":"And there abode three months. And when the Jews laid wait for him, as he was about to sail into Syria, he purposed to return through Macedonia."},"BSB":{"text":"where he stayed three months. And when the Jews formed a plot against him as he was about to sail for Syria, he decided to go back through Macedonia."}},"definableWords":["formed"],"peopleInVerse":[]},"4":{"text":"And there accompanied him into Asia Sopater of Berea; and of the Thessalonians, Aristarchus and Secundus; and Gaius of Derbe, and Timotheus; and of Asia, Tychicus and Trophimus.","ref":"Acts 20:4","synthesized":"Paul was accompanied by Sopater son of Pyrrhus from Berea, Aristarchus and Secundus from Thessalonica, Gaius from Derbe, Timothy, and Tychicus and Trophimus from the province of Asia.","sources":{"KJV":{"text":"And there accompanied him into Asia Sopater of Berea; and of the Thessalonians, Aristarchus and Secundus; and Gaius of Derbe, and Timotheus; and of Asia, Tychicus and Trophimus."},"BSB":{"text":"Paul was accompanied by Sopater son of Pyrrhus from Berea, Aristarchus and Secundus from Thessalonica, Gaius from Derbe, Timothy, and Tychicus and Trophimus from the province of Asia."}},"definableWords":["son"],"peopleInVerse":["Paul"]},"5":{"text":"These going before tarried for us at Troas.","ref":"Acts 20:5","synthesized":"These men went on ahead and waited for us in Troas.","sources":{"KJV":{"text":"These going before tarried for us at Troas."},"BSB":{"text":"These men went on ahead and waited for us in Troas."}},"definableWords":["men"],"peopleInVerse":[]},"6":{"text":"And we sailed away from Philippi after the days of unleavened bread, and came unto them to Troas in five days; where we abode seven days.","ref":"Acts 20:6","synthesized":"And after the Feast of Unleavened Bread, we sailed from Philippi, and five days later we rejoined them in Troas, where we stayed seven days.","sources":{"KJV":{"text":"And we sailed away from Philippi after the days of unleavened bread, and came unto them to Troas in five days; where we abode seven days."},"BSB":{"text":"And after the Feast of Unleavened Bread, we sailed from Philippi, and five days later we rejoined them in Troas, where we stayed seven days."}},"definableWords":["days"],"peopleInVerse":[]},"7":{"text":"And upon the first day of the week, when the disciples came together to break bread, Paul preached unto them, ready to depart on the morrow; and continued his speech until midnight.","ref":"Acts 20:7","synthesized":"On the first day of the week we came together to break bread. Since Paul was ready to leave the next day, he talked to them and kept on speaking until midnight.","sources":{"KJV":{"text":"And upon the first day of the week, when the disciples came together to break bread, Paul preached unto them, ready to depart on the morrow; and continued his speech until midnight."},"BSB":{"text":"On the first day of the week we came together to break bread. Since Paul was ready to leave the next day, he talked to them and kept on speaking until midnight."}},"definableWords":["day"],"peopleInVerse":["Paul"]},"8":{"text":"And there were many lights in the upper chamber, where they were gathered together.","ref":"Acts 20:8","synthesized":"Now there were many lamps in the upper room where we were gathered.","sources":{"KJV":{"text":"And there were many lights in the upper chamber, where they were gathered together."},"BSB":{"text":"Now there were many lamps in the upper room where we were gathered."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"And there sat in a window a certain young man named Eutychus, being fallen into a deep sleep: and as Paul was long preaching, he sunk down with sleep, and fell down from the third loft, and was taken up dead.","ref":"Acts 20:9","synthesized":"And a certain young man named Eutychus, seated in the window, was sinking into a deep sleep as Paul talked on and on. When he was sound asleep, he fell from the third story and was picked up dead.","sources":{"KJV":{"text":"And there sat in a window a certain young man named Eutychus, being fallen into a deep sleep: and as Paul was long preaching, he sunk down with sleep, and fell down from the third loft, and was taken up dead."},"BSB":{"text":"And a certain young man named Eutychus, seated in the window, was sinking into a deep sleep as Paul talked on and on. When he was sound asleep, he fell from the third story and was picked up dead."}},"definableWords":["man","deep"],"peopleInVerse":["Paul"]},"10":{"text":"And Paul went down, and fell on him, and embracing him said, Trouble not yourselves; for his life is in him.","ref":"Acts 20:10","synthesized":"But Paul went down, threw himself on the young man, and embraced him. “Do not be alarmed!” he said. “He is still alive!”","sources":{"KJV":{"text":"And Paul went down, and fell on him, and embracing him said, Trouble not yourselves; for his life is in him."},"BSB":{"text":"But Paul went down, threw himself on the young man, and embraced him. “Do not be alarmed!” he said. “He is still alive!”"}},"definableWords":["man"],"peopleInVerse":["Paul"]},"11":{"text":"When he therefore was come up again, and had broken bread, and eaten, and talked a long while, even till break of day, so he departed.","ref":"Acts 20:11","synthesized":"Then Paul went back upstairs, broke bread, and ate. And after speaking until daybreak, he departed.","sources":{"KJV":{"text":"When he therefore was come up again, and had broken bread, and eaten, and talked a long while, even till break of day, so he departed."},"BSB":{"text":"Then Paul went back upstairs, broke bread, and ate. And after speaking until daybreak, he departed."}},"definableWords":[],"peopleInVerse":["Paul"]},"12":{"text":"And they brought the young man alive, and were not a little comforted.","ref":"Acts 20:12","synthesized":"And the people were greatly relieved to take the boy home alive.","sources":{"KJV":{"text":"And they brought the young man alive, and were not a little comforted."},"BSB":{"text":"And the people were greatly relieved to take the boy home alive."}},"definableWords":["people"],"peopleInVerse":[]},"13":{"text":"And we went before to ship, and sailed unto Assos, there intending to take in Paul: for so had he appointed, minding himself to go afoot.","ref":"Acts 20:13","synthesized":"We went on ahead to the ship and sailed to Assos, where we were to take Paul aboard. He had arranged this because he was going there on foot.","sources":{"KJV":{"text":"And we went before to ship, and sailed unto Assos, there intending to take in Paul: for so had he appointed, minding himself to go afoot."},"BSB":{"text":"We went on ahead to the ship and sailed to Assos, where we were to take Paul aboard. He had arranged this because he was going there on foot."}},"definableWords":[],"peopleInVerse":["Paul"]},"14":{"text":"And when he met with us at Assos, we took him in, and came to Mitylene.","ref":"Acts 20:14","synthesized":"And when he met us at Assos, we took him aboard and went on to Mitylene.","sources":{"KJV":{"text":"And when he met with us at Assos, we took him in, and came to Mitylene."},"BSB":{"text":"And when he met us at Assos, we took him aboard and went on to Mitylene."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And we sailed thence, and came the next day over against Chios; and the next day we arrived at Samos, and tarried at Trogyllium; and the next day we came to Miletus.","ref":"Acts 20:15","synthesized":"Sailing on from there, we arrived the next day opposite Chios. The day after that we arrived at Samos, and on the following day we came to Miletus.","sources":{"KJV":{"text":"And we sailed thence, and came the next day over against Chios; and the next day we arrived at Samos, and tarried at Trogyllium; and the next day we came to Miletus."},"BSB":{"text":"Sailing on from there, we arrived the next day opposite Chios. The day after that we arrived at Samos, and on the following day we came to Miletus."}},"definableWords":["day"],"peopleInVerse":[]},"16":{"text":"For Paul had determined to sail by Ephesus, because he would not spend the time in Asia: for he hasted, if it were possible for him, to be at Jerusalem the day of Pentecost.","ref":"Acts 20:16","synthesized":"Paul had decided to sail past Ephesus to avoid spending time in the province of Asia, because he was in a hurry to reach Jerusalem, if possible, by the day of Pentecost.","sources":{"KJV":{"text":"For Paul had determined to sail by Ephesus, because he would not spend the time in Asia: for he hasted, if it were possible for him, to be at Jerusalem the day of Pentecost."},"BSB":{"text":"Paul had decided to sail past Ephesus to avoid spending time in the province of Asia, because he was in a hurry to reach Jerusalem, if possible, by the day of Pentecost."}},"definableWords":["Jerusalem","day","Pentecost"],"peopleInVerse":["Paul"]},"17":{"text":"And from Miletus he sent to Ephesus, and called the elders of the church.","ref":"Acts 20:17","synthesized":"From Miletus, Paul sent to Ephesus for the elders of the church.","sources":{"KJV":{"text":"And from Miletus he sent to Ephesus, and called the elders of the church."},"BSB":{"text":"From Miletus, Paul sent to Ephesus for the elders of the church."}},"definableWords":["church"],"peopleInVerse":["Paul"]},"18":{"text":"And when they were come to him, he said unto them, Ye know, from the first day that I came into Asia, after what manner I have been with you at all seasons,","ref":"Acts 20:18","synthesized":"When they came to him, he said, “You know how I lived the whole time I was with you, from the first day I arrived in the province of Asia.","sources":{"KJV":{"text":"And when they were come to him, he said unto them, Ye know, from the first day that I came into Asia, after what manner I have been with you at all seasons,"},"BSB":{"text":"When they came to him, he said, “You know how I lived the whole time I was with you, from the first day I arrived in the province of Asia."}},"definableWords":["day"],"peopleInVerse":[]},"19":{"text":"Serving the LORD with all humility of mind, and with many tears, and temptations, which befell me by the lying in wait of the Jews:","ref":"Acts 20:19","synthesized":"I served the Lord with great humility and with tears, especially in the trials that came upon me through the plots of the Jews.","sources":{"KJV":{"text":"Serving the LORD with all humility of mind, and with many tears, and temptations, which befell me by the lying in wait of the Jews:"},"BSB":{"text":"I served the Lord with great humility and with tears, especially in the trials that came upon me through the plots of the Jews."}},"definableWords":["Lord","great"],"peopleInVerse":[]},"20":{"text":"And how I kept back nothing that was profitable unto you, but have shewed you, and have taught you publickly, and from house to house,","ref":"Acts 20:20","synthesized":"I did not shrink back from declaring anything that was helpful to you as I taught you publicly and from house to house,","sources":{"KJV":{"text":"And how I kept back nothing that was profitable unto you, but have shewed you, and have taught you publickly, and from house to house,"},"BSB":{"text":"I did not shrink back from declaring anything that was helpful to you as I taught you publicly and from house to house,"}},"definableWords":["house"],"peopleInVerse":[]},"21":{"text":"Testifying both to the Jews, and also to the Greeks, repentance toward God, and faith toward our Lord Jesus Christ.","ref":"Acts 20:21","synthesized":"testifying to Jews and Greeks alike about repentance to God and faith in our Lord Jesus Christ.","sources":{"KJV":{"text":"Testifying both to the Jews, and also to the Greeks, repentance toward God, and faith toward our Lord Jesus Christ."},"BSB":{"text":"testifying to Jews and Greeks alike about repentance to God and faith in our Lord Jesus Christ."}},"definableWords":["repentance","God","faith","Lord","Christ"],"peopleInVerse":["Jesus"]},"22":{"text":"And now, behold, I go bound in the spirit unto Jerusalem, not knowing the things that shall befall me there:","ref":"Acts 20:22","synthesized":"And now, compelled by the Spirit, I am going to Jerusalem, not knowing what will happen to me there.","sources":{"KJV":{"text":"And now, behold, I go bound in the spirit unto Jerusalem, not knowing the things that shall befall me there:"},"BSB":{"text":"And now, compelled by the Spirit, I am going to Jerusalem, not knowing what will happen to me there."}},"definableWords":["Spirit","Jerusalem"],"peopleInVerse":[]},"23":{"text":"Save that the Holy Ghost witnesseth in every city, saying that bonds and afflictions abide me.","ref":"Acts 20:23","synthesized":"I only know that in town after town the Holy Spirit warns me that chains and afflictions await me.","sources":{"KJV":{"text":"Save that the Holy Ghost witnesseth in every city, saying that bonds and afflictions abide me."},"BSB":{"text":"I only know that in town after town the Holy Spirit warns me that chains and afflictions await me."}},"definableWords":["holy","Spirit"],"peopleInVerse":[]},"24":{"text":"But none of these things move me, neither count I my life dear unto myself, so that I might finish my course with joy, and the ministry, which I have received of the Lord Jesus, to testify the gospel of the grace of God.","ref":"Acts 20:24","synthesized":"But I consider my life of no value to me, if only I may finish my course and complete the ministry I have received from the Lord Jesus—the ministry of testifying to the good news of God’s grace.","sources":{"KJV":{"text":"But none of these things move me, neither count I my life dear unto myself, so that I might finish my course with joy, and the ministry, which I have received of the Lord Jesus, to testify the gospel of the grace of God."},"BSB":{"text":"But I consider my life of no value to me, if only I may finish my course and complete the ministry I have received from the Lord Jesus—the ministry of testifying to the good news of God’s grace."}},"definableWords":["life","Lord","good","God","grace"],"peopleInVerse":["Jesus"]},"25":{"text":"And now, behold, I know that ye all, among whom I have gone preaching the kingdom of God, shall see my face no more.","ref":"Acts 20:25","synthesized":"Now I know that none of you among whom I have preached the kingdom will see my face again.","sources":{"KJV":{"text":"And now, behold, I know that ye all, among whom I have gone preaching the kingdom of God, shall see my face no more."},"BSB":{"text":"Now I know that none of you among whom I have preached the kingdom will see my face again."}},"definableWords":["kingdom","see"],"peopleInVerse":[]},"26":{"text":"Wherefore I take you to record this day, that I am pure from the blood of all men.","ref":"Acts 20:26","synthesized":"Therefore I testify to you this day that I am innocent of the blood of all men.","sources":{"KJV":{"text":"Wherefore I take you to record this day, that I am pure from the blood of all men."},"BSB":{"text":"Therefore I testify to you this day that I am innocent of the blood of all men."}},"definableWords":["day","blood","men"],"peopleInVerse":[]},"27":{"text":"For I have not shunned to declare unto you all the counsel of God.","ref":"Acts 20:27","synthesized":"For I did not shrink back from declaring to you the whole will of God.","sources":{"KJV":{"text":"For I have not shunned to declare unto you all the counsel of God."},"BSB":{"text":"For I did not shrink back from declaring to you the whole will of God."}},"definableWords":["God"],"peopleInVerse":[]},"28":{"text":"Take heed therefore unto yourselves, and to all the flock, over the which the Holy Ghost hath made you overseers, to feed the church of God, which he hath purchased with his own blood.","ref":"Acts 20:28","synthesized":"Keep watch over yourselves and the entire flock of which the Holy Spirit has made you overseers. Be shepherds of the church of God, which He purchased with His own blood.","sources":{"KJV":{"text":"Take heed therefore unto yourselves, and to all the flock, over the which the Holy Ghost hath made you overseers, to feed the church of God, which he hath purchased with his own blood."},"BSB":{"text":"Keep watch over yourselves and the entire flock of which the Holy Spirit has made you overseers. Be shepherds of the church of God, which He purchased with His own blood."}},"definableWords":["keep","holy","Spirit","made","church","God","blood"],"peopleInVerse":[]},"29":{"text":"For I know this, that after my departing shall grievous wolves enter in among you, not sparing the flock.","ref":"Acts 20:29","synthesized":"I know that after my departure, savage wolves will come in among you and will not spare the flock.","sources":{"KJV":{"text":"For I know this, that after my departing shall grievous wolves enter in among you, not sparing the flock."},"BSB":{"text":"I know that after my departure, savage wolves will come in among you and will not spare the flock."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"Also of your own selves shall men arise, speaking perverse things, to draw away disciples after them.","ref":"Acts 20:30","synthesized":"Even from your own number, men will rise up and distort the truth to draw away disciples after them.","sources":{"KJV":{"text":"Also of your own selves shall men arise, speaking perverse things, to draw away disciples after them."},"BSB":{"text":"Even from your own number, men will rise up and distort the truth to draw away disciples after them."}},"definableWords":["men","truth"],"peopleInVerse":[]},"31":{"text":"Therefore watch, and remember, that by the space of three years I ceased not to warn every one night and day with tears.","ref":"Acts 20:31","synthesized":"Therefore be alert and remember that for three years I never stopped warning each of you night and day with tears.","sources":{"KJV":{"text":"Therefore watch, and remember, that by the space of three years I ceased not to warn every one night and day with tears."},"BSB":{"text":"Therefore be alert and remember that for three years I never stopped warning each of you night and day with tears."}},"definableWords":["remember","years","night","day"],"peopleInVerse":[]},"32":{"text":"And now, brethren, I commend you to God, and to the word of his grace, which is able to build you up, and to give you an inheritance among all them which are sanctified.","ref":"Acts 20:32","synthesized":"And now I commit you to God and to the word of His grace, which can build you up and give you an inheritance among all who are sanctified.","sources":{"KJV":{"text":"And now, brethren, I commend you to God, and to the word of his grace, which is able to build you up, and to give you an inheritance among all them which are sanctified."},"BSB":{"text":"And now I commit you to God and to the word of His grace, which can build you up and give you an inheritance among all who are sanctified."}},"definableWords":["God","word","grace"],"peopleInVerse":[]},"33":{"text":"I have coveted no man’s silver, or gold, or apparel.","ref":"Acts 20:33","synthesized":"I have not coveted anyone’s silver or gold or clothing.","sources":{"KJV":{"text":"I have coveted no man’s silver, or gold, or apparel."},"BSB":{"text":"I have not coveted anyone’s silver or gold or clothing."}},"definableWords":["or"],"peopleInVerse":[]},"34":{"text":"Yea, ye yourselves know, that these hands have ministered unto my necessities, and to them that were with me.","ref":"Acts 20:34","synthesized":"You yourselves know that these hands of mine have ministered to my own needs and those of my companions.","sources":{"KJV":{"text":"Yea, ye yourselves know, that these hands have ministered unto my necessities, and to them that were with me."},"BSB":{"text":"You yourselves know that these hands of mine have ministered to my own needs and those of my companions."}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"I have shewed you all things, how that so labouring ye ought to support the weak, and to remember the words of the Lord Jesus, how he said, It is more blessed to give than to receive.","ref":"Acts 20:35","synthesized":"In everything, I showed you that by this kind of hard work we must help the weak, remembering the words of the Lord Jesus Himself: ‘It is more blessed to give than to receive.’”","sources":{"KJV":{"text":"I have shewed you all things, how that so labouring ye ought to support the weak, and to remember the words of the Lord Jesus, how he said, It is more blessed to give than to receive."},"BSB":{"text":"In everything, I showed you that by this kind of hard work we must help the weak, remembering the words of the Lord Jesus Himself: ‘It is more blessed to give than to receive.’”"}},"definableWords":["work","Lord","blessed"],"peopleInVerse":["Jesus"]},"36":{"text":"And when he had thus spoken, he kneeled down, and prayed with them all.","ref":"Acts 20:36","synthesized":"When Paul had said this, he knelt down with all of them and prayed.","sources":{"KJV":{"text":"And when he had thus spoken, he kneeled down, and prayed with them all."},"BSB":{"text":"When Paul had said this, he knelt down with all of them and prayed."}},"definableWords":[],"peopleInVerse":["Paul"]},"37":{"text":"And they all wept sore, and fell on Paul’s neck, and kissed him,","ref":"Acts 20:37","synthesized":"They all wept openly as they embraced Paul and kissed him.","sources":{"KJV":{"text":"And they all wept sore, and fell on Paul’s neck, and kissed him,"},"BSB":{"text":"They all wept openly as they embraced Paul and kissed him."}},"definableWords":[],"peopleInVerse":["Paul"]},"38":{"text":"Sorrowing most of all for the words which he spake, that they should see his face no more. And they accompanied him unto the ship.","ref":"Acts 20:38","synthesized":"They were especially grieved by his statement that they would never see his face again. Then they accompanied him to the ship.","sources":{"KJV":{"text":"Sorrowing most of all for the words which he spake, that they should see his face no more. And they accompanied him unto the ship."},"BSB":{"text":"They were especially grieved by his statement that they would never see his face again. Then they accompanied him to the ship."}},"definableWords":["see"],"peopleInVerse":[]}}},"21":{"chapter":"21","title":"PAUL ARRESTED AT JERUSALEM","verses":{"1":{"text":"And it came to pass, that after we were gotten from them, and had launched, we came with a straight course unto Coos, and the day following unto Rhodes, and from thence unto Patara:","ref":"Acts 21:1","synthesized":"After we had torn ourselves away from them, we sailed directly to Cos, and the next day on to Rhodes, and from there to Patara.","sources":{"KJV":{"text":"And it came to pass, that after we were gotten from them, and had launched, we came with a straight course unto Coos, and the day following unto Rhodes, and from thence unto Patara:"},"BSB":{"text":"After we had torn ourselves away from them, we sailed directly to Cos, and the next day on to Rhodes, and from there to Patara."}},"definableWords":["day"],"peopleInVerse":[]},"2":{"text":"And finding a ship sailing over unto Phenicia, we went aboard, and set forth.","ref":"Acts 21:2","synthesized":"Finding a ship crossing over to Phoenicia, we boarded it and set sail.","sources":{"KJV":{"text":"And finding a ship sailing over unto Phenicia, we went aboard, and set forth."},"BSB":{"text":"Finding a ship crossing over to Phoenicia, we boarded it and set sail."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Now when we had discovered Cyprus, we left it on the left hand, and sailed into Syria, and landed at Tyre: for there the ship was to unlade her burden.","ref":"Acts 21:3","synthesized":"After sighting Cyprus and passing south of it, we sailed on to Syria and landed at Tyre, where the ship was to unload its cargo.","sources":{"KJV":{"text":"Now when we had discovered Cyprus, we left it on the left hand, and sailed into Syria, and landed at Tyre: for there the ship was to unlade her burden."},"BSB":{"text":"After sighting Cyprus and passing south of it, we sailed on to Syria and landed at Tyre, where the ship was to unload its cargo."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"And finding disciples, we tarried there seven days: who said to Paul through the Spirit, that he should not go up to Jerusalem.","ref":"Acts 21:4","synthesized":"We sought out the disciples in Tyre and stayed with them seven days. Through the Spirit they kept telling Paul not to go up to Jerusalem.","sources":{"KJV":{"text":"And finding disciples, we tarried there seven days: who said to Paul through the Spirit, that he should not go up to Jerusalem."},"BSB":{"text":"We sought out the disciples in Tyre and stayed with them seven days. Through the Spirit they kept telling Paul not to go up to Jerusalem."}},"definableWords":["days","Spirit","Jerusalem"],"peopleInVerse":["Paul"]},"5":{"text":"And when we had accomplished those days, we departed and went our way; and they all brought us on our way, with wives and children, till we were out of the city: and we kneeled down on the shore, and prayed.","ref":"Acts 21:5","synthesized":"But when our time there had ended, we set out on our journey. All the disciples, with their wives and children, accompanied us out of the city and knelt down on the beach to pray with us.","sources":{"KJV":{"text":"And when we had accomplished those days, we departed and went our way; and they all brought us on our way, with wives and children, till we were out of the city: and we kneeled down on the shore, and prayed."},"BSB":{"text":"But when our time there had ended, we set out on our journey. All the disciples, with their wives and children, accompanied us out of the city and knelt down on the beach to pray with us."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"And when we had taken our leave one of another, we took ship; and they returned home again.","ref":"Acts 21:6","synthesized":"And after we had said our farewells, we went aboard the ship, and they returned home.","sources":{"KJV":{"text":"And when we had taken our leave one of another, we took ship; and they returned home again."},"BSB":{"text":"And after we had said our farewells, we went aboard the ship, and they returned home."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And when we had finished our course from Tyre, we came to Ptolemais, and saluted the brethren, and abode with them one day.","ref":"Acts 21:7","synthesized":"When we had finished our voyage from Tyre, we landed at Ptolemais, where we greeted the brothers and stayed with them for a day.","sources":{"KJV":{"text":"And when we had finished our course from Tyre, we came to Ptolemais, and saluted the brethren, and abode with them one day."},"BSB":{"text":"When we had finished our voyage from Tyre, we landed at Ptolemais, where we greeted the brothers and stayed with them for a day."}},"definableWords":["day"],"peopleInVerse":[]},"8":{"text":"And the next day we that were of Paul’s company departed, and came unto Caesarea: and we entered into the house of Philip the evangelist, which was one of the seven; and abode with him.","ref":"Acts 21:8","synthesized":"Leaving the next day, we went on to Caesarea and stayed at the home of Philip the evangelist, who was one of the Seven.","sources":{"KJV":{"text":"And the next day we that were of Paul’s company departed, and came unto Caesarea: and we entered into the house of Philip the evangelist, which was one of the seven; and abode with him."},"BSB":{"text":"Leaving the next day, we went on to Caesarea and stayed at the home of Philip the evangelist, who was one of the Seven."}},"definableWords":["day","evangelist","one"],"peopleInVerse":[]},"9":{"text":"And the same man had four daughters, virgins, which did prophesy.","ref":"Acts 21:9","synthesized":"He had four unmarried daughters who prophesied.","sources":{"KJV":{"text":"And the same man had four daughters, virgins, which did prophesy."},"BSB":{"text":"He had four unmarried daughters who prophesied."}},"definableWords":["daughters"],"peopleInVerse":[]},"10":{"text":"And as we tarried there many days, there came down from Judaea a certain prophet, named Agabus.","ref":"Acts 21:10","synthesized":"After we had been there several days, a prophet named Agabus came down from Judea.","sources":{"KJV":{"text":"And as we tarried there many days, there came down from Judaea a certain prophet, named Agabus."},"BSB":{"text":"After we had been there several days, a prophet named Agabus came down from Judea."}},"definableWords":["days","prophet","Judea"],"peopleInVerse":[]},"11":{"text":"And when he was come unto us, he took Paul’s girdle, and bound his own hands and feet, and said, Thus saith the Holy Ghost, So shall the Jews at Jerusalem bind the man that owneth this girdle, and shall deliver him into the hands of the Gentiles.","ref":"Acts 21:11","synthesized":"Coming over to us, he took Paul’s belt, bound his own feet and hands, and said, “The Holy Spirit says: ‘In this way the Jews of Jerusalem will bind the owner of this belt and hand him over to the Gentiles.’”","sources":{"KJV":{"text":"And when he was come unto us, he took Paul’s girdle, and bound his own hands and feet, and said, Thus saith the Holy Ghost, So shall the Jews at Jerusalem bind the man that owneth this girdle, and shall deliver him into the hands of the Gentiles."},"BSB":{"text":"Coming over to us, he took Paul’s belt, bound his own feet and hands, and said, “The Holy Spirit says: ‘In this way the Jews of Jerusalem will bind the owner of this belt and hand him over to the Gentiles.’”"}},"definableWords":["holy","Spirit","way","Jerusalem"],"peopleInVerse":["Paul"]},"12":{"text":"And when we heard these things, both we, and they of that place, besought him not to go up to Jerusalem.","ref":"Acts 21:12","synthesized":"When we heard this, we and the people there pleaded with Paul not to go up to Jerusalem.","sources":{"KJV":{"text":"And when we heard these things, both we, and they of that place, besought him not to go up to Jerusalem."},"BSB":{"text":"When we heard this, we and the people there pleaded with Paul not to go up to Jerusalem."}},"definableWords":["people","Jerusalem"],"peopleInVerse":["Paul"]},"13":{"text":"Then Paul answered, What mean ye to weep and to break mine heart? for I am ready not to be bound only, but also to die at Jerusalem for the name of the Lord Jesus.","ref":"Acts 21:13","synthesized":"Then Paul answered, “Why are you weeping and breaking my heart? I am ready not only to be bound, but also to die in Jerusalem for the name of the Lord Jesus.”","sources":{"KJV":{"text":"Then Paul answered, What mean ye to weep and to break mine heart? for I am ready not to be bound only, but also to die at Jerusalem for the name of the Lord Jesus."},"BSB":{"text":"Then Paul answered, “Why are you weeping and breaking my heart? I am ready not only to be bound, but also to die in Jerusalem for the name of the Lord Jesus.”"}},"definableWords":["heart","die","Jerusalem","name","Lord"],"peopleInVerse":["Paul","Jesus"]},"14":{"text":"And when he would not be persuaded, we ceased, saying, The will of the Lord be done.","ref":"Acts 21:14","synthesized":"When he would not be dissuaded, we fell silent and said, “The Lord’s will be done.”","sources":{"KJV":{"text":"And when he would not be persuaded, we ceased, saying, The will of the Lord be done."},"BSB":{"text":"When he would not be dissuaded, we fell silent and said, “The Lord’s will be done.”"}},"definableWords":["Lord"],"peopleInVerse":[]},"15":{"text":"And after those days we took up our carriages, and went up to Jerusalem.","ref":"Acts 21:15","synthesized":"After these days, we packed up and went on to Jerusalem.","sources":{"KJV":{"text":"And after those days we took up our carriages, and went up to Jerusalem."},"BSB":{"text":"After these days, we packed up and went on to Jerusalem."}},"definableWords":["days","Jerusalem"],"peopleInVerse":[]},"16":{"text":"There went with us also certain of the disciples of Caesarea, and brought with them one Mnason of Cyprus, an old disciple, with whom we should lodge.","ref":"Acts 21:16","synthesized":"Some of the disciples from Caesarea accompanied us, and they took us to stay at the home of Mnason the Cypriot, an early disciple.","sources":{"KJV":{"text":"There went with us also certain of the disciples of Caesarea, and brought with them one Mnason of Cyprus, an old disciple, with whom we should lodge."},"BSB":{"text":"Some of the disciples from Caesarea accompanied us, and they took us to stay at the home of Mnason the Cypriot, an early disciple."}},"definableWords":["disciple"],"peopleInVerse":[]},"17":{"text":"And when we were come to Jerusalem, the brethren received us gladly.","ref":"Acts 21:17","synthesized":"When we arrived in Jerusalem, the brothers welcomed us joyfully.","sources":{"KJV":{"text":"And when we were come to Jerusalem, the brethren received us gladly."},"BSB":{"text":"When we arrived in Jerusalem, the brothers welcomed us joyfully."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"18":{"text":"And the day following Paul went in with us unto James; and all the elders were present.","ref":"Acts 21:18","synthesized":"The next day Paul went in with us to see James, and all the elders were present.","sources":{"KJV":{"text":"And the day following Paul went in with us unto James; and all the elders were present."},"BSB":{"text":"The next day Paul went in with us to see James, and all the elders were present."}},"definableWords":["day","see"],"peopleInVerse":["Paul","James"]},"19":{"text":"And when he had saluted them, he declared particularly what things God had wrought among the Gentiles by his ministry.","ref":"Acts 21:19","synthesized":"Paul greeted them and recounted one by one the things that God had done among the Gentiles through his ministry.","sources":{"KJV":{"text":"And when he had saluted them, he declared particularly what things God had wrought among the Gentiles by his ministry."},"BSB":{"text":"Paul greeted them and recounted one by one the things that God had done among the Gentiles through his ministry."}},"definableWords":["one","God"],"peopleInVerse":["Paul"]},"20":{"text":"And when they heard it, they glorified the Lord, and said unto him, Thou seest, brother, how many thousands of Jews there are which believe; and they are all zealous of the law:","ref":"Acts 21:20","synthesized":"When they heard this, they glorified God. Then they said to Paul, “You see, brother, how many thousands of Jews have believed, and all of them are zealous for the law.","sources":{"KJV":{"text":"And when they heard it, they glorified the Lord, and said unto him, Thou seest, brother, how many thousands of Jews there are which believe; and they are all zealous of the law:"},"BSB":{"text":"When they heard this, they glorified God. Then they said to Paul, “You see, brother, how many thousands of Jews have believed, and all of them are zealous for the law."}},"definableWords":["God","see","brother","believed","law"],"peopleInVerse":["Paul"]},"21":{"text":"And they are informed of thee, that thou teachest all the Jews which are among the Gentiles to forsake Moses, saying that they ought not to circumcise their children, neither to walk after the customs.","ref":"Acts 21:21","synthesized":"But they are under the impression that you teach all the Jews who live among the Gentiles to forsake Moses, telling them not to circumcise their children or observe our customs.","sources":{"KJV":{"text":"And they are informed of thee, that thou teachest all the Jews which are among the Gentiles to forsake Moses, saying that they ought not to circumcise their children, neither to walk after the customs."},"BSB":{"text":"But they are under the impression that you teach all the Jews who live among the Gentiles to forsake Moses, telling them not to circumcise their children or observe our customs."}},"definableWords":["live","or"],"peopleInVerse":["Moses"]},"22":{"text":"What is it therefore? the multitude must needs come together: for they will hear that thou art come.","ref":"Acts 21:22","synthesized":"What then should we do? They will certainly hear that you have come.","sources":{"KJV":{"text":"What is it therefore? the multitude must needs come together: for they will hear that thou art come."},"BSB":{"text":"What then should we do? They will certainly hear that you have come."}},"definableWords":["hear"],"peopleInVerse":[]},"23":{"text":"Do therefore this that we say to thee: We have four men which have a vow on them;","ref":"Acts 21:23","synthesized":"Therefore do what we advise you. There are four men with us who have taken a vow.","sources":{"KJV":{"text":"Do therefore this that we say to thee: We have four men which have a vow on them;"},"BSB":{"text":"Therefore do what we advise you. There are four men with us who have taken a vow."}},"definableWords":["men"],"peopleInVerse":[]},"24":{"text":"Them take, and purify thyself with them, and be at charges with them, that they may shave their heads: and all may know that those things, whereof they were informed concerning thee, are nothing; but that thou thyself also walkest orderly, and keepest the law.","ref":"Acts 21:24","synthesized":"Take these men, purify yourself along with them, and pay their expenses so they can have their heads shaved. Then everyone will know that there is no truth to these rumors about you, but that you also live in obedience to the law.","sources":{"KJV":{"text":"Them take, and purify thyself with them, and be at charges with them, that they may shave their heads: and all may know that those things, whereof they were informed concerning thee, are nothing; but that thou thyself also walkest orderly, and keepest the law."},"BSB":{"text":"Take these men, purify yourself along with them, and pay their expenses so they can have their heads shaved. Then everyone will know that there is no truth to these rumors about you, but that you also live in obedience to the law."}},"definableWords":["men","truth","live","law"],"peopleInVerse":[]},"25":{"text":"As touching the Gentiles which believe, we have written and concluded that they observe no such thing, save only that they keep themselves from things offered to idols, and from blood, and from strangled, and from fornication.","ref":"Acts 21:25","synthesized":"As for the Gentile believers, we have written to them our decision that they must abstain from food sacrificed to idols, from blood, from the meat of strangled animals, and from sexual immorality.”","sources":{"KJV":{"text":"As touching the Gentiles which believe, we have written and concluded that they observe no such thing, save only that they keep themselves from things offered to idols, and from blood, and from strangled, and from fornication."},"BSB":{"text":"As for the Gentile believers, we have written to them our decision that they must abstain from food sacrificed to idols, from blood, from the meat of strangled animals, and from sexual immorality.”"}},"definableWords":["gentile","blood"],"peopleInVerse":[]},"26":{"text":"Then Paul took the men, and the next day purifying himself with them entered into the temple, to signify the accomplishment of the days of purification, until that an offering should be offered for every one of them.","ref":"Acts 21:26","synthesized":"So the next day Paul took the men and purified himself along with them. Then he entered the temple to give notice of the date when their purification would be complete and the offering would be made for each of them.","sources":{"KJV":{"text":"Then Paul took the men, and the next day purifying himself with them entered into the temple, to signify the accomplishment of the days of purification, until that an offering should be offered for every one of them."},"BSB":{"text":"So the next day Paul took the men and purified himself along with them. Then he entered the temple to give notice of the date when their purification would be complete and the offering would be made for each of them."}},"definableWords":["day","men","temple","offering","made"],"peopleInVerse":["Paul"]},"27":{"text":"And when the seven days were almost ended, the Jews which were of Asia, when they saw him in the temple, stirred up all the people, and laid hands on him,","ref":"Acts 21:27","synthesized":"When the seven days were almost over, some Jews from the province of Asia saw Paul at the temple. They stirred up the whole crowd and seized him,","sources":{"KJV":{"text":"And when the seven days were almost ended, the Jews which were of Asia, when they saw him in the temple, stirred up all the people, and laid hands on him,"},"BSB":{"text":"When the seven days were almost over, some Jews from the province of Asia saw Paul at the temple. They stirred up the whole crowd and seized him,"}},"definableWords":["days","saw","temple"],"peopleInVerse":["Paul"]},"28":{"text":"Crying out, Men of Israel, help: This is the man, that teacheth all men every where against the people, and the law, and this place: and further brought Greeks also into the temple, and hath polluted this holy place.","ref":"Acts 21:28","synthesized":"crying out, “Men of Israel, help us! This is the man who teaches everywhere against our people and against our law and against this place. Furthermore, he has brought Greeks into the temple and defiled this holy place.”","sources":{"KJV":{"text":"Crying out, Men of Israel, help: This is the man, that teacheth all men every where against the people, and the law, and this place: and further brought Greeks also into the temple, and hath polluted this holy place."},"BSB":{"text":"crying out, “Men of Israel, help us! This is the man who teaches everywhere against our people and against our law and against this place. Furthermore, he has brought Greeks into the temple and defiled this holy place.”"}},"definableWords":["men","Israel","man","people","law","temple","holy"],"peopleInVerse":[]},"29":{"text":"(For they had seen before with him in the city Trophimus an Ephesian, whom they supposed that Paul had brought into the temple.)","ref":"Acts 21:29","synthesized":"For they had previously seen Trophimus the Ephesian with him in the city, and they assumed that Paul had brought him into the temple.","sources":{"KJV":{"text":"(For they had seen before with him in the city Trophimus an Ephesian, whom they supposed that Paul had brought into the temple.)"},"BSB":{"text":"For they had previously seen Trophimus the Ephesian with him in the city, and they assumed that Paul had brought him into the temple."}},"definableWords":["temple"],"peopleInVerse":["Paul"]},"30":{"text":"And all the city was moved, and the people ran together: and they took Paul, and drew him out of the temple: and forthwith the doors were shut.","ref":"Acts 21:30","synthesized":"The whole city was stirred up, and the people rushed together. They seized Paul and dragged him out of the temple, and at once the gates were shut.","sources":{"KJV":{"text":"And all the city was moved, and the people ran together: and they took Paul, and drew him out of the temple: and forthwith the doors were shut."},"BSB":{"text":"The whole city was stirred up, and the people rushed together. They seized Paul and dragged him out of the temple, and at once the gates were shut."}},"definableWords":["people","temple"],"peopleInVerse":["Paul"]},"31":{"text":"And as they went about to kill him, tidings came unto the chief captain of the band, that all Jerusalem was in an uproar.","ref":"Acts 21:31","synthesized":"While they were trying to kill him, the commander of the Roman regiment received a report that all Jerusalem was in turmoil.","sources":{"KJV":{"text":"And as they went about to kill him, tidings came unto the chief captain of the band, that all Jerusalem was in an uproar."},"BSB":{"text":"While they were trying to kill him, the commander of the Roman regiment received a report that all Jerusalem was in turmoil."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"32":{"text":"Who immediately took soldiers and centurions, and ran down unto them: and when they saw the chief captain and the soldiers, they left beating of Paul.","ref":"Acts 21:32","synthesized":"Immediately he took some soldiers and centurions and ran down to the crowd. When the people saw the commander and the soldiers, they stopped beating Paul.","sources":{"KJV":{"text":"Who immediately took soldiers and centurions, and ran down unto them: and when they saw the chief captain and the soldiers, they left beating of Paul."},"BSB":{"text":"Immediately he took some soldiers and centurions and ran down to the crowd. When the people saw the commander and the soldiers, they stopped beating Paul."}},"definableWords":["people","saw"],"peopleInVerse":["Paul"]},"33":{"text":"Then the chief captain came near, and took him, and commanded him to be bound with two chains; and demanded who he was, and what he had done.","ref":"Acts 21:33","synthesized":"The commander came up and arrested Paul, ordering that he be bound with two chains. Then he asked who he was and what he had done.","sources":{"KJV":{"text":"Then the chief captain came near, and took him, and commanded him to be bound with two chains; and demanded who he was, and what he had done."},"BSB":{"text":"The commander came up and arrested Paul, ordering that he be bound with two chains. Then he asked who he was and what he had done."}},"definableWords":[],"peopleInVerse":["Paul"]},"34":{"text":"And some cried one thing, some another, among the multitude: and when he could not know the certainty for the tumult, he commanded him to be carried into the castle.","ref":"Acts 21:34","synthesized":"Some in the crowd were shouting one thing, and some another. And since the commander could not get at the truth because of the uproar, he ordered that Paul be brought into the barracks.","sources":{"KJV":{"text":"And some cried one thing, some another, among the multitude: and when he could not know the certainty for the tumult, he commanded him to be carried into the castle."},"BSB":{"text":"Some in the crowd were shouting one thing, and some another. And since the commander could not get at the truth because of the uproar, he ordered that Paul be brought into the barracks."}},"definableWords":["one","truth"],"peopleInVerse":["Paul"]},"35":{"text":"And when he came upon the stairs, so it was, that he was borne of the soldiers for the violence of the people.","ref":"Acts 21:35","synthesized":"When Paul reached the steps, he had to be carried by the soldiers because of the violence of the mob.","sources":{"KJV":{"text":"And when he came upon the stairs, so it was, that he was borne of the soldiers for the violence of the people."},"BSB":{"text":"When Paul reached the steps, he had to be carried by the soldiers because of the violence of the mob."}},"definableWords":[],"peopleInVerse":["Paul"]},"36":{"text":"For the multitude of the people followed after, crying, Away with him.","ref":"Acts 21:36","synthesized":"For the crowd that followed him kept shouting, “Away with him!”","sources":{"KJV":{"text":"For the multitude of the people followed after, crying, Away with him."},"BSB":{"text":"For the crowd that followed him kept shouting, “Away with him!”"}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"And as Paul was to be led into the castle, he said unto the chief captain, May I speak unto thee? Who said, Canst thou speak Greek?","ref":"Acts 21:37","synthesized":"As they were about to take Paul into the barracks, he asked the commander, “May I say something to you?”  “Do you speak Greek?” he replied.","sources":{"KJV":{"text":"And as Paul was to be led into the castle, he said unto the chief captain, May I speak unto thee? Who said, Canst thou speak Greek?"},"BSB":{"text":"As they were about to take Paul into the barracks, he asked the commander, “May I say something to you?”  “Do you speak Greek?” he replied."}},"definableWords":["Greek"],"peopleInVerse":["Paul"]},"38":{"text":"Art not thou that Egyptian, which before these days madest an uproar, and leddest out into the wilderness four thousand men that were murderers?","ref":"Acts 21:38","synthesized":"“Aren’t you the Egyptian who incited a rebellion some time ago and led four thousand members of the ‘Assassins’ into the wilderness?”","sources":{"KJV":{"text":"Art not thou that Egyptian, which before these days madest an uproar, and leddest out into the wilderness four thousand men that were murderers?"},"BSB":{"text":"“Aren’t you the Egyptian who incited a rebellion some time ago and led four thousand members of the ‘Assassins’ into the wilderness?”"}},"definableWords":[],"peopleInVerse":[]},"39":{"text":"But Paul said, I am a man which am a Jew of Tarsus, a city in Cilicia, a citizen of no mean city: and, I beseech thee, suffer me to speak unto the people.","ref":"Acts 21:39","synthesized":"But Paul answered, “I am a Jew from Tarsus in Cilicia, a citizen of no ordinary city. Now I beg you to allow me to speak to the people.”","sources":{"KJV":{"text":"But Paul said, I am a man which am a Jew of Tarsus, a city in Cilicia, a citizen of no mean city: and, I beseech thee, suffer me to speak unto the people."},"BSB":{"text":"But Paul answered, “I am a Jew from Tarsus in Cilicia, a citizen of no ordinary city. Now I beg you to allow me to speak to the people.”"}},"definableWords":["Jew","people"],"peopleInVerse":["Paul"]},"40":{"text":"And when he had given him licence, Paul stood on the stairs, and beckoned with the hand unto the people. And when there was made a great silence, he spake unto them in the Hebrew tongue, saying,","ref":"Acts 21:40","synthesized":"Having received permission, Paul stood on the steps and motioned to the crowd. A great hush came over the crowd, and he addressed them in Hebrew:","sources":{"KJV":{"text":"And when he had given him licence, Paul stood on the stairs, and beckoned with the hand unto the people. And when there was made a great silence, he spake unto them in the Hebrew tongue, saying,"},"BSB":{"text":"Having received permission, Paul stood on the steps and motioned to the crowd. A great hush came over the crowd, and he addressed them in Hebrew:"}},"definableWords":["great"],"peopleInVerse":["Paul"]}}},"22":{"chapter":"22","title":"PAUL'S TESTIMONY ON THE STAIRS","verses":{"1":{"text":"Men, brethren, and fathers, hear ye my defence which I make now unto you.","ref":"Acts 22:1","synthesized":"“Brothers and fathers, listen now to my defense before you.”","sources":{"KJV":{"text":"Men, brethren, and fathers, hear ye my defence which I make now unto you."},"BSB":{"text":"“Brothers and fathers, listen now to my defense before you.”"}},"definableWords":["fathers"],"peopleInVerse":[]},"2":{"text":"(And when they heard that he spake in the Hebrew tongue to them, they kept the more silence: and he saith,)","ref":"Acts 22:2","synthesized":"When they heard him speak to them in Hebrew, they became even more silent.  Then Paul declared,","sources":{"KJV":{"text":"(And when they heard that he spake in the Hebrew tongue to them, they kept the more silence: and he saith,)"},"BSB":{"text":"When they heard him speak to them in Hebrew, they became even more silent.  Then Paul declared,"}},"definableWords":[],"peopleInVerse":["Paul"]},"3":{"text":"I am verily a man which am a Jew, born in Tarsus, a city in Cilicia, yet brought up in this city at the feet of Gamaliel, and taught according to the perfect manner of the law of the fathers, and was zealous toward God, as ye all are this day.","ref":"Acts 22:3","synthesized":"“I am a Jew, born in Tarsus of Cilicia, but raised in this city. I was educated at the feet of Gamaliel in strict conformity to the law of our fathers. I am just as zealous for God as any of you here today.","sources":{"KJV":{"text":"I am verily a man which am a Jew, born in Tarsus, a city in Cilicia, yet brought up in this city at the feet of Gamaliel, and taught according to the perfect manner of the law of the fathers, and was zealous toward God, as ye all are this day."},"BSB":{"text":"“I am a Jew, born in Tarsus of Cilicia, but raised in this city. I was educated at the feet of Gamaliel in strict conformity to the law of our fathers. I am just as zealous for God as any of you here today."}},"definableWords":["Jew","law","fathers","God"],"peopleInVerse":[]},"4":{"text":"And I persecuted this way unto the death, binding and delivering into prisons both men and women.","ref":"Acts 22:4","synthesized":"I persecuted this Way even to the death, detaining both men and women and throwing them into prison,","sources":{"KJV":{"text":"And I persecuted this way unto the death, binding and delivering into prisons both men and women."},"BSB":{"text":"I persecuted this Way even to the death, detaining both men and women and throwing them into prison,"}},"definableWords":["way","death","men","women"],"peopleInVerse":[]},"5":{"text":"As also the high priest doth bear me witness, and all the estate of the elders: from whom also I received letters unto the brethren, and went to Damascus, to bring them which were there bound unto Jerusalem, for to be punished.","ref":"Acts 22:5","synthesized":"as the high priest and the whole Council can testify about me. I even obtained letters from them to their brothers in Damascus, and I was on my way to apprehend these people and bring them to Jerusalem to be punished.","sources":{"KJV":{"text":"As also the high priest doth bear me witness, and all the estate of the elders: from whom also I received letters unto the brethren, and went to Damascus, to bring them which were there bound unto Jerusalem, for to be punished."},"BSB":{"text":"as the high priest and the whole Council can testify about me. I even obtained letters from them to their brothers in Damascus, and I was on my way to apprehend these people and bring them to Jerusalem to be punished."}},"definableWords":["priest","way","people","Jerusalem"],"peopleInVerse":[]},"6":{"text":"And it came to pass, that, as I made my journey, and was come nigh unto Damascus about noon, suddenly there shone from heaven a great light round about me.","ref":"Acts 22:6","synthesized":"About noon as I was approaching Damascus, suddenly a bright light from heaven flashed around me.","sources":{"KJV":{"text":"And it came to pass, that, as I made my journey, and was come nigh unto Damascus about noon, suddenly there shone from heaven a great light round about me."},"BSB":{"text":"About noon as I was approaching Damascus, suddenly a bright light from heaven flashed around me."}},"definableWords":["light","heaven"],"peopleInVerse":[]},"7":{"text":"And I fell unto the ground, and heard a voice saying unto me, Saul, Saul, why persecutest thou me?","ref":"Acts 22:7","synthesized":"I fell to the ground and heard a voice say to me, ‘Saul, Saul, why do you persecute Me?’","sources":{"KJV":{"text":"And I fell unto the ground, and heard a voice saying unto me, Saul, Saul, why persecutest thou me?"},"BSB":{"text":"I fell to the ground and heard a voice say to me, ‘Saul, Saul, why do you persecute Me?’"}},"definableWords":["ground","voice"],"peopleInVerse":["Saul"]},"8":{"text":"And I answered, Who art thou, Lord? And he said unto me, I am Jesus of Nazareth, whom thou persecutest.","ref":"Acts 22:8","synthesized":"‘Who are You, Lord?’ I asked.  ‘I am Jesus of Nazareth, whom you are persecuting,’ He replied.","sources":{"KJV":{"text":"And I answered, Who art thou, Lord? And he said unto me, I am Jesus of Nazareth, whom thou persecutest."},"BSB":{"text":"‘Who are You, Lord?’ I asked.  ‘I am Jesus of Nazareth, whom you are persecuting,’ He replied."}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"9":{"text":"And they that were with me saw indeed the light, and were afraid; but they heard not the voice of him that spake to me.","ref":"Acts 22:9","synthesized":"My companions saw the light, but they could not understand the voice of the One speaking to me.","sources":{"KJV":{"text":"And they that were with me saw indeed the light, and were afraid; but they heard not the voice of him that spake to me."},"BSB":{"text":"My companions saw the light, but they could not understand the voice of the One speaking to me."}},"definableWords":["saw","light","voice","one"],"peopleInVerse":[]},"10":{"text":"And I said, What shall I do, LORD? And the Lord said unto me, Arise, and go into Damascus; and there it shall be told thee of all things which are appointed for thee to do.","ref":"Acts 22:10","synthesized":"Then I asked, ‘What should I do, Lord?’  ‘Get up and go into Damascus,’ He told me. ‘There you will be told all that you have been appointed to do.’","sources":{"KJV":{"text":"And I said, What shall I do, LORD? And the Lord said unto me, Arise, and go into Damascus; and there it shall be told thee of all things which are appointed for thee to do."},"BSB":{"text":"Then I asked, ‘What should I do, Lord?’  ‘Get up and go into Damascus,’ He told me. ‘There you will be told all that you have been appointed to do.’"}},"definableWords":["Lord"],"peopleInVerse":[]},"11":{"text":"And when I could not see for the glory of that light, being led by the hand of them that were with me, I came into Damascus.","ref":"Acts 22:11","synthesized":"Because the brilliance of the light had blinded me, my companions led me by the hand into Damascus.","sources":{"KJV":{"text":"And when I could not see for the glory of that light, being led by the hand of them that were with me, I came into Damascus."},"BSB":{"text":"Because the brilliance of the light had blinded me, my companions led me by the hand into Damascus."}},"definableWords":["light"],"peopleInVerse":[]},"12":{"text":"And one Ananias, a devout man according to the law, having a good report of all the Jews which dwelt there,","ref":"Acts 22:12","synthesized":"There a man named Ananias, a devout observer of the law who was highly regarded by all the Jews living there,","sources":{"KJV":{"text":"And one Ananias, a devout man according to the law, having a good report of all the Jews which dwelt there,"},"BSB":{"text":"There a man named Ananias, a devout observer of the law who was highly regarded by all the Jews living there,"}},"definableWords":["man","law","living"],"peopleInVerse":[]},"13":{"text":"Came unto me, and stood, and said unto me, Brother Saul, receive thy sight. And the same hour I looked up upon him.","ref":"Acts 22:13","synthesized":"came and stood beside me. ‘Brother Saul,’ he said, ‘receive your sight.’ And at that moment I could see him.","sources":{"KJV":{"text":"Came unto me, and stood, and said unto me, Brother Saul, receive thy sight. And the same hour I looked up upon him."},"BSB":{"text":"came and stood beside me. ‘Brother Saul,’ he said, ‘receive your sight.’ And at that moment I could see him."}},"definableWords":["brother","see"],"peopleInVerse":["Saul"]},"14":{"text":"And he said, The God of our fathers hath chosen thee, that thou shouldest know his will, and see that Just One, and shouldest hear the voice of his mouth.","ref":"Acts 22:14","synthesized":"Then he said, ‘The God of our fathers has appointed you to know His will, and to see the Righteous One, and to hear His voice.","sources":{"KJV":{"text":"And he said, The God of our fathers hath chosen thee, that thou shouldest know his will, and see that Just One, and shouldest hear the voice of his mouth."},"BSB":{"text":"Then he said, ‘The God of our fathers has appointed you to know His will, and to see the Righteous One, and to hear His voice."}},"definableWords":["God","fathers","see","righteous","one","hear","voice"],"peopleInVerse":[]},"15":{"text":"For thou shalt be his witness unto all men of what thou hast seen and heard.","ref":"Acts 22:15","synthesized":"You will be His witness to everyone of what you have seen and heard.","sources":{"KJV":{"text":"For thou shalt be his witness unto all men of what thou hast seen and heard."},"BSB":{"text":"You will be His witness to everyone of what you have seen and heard."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"And now why tarriest thou? arise, and be baptized, and wash away thy sins, calling on the name of the Lord.","ref":"Acts 22:16","synthesized":"And now what are you waiting for? Get up, be baptized, and wash your sins away, calling on His name.’","sources":{"KJV":{"text":"And now why tarriest thou? arise, and be baptized, and wash away thy sins, calling on the name of the Lord."},"BSB":{"text":"And now what are you waiting for? Get up, be baptized, and wash your sins away, calling on His name.’"}},"definableWords":["name"],"peopleInVerse":[]},"17":{"text":"And it came to pass, that, when I was come again to Jerusalem, even while I prayed in the temple, I was in a trance;","ref":"Acts 22:17","synthesized":"Later, when I had returned to Jerusalem and was praying at the temple, I fell into a trance","sources":{"KJV":{"text":"And it came to pass, that, when I was come again to Jerusalem, even while I prayed in the temple, I was in a trance;"},"BSB":{"text":"Later, when I had returned to Jerusalem and was praying at the temple, I fell into a trance"}},"definableWords":["Jerusalem","temple"],"peopleInVerse":[]},"18":{"text":"And saw him saying unto me, Make haste, and get thee quickly out of Jerusalem: for they will not receive thy testimony concerning me.","ref":"Acts 22:18","synthesized":"and saw the Lord saying to me, ‘Hurry! Leave Jerusalem quickly, because the people here will not accept your testimony about Me.’","sources":{"KJV":{"text":"And saw him saying unto me, Make haste, and get thee quickly out of Jerusalem: for they will not receive thy testimony concerning me."},"BSB":{"text":"and saw the Lord saying to me, ‘Hurry! Leave Jerusalem quickly, because the people here will not accept your testimony about Me.’"}},"definableWords":["saw","Lord","Jerusalem","people"],"peopleInVerse":[]},"19":{"text":"And I said, Lord, they know that I imprisoned and beat in every synagogue them that believed on thee:","ref":"Acts 22:19","synthesized":"‘Lord,’ I answered, ‘they know very well that in one synagogue after another I imprisoned and beat those who believed in You.","sources":{"KJV":{"text":"And I said, Lord, they know that I imprisoned and beat in every synagogue them that believed on thee:"},"BSB":{"text":"‘Lord,’ I answered, ‘they know very well that in one synagogue after another I imprisoned and beat those who believed in You."}},"definableWords":["Lord","one","believed"],"peopleInVerse":[]},"20":{"text":"And when the blood of thy martyr Stephen was shed, I also was standing by, and consenting unto his death, and kept the raiment of them that slew him.","ref":"Acts 22:20","synthesized":"And when the blood of Your witness Stephen was shed, I stood there giving my approval and watching over the garments of those who killed him.’","sources":{"KJV":{"text":"And when the blood of thy martyr Stephen was shed, I also was standing by, and consenting unto his death, and kept the raiment of them that slew him."},"BSB":{"text":"And when the blood of Your witness Stephen was shed, I stood there giving my approval and watching over the garments of those who killed him.’"}},"definableWords":["blood"],"peopleInVerse":["Stephen"]},"21":{"text":"And he said unto me, Depart: for I will send thee far hence unto the Gentiles.","ref":"Acts 22:21","synthesized":"Then He said to me, ‘Go! I will send you far away to the Gentiles.’”","sources":{"KJV":{"text":"And he said unto me, Depart: for I will send thee far hence unto the Gentiles."},"BSB":{"text":"Then He said to me, ‘Go! I will send you far away to the Gentiles.’”"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"And they gave him audience unto this word, and then lifted up their voices, and said, Away with such a fellow from the earth: for it is not fit that he should live.","ref":"Acts 22:22","synthesized":"The crowd listened to Paul until he made this statement. Then they lifted up their voices and shouted, “Rid the earth of him! He is not fit to live!”","sources":{"KJV":{"text":"And they gave him audience unto this word, and then lifted up their voices, and said, Away with such a fellow from the earth: for it is not fit that he should live."},"BSB":{"text":"The crowd listened to Paul until he made this statement. Then they lifted up their voices and shouted, “Rid the earth of him! He is not fit to live!”"}},"definableWords":["made","earth","live"],"peopleInVerse":["Paul"]},"23":{"text":"And as they cried out, and cast off their clothes, and threw dust into the air,","ref":"Acts 22:23","synthesized":"As they were shouting and throwing off their cloaks and tossing dust into the air,","sources":{"KJV":{"text":"And as they cried out, and cast off their clothes, and threw dust into the air,"},"BSB":{"text":"As they were shouting and throwing off their cloaks and tossing dust into the air,"}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"The chief captain commanded him to be brought into the castle, and bade that he should be examined by scourging; that he might know wherefore they cried so against him.","ref":"Acts 22:24","synthesized":"the commander ordered that Paul be brought into the barracks. He directed that Paul be flogged and interrogated to determine the reason for this outcry against him.","sources":{"KJV":{"text":"The chief captain commanded him to be brought into the castle, and bade that he should be examined by scourging; that he might know wherefore they cried so against him."},"BSB":{"text":"the commander ordered that Paul be brought into the barracks. He directed that Paul be flogged and interrogated to determine the reason for this outcry against him."}},"definableWords":[],"peopleInVerse":["Paul"]},"25":{"text":"And as they bound him with thongs, Paul said unto the centurion that stood by, Is it lawful for you to scourge a man that is a Roman, and uncondemned?","ref":"Acts 22:25","synthesized":"But as they stretched him out to strap him down, Paul said to the centurion standing there, “Is it lawful for you to flog a Roman citizen without a trial?”","sources":{"KJV":{"text":"And as they bound him with thongs, Paul said unto the centurion that stood by, Is it lawful for you to scourge a man that is a Roman, and uncondemned?"},"BSB":{"text":"But as they stretched him out to strap him down, Paul said to the centurion standing there, “Is it lawful for you to flog a Roman citizen without a trial?”"}},"definableWords":[],"peopleInVerse":["Paul"]},"26":{"text":"When the centurion heard that, he went and told the chief captain, saying, Take heed what thou doest: for this man is a Roman.","ref":"Acts 22:26","synthesized":"On hearing this, the centurion went and reported it to the commander. “What are you going to do?” he said. “This man is a Roman citizen.”","sources":{"KJV":{"text":"When the centurion heard that, he went and told the chief captain, saying, Take heed what thou doest: for this man is a Roman."},"BSB":{"text":"On hearing this, the centurion went and reported it to the commander. “What are you going to do?” he said. “This man is a Roman citizen.”"}},"definableWords":["man"],"peopleInVerse":[]},"27":{"text":"Then the chief captain came, and said unto him, Tell me, art thou a Roman? He said, Yea.","ref":"Acts 22:27","synthesized":"The commander went to Paul and asked, “Tell me, are you a Roman citizen?”  “Yes,” he answered.","sources":{"KJV":{"text":"Then the chief captain came, and said unto him, Tell me, art thou a Roman? He said, Yea."},"BSB":{"text":"The commander went to Paul and asked, “Tell me, are you a Roman citizen?”  “Yes,” he answered."}},"definableWords":[],"peopleInVerse":["Paul"]},"28":{"text":"And the chief captain answered, With a great sum obtained I this freedom. And Paul said, But I was free born.","ref":"Acts 22:28","synthesized":"“I paid a high price for my citizenship,” said the commander.  “But I was born a citizen,” Paul replied.","sources":{"KJV":{"text":"And the chief captain answered, With a great sum obtained I this freedom. And Paul said, But I was free born."},"BSB":{"text":"“I paid a high price for my citizenship,” said the commander.  “But I was born a citizen,” Paul replied."}},"definableWords":[],"peopleInVerse":["Paul"]},"29":{"text":"Then straightway they departed from him which should have examined him: and the chief captain also was afraid, after he knew that he was a Roman, and because he had bound him.","ref":"Acts 22:29","synthesized":"Then those who were about to interrogate Paul stepped back, and the commander himself was alarmed when he realized that he had put a Roman citizen in chains.","sources":{"KJV":{"text":"Then straightway they departed from him which should have examined him: and the chief captain also was afraid, after he knew that he was a Roman, and because he had bound him."},"BSB":{"text":"Then those who were about to interrogate Paul stepped back, and the commander himself was alarmed when he realized that he had put a Roman citizen in chains."}},"definableWords":[],"peopleInVerse":["Paul"]},"30":{"text":"On the morrow, because he would have known the certainty wherefore he was accused of the Jews, he loosed him from his bands, and commanded the chief priests and all their council to appear, and brought Paul down, and set him before them.","ref":"Acts 22:30","synthesized":"The next day the commander, wanting to learn the real reason Paul was accused by the Jews, released him and ordered the chief priests and the whole Sanhedrin to assemble. Then he brought Paul down and had him stand before them.","sources":{"KJV":{"text":"On the morrow, because he would have known the certainty wherefore he was accused of the Jews, he loosed him from his bands, and commanded the chief priests and all their council to appear, and brought Paul down, and set him before them."},"BSB":{"text":"The next day the commander, wanting to learn the real reason Paul was accused by the Jews, released him and ordered the chief priests and the whole Sanhedrin to assemble. Then he brought Paul down and had him stand before them."}},"definableWords":["day","stand"],"peopleInVerse":["Paul"]}}},"23":{"chapter":"23","title":"PAUL BEFORE THE SANHEDRIN","verses":{"1":{"text":"And Paul, earnestly beholding the council, said, Men and brethren, I have lived in all good conscience before God until this day.","ref":"Acts 23:1","synthesized":"Paul looked directly at the Sanhedrin and said, “Brothers, I have conducted myself before God in all good conscience to this day.”","sources":{"KJV":{"text":"And Paul, earnestly beholding the council, said, Men and brethren, I have lived in all good conscience before God until this day."},"BSB":{"text":"Paul looked directly at the Sanhedrin and said, “Brothers, I have conducted myself before God in all good conscience to this day.”"}},"definableWords":["God","good","day"],"peopleInVerse":["Paul"]},"2":{"text":"And the high priest Ananias commanded them that stood by him to smite him on the mouth.","ref":"Acts 23:2","synthesized":"At this, the high priest Ananias ordered those standing near Paul to strike him on the mouth.","sources":{"KJV":{"text":"And the high priest Ananias commanded them that stood by him to smite him on the mouth."},"BSB":{"text":"At this, the high priest Ananias ordered those standing near Paul to strike him on the mouth."}},"definableWords":["priest"],"peopleInVerse":["Paul"]},"3":{"text":"Then said Paul unto him, God shall smite thee, thou whited wall: for sittest thou to judge me after the law, and commandest me to be smitten contrary to the law?","ref":"Acts 23:3","synthesized":"Then Paul said to him, “God will strike you, you whitewashed wall! You sit here to judge me according to the law, yet you yourself violate the law by commanding that I be struck.”","sources":{"KJV":{"text":"Then said Paul unto him, God shall smite thee, thou whited wall: for sittest thou to judge me after the law, and commandest me to be smitten contrary to the law?"},"BSB":{"text":"Then Paul said to him, “God will strike you, you whitewashed wall! You sit here to judge me according to the law, yet you yourself violate the law by commanding that I be struck.”"}},"definableWords":["God","law"],"peopleInVerse":["Paul"]},"4":{"text":"And they that stood by said, Revilest thou God’s high priest?","ref":"Acts 23:4","synthesized":"But those standing nearby said, “How dare you insult the high priest of God!”","sources":{"KJV":{"text":"And they that stood by said, Revilest thou God’s high priest?"},"BSB":{"text":"But those standing nearby said, “How dare you insult the high priest of God!”"}},"definableWords":["priest","God"],"peopleInVerse":[]},"5":{"text":"Then said Paul, I wist not, brethren, that he was the high priest: for it is written, Thou shalt not speak evil of the ruler of thy people.","ref":"Acts 23:5","synthesized":"“Brothers,” Paul replied, “I was not aware that he was the high priest, for it is written: ‘Do not speak evil about the ruler of your people.’”","sources":{"KJV":{"text":"Then said Paul, I wist not, brethren, that he was the high priest: for it is written, Thou shalt not speak evil of the ruler of thy people."},"BSB":{"text":"“Brothers,” Paul replied, “I was not aware that he was the high priest, for it is written: ‘Do not speak evil about the ruler of your people.’”"}},"definableWords":["priest","evil","ruler","people"],"peopleInVerse":["Paul"]},"6":{"text":"But when Paul perceived that the one part were Sadducees, and the other Pharisees, he cried out in the council, Men and brethren, I am a Pharisee, the son of a Pharisee: of the hope and resurrection of the dead I am called in question.","ref":"Acts 23:6","synthesized":"Then Paul, knowing that some of them were Sadducees and others Pharisees, called out in the Sanhedrin, “Brothers, I am a Pharisee, the son of a Pharisee. It is because of my hope in the resurrection of the dead that I am on trial.”","sources":{"KJV":{"text":"But when Paul perceived that the one part were Sadducees, and the other Pharisees, he cried out in the council, Men and brethren, I am a Pharisee, the son of a Pharisee: of the hope and resurrection of the dead I am called in question."},"BSB":{"text":"Then Paul, knowing that some of them were Sadducees and others Pharisees, called out in the Sanhedrin, “Brothers, I am a Pharisee, the son of a Pharisee. It is because of my hope in the resurrection of the dead that I am on trial.”"}},"definableWords":["Pharisee","son","hope","resurrection"],"peopleInVerse":["Paul"]},"7":{"text":"And when he had so said, there arose a dissension between the Pharisees and the Sadducees: and the multitude was divided.","ref":"Acts 23:7","synthesized":"As soon as he had said this, a dispute broke out between the Pharisees and Sadducees, and the assembly was divided.","sources":{"KJV":{"text":"And when he had so said, there arose a dissension between the Pharisees and the Sadducees: and the multitude was divided."},"BSB":{"text":"As soon as he had said this, a dispute broke out between the Pharisees and Sadducees, and the assembly was divided."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For the Sadducees say that there is no resurrection, neither angel, nor spirit: but the Pharisees confess both.","ref":"Acts 23:8","synthesized":"For the Sadducees say that there is neither a resurrection, nor angels, nor spirits, but the Pharisees acknowledge them all.","sources":{"KJV":{"text":"For the Sadducees say that there is no resurrection, neither angel, nor spirit: but the Pharisees confess both."},"BSB":{"text":"For the Sadducees say that there is neither a resurrection, nor angels, nor spirits, but the Pharisees acknowledge them all."}},"definableWords":["resurrection"],"peopleInVerse":[]},"9":{"text":"And there arose a great cry: and the scribes that were of the Pharisees’ part arose, and strove, saying, We find no evil in this man: but if a spirit or an angel hath spoken to him, let us not fight against God.","ref":"Acts 23:9","synthesized":"A great clamor arose, and some scribes from the party of the Pharisees got up and contended sharply, “We find nothing wrong with this man. What if a spirit or an angel has spoken to him?”","sources":{"KJV":{"text":"And there arose a great cry: and the scribes that were of the Pharisees’ part arose, and strove, saying, We find no evil in this man: but if a spirit or an angel hath spoken to him, let us not fight against God."},"BSB":{"text":"A great clamor arose, and some scribes from the party of the Pharisees got up and contended sharply, “We find nothing wrong with this man. What if a spirit or an angel has spoken to him?”"}},"definableWords":["great","man","spirit","or","angel"],"peopleInVerse":[]},"10":{"text":"And when there arose a great dissension, the chief captain, fearing lest Paul should have been pulled in pieces of them, commanded the soldiers to go down, and to take him by force from among them, and to bring him into the castle.","ref":"Acts 23:10","synthesized":"The dispute grew so violent that the commander was afraid they would tear Paul to pieces. He ordered the soldiers to go down and remove him by force and bring him into the barracks.","sources":{"KJV":{"text":"And when there arose a great dissension, the chief captain, fearing lest Paul should have been pulled in pieces of them, commanded the soldiers to go down, and to take him by force from among them, and to bring him into the castle."},"BSB":{"text":"The dispute grew so violent that the commander was afraid they would tear Paul to pieces. He ordered the soldiers to go down and remove him by force and bring him into the barracks."}},"definableWords":[],"peopleInVerse":["Paul"]},"11":{"text":"And the night following the Lord stood by him, and said, Be of good cheer, Paul: for as thou hast testified of me in Jerusalem, so must thou bear witness also at Rome.","ref":"Acts 23:11","synthesized":"The following night the Lord stood near Paul and said, “Take courage! As you have testified about Me in Jerusalem, so also you must testify in Rome.”","sources":{"KJV":{"text":"And the night following the Lord stood by him, and said, Be of good cheer, Paul: for as thou hast testified of me in Jerusalem, so must thou bear witness also at Rome."},"BSB":{"text":"The following night the Lord stood near Paul and said, “Take courage! As you have testified about Me in Jerusalem, so also you must testify in Rome.”"}},"definableWords":["night","Lord","Jerusalem"],"peopleInVerse":["Paul"]},"12":{"text":"And when it was day, certain of the Jews banded together, and bound themselves under a curse, saying that they would neither eat nor drink till they had killed Paul.","ref":"Acts 23:12","synthesized":"When daylight came, the Jews formed a conspiracy and bound themselves with an oath not to eat or drink until they had killed Paul.","sources":{"KJV":{"text":"And when it was day, certain of the Jews banded together, and bound themselves under a curse, saying that they would neither eat nor drink till they had killed Paul."},"BSB":{"text":"When daylight came, the Jews formed a conspiracy and bound themselves with an oath not to eat or drink until they had killed Paul."}},"definableWords":["formed","or"],"peopleInVerse":["Paul"]},"13":{"text":"And they were more than forty which had made this conspiracy.","ref":"Acts 23:13","synthesized":"More than forty of them were involved in this plot.","sources":{"KJV":{"text":"And they were more than forty which had made this conspiracy."},"BSB":{"text":"More than forty of them were involved in this plot."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"And they came to the chief priests and elders, and said, We have bound ourselves under a great curse, that we will eat nothing until we have slain Paul.","ref":"Acts 23:14","synthesized":"They went to the chief priests and elders and said, “We have bound ourselves with a solemn oath not to eat anything until we have killed Paul.","sources":{"KJV":{"text":"And they came to the chief priests and elders, and said, We have bound ourselves under a great curse, that we will eat nothing until we have slain Paul."},"BSB":{"text":"They went to the chief priests and elders and said, “We have bound ourselves with a solemn oath not to eat anything until we have killed Paul."}},"definableWords":[],"peopleInVerse":["Paul"]},"15":{"text":"Now therefore ye with the council signify to the chief captain that he bring him down unto you to morrow, as though ye would enquire something more perfectly concerning him: and we, or ever he come near, are ready to kill him.","ref":"Acts 23:15","synthesized":"Now then, you and the Sanhedrin petition the commander to bring him down to you on the pretext of examining his case more carefully. We are ready to kill him on the way.”","sources":{"KJV":{"text":"Now therefore ye with the council signify to the chief captain that he bring him down unto you to morrow, as though ye would enquire something more perfectly concerning him: and we, or ever he come near, are ready to kill him."},"BSB":{"text":"Now then, you and the Sanhedrin petition the commander to bring him down to you on the pretext of examining his case more carefully. We are ready to kill him on the way.”"}},"definableWords":["way"],"peopleInVerse":[]},"16":{"text":"And when Paul’s sister’s son heard of their lying in wait, he went and entered into the castle, and told Paul.","ref":"Acts 23:16","synthesized":"But when the son of Paul’s sister heard about the plot, he went into the barracks and told Paul.","sources":{"KJV":{"text":"And when Paul’s sister’s son heard of their lying in wait, he went and entered into the castle, and told Paul."},"BSB":{"text":"But when the son of Paul’s sister heard about the plot, he went into the barracks and told Paul."}},"definableWords":["son","sister"],"peopleInVerse":["Paul"]},"17":{"text":"Then Paul called one of the centurions unto him, and said, Bring this young man unto the chief captain: for he hath a certain thing to tell him.","ref":"Acts 23:17","synthesized":"Then Paul called one of the centurions and said, “Take this young man to the commander; he has something to tell him.”","sources":{"KJV":{"text":"Then Paul called one of the centurions unto him, and said, Bring this young man unto the chief captain: for he hath a certain thing to tell him."},"BSB":{"text":"Then Paul called one of the centurions and said, “Take this young man to the commander; he has something to tell him.”"}},"definableWords":["one","man"],"peopleInVerse":["Paul"]},"18":{"text":"So he took him, and brought him to the chief captain, and said, Paul the prisoner called me unto him, and prayed me to bring this young man unto thee, who hath something to say unto thee.","ref":"Acts 23:18","synthesized":"So the centurion took him to the commander and said, “Paul the prisoner sent and asked me to bring this young man to you. He has something to tell you.”","sources":{"KJV":{"text":"So he took him, and brought him to the chief captain, and said, Paul the prisoner called me unto him, and prayed me to bring this young man unto thee, who hath something to say unto thee."},"BSB":{"text":"So the centurion took him to the commander and said, “Paul the prisoner sent and asked me to bring this young man to you. He has something to tell you.”"}},"definableWords":["man"],"peopleInVerse":["Paul"]},"19":{"text":"Then the chief captain took him by the hand, and went with him aside privately, and asked him, What is that thou hast to tell me?","ref":"Acts 23:19","synthesized":"The commander took the young man by the hand, drew him aside, and asked, “What do you need to tell me?”","sources":{"KJV":{"text":"Then the chief captain took him by the hand, and went with him aside privately, and asked him, What is that thou hast to tell me?"},"BSB":{"text":"The commander took the young man by the hand, drew him aside, and asked, “What do you need to tell me?”"}},"definableWords":["man"],"peopleInVerse":[]},"20":{"text":"And he said, The Jews have agreed to desire thee that thou wouldest bring down Paul to morrow into the council, as though they would enquire somewhat of him more perfectly.","ref":"Acts 23:20","synthesized":"He answered, “The Jews have agreed to ask you to bring Paul to the Sanhedrin tomorrow on the pretext of acquiring more information about him.","sources":{"KJV":{"text":"And he said, The Jews have agreed to desire thee that thou wouldest bring down Paul to morrow into the council, as though they would enquire somewhat of him more perfectly."},"BSB":{"text":"He answered, “The Jews have agreed to ask you to bring Paul to the Sanhedrin tomorrow on the pretext of acquiring more information about him."}},"definableWords":[],"peopleInVerse":["Paul"]},"21":{"text":"But do not thou yield unto them: for there lie in wait for him of them more than forty men, which have bound themselves with an oath, that they will neither eat nor drink till they have killed him: and now are they ready, looking for a promise from thee.","ref":"Acts 23:21","synthesized":"Do not let them persuade you, because more than forty men are waiting to ambush him. They have bound themselves with an oath not to eat or drink until they have killed him; they are ready now, awaiting your consent.”","sources":{"KJV":{"text":"But do not thou yield unto them: for there lie in wait for him of them more than forty men, which have bound themselves with an oath, that they will neither eat nor drink till they have killed him: and now are they ready, looking for a promise from thee."},"BSB":{"text":"Do not let them persuade you, because more than forty men are waiting to ambush him. They have bound themselves with an oath not to eat or drink until they have killed him; they are ready now, awaiting your consent.”"}},"definableWords":["men","or"],"peopleInVerse":[]},"22":{"text":"So the chief captain then let the young man depart, and charged him, See thou tell no man that thou hast shewed these things to me.","ref":"Acts 23:22","synthesized":"So the commander dismissed the young man and instructed him, “Do not tell anyone that you have reported this to me.”","sources":{"KJV":{"text":"So the chief captain then let the young man depart, and charged him, See thou tell no man that thou hast shewed these things to me."},"BSB":{"text":"So the commander dismissed the young man and instructed him, “Do not tell anyone that you have reported this to me.”"}},"definableWords":["man"],"peopleInVerse":[]},"23":{"text":"And he called unto him two centurions, saying, Make ready two hundred soldiers to go to Caesarea, and horsemen threescore and ten, and spearmen two hundred, at the third hour of the night;","ref":"Acts 23:23","synthesized":"Then he called two of his centurions and said, “Prepare two hundred soldiers, seventy horsemen, and two hundred spearmen to go to Caesarea in the third hour of the night.","sources":{"KJV":{"text":"And he called unto him two centurions, saying, Make ready two hundred soldiers to go to Caesarea, and horsemen threescore and ten, and spearmen two hundred, at the third hour of the night;"},"BSB":{"text":"Then he called two of his centurions and said, “Prepare two hundred soldiers, seventy horsemen, and two hundred spearmen to go to Caesarea in the third hour of the night."}},"definableWords":["night"],"peopleInVerse":[]},"24":{"text":"And provide them beasts, that they may set Paul on, and bring him safe unto Felix the governor.","ref":"Acts 23:24","synthesized":"Provide mounts for Paul to take him safely to Governor Felix.”","sources":{"KJV":{"text":"And provide them beasts, that they may set Paul on, and bring him safe unto Felix the governor."},"BSB":{"text":"Provide mounts for Paul to take him safely to Governor Felix.”"}},"definableWords":[],"peopleInVerse":["Paul"]},"25":{"text":"And he wrote a letter after this manner:","ref":"Acts 23:25","synthesized":"And he wrote the following letter:","sources":{"KJV":{"text":"And he wrote a letter after this manner:"},"BSB":{"text":"And he wrote the following letter:"}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"Claudius Lysias unto the most excellent governor Felix sendeth greeting.","ref":"Acts 23:26","synthesized":"Claudius Lysias,  To His Excellency, Governor Felix:  Greetings.","sources":{"KJV":{"text":"Claudius Lysias unto the most excellent governor Felix sendeth greeting."},"BSB":{"text":"Claudius Lysias,  To His Excellency, Governor Felix:  Greetings."}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"This man was taken of the Jews, and should have been killed of them: then came I with an army, and rescued him, having understood that he was a Roman.","ref":"Acts 23:27","synthesized":"This man was seized by the Jews, and they were about to kill him when I came with my troops to rescue him. For I had learned that he is a Roman citizen,","sources":{"KJV":{"text":"This man was taken of the Jews, and should have been killed of them: then came I with an army, and rescued him, having understood that he was a Roman."},"BSB":{"text":"This man was seized by the Jews, and they were about to kill him when I came with my troops to rescue him. For I had learned that he is a Roman citizen,"}},"definableWords":["man"],"peopleInVerse":[]},"28":{"text":"And when I would have known the cause wherefore they accused him, I brought him forth into their council:","ref":"Acts 23:28","synthesized":"and since I wanted to understand their charges against him, I brought him down to their Sanhedrin.","sources":{"KJV":{"text":"And when I would have known the cause wherefore they accused him, I brought him forth into their council:"},"BSB":{"text":"and since I wanted to understand their charges against him, I brought him down to their Sanhedrin."}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"Whom I perceived to be accused of questions of their law, but to have nothing laid to his charge worthy of death or of bonds.","ref":"Acts 23:29","synthesized":"I found that the accusation involved questions about their own law, but there was no charge worthy of death or imprisonment.","sources":{"KJV":{"text":"Whom I perceived to be accused of questions of their law, but to have nothing laid to his charge worthy of death or of bonds."},"BSB":{"text":"I found that the accusation involved questions about their own law, but there was no charge worthy of death or imprisonment."}},"definableWords":["law","charge","death","or"],"peopleInVerse":[]},"30":{"text":"And when it was told me how that the Jews laid wait for the man, I sent straightway to thee, and gave commandment to his accusers also to say before thee what they had against him. Farewell.","ref":"Acts 23:30","synthesized":"When I was informed that there was a plot against the man, I sent him to you at once. I also instructed his accusers to present their case against him before you.","sources":{"KJV":{"text":"And when it was told me how that the Jews laid wait for the man, I sent straightway to thee, and gave commandment to his accusers also to say before thee what they had against him. Farewell."},"BSB":{"text":"When I was informed that there was a plot against the man, I sent him to you at once. I also instructed his accusers to present their case against him before you."}},"definableWords":["man"],"peopleInVerse":[]},"31":{"text":"Then the soldiers, as it was commanded them, took Paul, and brought him by night to Antipatris.","ref":"Acts 23:31","synthesized":"So the soldiers followed their orders and brought Paul by night to Antipatris.","sources":{"KJV":{"text":"Then the soldiers, as it was commanded them, took Paul, and brought him by night to Antipatris."},"BSB":{"text":"So the soldiers followed their orders and brought Paul by night to Antipatris."}},"definableWords":["night"],"peopleInVerse":["Paul"]},"32":{"text":"On the morrow they left the horsemen to go with him, and returned to the castle:","ref":"Acts 23:32","synthesized":"The next day they returned to the barracks and let the horsemen go on with him.","sources":{"KJV":{"text":"On the morrow they left the horsemen to go with him, and returned to the castle:"},"BSB":{"text":"The next day they returned to the barracks and let the horsemen go on with him."}},"definableWords":["day"],"peopleInVerse":[]},"33":{"text":"Who, when they came to Caesarea, and delivered the epistle to the governor, presented Paul also before him.","ref":"Acts 23:33","synthesized":"When the horsemen arrived in Caesarea, they delivered the letter to the governor and presented Paul to him.","sources":{"KJV":{"text":"Who, when they came to Caesarea, and delivered the epistle to the governor, presented Paul also before him."},"BSB":{"text":"When the horsemen arrived in Caesarea, they delivered the letter to the governor and presented Paul to him."}},"definableWords":[],"peopleInVerse":["Paul"]},"34":{"text":"And when the governor had read the letter, he asked of what province he was. And when he understood that he was of Cilicia;","ref":"Acts 23:34","synthesized":"The governor read the letter and asked what province Paul was from. Learning that he was from Cilicia,","sources":{"KJV":{"text":"And when the governor had read the letter, he asked of what province he was. And when he understood that he was of Cilicia;"},"BSB":{"text":"The governor read the letter and asked what province Paul was from. Learning that he was from Cilicia,"}},"definableWords":[],"peopleInVerse":["Paul"]},"35":{"text":"I will hear thee, said he, when thine accusers are also come. And he commanded him to be kept in Herod’s judgment hall.","ref":"Acts 23:35","synthesized":"he said, “I will hear your case when your accusers arrive.” Then he ordered that Paul be kept under guard in Herod’s Praetorium.","sources":{"KJV":{"text":"I will hear thee, said he, when thine accusers are also come. And he commanded him to be kept in Herod’s judgment hall."},"BSB":{"text":"he said, “I will hear your case when your accusers arrive.” Then he ordered that Paul be kept under guard in Herod’s Praetorium."}},"definableWords":["hear"],"peopleInVerse":["Paul","Herod"]}}},"24":{"chapter":"24","title":"PAUL BEFORE FELIX","verses":{"1":{"text":"And after five days Ananias the high priest descended with the elders, and with a certain orator named Tertullus, who informed the governor against Paul.","ref":"Acts 24:1","synthesized":"Five days later the high priest Ananias came down with some elders and a lawyer named Tertullus, who presented to the governor their case against Paul.","sources":{"KJV":{"text":"And after five days Ananias the high priest descended with the elders, and with a certain orator named Tertullus, who informed the governor against Paul."},"BSB":{"text":"Five days later the high priest Ananias came down with some elders and a lawyer named Tertullus, who presented to the governor their case against Paul."}},"definableWords":["days","priest"],"peopleInVerse":["Paul"]},"2":{"text":"And when he was called forth, Tertullus began to accuse him, saying, Seeing that by thee we enjoy great quietness, and that very worthy deeds are done unto this nation by thy providence,","ref":"Acts 24:2","synthesized":"When Paul had been called in, Tertullus opened the prosecution: “Because of you, we have enjoyed a lasting peace, and your foresight has brought improvements to this nation.","sources":{"KJV":{"text":"And when he was called forth, Tertullus began to accuse him, saying, Seeing that by thee we enjoy great quietness, and that very worthy deeds are done unto this nation by thy providence,"},"BSB":{"text":"When Paul had been called in, Tertullus opened the prosecution: “Because of you, we have enjoyed a lasting peace, and your foresight has brought improvements to this nation."}},"definableWords":["peace","nation"],"peopleInVerse":["Paul"]},"3":{"text":"We accept it always, and in all places, most noble Felix, with all thankfulness.","ref":"Acts 24:3","synthesized":"In every way and everywhere, most excellent Felix, we acknowledge this with all gratitude.","sources":{"KJV":{"text":"We accept it always, and in all places, most noble Felix, with all thankfulness."},"BSB":{"text":"In every way and everywhere, most excellent Felix, we acknowledge this with all gratitude."}},"definableWords":["way"],"peopleInVerse":[]},"4":{"text":"Notwithstanding, that I be not further tedious unto thee, I pray thee that thou wouldest hear us of thy clemency a few words.","ref":"Acts 24:4","synthesized":"But in order not to burden you any further, I beg your indulgence to hear us briefly.","sources":{"KJV":{"text":"Notwithstanding, that I be not further tedious unto thee, I pray thee that thou wouldest hear us of thy clemency a few words."},"BSB":{"text":"But in order not to burden you any further, I beg your indulgence to hear us briefly."}},"definableWords":["hear"],"peopleInVerse":[]},"5":{"text":"For we have found this man a pestilent fellow, and a mover of sedition among all the Jews throughout the world, and a ringleader of the sect of the Nazarenes:","ref":"Acts 24:5","synthesized":"We have found this man to be a pestilence, stirring up dissension among the Jews all over the world. He is a ringleader of the sect of the Nazarenes,","sources":{"KJV":{"text":"For we have found this man a pestilent fellow, and a mover of sedition among all the Jews throughout the world, and a ringleader of the sect of the Nazarenes:"},"BSB":{"text":"We have found this man to be a pestilence, stirring up dissension among the Jews all over the world. He is a ringleader of the sect of the Nazarenes,"}},"definableWords":["man"],"peopleInVerse":[]},"6":{"text":"Who also hath gone about to profane the temple: whom we took, and would have judged according to our law.","ref":"Acts 24:6","synthesized":"and he even tried to desecrate the temple; so we seized him.","sources":{"KJV":{"text":"Who also hath gone about to profane the temple: whom we took, and would have judged according to our law."},"BSB":{"text":"and he even tried to desecrate the temple; so we seized him."}},"definableWords":["temple"],"peopleInVerse":[]},"7":{"text":"But the chief captain Lysias came upon us, and with great violence took him away out of our hands,","ref":"Acts 24:7","synthesized":"But the chief captain Lysias came upon us, and with great violence took him away out of our hands,","sources":{"KJV":{"text":"But the chief captain Lysias came upon us, and with great violence took him away out of our hands,"}},"definableWords":["great"],"peopleInVerse":[]},"8":{"text":"Commanding his accusers to come unto thee: by examining of whom thyself mayest take knowledge of all these things, whereof we accuse him.","ref":"Acts 24:8","synthesized":"By examining him yourself, you will be able to learn the truth about all our charges against him.”","sources":{"KJV":{"text":"Commanding his accusers to come unto thee: by examining of whom thyself mayest take knowledge of all these things, whereof we accuse him."},"BSB":{"text":"By examining him yourself, you will be able to learn the truth about all our charges against him.”"}},"definableWords":["truth"],"peopleInVerse":[]},"9":{"text":"And the Jews also assented, saying that these things were so.","ref":"Acts 24:9","synthesized":"The Jews concurred, asserting that these charges were true.","sources":{"KJV":{"text":"And the Jews also assented, saying that these things were so."},"BSB":{"text":"The Jews concurred, asserting that these charges were true."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Then Paul, after that the governor had beckoned unto him to speak, answered, Forasmuch as I know that thou hast been of many years a judge unto this nation, I do the more cheerfully answer for myself:","ref":"Acts 24:10","synthesized":"When the governor motioned for Paul to speak, he began his response: “Knowing that you have been a judge over this nation for many years, I gladly make my defense.","sources":{"KJV":{"text":"Then Paul, after that the governor had beckoned unto him to speak, answered, Forasmuch as I know that thou hast been of many years a judge unto this nation, I do the more cheerfully answer for myself:"},"BSB":{"text":"When the governor motioned for Paul to speak, he began his response: “Knowing that you have been a judge over this nation for many years, I gladly make my defense."}},"definableWords":["nation","years","make"],"peopleInVerse":["Paul"]},"11":{"text":"Because that thou mayest understand, that there are yet but twelve days since I went up to Jerusalem for to worship.","ref":"Acts 24:11","synthesized":"You can verify for yourself that no more than twelve days ago I went up to Jerusalem to worship.","sources":{"KJV":{"text":"Because that thou mayest understand, that there are yet but twelve days since I went up to Jerusalem for to worship."},"BSB":{"text":"You can verify for yourself that no more than twelve days ago I went up to Jerusalem to worship."}},"definableWords":["days","Jerusalem","worship"],"peopleInVerse":[]},"12":{"text":"And they neither found me in the temple disputing with any man, neither raising up the people, neither in the synagogues, nor in the city:","ref":"Acts 24:12","synthesized":"Yet my accusers did not find me debating with anyone in the temple or riling up a crowd in the synagogues or in the city.","sources":{"KJV":{"text":"And they neither found me in the temple disputing with any man, neither raising up the people, neither in the synagogues, nor in the city:"},"BSB":{"text":"Yet my accusers did not find me debating with anyone in the temple or riling up a crowd in the synagogues or in the city."}},"definableWords":["temple","or"],"peopleInVerse":[]},"13":{"text":"Neither can they prove the things whereof they now accuse me.","ref":"Acts 24:13","synthesized":"Nor can they prove to you any of their charges against me.","sources":{"KJV":{"text":"Neither can they prove the things whereof they now accuse me."},"BSB":{"text":"Nor can they prove to you any of their charges against me."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"But this I confess unto thee, that after the way which they call heresy, so worship I the God of my fathers, believing all things which are written in the law and in the prophets:","ref":"Acts 24:14","synthesized":"I do confess to you, however, that I worship the God of our fathers according to the Way, which they call a sect. I believe everything that is laid down by the Law and written in the Prophets,","sources":{"KJV":{"text":"But this I confess unto thee, that after the way which they call heresy, so worship I the God of my fathers, believing all things which are written in the law and in the prophets:"},"BSB":{"text":"I do confess to you, however, that I worship the God of our fathers according to the Way, which they call a sect. I believe everything that is laid down by the Law and written in the Prophets,"}},"definableWords":["worship","God","fathers","way","law"],"peopleInVerse":[]},"15":{"text":"And have hope toward God, which they themselves also allow, that there shall be a resurrection of the dead, both of the just and unjust.","ref":"Acts 24:15","synthesized":"and I have the same hope in God that they themselves cherish, that there will be a resurrection of both the righteous and the wicked.","sources":{"KJV":{"text":"And have hope toward God, which they themselves also allow, that there shall be a resurrection of the dead, both of the just and unjust."},"BSB":{"text":"and I have the same hope in God that they themselves cherish, that there will be a resurrection of both the righteous and the wicked."}},"definableWords":["hope","God","resurrection","righteous"],"peopleInVerse":[]},"16":{"text":"And herein do I exercise myself, to have always a conscience void of offence toward God, and toward men.","ref":"Acts 24:16","synthesized":"In this hope, I strive always to maintain a clear conscience before God and man.","sources":{"KJV":{"text":"And herein do I exercise myself, to have always a conscience void of offence toward God, and toward men."},"BSB":{"text":"In this hope, I strive always to maintain a clear conscience before God and man."}},"definableWords":["hope","God","man"],"peopleInVerse":[]},"17":{"text":"Now after many years I came to bring alms to my nation, and offerings.","ref":"Acts 24:17","synthesized":"After several years, then, I returned to Jerusalem to bring alms to my people and to present offerings.","sources":{"KJV":{"text":"Now after many years I came to bring alms to my nation, and offerings."},"BSB":{"text":"After several years, then, I returned to Jerusalem to bring alms to my people and to present offerings."}},"definableWords":["years","Jerusalem","people"],"peopleInVerse":[]},"18":{"text":"Whereupon certain Jews from Asia found me purified in the temple, neither with multitude, nor with tumult.","ref":"Acts 24:18","synthesized":"At the time they found me in the temple, I was ceremonially clean and was not inciting a crowd or an uproar. But there are some Jews from the province of Asia","sources":{"KJV":{"text":"Whereupon certain Jews from Asia found me purified in the temple, neither with multitude, nor with tumult."},"BSB":{"text":"At the time they found me in the temple, I was ceremonially clean and was not inciting a crowd or an uproar. But there are some Jews from the province of Asia"}},"definableWords":["temple","or"],"peopleInVerse":[]},"19":{"text":"Who ought to have been here before thee, and object, if they had ought against me.","ref":"Acts 24:19","synthesized":"who ought to appear before you and bring charges, if they have anything against me.","sources":{"KJV":{"text":"Who ought to have been here before thee, and object, if they had ought against me."},"BSB":{"text":"who ought to appear before you and bring charges, if they have anything against me."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Or else let these same here say, if they have found any evil doing in me, while I stood before the council,","ref":"Acts 24:20","synthesized":"Otherwise, let these men state for themselves any crime they found in me when I stood before the Sanhedrin,","sources":{"KJV":{"text":"Or else let these same here say, if they have found any evil doing in me, while I stood before the council,"},"BSB":{"text":"Otherwise, let these men state for themselves any crime they found in me when I stood before the Sanhedrin,"}},"definableWords":["men"],"peopleInVerse":[]},"21":{"text":"Except it be for this one voice, that I cried standing among them, Touching the resurrection of the dead I am called in question by you this day.","ref":"Acts 24:21","synthesized":"unless it was this one thing I called out as I stood in their presence: ‘It is concerning the resurrection of the dead that I am on trial before you today.’”","sources":{"KJV":{"text":"Except it be for this one voice, that I cried standing among them, Touching the resurrection of the dead I am called in question by you this day."},"BSB":{"text":"unless it was this one thing I called out as I stood in their presence: ‘It is concerning the resurrection of the dead that I am on trial before you today.’”"}},"definableWords":["one","resurrection"],"peopleInVerse":[]},"22":{"text":"And when Felix heard these things, having more perfect knowledge of that way, he deferred them, and said, When Lysias the chief captain shall come down, I will know the uttermost of your matter.","ref":"Acts 24:22","synthesized":"Then Felix, who was well informed about the Way, adjourned the hearing and said, “When Lysias the commander comes, I will decide your case.”","sources":{"KJV":{"text":"And when Felix heard these things, having more perfect knowledge of that way, he deferred them, and said, When Lysias the chief captain shall come down, I will know the uttermost of your matter."},"BSB":{"text":"Then Felix, who was well informed about the Way, adjourned the hearing and said, “When Lysias the commander comes, I will decide your case.”"}},"definableWords":["way"],"peopleInVerse":[]},"23":{"text":"And he commanded a centurion to keep Paul, and to let him have liberty, and that he should forbid none of his acquaintance to minister or come unto him.","ref":"Acts 24:23","synthesized":"He ordered the centurion to keep Paul under guard, but to allow him some freedom and permit his friends to minister to his needs.","sources":{"KJV":{"text":"And he commanded a centurion to keep Paul, and to let him have liberty, and that he should forbid none of his acquaintance to minister or come unto him."},"BSB":{"text":"He ordered the centurion to keep Paul under guard, but to allow him some freedom and permit his friends to minister to his needs."}},"definableWords":["keep"],"peopleInVerse":["Paul"]},"24":{"text":"And after certain days, when Felix came with his wife Drusilla, which was a Jewess, he sent for Paul, and heard him concerning the faith in Christ.","ref":"Acts 24:24","synthesized":"After several days, Felix returned with his wife Drusilla, who was a Jewess. He sent for Paul and listened to him speak about faith in Christ Jesus.","sources":{"KJV":{"text":"And after certain days, when Felix came with his wife Drusilla, which was a Jewess, he sent for Paul, and heard him concerning the faith in Christ."},"BSB":{"text":"After several days, Felix returned with his wife Drusilla, who was a Jewess. He sent for Paul and listened to him speak about faith in Christ Jesus."}},"definableWords":["days","wife","faith","Christ"],"peopleInVerse":["Paul","Jesus"]},"25":{"text":"And as he reasoned of righteousness, temperance, and judgment to come, Felix trembled, and answered, Go thy way for this time; when I have a convenient season, I will call for thee.","ref":"Acts 24:25","synthesized":"As Paul expounded on righteousness, self-control, and the coming judgment, Felix became frightened and said, “You may go for now. When I find the time, I will call for you.”","sources":{"KJV":{"text":"And as he reasoned of righteousness, temperance, and judgment to come, Felix trembled, and answered, Go thy way for this time; when I have a convenient season, I will call for thee."},"BSB":{"text":"As Paul expounded on righteousness, self-control, and the coming judgment, Felix became frightened and said, “You may go for now. When I find the time, I will call for you.”"}},"definableWords":["righteousness","judgment"],"peopleInVerse":["Paul"]},"26":{"text":"He hoped also that money should have been given him of Paul, that he might loose him: wherefore he sent for him the oftener, and communed with him.","ref":"Acts 24:26","synthesized":"At the same time, he was hoping that Paul would offer him a bribe. So he sent for Paul frequently and talked with him.","sources":{"KJV":{"text":"He hoped also that money should have been given him of Paul, that he might loose him: wherefore he sent for him the oftener, and communed with him."},"BSB":{"text":"At the same time, he was hoping that Paul would offer him a bribe. So he sent for Paul frequently and talked with him."}},"definableWords":[],"peopleInVerse":["Paul"]},"27":{"text":"But after two years Porcius Festus came into Felix’ room: and Felix, willing to shew the Jews a pleasure, left Paul bound.","ref":"Acts 24:27","synthesized":"After two years had passed, Felix was succeeded by Porcius Festus. And wishing to do the Jews a favor, Felix left Paul in prison.","sources":{"KJV":{"text":"But after two years Porcius Festus came into Felix’ room: and Felix, willing to shew the Jews a pleasure, left Paul bound."},"BSB":{"text":"After two years had passed, Felix was succeeded by Porcius Festus. And wishing to do the Jews a favor, Felix left Paul in prison."}},"definableWords":["years"],"peopleInVerse":["Paul"]}}},"25":{"chapter":"25","title":"PAUL BEFORE FESTUS","verses":{"1":{"text":"Now when Festus was come into the province, after three days he ascended from Caesarea to Jerusalem.","ref":"Acts 25:1","synthesized":"Three days after his arrival in the province, Festus went up from Caesarea to Jerusalem,","sources":{"KJV":{"text":"Now when Festus was come into the province, after three days he ascended from Caesarea to Jerusalem."},"BSB":{"text":"Three days after his arrival in the province, Festus went up from Caesarea to Jerusalem,"}},"definableWords":["days","Jerusalem"],"peopleInVerse":[]},"2":{"text":"Then the high priest and the chief of the Jews informed him against Paul, and besought him,","ref":"Acts 25:2","synthesized":"where the chief priests and Jewish leaders presented their case against Paul. They urged Festus","sources":{"KJV":{"text":"Then the high priest and the chief of the Jews informed him against Paul, and besought him,"},"BSB":{"text":"where the chief priests and Jewish leaders presented their case against Paul. They urged Festus"}},"definableWords":[],"peopleInVerse":["Paul"]},"3":{"text":"And desired favour against him, that he would send for him to Jerusalem, laying wait in the way to kill him.","ref":"Acts 25:3","synthesized":"to grant them a concession against Paul by summoning him to Jerusalem, because they were preparing an ambush to kill him along the way.","sources":{"KJV":{"text":"And desired favour against him, that he would send for him to Jerusalem, laying wait in the way to kill him."},"BSB":{"text":"to grant them a concession against Paul by summoning him to Jerusalem, because they were preparing an ambush to kill him along the way."}},"definableWords":["Jerusalem","way"],"peopleInVerse":["Paul"]},"4":{"text":"But Festus answered, that Paul should be kept at Caesarea, and that he himself would depart shortly thither.","ref":"Acts 25:4","synthesized":"But Festus replied, “Paul is being held in Caesarea, and I myself am going there soon.","sources":{"KJV":{"text":"But Festus answered, that Paul should be kept at Caesarea, and that he himself would depart shortly thither."},"BSB":{"text":"But Festus replied, “Paul is being held in Caesarea, and I myself am going there soon."}},"definableWords":[],"peopleInVerse":["Paul"]},"5":{"text":"Let them therefore, said he, which among you are able, go down with me, and accuse this man, if there be any wickedness in him.","ref":"Acts 25:5","synthesized":"So if this man has done anything wrong, let some of your leaders come down with me and accuse him there.”","sources":{"KJV":{"text":"Let them therefore, said he, which among you are able, go down with me, and accuse this man, if there be any wickedness in him."},"BSB":{"text":"So if this man has done anything wrong, let some of your leaders come down with me and accuse him there.”"}},"definableWords":["man"],"peopleInVerse":[]},"6":{"text":"And when he had tarried among them more than ten days, he went down unto Caesarea; and the next day sitting on the judgment seat commanded Paul to be brought.","ref":"Acts 25:6","synthesized":"After spending no more than eight or ten days with them, Festus went down to Caesarea. The next day he sat on the judgment seat and ordered that Paul be brought in.","sources":{"KJV":{"text":"And when he had tarried among them more than ten days, he went down unto Caesarea; and the next day sitting on the judgment seat commanded Paul to be brought."},"BSB":{"text":"After spending no more than eight or ten days with them, Festus went down to Caesarea. The next day he sat on the judgment seat and ordered that Paul be brought in."}},"definableWords":["or","days","day","judgment"],"peopleInVerse":["Paul"]},"7":{"text":"And when he was come, the Jews which came down from Jerusalem stood round about, and laid many and grievous complaints against Paul, which they could not prove.","ref":"Acts 25:7","synthesized":"When Paul arrived, the Jews who had come down from Jerusalem stood around him, bringing many serious charges that they could not prove.","sources":{"KJV":{"text":"And when he was come, the Jews which came down from Jerusalem stood round about, and laid many and grievous complaints against Paul, which they could not prove."},"BSB":{"text":"When Paul arrived, the Jews who had come down from Jerusalem stood around him, bringing many serious charges that they could not prove."}},"definableWords":["Jerusalem"],"peopleInVerse":["Paul"]},"8":{"text":"While he answered for himself, Neither against the law of the Jews, neither against the temple, nor yet against Caesar, have I offended any thing at all.","ref":"Acts 25:8","synthesized":"Then Paul made his defense: “I have committed no offense against the law of the Jews or against the temple or against Caesar.”","sources":{"KJV":{"text":"While he answered for himself, Neither against the law of the Jews, neither against the temple, nor yet against Caesar, have I offended any thing at all."},"BSB":{"text":"Then Paul made his defense: “I have committed no offense against the law of the Jews or against the temple or against Caesar.”"}},"definableWords":["made","law","or","temple"],"peopleInVerse":["Paul"]},"9":{"text":"But Festus, willing to do the Jews a pleasure, answered Paul, and said, Wilt thou go up to Jerusalem, and there be judged of these things before me?","ref":"Acts 25:9","synthesized":"But Festus, wishing to do the Jews a favor, said to Paul, “Are you willing to go up to Jerusalem to stand trial before me on these charges?”","sources":{"KJV":{"text":"But Festus, willing to do the Jews a pleasure, answered Paul, and said, Wilt thou go up to Jerusalem, and there be judged of these things before me?"},"BSB":{"text":"But Festus, wishing to do the Jews a favor, said to Paul, “Are you willing to go up to Jerusalem to stand trial before me on these charges?”"}},"definableWords":["Jerusalem","stand"],"peopleInVerse":["Paul"]},"10":{"text":"Then said Paul, I stand at Caesar’s judgment seat, where I ought to be judged: to the Jews have I done no wrong, as thou very well knowest.","ref":"Acts 25:10","synthesized":"Paul replied, “I am standing before the judgment seat of Caesar, where I ought to be tried. I have done nothing wrong to the Jews, as you yourself know very well.","sources":{"KJV":{"text":"Then said Paul, I stand at Caesar’s judgment seat, where I ought to be judged: to the Jews have I done no wrong, as thou very well knowest."},"BSB":{"text":"Paul replied, “I am standing before the judgment seat of Caesar, where I ought to be tried. I have done nothing wrong to the Jews, as you yourself know very well."}},"definableWords":["judgment"],"peopleInVerse":["Paul"]},"11":{"text":"For if I be an offender, or have committed any thing worthy of death, I refuse not to die: but if there be none of these things whereof these accuse me, no man may deliver me unto them. I appeal unto Caesar.","ref":"Acts 25:11","synthesized":"If, however, I am guilty of anything worthy of death, I do not refuse to die. But if there is no truth to their accusations against me, no one has the right to hand me over to them. I appeal to Caesar!”","sources":{"KJV":{"text":"For if I be an offender, or have committed any thing worthy of death, I refuse not to die: but if there be none of these things whereof these accuse me, no man may deliver me unto them. I appeal unto Caesar."},"BSB":{"text":"If, however, I am guilty of anything worthy of death, I do not refuse to die. But if there is no truth to their accusations against me, no one has the right to hand me over to them. I appeal to Caesar!”"}},"definableWords":["death","die","truth","one"],"peopleInVerse":[]},"12":{"text":"Then Festus, when he had conferred with the council, answered, Hast thou appealed unto Caesar? unto Caesar shalt thou go.","ref":"Acts 25:12","synthesized":"Then Festus conferred with his council and replied, “You have appealed to Caesar. To Caesar you will go!”","sources":{"KJV":{"text":"Then Festus, when he had conferred with the council, answered, Hast thou appealed unto Caesar? unto Caesar shalt thou go."},"BSB":{"text":"Then Festus conferred with his council and replied, “You have appealed to Caesar. To Caesar you will go!”"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"And after certain days king Agrippa and Bernice came unto Caesarea to salute Festus.","ref":"Acts 25:13","synthesized":"After several days had passed, King Agrippa and Bernice came down to Caesarea to pay their respects to Festus.","sources":{"KJV":{"text":"And after certain days king Agrippa and Bernice came unto Caesarea to salute Festus."},"BSB":{"text":"After several days had passed, King Agrippa and Bernice came down to Caesarea to pay their respects to Festus."}},"definableWords":["days","King"],"peopleInVerse":[]},"14":{"text":"And when they had been there many days, Festus declared Paul’s cause unto the king, saying, There is a certain man left in bonds by Felix:","ref":"Acts 25:14","synthesized":"Since they were staying several days, Festus laid out Paul’s case before the king: “There is a certain man whom Felix left in prison.","sources":{"KJV":{"text":"And when they had been there many days, Festus declared Paul’s cause unto the king, saying, There is a certain man left in bonds by Felix:"},"BSB":{"text":"Since they were staying several days, Festus laid out Paul’s case before the king: “There is a certain man whom Felix left in prison."}},"definableWords":["days","king","man"],"peopleInVerse":["Paul"]},"15":{"text":"About whom, when I was at Jerusalem, the chief priests and the elders of the Jews informed me, desiring to have judgment against him.","ref":"Acts 25:15","synthesized":"While I was in Jerusalem, the chief priests and elders of the Jews presented their case and requested a judgment against him.","sources":{"KJV":{"text":"About whom, when I was at Jerusalem, the chief priests and the elders of the Jews informed me, desiring to have judgment against him."},"BSB":{"text":"While I was in Jerusalem, the chief priests and elders of the Jews presented their case and requested a judgment against him."}},"definableWords":["Jerusalem","judgment"],"peopleInVerse":[]},"16":{"text":"To whom I answered, It is not the manner of the Romans to deliver any man to die, before that he which is accused have the accusers face to face, and have licence to answer for himself concerning the crime laid against him.","ref":"Acts 25:16","synthesized":"I told them that it is not the Roman custom to hand a man over before he has had an opportunity to face his accusers and defend himself against their charges.","sources":{"KJV":{"text":"To whom I answered, It is not the manner of the Romans to deliver any man to die, before that he which is accused have the accusers face to face, and have licence to answer for himself concerning the crime laid against him."},"BSB":{"text":"I told them that it is not the Roman custom to hand a man over before he has had an opportunity to face his accusers and defend himself against their charges."}},"definableWords":["man"],"peopleInVerse":[]},"17":{"text":"Therefore, when they were come hither, without any delay on the morrow I sat on the judgment seat, and commanded the man to be brought forth.","ref":"Acts 25:17","synthesized":"So when they came here with me, I did not delay. The next day I sat on the judgment seat and ordered that the man be brought in.","sources":{"KJV":{"text":"Therefore, when they were come hither, without any delay on the morrow I sat on the judgment seat, and commanded the man to be brought forth."},"BSB":{"text":"So when they came here with me, I did not delay. The next day I sat on the judgment seat and ordered that the man be brought in."}},"definableWords":["day","judgment","man"],"peopleInVerse":[]},"18":{"text":"Against whom when the accusers stood up, they brought none accusation of such things as I supposed:","ref":"Acts 25:18","synthesized":"But when his accusers rose to speak, they did not charge him with any of the crimes I had expected.","sources":{"KJV":{"text":"Against whom when the accusers stood up, they brought none accusation of such things as I supposed:"},"BSB":{"text":"But when his accusers rose to speak, they did not charge him with any of the crimes I had expected."}},"definableWords":["charge"],"peopleInVerse":[]},"19":{"text":"But had certain questions against him of their own superstition, and of one Jesus, which was dead, whom Paul affirmed to be alive.","ref":"Acts 25:19","synthesized":"They only had some contentions with him regarding their own religion and a certain Jesus who had died, but whom Paul affirmed to be alive.","sources":{"KJV":{"text":"But had certain questions against him of their own superstition, and of one Jesus, which was dead, whom Paul affirmed to be alive."},"BSB":{"text":"They only had some contentions with him regarding their own religion and a certain Jesus who had died, but whom Paul affirmed to be alive."}},"definableWords":[],"peopleInVerse":["Jesus","Paul"]},"20":{"text":"And because I doubted of such manner of questions, I asked him whether he would go to Jerusalem, and there be judged of these matters.","ref":"Acts 25:20","synthesized":"Since I was at a loss as to how to investigate these matters, I asked if he was willing to go to Jerusalem and be tried there on these charges.","sources":{"KJV":{"text":"And because I doubted of such manner of questions, I asked him whether he would go to Jerusalem, and there be judged of these matters."},"BSB":{"text":"Since I was at a loss as to how to investigate these matters, I asked if he was willing to go to Jerusalem and be tried there on these charges."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"21":{"text":"But when Paul had appealed to be reserved unto the hearing of Augustus, I commanded him to be kept till I might send him to Caesar.","ref":"Acts 25:21","synthesized":"But when Paul appealed to be held over for the decision of the Emperor, I ordered that he be held until I could send him to Caesar.”","sources":{"KJV":{"text":"But when Paul had appealed to be reserved unto the hearing of Augustus, I commanded him to be kept till I might send him to Caesar."},"BSB":{"text":"But when Paul appealed to be held over for the decision of the Emperor, I ordered that he be held until I could send him to Caesar.”"}},"definableWords":[],"peopleInVerse":["Paul"]},"22":{"text":"Then Agrippa said unto Festus, I would also hear the man myself. To morrow, said he, thou shalt hear him.","ref":"Acts 25:22","synthesized":"Then Agrippa said to Festus, “I would like to hear this man myself.”  “Tomorrow you will hear him,” Festus declared.","sources":{"KJV":{"text":"Then Agrippa said unto Festus, I would also hear the man myself. To morrow, said he, thou shalt hear him."},"BSB":{"text":"Then Agrippa said to Festus, “I would like to hear this man myself.”  “Tomorrow you will hear him,” Festus declared."}},"definableWords":["hear","man"],"peopleInVerse":[]},"23":{"text":"And on the morrow, when Agrippa was come, and Bernice, with great pomp, and was entered into the place of hearing, with the chief captains, and principal men of the city, at Festus’ commandment Paul was brought forth.","ref":"Acts 25:23","synthesized":"The next day Agrippa and Bernice came with great pomp and entered the auditorium, along with the commanders and leading men of the city. And Festus ordered that Paul be brought in.","sources":{"KJV":{"text":"And on the morrow, when Agrippa was come, and Bernice, with great pomp, and was entered into the place of hearing, with the chief captains, and principal men of the city, at Festus’ commandment Paul was brought forth."},"BSB":{"text":"The next day Agrippa and Bernice came with great pomp and entered the auditorium, along with the commanders and leading men of the city. And Festus ordered that Paul be brought in."}},"definableWords":["day","great","men"],"peopleInVerse":["Paul"]},"24":{"text":"And Festus said, King Agrippa, and all men which are here present with us, ye see this man, about whom all the multitude of the Jews have dealt with me, both at Jerusalem, and also here, crying that he ought not to live any longer.","ref":"Acts 25:24","synthesized":"Then Festus said, “King Agrippa and all who are present with us, you see this man. The whole Jewish community has petitioned me about him, both here and in Jerusalem, crying out that he ought not to live any longer.","sources":{"KJV":{"text":"And Festus said, King Agrippa, and all men which are here present with us, ye see this man, about whom all the multitude of the Jews have dealt with me, both at Jerusalem, and also here, crying that he ought not to live any longer."},"BSB":{"text":"Then Festus said, “King Agrippa and all who are present with us, you see this man. The whole Jewish community has petitioned me about him, both here and in Jerusalem, crying out that he ought not to live any longer."}},"definableWords":["King","see","man","Jerusalem","live"],"peopleInVerse":[]},"25":{"text":"But when I found that he had committed nothing worthy of death, and that he himself hath appealed to Augustus, I have determined to send him.","ref":"Acts 25:25","synthesized":"But I found he had done nothing worthy of death, and since he has now appealed to the Emperor, I decided to send him.","sources":{"KJV":{"text":"But when I found that he had committed nothing worthy of death, and that he himself hath appealed to Augustus, I have determined to send him."},"BSB":{"text":"But I found he had done nothing worthy of death, and since he has now appealed to the Emperor, I decided to send him."}},"definableWords":["death"],"peopleInVerse":[]},"26":{"text":"Of whom I have no certain thing to write unto my lord. Wherefore I have brought him forth before you, and specially before thee, O king Agrippa, that, after examination had, I might have somewhat to write.","ref":"Acts 25:26","synthesized":"I have nothing definite to write to our sovereign one about him. Therefore I have brought him before all of you, and especially before you, King Agrippa, so that after this inquiry I may have something to write.","sources":{"KJV":{"text":"Of whom I have no certain thing to write unto my lord. Wherefore I have brought him forth before you, and specially before thee, O king Agrippa, that, after examination had, I might have somewhat to write."},"BSB":{"text":"I have nothing definite to write to our sovereign one about him. Therefore I have brought him before all of you, and especially before you, King Agrippa, so that after this inquiry I may have something to write."}},"definableWords":["one","King"],"peopleInVerse":[]},"27":{"text":"For it seemeth to me unreasonable to send a prisoner, and not withal to signify the crimes laid against him.","ref":"Acts 25:27","synthesized":"For it seems unreasonable to me to send on a prisoner without specifying the charges against him.”","sources":{"KJV":{"text":"For it seemeth to me unreasonable to send a prisoner, and not withal to signify the crimes laid against him."},"BSB":{"text":"For it seems unreasonable to me to send on a prisoner without specifying the charges against him.”"}},"definableWords":[],"peopleInVerse":[]}}},"26":{"chapter":"26","title":"PAUL BEFORE AGRIPPA","verses":{"1":{"text":"Then Agrippa said unto Paul, Thou art permitted to speak for thyself. Then Paul stretched forth the hand, and answered for himself:","ref":"Acts 26:1","synthesized":"Agrippa said to Paul, “You have permission to speak for yourself.”  Then Paul stretched out his hand and began his defense:","sources":{"KJV":{"text":"Then Agrippa said unto Paul, Thou art permitted to speak for thyself. Then Paul stretched forth the hand, and answered for himself:"},"BSB":{"text":"Agrippa said to Paul, “You have permission to speak for yourself.”  Then Paul stretched out his hand and began his defense:"}},"definableWords":[],"peopleInVerse":["Paul"]},"2":{"text":"I think myself happy, king Agrippa, because I shall answer for myself this day before thee touching all the things whereof I am accused of the Jews:","ref":"Acts 26:2","synthesized":"“King Agrippa, I consider myself fortunate to stand before you today to defend myself against all the accusations of the Jews,","sources":{"KJV":{"text":"I think myself happy, king Agrippa, because I shall answer for myself this day before thee touching all the things whereof I am accused of the Jews:"},"BSB":{"text":"“King Agrippa, I consider myself fortunate to stand before you today to defend myself against all the accusations of the Jews,"}},"definableWords":["King","stand"],"peopleInVerse":[]},"3":{"text":"Especially because I know thee to be expert in all customs and questions which are among the Jews: wherefore I beseech thee to hear me patiently.","ref":"Acts 26:3","synthesized":"especially since you are acquainted with all the Jewish customs and controversies. I beg you, therefore, to listen to me patiently.","sources":{"KJV":{"text":"Especially because I know thee to be expert in all customs and questions which are among the Jews: wherefore I beseech thee to hear me patiently."},"BSB":{"text":"especially since you are acquainted with all the Jewish customs and controversies. I beg you, therefore, to listen to me patiently."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"My manner of life from my youth, which was at the first among mine own nation at Jerusalem, know all the Jews;","ref":"Acts 26:4","synthesized":"Surely all the Jews know how I have lived from the earliest days of my youth, among my own people and in Jerusalem.","sources":{"KJV":{"text":"My manner of life from my youth, which was at the first among mine own nation at Jerusalem, know all the Jews;"},"BSB":{"text":"Surely all the Jews know how I have lived from the earliest days of my youth, among my own people and in Jerusalem."}},"definableWords":["days","people","Jerusalem"],"peopleInVerse":[]},"5":{"text":"Which knew me from the beginning, if they would testify, that after the most straitest sect of our religion I lived a Pharisee.","ref":"Acts 26:5","synthesized":"They have known me for a long time and can testify, if they are willing, that I lived as a Pharisee, adhering to the strictest sect of our religion.","sources":{"KJV":{"text":"Which knew me from the beginning, if they would testify, that after the most straitest sect of our religion I lived a Pharisee."},"BSB":{"text":"They have known me for a long time and can testify, if they are willing, that I lived as a Pharisee, adhering to the strictest sect of our religion."}},"definableWords":["Pharisee"],"peopleInVerse":[]},"6":{"text":"And now I stand and am judged for the hope of the promise made of God unto our fathers:","ref":"Acts 26:6","synthesized":"And now I stand on trial because of my hope in the promise that God made to our fathers,","sources":{"KJV":{"text":"And now I stand and am judged for the hope of the promise made of God unto our fathers:"},"BSB":{"text":"And now I stand on trial because of my hope in the promise that God made to our fathers,"}},"definableWords":["stand","hope","promise","God","made","fathers"],"peopleInVerse":[]},"7":{"text":"Unto which promise our twelve tribes, instantly serving God day and night, hope to come. For which hope’s sake, king Agrippa, I am accused of the Jews.","ref":"Acts 26:7","synthesized":"the promise our twelve tribes are hoping to realize as they earnestly serve God day and night. It is because of this hope, O king, that I am accused by the Jews.","sources":{"KJV":{"text":"Unto which promise our twelve tribes, instantly serving God day and night, hope to come. For which hope’s sake, king Agrippa, I am accused of the Jews."},"BSB":{"text":"the promise our twelve tribes are hoping to realize as they earnestly serve God day and night. It is because of this hope, O king, that I am accused by the Jews."}},"definableWords":["promise","God","day","night","hope","king"],"peopleInVerse":[]},"8":{"text":"Why should it be thought a thing incredible with you, that God should raise the dead?","ref":"Acts 26:8","synthesized":"Why would any of you consider it incredible that God raises the dead?","sources":{"KJV":{"text":"Why should it be thought a thing incredible with you, that God should raise the dead?"},"BSB":{"text":"Why would any of you consider it incredible that God raises the dead?"}},"definableWords":["God"],"peopleInVerse":[]},"9":{"text":"I verily thought with myself, that I ought to do many things contrary to the name of Jesus of Nazareth.","ref":"Acts 26:9","synthesized":"So then, I too was convinced that I ought to do all I could to oppose the name of Jesus of Nazareth.","sources":{"KJV":{"text":"I verily thought with myself, that I ought to do many things contrary to the name of Jesus of Nazareth."},"BSB":{"text":"So then, I too was convinced that I ought to do all I could to oppose the name of Jesus of Nazareth."}},"definableWords":["name"],"peopleInVerse":["Jesus"]},"10":{"text":"Which thing I also did in Jerusalem: and many of the saints did I shut up in prison, having received authority from the chief priests; and when they were put to death, I gave my voice against them.","ref":"Acts 26:10","synthesized":"And that is what I did in Jerusalem. With authority from the chief priests I put many of the saints in prison, and when they were condemned to death, I cast my vote against them.","sources":{"KJV":{"text":"Which thing I also did in Jerusalem: and many of the saints did I shut up in prison, having received authority from the chief priests; and when they were put to death, I gave my voice against them."},"BSB":{"text":"And that is what I did in Jerusalem. With authority from the chief priests I put many of the saints in prison, and when they were condemned to death, I cast my vote against them."}},"definableWords":["Jerusalem","death"],"peopleInVerse":[]},"11":{"text":"And I punished them oft in every synagogue, and compelled them to blaspheme; and being exceedingly mad against them, I persecuted them even unto strange cities.","ref":"Acts 26:11","synthesized":"I frequently had them punished in the synagogues, and I tried to make them blaspheme. In my raging fury against them, I even went to foreign cities to persecute them.","sources":{"KJV":{"text":"And I punished them oft in every synagogue, and compelled them to blaspheme; and being exceedingly mad against them, I persecuted them even unto strange cities."},"BSB":{"text":"I frequently had them punished in the synagogues, and I tried to make them blaspheme. In my raging fury against them, I even went to foreign cities to persecute them."}},"definableWords":["make"],"peopleInVerse":[]},"12":{"text":"Whereupon as I went to Damascus with authority and commission from the chief priests,","ref":"Acts 26:12","synthesized":"In this pursuit I was on my way to Damascus with the authority and commission of the chief priests.","sources":{"KJV":{"text":"Whereupon as I went to Damascus with authority and commission from the chief priests,"},"BSB":{"text":"In this pursuit I was on my way to Damascus with the authority and commission of the chief priests."}},"definableWords":["way"],"peopleInVerse":[]},"13":{"text":"At midday, O king, I saw in the way a light from heaven, above the brightness of the sun, shining round about me and them which journeyed with me.","ref":"Acts 26:13","synthesized":"About noon, O king, as I was on the road, I saw a light from heaven, brighter than the sun, shining around me and my companions.","sources":{"KJV":{"text":"At midday, O king, I saw in the way a light from heaven, above the brightness of the sun, shining round about me and them which journeyed with me."},"BSB":{"text":"About noon, O king, as I was on the road, I saw a light from heaven, brighter than the sun, shining around me and my companions."}},"definableWords":["king","saw","light","heaven"],"peopleInVerse":[]},"14":{"text":"And when we were all fallen to the earth, I heard a voice speaking unto me, and saying in the Hebrew tongue, Saul, Saul, why persecutest thou me? it is hard for thee to kick against the pricks.","ref":"Acts 26:14","synthesized":"We all fell to the ground, and I heard a voice say to me in Hebrew, ‘Saul, Saul, why do you persecute Me? It is hard for you to kick against the goads.’","sources":{"KJV":{"text":"And when we were all fallen to the earth, I heard a voice speaking unto me, and saying in the Hebrew tongue, Saul, Saul, why persecutest thou me? it is hard for thee to kick against the pricks."},"BSB":{"text":"We all fell to the ground, and I heard a voice say to me in Hebrew, ‘Saul, Saul, why do you persecute Me? It is hard for you to kick against the goads.’"}},"definableWords":["ground","voice"],"peopleInVerse":["Saul"]},"15":{"text":"And I said, Who art thou, Lord? And he said, I am Jesus whom thou persecutest.","ref":"Acts 26:15","synthesized":"‘Who are You, Lord?’ I asked.  ‘I am Jesus, whom you are persecuting,’ the Lord replied.","sources":{"KJV":{"text":"And I said, Who art thou, Lord? And he said, I am Jesus whom thou persecutest."},"BSB":{"text":"‘Who are You, Lord?’ I asked.  ‘I am Jesus, whom you are persecuting,’ the Lord replied."}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"16":{"text":"But rise, and stand upon thy feet: for I have appeared unto thee for this purpose, to make thee a minister and a witness both of these things which thou hast seen, and of those things in the which I will appear unto thee;","ref":"Acts 26:16","synthesized":"‘But get up and stand on your feet. For I have appeared to you to appoint you as a servant and as a witness of what you have seen from Me and what I will show you.","sources":{"KJV":{"text":"But rise, and stand upon thy feet: for I have appeared unto thee for this purpose, to make thee a minister and a witness both of these things which thou hast seen, and of those things in the which I will appear unto thee;"},"BSB":{"text":"‘But get up and stand on your feet. For I have appeared to you to appoint you as a servant and as a witness of what you have seen from Me and what I will show you."}},"definableWords":["stand","servant"],"peopleInVerse":[]},"17":{"text":"Delivering thee from the people, and from the Gentiles, unto whom now I send thee,","ref":"Acts 26:17","synthesized":"I will rescue you from your own people and from the Gentiles. I am sending you to them","sources":{"KJV":{"text":"Delivering thee from the people, and from the Gentiles, unto whom now I send thee,"},"BSB":{"text":"I will rescue you from your own people and from the Gentiles. I am sending you to them"}},"definableWords":["people"],"peopleInVerse":[]},"18":{"text":"To open their eyes, and to turn them from darkness to light, and from the power of Satan unto God, that they may receive forgiveness of sins, and inheritance among them which are sanctified by faith that is in me.","ref":"Acts 26:18","synthesized":"to open their eyes, so that they may turn from darkness to light and from the power of Satan to God, that they may receive forgiveness of sins and an inheritance among those sanctified by faith in Me.’","sources":{"KJV":{"text":"To open their eyes, and to turn them from darkness to light, and from the power of Satan unto God, that they may receive forgiveness of sins, and inheritance among them which are sanctified by faith that is in me."},"BSB":{"text":"to open their eyes, so that they may turn from darkness to light and from the power of Satan to God, that they may receive forgiveness of sins and an inheritance among those sanctified by faith in Me.’"}},"definableWords":["darkness","light","Satan","God","faith"],"peopleInVerse":[]},"19":{"text":"Whereupon, O king Agrippa, I was not disobedient unto the heavenly vision:","ref":"Acts 26:19","synthesized":"So then, King Agrippa, I was not disobedient to the heavenly vision.","sources":{"KJV":{"text":"Whereupon, O king Agrippa, I was not disobedient unto the heavenly vision:"},"BSB":{"text":"So then, King Agrippa, I was not disobedient to the heavenly vision."}},"definableWords":["King"],"peopleInVerse":[]},"20":{"text":"But shewed first unto them of Damascus, and at Jerusalem, and throughout all the coasts of Judaea, and then to the Gentiles, that they should repent and turn to God, and do works meet for repentance.","ref":"Acts 26:20","synthesized":"First to those in Damascus and Jerusalem, then to everyone in the region of Judea, and then to the Gentiles, I declared that they should repent and turn to God, performing deeds worthy of their repentance.","sources":{"KJV":{"text":"But shewed first unto them of Damascus, and at Jerusalem, and throughout all the coasts of Judaea, and then to the Gentiles, that they should repent and turn to God, and do works meet for repentance."},"BSB":{"text":"First to those in Damascus and Jerusalem, then to everyone in the region of Judea, and then to the Gentiles, I declared that they should repent and turn to God, performing deeds worthy of their repentance."}},"definableWords":["Jerusalem","Judea","God","repentance"],"peopleInVerse":[]},"21":{"text":"For these causes the Jews caught me in the temple, and went about to kill me.","ref":"Acts 26:21","synthesized":"For this reason the Jews seized me in the temple courts and tried to kill me.","sources":{"KJV":{"text":"For these causes the Jews caught me in the temple, and went about to kill me."},"BSB":{"text":"For this reason the Jews seized me in the temple courts and tried to kill me."}},"definableWords":["temple"],"peopleInVerse":[]},"22":{"text":"Having therefore obtained help of God, I continue unto this day, witnessing both to small and great, saying none other things than those which the prophets and Moses did say should come:","ref":"Acts 26:22","synthesized":"But I have had God’s help to this day, and I stand here to testify to small and great alike. I am saying nothing beyond what the prophets and Moses said would happen:","sources":{"KJV":{"text":"Having therefore obtained help of God, I continue unto this day, witnessing both to small and great, saying none other things than those which the prophets and Moses did say should come:"},"BSB":{"text":"But I have had God’s help to this day, and I stand here to testify to small and great alike. I am saying nothing beyond what the prophets and Moses said would happen:"}},"definableWords":["God","day","stand","great"],"peopleInVerse":["Moses"]},"23":{"text":"That Christ should suffer, and that he should be the first that should rise from the dead, and should shew light unto the people, and to the Gentiles.","ref":"Acts 26:23","synthesized":"that the Christ would suffer, and as the first to rise from the dead, would proclaim light to our people and to the Gentiles.”","sources":{"KJV":{"text":"That Christ should suffer, and that he should be the first that should rise from the dead, and should shew light unto the people, and to the Gentiles."},"BSB":{"text":"that the Christ would suffer, and as the first to rise from the dead, would proclaim light to our people and to the Gentiles.”"}},"definableWords":["Christ","light","people"],"peopleInVerse":[]},"24":{"text":"And as he thus spake for himself, Festus said with a loud voice, Paul, thou art beside thyself; much learning doth make thee mad.","ref":"Acts 26:24","synthesized":"At this stage of Paul’s defense, Festus exclaimed in a loud voice, “You are insane, Paul! Your great learning is driving you to madness!”","sources":{"KJV":{"text":"And as he thus spake for himself, Festus said with a loud voice, Paul, thou art beside thyself; much learning doth make thee mad."},"BSB":{"text":"At this stage of Paul’s defense, Festus exclaimed in a loud voice, “You are insane, Paul! Your great learning is driving you to madness!”"}},"definableWords":["voice","great"],"peopleInVerse":["Paul"]},"25":{"text":"But he said, I am not mad, most noble Festus; but speak forth the words of truth and soberness.","ref":"Acts 26:25","synthesized":"But Paul answered, “I am not insane, most excellent Festus; I am speaking words of truth and sobriety.","sources":{"KJV":{"text":"But he said, I am not mad, most noble Festus; but speak forth the words of truth and soberness."},"BSB":{"text":"But Paul answered, “I am not insane, most excellent Festus; I am speaking words of truth and sobriety."}},"definableWords":["truth"],"peopleInVerse":["Paul"]},"26":{"text":"For the king knoweth of these things, before whom also I speak freely: for I am persuaded that none of these things are hidden from him; for this thing was not done in a corner.","ref":"Acts 26:26","synthesized":"For the king knows about these matters, and I can speak freely to him. I am confident that none of this has escaped his notice, because it was not done in a corner.","sources":{"KJV":{"text":"For the king knoweth of these things, before whom also I speak freely: for I am persuaded that none of these things are hidden from him; for this thing was not done in a corner."},"BSB":{"text":"For the king knows about these matters, and I can speak freely to him. I am confident that none of this has escaped his notice, because it was not done in a corner."}},"definableWords":["king"],"peopleInVerse":[]},"27":{"text":"King Agrippa, believest thou the prophets? I know that thou believest.","ref":"Acts 26:27","synthesized":"King Agrippa, do you believe the prophets? I know you do.”","sources":{"KJV":{"text":"King Agrippa, believest thou the prophets? I know that thou believest."},"BSB":{"text":"King Agrippa, do you believe the prophets? I know you do.”"}},"definableWords":["King"],"peopleInVerse":[]},"28":{"text":"Then Agrippa said unto Paul, Almost thou persuadest me to be a Christian.","ref":"Acts 26:28","synthesized":"Then Agrippa said to Paul, “Can you persuade me in such a short time to become a Christian?”","sources":{"KJV":{"text":"Then Agrippa said unto Paul, Almost thou persuadest me to be a Christian."},"BSB":{"text":"Then Agrippa said to Paul, “Can you persuade me in such a short time to become a Christian?”"}},"definableWords":[],"peopleInVerse":["Paul"]},"29":{"text":"And Paul said, I would to God, that not only thou, but also all that hear me this day, were both almost, and altogether such as I am, except these bonds.","ref":"Acts 26:29","synthesized":"“Short time or long,” Paul replied, “I wish to God that not only you but all who hear me this day may become what I am, except for these chains.”","sources":{"KJV":{"text":"And Paul said, I would to God, that not only thou, but also all that hear me this day, were both almost, and altogether such as I am, except these bonds."},"BSB":{"text":"“Short time or long,” Paul replied, “I wish to God that not only you but all who hear me this day may become what I am, except for these chains.”"}},"definableWords":["or","God","hear","day"],"peopleInVerse":["Paul"]},"30":{"text":"And when he had thus spoken, the king rose up, and the governor, and Bernice, and they that sat with them:","ref":"Acts 26:30","synthesized":"Then the king and the governor rose, along with Bernice and those seated with them.","sources":{"KJV":{"text":"And when he had thus spoken, the king rose up, and the governor, and Bernice, and they that sat with them:"},"BSB":{"text":"Then the king and the governor rose, along with Bernice and those seated with them."}},"definableWords":["king"],"peopleInVerse":[]},"31":{"text":"And when they were gone aside, they talked between themselves, saying, This man doeth nothing worthy of death or of bonds.","ref":"Acts 26:31","synthesized":"On their way out, they said to one another, “This man has done nothing worthy of death or imprisonment.”","sources":{"KJV":{"text":"And when they were gone aside, they talked between themselves, saying, This man doeth nothing worthy of death or of bonds."},"BSB":{"text":"On their way out, they said to one another, “This man has done nothing worthy of death or imprisonment.”"}},"definableWords":["way","one","man","death","or"],"peopleInVerse":[]},"32":{"text":"Then said Agrippa unto Festus, This man might have been set at liberty, if he had not appealed unto Caesar.","ref":"Acts 26:32","synthesized":"And Agrippa said to Festus, “This man could have been released if he had not appealed to Caesar.”","sources":{"KJV":{"text":"Then said Agrippa unto Festus, This man might have been set at liberty, if he had not appealed unto Caesar."},"BSB":{"text":"And Agrippa said to Festus, “This man could have been released if he had not appealed to Caesar.”"}},"definableWords":["man"],"peopleInVerse":[]}}},"27":{"chapter":"27","title":"PAUL'S SHIPWRECK","verses":{"1":{"text":"And when it was determined that we should sail into Italy, they delivered Paul and certain other prisoners unto one named Julius, a centurion of Augustus’ band.","ref":"Acts 27:1","synthesized":"When it was decided that we would sail for Italy, Paul and some other prisoners were handed over to a centurion named Julius, who belonged to the Imperial Regiment.","sources":{"KJV":{"text":"And when it was determined that we should sail into Italy, they delivered Paul and certain other prisoners unto one named Julius, a centurion of Augustus’ band."},"BSB":{"text":"When it was decided that we would sail for Italy, Paul and some other prisoners were handed over to a centurion named Julius, who belonged to the Imperial Regiment."}},"definableWords":[],"peopleInVerse":["Paul"]},"2":{"text":"And entering into a ship of Adramyttium, we launched, meaning to sail by the coasts of Asia; one Aristarchus, a Macedonian of Thessalonica, being with us.","ref":"Acts 27:2","synthesized":"We boarded an Adramyttian ship about to sail for ports along the coast of Asia, and we put out to sea. Aristarchus, a Macedonian from Thessalonica, was with us.","sources":{"KJV":{"text":"And entering into a ship of Adramyttium, we launched, meaning to sail by the coasts of Asia; one Aristarchus, a Macedonian of Thessalonica, being with us."},"BSB":{"text":"We boarded an Adramyttian ship about to sail for ports along the coast of Asia, and we put out to sea. Aristarchus, a Macedonian from Thessalonica, was with us."}},"definableWords":["sea"],"peopleInVerse":[]},"3":{"text":"And the next day we touched at Sidon. And Julius courteously entreated Paul, and gave him liberty to go unto his friends to refresh himself.","ref":"Acts 27:3","synthesized":"The next day we landed at Sidon, and Julius treated Paul with consideration, allowing him to visit his friends and receive their care.","sources":{"KJV":{"text":"And the next day we touched at Sidon. And Julius courteously entreated Paul, and gave him liberty to go unto his friends to refresh himself."},"BSB":{"text":"The next day we landed at Sidon, and Julius treated Paul with consideration, allowing him to visit his friends and receive their care."}},"definableWords":["day"],"peopleInVerse":["Paul"]},"4":{"text":"And when we had launched from thence, we sailed under Cyprus, because the winds were contrary.","ref":"Acts 27:4","synthesized":"After putting out from there, we sailed to the lee of Cyprus because the winds were against us.","sources":{"KJV":{"text":"And when we had launched from thence, we sailed under Cyprus, because the winds were contrary."},"BSB":{"text":"After putting out from there, we sailed to the lee of Cyprus because the winds were against us."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"And when we had sailed over the sea of Cilicia and Pamphylia, we came to Myra, a city of Lycia.","ref":"Acts 27:5","synthesized":"And when we had sailed across the open sea off the coast of Cilicia and Pamphylia, we came to Myra in Lycia.","sources":{"KJV":{"text":"And when we had sailed over the sea of Cilicia and Pamphylia, we came to Myra, a city of Lycia."},"BSB":{"text":"And when we had sailed across the open sea off the coast of Cilicia and Pamphylia, we came to Myra in Lycia."}},"definableWords":["sea"],"peopleInVerse":[]},"6":{"text":"And there the centurion found a ship of Alexandria sailing into Italy; and he put us therein.","ref":"Acts 27:6","synthesized":"There the centurion found an Alexandrian ship sailing for Italy and put us on board.","sources":{"KJV":{"text":"And there the centurion found a ship of Alexandria sailing into Italy; and he put us therein."},"BSB":{"text":"There the centurion found an Alexandrian ship sailing for Italy and put us on board."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And when we had sailed slowly many days, and scarce were come over against Cnidus, the wind not suffering us, we sailed under Crete, over against Salmone;","ref":"Acts 27:7","synthesized":"After sailing slowly for many days, we arrived off Cnidus. When the wind impeded us, we sailed to the lee of Crete, opposite Salmone.","sources":{"KJV":{"text":"And when we had sailed slowly many days, and scarce were come over against Cnidus, the wind not suffering us, we sailed under Crete, over against Salmone;"},"BSB":{"text":"After sailing slowly for many days, we arrived off Cnidus. When the wind impeded us, we sailed to the lee of Crete, opposite Salmone."}},"definableWords":["days"],"peopleInVerse":[]},"8":{"text":"And, hardly passing it, came unto a place which is called The fair havens; nigh whereunto was the city of Lasea.","ref":"Acts 27:8","synthesized":"After we had moved along the coast with difficulty, we came to a place called Fair Havens, near the town of Lasea.","sources":{"KJV":{"text":"And, hardly passing it, came unto a place which is called The fair havens; nigh whereunto was the city of Lasea."},"BSB":{"text":"After we had moved along the coast with difficulty, we came to a place called Fair Havens, near the town of Lasea."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Now when much time was spent, and when sailing was now dangerous, because the fast was now already past, Paul admonished them,","ref":"Acts 27:9","synthesized":"By now much time had passed, and the voyage had already become dangerous because it was after the Fast. So Paul advised them,","sources":{"KJV":{"text":"Now when much time was spent, and when sailing was now dangerous, because the fast was now already past, Paul admonished them,"},"BSB":{"text":"By now much time had passed, and the voyage had already become dangerous because it was after the Fast. So Paul advised them,"}},"definableWords":["fast"],"peopleInVerse":["Paul"]},"10":{"text":"And said unto them, Sirs, I perceive that this voyage will be with hurt and much damage, not only of the lading and ship, but also of our lives.","ref":"Acts 27:10","synthesized":"“Men, I can see that our voyage will be filled with disaster and great loss, not only to ship and cargo, but to our own lives as well.”","sources":{"KJV":{"text":"And said unto them, Sirs, I perceive that this voyage will be with hurt and much damage, not only of the lading and ship, but also of our lives."},"BSB":{"text":"“Men, I can see that our voyage will be filled with disaster and great loss, not only to ship and cargo, but to our own lives as well.”"}},"definableWords":["men","see","great"],"peopleInVerse":[]},"11":{"text":"Nevertheless the centurion believed the master and the owner of the ship, more than those things which were spoken by Paul.","ref":"Acts 27:11","synthesized":"But contrary to Paul’s advice, the centurion was persuaded by the pilot and by the owner of the ship.","sources":{"KJV":{"text":"Nevertheless the centurion believed the master and the owner of the ship, more than those things which were spoken by Paul."},"BSB":{"text":"But contrary to Paul’s advice, the centurion was persuaded by the pilot and by the owner of the ship."}},"definableWords":[],"peopleInVerse":["Paul"]},"12":{"text":"And because the haven was not commodious to winter in, the more part advised to depart thence also, if by any means they might attain to Phenice, and there to winter; which is an haven of Crete, and lieth toward the south west and north west.","ref":"Acts 27:12","synthesized":"Since the harbor was unsuitable to winter in, the majority decided to sail on, if somehow they could reach Phoenix to winter there. Phoenix was a harbor in Crete facing both southwest and northwest.","sources":{"KJV":{"text":"And because the haven was not commodious to winter in, the more part advised to depart thence also, if by any means they might attain to Phenice, and there to winter; which is an haven of Crete, and lieth toward the south west and north west."},"BSB":{"text":"Since the harbor was unsuitable to winter in, the majority decided to sail on, if somehow they could reach Phoenix to winter there. Phoenix was a harbor in Crete facing both southwest and northwest."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"And when the south wind blew softly, supposing that they had obtained their purpose, loosing thence, they sailed close by Crete.","ref":"Acts 27:13","synthesized":"When a gentle south wind began to blow, they thought they had their opportunity. So they weighed anchor and sailed along, hugging the coast of Crete.","sources":{"KJV":{"text":"And when the south wind blew softly, supposing that they had obtained their purpose, loosing thence, they sailed close by Crete."},"BSB":{"text":"When a gentle south wind began to blow, they thought they had their opportunity. So they weighed anchor and sailed along, hugging the coast of Crete."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"But not long after there arose against it a tempestuous wind, called Euroclydon.","ref":"Acts 27:14","synthesized":"But it was not long before a cyclone called the Northeaster swept down across the island.","sources":{"KJV":{"text":"But not long after there arose against it a tempestuous wind, called Euroclydon."},"BSB":{"text":"But it was not long before a cyclone called the Northeaster swept down across the island."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And when the ship was caught, and could not bear up into the wind, we let her drive.","ref":"Acts 27:15","synthesized":"Unable to head into the wind, the ship was caught up. So we gave way and let ourselves be driven along.","sources":{"KJV":{"text":"And when the ship was caught, and could not bear up into the wind, we let her drive."},"BSB":{"text":"Unable to head into the wind, the ship was caught up. So we gave way and let ourselves be driven along."}},"definableWords":["way"],"peopleInVerse":[]},"16":{"text":"And running under a certain island which is called Clauda, we had much work to come by the boat:","ref":"Acts 27:16","synthesized":"Passing to the lee of a small island called Cauda, we barely managed to secure the lifeboat.","sources":{"KJV":{"text":"And running under a certain island which is called Clauda, we had much work to come by the boat:"},"BSB":{"text":"Passing to the lee of a small island called Cauda, we barely managed to secure the lifeboat."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Which when they had taken up, they used helps, undergirding the ship; and, fearing lest they should fall into the quicksands, strake sail, and so were driven.","ref":"Acts 27:17","synthesized":"After hoisting it up, the crew used ropes to undergird the ship. And fearing that they would run aground on the sandbars of Syrtis, they lowered the sea anchor and were driven along.","sources":{"KJV":{"text":"Which when they had taken up, they used helps, undergirding the ship; and, fearing lest they should fall into the quicksands, strake sail, and so were driven."},"BSB":{"text":"After hoisting it up, the crew used ropes to undergird the ship. And fearing that they would run aground on the sandbars of Syrtis, they lowered the sea anchor and were driven along."}},"definableWords":["run","sea"],"peopleInVerse":[]},"18":{"text":"And we being exceedingly tossed with a tempest, the next day they lightened the ship;","ref":"Acts 27:18","synthesized":"We were tossed so violently that the next day the men began to jettison the cargo.","sources":{"KJV":{"text":"And we being exceedingly tossed with a tempest, the next day they lightened the ship;"},"BSB":{"text":"We were tossed so violently that the next day the men began to jettison the cargo."}},"definableWords":["day","men"],"peopleInVerse":[]},"19":{"text":"And the third day we cast out with our own hands the tackling of the ship.","ref":"Acts 27:19","synthesized":"On the third day, they threw the ship’s tackle overboard with their own hands.","sources":{"KJV":{"text":"And the third day we cast out with our own hands the tackling of the ship."},"BSB":{"text":"On the third day, they threw the ship’s tackle overboard with their own hands."}},"definableWords":["day"],"peopleInVerse":[]},"20":{"text":"And when neither sun nor stars in many days appeared, and no small tempest lay on us, all hope that we should be saved was then taken away.","ref":"Acts 27:20","synthesized":"When neither sun nor stars appeared for many days and the great storm continued to batter us, we abandoned all hope of being saved.","sources":{"KJV":{"text":"And when neither sun nor stars in many days appeared, and no small tempest lay on us, all hope that we should be saved was then taken away."},"BSB":{"text":"When neither sun nor stars appeared for many days and the great storm continued to batter us, we abandoned all hope of being saved."}},"definableWords":["days","great","hope"],"peopleInVerse":[]},"21":{"text":"But after long abstinence Paul stood forth in the midst of them, and said, Sirs, ye should have hearkened unto me, and not have loosed from Crete, and to have gained this harm and loss.","ref":"Acts 27:21","synthesized":"After the men had gone a long time without food, Paul stood up among them and said, “Men, you should have followed my advice not to sail from Crete. Then you would have averted this disaster and loss.","sources":{"KJV":{"text":"But after long abstinence Paul stood forth in the midst of them, and said, Sirs, ye should have hearkened unto me, and not have loosed from Crete, and to have gained this harm and loss."},"BSB":{"text":"After the men had gone a long time without food, Paul stood up among them and said, “Men, you should have followed my advice not to sail from Crete. Then you would have averted this disaster and loss."}},"definableWords":["men"],"peopleInVerse":["Paul"]},"22":{"text":"And now I exhort you to be of good cheer: for there shall be no loss of any man’s life among you, but of the ship.","ref":"Acts 27:22","synthesized":"But now I urge you to keep up your courage, because you will not experience any loss of life, but only of the ship.","sources":{"KJV":{"text":"And now I exhort you to be of good cheer: for there shall be no loss of any man’s life among you, but of the ship."},"BSB":{"text":"But now I urge you to keep up your courage, because you will not experience any loss of life, but only of the ship."}},"definableWords":["keep","life"],"peopleInVerse":[]},"23":{"text":"For there stood by me this night the angel of God, whose I am, and whom I serve,","ref":"Acts 27:23","synthesized":"For just last night an angel of God, whose I am and whom I serve, stood beside me","sources":{"KJV":{"text":"For there stood by me this night the angel of God, whose I am, and whom I serve,"},"BSB":{"text":"For just last night an angel of God, whose I am and whom I serve, stood beside me"}},"definableWords":["night","angel","God"],"peopleInVerse":[]},"24":{"text":"Saying, Fear not, Paul; thou must be brought before Caesar: and, lo, God hath given thee all them that sail with thee.","ref":"Acts 27:24","synthesized":"and said, ‘Do not be afraid, Paul; you must stand before Caesar. And look, God has granted you the lives of all who sail with you.’","sources":{"KJV":{"text":"Saying, Fear not, Paul; thou must be brought before Caesar: and, lo, God hath given thee all them that sail with thee."},"BSB":{"text":"and said, ‘Do not be afraid, Paul; you must stand before Caesar. And look, God has granted you the lives of all who sail with you.’"}},"definableWords":["stand","God"],"peopleInVerse":["Paul"]},"25":{"text":"Wherefore, sirs, be of good cheer: for I believe God, that it shall be even as it was told me.","ref":"Acts 27:25","synthesized":"So take courage, men, for I believe God that it will happen just as He told me.","sources":{"KJV":{"text":"Wherefore, sirs, be of good cheer: for I believe God, that it shall be even as it was told me."},"BSB":{"text":"So take courage, men, for I believe God that it will happen just as He told me."}},"definableWords":["men","God"],"peopleInVerse":[]},"26":{"text":"Howbeit we must be cast upon a certain island.","ref":"Acts 27:26","synthesized":"However, we must run aground on some island.”","sources":{"KJV":{"text":"Howbeit we must be cast upon a certain island."},"BSB":{"text":"However, we must run aground on some island.”"}},"definableWords":["run"],"peopleInVerse":[]},"27":{"text":"But when the fourteenth night was come, as we were driven up and down in Adria, about midnight the shipmen deemed that they drew near to some country;","ref":"Acts 27:27","synthesized":"On the fourteenth night we were still being driven across the Adriatic Sea. About midnight the sailors sensed they were approaching land.","sources":{"KJV":{"text":"But when the fourteenth night was come, as we were driven up and down in Adria, about midnight the shipmen deemed that they drew near to some country;"},"BSB":{"text":"On the fourteenth night we were still being driven across the Adriatic Sea. About midnight the sailors sensed they were approaching land."}},"definableWords":["night","sea","land"],"peopleInVerse":[]},"28":{"text":"And sounded, and found it twenty fathoms: and when they had gone a little further, they sounded again, and found it fifteen fathoms.","ref":"Acts 27:28","synthesized":"They took soundings and found that the water was twenty fathoms deep. Going a little farther, they took another set of soundings that read fifteen fathoms.","sources":{"KJV":{"text":"And sounded, and found it twenty fathoms: and when they had gone a little further, they sounded again, and found it fifteen fathoms."},"BSB":{"text":"They took soundings and found that the water was twenty fathoms deep. Going a little farther, they took another set of soundings that read fifteen fathoms."}},"definableWords":["water","deep"],"peopleInVerse":[]},"29":{"text":"Then fearing lest we should have fallen upon rocks, they cast four anchors out of the stern, and wished for the day.","ref":"Acts 27:29","synthesized":"Fearing that we would run aground on the rocks, they dropped four anchors from the stern and prayed for daybreak.","sources":{"KJV":{"text":"Then fearing lest we should have fallen upon rocks, they cast four anchors out of the stern, and wished for the day."},"BSB":{"text":"Fearing that we would run aground on the rocks, they dropped four anchors from the stern and prayed for daybreak."}},"definableWords":["run"],"peopleInVerse":[]},"30":{"text":"And as the shipmen were about to flee out of the ship, when they had let down the boat into the sea, under colour as though they would have cast anchors out of the foreship,","ref":"Acts 27:30","synthesized":"Meanwhile, the sailors attempted to escape from the ship. Pretending to lower anchors from the bow, they let the lifeboat down into the sea.","sources":{"KJV":{"text":"And as the shipmen were about to flee out of the ship, when they had let down the boat into the sea, under colour as though they would have cast anchors out of the foreship,"},"BSB":{"text":"Meanwhile, the sailors attempted to escape from the ship. Pretending to lower anchors from the bow, they let the lifeboat down into the sea."}},"definableWords":["sea"],"peopleInVerse":[]},"31":{"text":"Paul said to the centurion and to the soldiers, Except these abide in the ship, ye cannot be saved.","ref":"Acts 27:31","synthesized":"But Paul said to the centurion and the soldiers, “Unless these men remain with the ship, you cannot be saved.”","sources":{"KJV":{"text":"Paul said to the centurion and to the soldiers, Except these abide in the ship, ye cannot be saved."},"BSB":{"text":"But Paul said to the centurion and the soldiers, “Unless these men remain with the ship, you cannot be saved.”"}},"definableWords":["men"],"peopleInVerse":["Paul"]},"32":{"text":"Then the soldiers cut off the ropes of the boat, and let her fall off.","ref":"Acts 27:32","synthesized":"So the soldiers cut the ropes to the lifeboat and set it adrift.","sources":{"KJV":{"text":"Then the soldiers cut off the ropes of the boat, and let her fall off."},"BSB":{"text":"So the soldiers cut the ropes to the lifeboat and set it adrift."}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"And while the day was coming on, Paul besought them all to take meat, saying, This day is the fourteenth day that ye have tarried and continued fasting, having taken nothing.","ref":"Acts 27:33","synthesized":"Right up to daybreak, Paul kept urging them all to eat: “Today is your fourteenth day in constant suspense, without taking any food.","sources":{"KJV":{"text":"And while the day was coming on, Paul besought them all to take meat, saying, This day is the fourteenth day that ye have tarried and continued fasting, having taken nothing."},"BSB":{"text":"Right up to daybreak, Paul kept urging them all to eat: “Today is your fourteenth day in constant suspense, without taking any food."}},"definableWords":["day"],"peopleInVerse":["Paul"]},"34":{"text":"Wherefore I pray you to take some meat: for this is for your health: for there shall not an hair fall from the head of any of you.","ref":"Acts 27:34","synthesized":"So for your own preservation, I urge you to eat something, because not a single hair of your head will be lost.”","sources":{"KJV":{"text":"Wherefore I pray you to take some meat: for this is for your health: for there shall not an hair fall from the head of any of you."},"BSB":{"text":"So for your own preservation, I urge you to eat something, because not a single hair of your head will be lost.”"}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"And when he had thus spoken, he took bread, and gave thanks to God in presence of them all: and when he had broken it, he began to eat.","ref":"Acts 27:35","synthesized":"After he had said this, Paul took bread and gave thanks to God in front of them all. Then he broke it and began to eat.","sources":{"KJV":{"text":"And when he had thus spoken, he took bread, and gave thanks to God in presence of them all: and when he had broken it, he began to eat."},"BSB":{"text":"After he had said this, Paul took bread and gave thanks to God in front of them all. Then he broke it and began to eat."}},"definableWords":["God"],"peopleInVerse":["Paul"]},"36":{"text":"Then were they all of good cheer, and they also took some meat.","ref":"Acts 27:36","synthesized":"They were all encouraged and took some food themselves.","sources":{"KJV":{"text":"Then were they all of good cheer, and they also took some meat."},"BSB":{"text":"They were all encouraged and took some food themselves."}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"And we were in all in the ship two hundred threescore and sixteen souls.","ref":"Acts 27:37","synthesized":"In all, there were 276 of us on board.","sources":{"KJV":{"text":"And we were in all in the ship two hundred threescore and sixteen souls."},"BSB":{"text":"In all, there were 276 of us on board."}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"And when they had eaten enough, they lightened the ship, and cast out the wheat into the sea.","ref":"Acts 27:38","synthesized":"After the men had eaten their fill, they lightened the ship by throwing the grain into the sea.","sources":{"KJV":{"text":"And when they had eaten enough, they lightened the ship, and cast out the wheat into the sea."},"BSB":{"text":"After the men had eaten their fill, they lightened the ship by throwing the grain into the sea."}},"definableWords":["men","fill","sea"],"peopleInVerse":[]},"39":{"text":"And when it was day, they knew not the land: but they discovered a certain creek with a shore, into the which they were minded, if it were possible, to thrust in the ship.","ref":"Acts 27:39","synthesized":"When daylight came, they did not recognize the land, but they sighted a bay with a sandy beach, where they decided to run the ship aground if they could.","sources":{"KJV":{"text":"And when it was day, they knew not the land: but they discovered a certain creek with a shore, into the which they were minded, if it were possible, to thrust in the ship."},"BSB":{"text":"When daylight came, they did not recognize the land, but they sighted a bay with a sandy beach, where they decided to run the ship aground if they could."}},"definableWords":["land","run"],"peopleInVerse":[]},"40":{"text":"And when they had taken up the anchors, they committed themselves unto the sea, and loosed the rudder bands, and hoised up the mainsail to the wind, and made toward shore.","ref":"Acts 27:40","synthesized":"Cutting away the anchors, they left them in the sea as they loosened the ropes that held the rudders. Then they hoisted the foresail to the wind and made for the beach.","sources":{"KJV":{"text":"And when they had taken up the anchors, they committed themselves unto the sea, and loosed the rudder bands, and hoised up the mainsail to the wind, and made toward shore."},"BSB":{"text":"Cutting away the anchors, they left them in the sea as they loosened the ropes that held the rudders. Then they hoisted the foresail to the wind and made for the beach."}},"definableWords":["sea","made"],"peopleInVerse":[]},"41":{"text":"And falling into a place where two seas met, they ran the ship aground; and the forepart stuck fast, and remained unmoveable, but the hinder part was broken with the violence of the waves.","ref":"Acts 27:41","synthesized":"But the vessel struck a sandbar and ran aground. The bow stuck fast and would not move, and the stern was being broken up by the pounding of the waves.","sources":{"KJV":{"text":"And falling into a place where two seas met, they ran the ship aground; and the forepart stuck fast, and remained unmoveable, but the hinder part was broken with the violence of the waves."},"BSB":{"text":"But the vessel struck a sandbar and ran aground. The bow stuck fast and would not move, and the stern was being broken up by the pounding of the waves."}},"definableWords":["fast"],"peopleInVerse":[]},"42":{"text":"And the soldiers’ counsel was to kill the prisoners, lest any of them should swim out, and escape.","ref":"Acts 27:42","synthesized":"The soldiers planned to kill the prisoners so none of them could swim to freedom.","sources":{"KJV":{"text":"And the soldiers’ counsel was to kill the prisoners, lest any of them should swim out, and escape."},"BSB":{"text":"The soldiers planned to kill the prisoners so none of them could swim to freedom."}},"definableWords":[],"peopleInVerse":[]},"43":{"text":"But the centurion, willing to save Paul, kept them from their purpose; and commanded that they which could swim should cast themselves first into the sea, and get to land:","ref":"Acts 27:43","synthesized":"But the centurion, wanting to spare Paul’s life, thwarted their plan. He commanded those who could swim to jump overboard first and get to land.","sources":{"KJV":{"text":"But the centurion, willing to save Paul, kept them from their purpose; and commanded that they which could swim should cast themselves first into the sea, and get to land:"},"BSB":{"text":"But the centurion, wanting to spare Paul’s life, thwarted their plan. He commanded those who could swim to jump overboard first and get to land."}},"definableWords":["life","land"],"peopleInVerse":["Paul"]},"44":{"text":"And the rest, some on boards, and some on broken pieces of the ship. And so it came to pass, that they escaped all safe to land.","ref":"Acts 27:44","synthesized":"The rest were to follow on planks and various parts of the ship. In this way everyone was brought safely to land.","sources":{"KJV":{"text":"And the rest, some on boards, and some on broken pieces of the ship. And so it came to pass, that they escaped all safe to land."},"BSB":{"text":"The rest were to follow on planks and various parts of the ship. In this way everyone was brought safely to land."}},"definableWords":["rest","way","land"],"peopleInVerse":[]}}},"28":{"chapter":"28","title":"PAUL ARRIVES IN ROME","verses":{"1":{"text":"And when they were escaped, then they knew that the island was called Melita.","ref":"Acts 28:1","synthesized":"Once we were safely ashore, we learned that the island was called Malta.","sources":{"KJV":{"text":"And when they were escaped, then they knew that the island was called Melita."},"BSB":{"text":"Once we were safely ashore, we learned that the island was called Malta."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"And the barbarous people shewed us no little kindness: for they kindled a fire, and received us every one, because of the present rain, and because of the cold.","ref":"Acts 28:2","synthesized":"The islanders showed us extraordinary kindness. They kindled a fire and welcomed all of us because it was raining and cold.","sources":{"KJV":{"text":"And the barbarous people shewed us no little kindness: for they kindled a fire, and received us every one, because of the present rain, and because of the cold."},"BSB":{"text":"The islanders showed us extraordinary kindness. They kindled a fire and welcomed all of us because it was raining and cold."}},"definableWords":["kindness"],"peopleInVerse":[]},"3":{"text":"And when Paul had gathered a bundle of sticks, and laid them on the fire, there came a viper out of the heat, and fastened on his hand.","ref":"Acts 28:3","synthesized":"Paul gathered a bundle of sticks, and as he laid them on the fire, a viper, driven out by the heat, fastened itself to his hand.","sources":{"KJV":{"text":"And when Paul had gathered a bundle of sticks, and laid them on the fire, there came a viper out of the heat, and fastened on his hand."},"BSB":{"text":"Paul gathered a bundle of sticks, and as he laid them on the fire, a viper, driven out by the heat, fastened itself to his hand."}},"definableWords":[],"peopleInVerse":["Paul"]},"4":{"text":"And when the barbarians saw the venomous beast hang on his hand, they said among themselves, No doubt this man is a murderer, whom, though he hath escaped the sea, yet vengeance suffereth not to live.","ref":"Acts 28:4","synthesized":"When the islanders saw the creature hanging from his hand, they said to one another, “Surely this man is a murderer. Although he was saved from the sea, Justice has not allowed him to live.”","sources":{"KJV":{"text":"And when the barbarians saw the venomous beast hang on his hand, they said among themselves, No doubt this man is a murderer, whom, though he hath escaped the sea, yet vengeance suffereth not to live."},"BSB":{"text":"When the islanders saw the creature hanging from his hand, they said to one another, “Surely this man is a murderer. Although he was saved from the sea, Justice has not allowed him to live.”"}},"definableWords":["saw","one","man","sea","justice","live"],"peopleInVerse":[]},"5":{"text":"And he shook off the beast into the fire, and felt no harm.","ref":"Acts 28:5","synthesized":"But Paul shook the creature off into the fire and suffered no ill effects.","sources":{"KJV":{"text":"And he shook off the beast into the fire, and felt no harm."},"BSB":{"text":"But Paul shook the creature off into the fire and suffered no ill effects."}},"definableWords":[],"peopleInVerse":["Paul"]},"6":{"text":"Howbeit they looked when he should have swollen, or fallen down dead suddenly: but after they had looked a great while, and saw no harm come to him, they changed their minds, and said that he was a god.","ref":"Acts 28:6","synthesized":"The islanders were expecting him to swell up or suddenly drop dead. But after waiting a long time and seeing nothing unusual happen to him, they changed their minds and said he was a god.","sources":{"KJV":{"text":"Howbeit they looked when he should have swollen, or fallen down dead suddenly: but after they had looked a great while, and saw no harm come to him, they changed their minds, and said that he was a god."},"BSB":{"text":"The islanders were expecting him to swell up or suddenly drop dead. But after waiting a long time and seeing nothing unusual happen to him, they changed their minds and said he was a god."}},"definableWords":["or","God"],"peopleInVerse":[]},"7":{"text":"In the same quarters were possessions of the chief man of the island, whose name was Publius; who received us, and lodged us three days courteously.","ref":"Acts 28:7","synthesized":"Nearby stood an estate belonging to Publius, the chief official of the island. He welcomed us and entertained us hospitably for three days.","sources":{"KJV":{"text":"In the same quarters were possessions of the chief man of the island, whose name was Publius; who received us, and lodged us three days courteously."},"BSB":{"text":"Nearby stood an estate belonging to Publius, the chief official of the island. He welcomed us and entertained us hospitably for three days."}},"definableWords":["days"],"peopleInVerse":[]},"8":{"text":"And it came to pass, that the father of Publius lay sick of a fever and of a bloody flux: to whom Paul entered in, and prayed, and laid his hands on him, and healed him.","ref":"Acts 28:8","synthesized":"The father of Publius was sick in bed, suffering from fever and dysentery. Paul went in to see him, and after praying and placing his hands on him, he healed the man.","sources":{"KJV":{"text":"And it came to pass, that the father of Publius lay sick of a fever and of a bloody flux: to whom Paul entered in, and prayed, and laid his hands on him, and healed him."},"BSB":{"text":"The father of Publius was sick in bed, suffering from fever and dysentery. Paul went in to see him, and after praying and placing his hands on him, he healed the man."}},"definableWords":["father","see","man"],"peopleInVerse":["Paul"]},"9":{"text":"So when this was done, others also, which had diseases in the island, came, and were healed:","ref":"Acts 28:9","synthesized":"After this had happened, the rest of the sick on the island came and were cured as well.","sources":{"KJV":{"text":"So when this was done, others also, which had diseases in the island, came, and were healed:"},"BSB":{"text":"After this had happened, the rest of the sick on the island came and were cured as well."}},"definableWords":["rest"],"peopleInVerse":[]},"10":{"text":"Who also honoured us with many honours; and when we departed, they laded us with such things as were necessary.","ref":"Acts 28:10","synthesized":"The islanders honored us in many ways and supplied our needs when we were ready to sail.","sources":{"KJV":{"text":"Who also honoured us with many honours; and when we departed, they laded us with such things as were necessary."},"BSB":{"text":"The islanders honored us in many ways and supplied our needs when we were ready to sail."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And after three months we departed in a ship of Alexandria, which had wintered in the isle, whose sign was Castor and Pollux.","ref":"Acts 28:11","synthesized":"After three months we set sail in an Alexandrian ship that had wintered in the island. It had the Twin Brothers as a figurehead.","sources":{"KJV":{"text":"And after three months we departed in a ship of Alexandria, which had wintered in the isle, whose sign was Castor and Pollux."},"BSB":{"text":"After three months we set sail in an Alexandrian ship that had wintered in the island. It had the Twin Brothers as a figurehead."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"And landing at Syracuse, we tarried there three days.","ref":"Acts 28:12","synthesized":"Putting in at Syracuse, we stayed there three days.","sources":{"KJV":{"text":"And landing at Syracuse, we tarried there three days."},"BSB":{"text":"Putting in at Syracuse, we stayed there three days."}},"definableWords":["days"],"peopleInVerse":[]},"13":{"text":"And from thence we fetched a compass, and came to Rhegium: and after one day the south wind blew, and we came the next day to Puteoli:","ref":"Acts 28:13","synthesized":"From there we weighed anchor and came to Rhegium. After one day, a south wind came up, and on the second day we arrived at Puteoli.","sources":{"KJV":{"text":"And from thence we fetched a compass, and came to Rhegium: and after one day the south wind blew, and we came the next day to Puteoli:"},"BSB":{"text":"From there we weighed anchor and came to Rhegium. After one day, a south wind came up, and on the second day we arrived at Puteoli."}},"definableWords":["one","day"],"peopleInVerse":[]},"14":{"text":"Where we found brethren, and were desired to tarry with them seven days: and so we went toward Rome.","ref":"Acts 28:14","synthesized":"There we found some brothers who invited us to spend the week with them. And so we came to Rome.","sources":{"KJV":{"text":"Where we found brethren, and were desired to tarry with them seven days: and so we went toward Rome."},"BSB":{"text":"There we found some brothers who invited us to spend the week with them. And so we came to Rome."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And from thence, when the brethren heard of us, they came to meet us as far as Appii forum, and The three taverns: whom when Paul saw, he thanked God, and took courage.","ref":"Acts 28:15","synthesized":"The brothers there had heard about us and traveled as far as the Forum of Appius and the Three Taverns to meet us. When Paul saw them, he was encouraged and gave thanks to God.","sources":{"KJV":{"text":"And from thence, when the brethren heard of us, they came to meet us as far as Appii forum, and The three taverns: whom when Paul saw, he thanked God, and took courage."},"BSB":{"text":"The brothers there had heard about us and traveled as far as the Forum of Appius and the Three Taverns to meet us. When Paul saw them, he was encouraged and gave thanks to God."}},"definableWords":["saw","God"],"peopleInVerse":["Paul"]},"16":{"text":"And when we came to Rome, the centurion delivered the prisoners to the captain of the guard: but Paul was suffered to dwell by himself with a soldier that kept him.","ref":"Acts 28:16","synthesized":"When we arrived in Rome, Paul was permitted to stay by himself, with a soldier to guard him.","sources":{"KJV":{"text":"And when we came to Rome, the centurion delivered the prisoners to the captain of the guard: but Paul was suffered to dwell by himself with a soldier that kept him."},"BSB":{"text":"When we arrived in Rome, Paul was permitted to stay by himself, with a soldier to guard him."}},"definableWords":[],"peopleInVerse":["Paul"]},"17":{"text":"And it came to pass, that after three days Paul called the chief of the Jews together: and when they were come together, he said unto them, Men and brethren, though I have committed nothing against the people, or customs of our fathers, yet was I delivered prisoner from Jerusalem into the hands of the Romans.","ref":"Acts 28:17","synthesized":"After three days, he called together the leaders of the Jews. When they had gathered, he said to them, “Brothers, although I have done nothing against our people or the customs of our fathers, I was taken prisoner in Jerusalem and handed over to the Romans.","sources":{"KJV":{"text":"And it came to pass, that after three days Paul called the chief of the Jews together: and when they were come together, he said unto them, Men and brethren, though I have committed nothing against the people, or customs of our fathers, yet was I delivered prisoner from Jerusalem into the hands of the Romans."},"BSB":{"text":"After three days, he called together the leaders of the Jews. When they had gathered, he said to them, “Brothers, although I have done nothing against our people or the customs of our fathers, I was taken prisoner in Jerusalem and handed over to the Romans."}},"definableWords":["days","people","or","fathers","Jerusalem"],"peopleInVerse":[]},"18":{"text":"Who, when they had examined me, would have let me go, because there was no cause of death in me.","ref":"Acts 28:18","synthesized":"They examined me and wanted to release me, because there was no basis for a death sentence against me.","sources":{"KJV":{"text":"Who, when they had examined me, would have let me go, because there was no cause of death in me."},"BSB":{"text":"They examined me and wanted to release me, because there was no basis for a death sentence against me."}},"definableWords":["death"],"peopleInVerse":[]},"19":{"text":"But when the Jews spake against it, I was constrained to appeal unto Caesar; not that I had ought to accuse my nation of.","ref":"Acts 28:19","synthesized":"But when the Jews objected, I was compelled to appeal to Caesar, even though I have no charge to bring against my nation.","sources":{"KJV":{"text":"But when the Jews spake against it, I was constrained to appeal unto Caesar; not that I had ought to accuse my nation of."},"BSB":{"text":"But when the Jews objected, I was compelled to appeal to Caesar, even though I have no charge to bring against my nation."}},"definableWords":["charge","nation"],"peopleInVerse":[]},"20":{"text":"For this cause therefore have I called for you, to see you, and to speak with you: because that for the hope of Israel I am bound with this chain.","ref":"Acts 28:20","synthesized":"So for this reason I have called to see you and speak with you. It is because of the hope of Israel that I am bound with this chain.”","sources":{"KJV":{"text":"For this cause therefore have I called for you, to see you, and to speak with you: because that for the hope of Israel I am bound with this chain."},"BSB":{"text":"So for this reason I have called to see you and speak with you. It is because of the hope of Israel that I am bound with this chain.”"}},"definableWords":["see","hope","Israel"],"peopleInVerse":[]},"21":{"text":"And they said unto him, We neither received letters out of Judaea concerning thee, neither any of the brethren that came shewed or spake any harm of thee.","ref":"Acts 28:21","synthesized":"The leaders replied, “We have not received any letters about you from Judea, nor have any of the brothers from there reported or even mentioned anything bad about you.","sources":{"KJV":{"text":"And they said unto him, We neither received letters out of Judaea concerning thee, neither any of the brethren that came shewed or spake any harm of thee."},"BSB":{"text":"The leaders replied, “We have not received any letters about you from Judea, nor have any of the brothers from there reported or even mentioned anything bad about you."}},"definableWords":["Judea","or"],"peopleInVerse":[]},"22":{"text":"But we desire to hear of thee what thou thinkest: for as concerning this sect, we know that every where it is spoken against.","ref":"Acts 28:22","synthesized":"But we consider your views worth hearing, because we know that people everywhere are speaking against this sect.”","sources":{"KJV":{"text":"But we desire to hear of thee what thou thinkest: for as concerning this sect, we know that every where it is spoken against."},"BSB":{"text":"But we consider your views worth hearing, because we know that people everywhere are speaking against this sect.”"}},"definableWords":["people"],"peopleInVerse":[]},"23":{"text":"And when they had appointed him a day, there came many to him into his lodging; to whom he expounded and testified the kingdom of God, persuading them concerning Jesus, both out of the law of Moses, and out of the prophets, from morning till evening.","ref":"Acts 28:23","synthesized":"So they set a day to meet with Paul, and many people came to the place he was staying. He expounded to them from morning to evening, testifying about the kingdom of God and persuading them about Jesus from the Law of Moses and the Prophets.","sources":{"KJV":{"text":"And when they had appointed him a day, there came many to him into his lodging; to whom he expounded and testified the kingdom of God, persuading them concerning Jesus, both out of the law of Moses, and out of the prophets, from morning till evening."},"BSB":{"text":"So they set a day to meet with Paul, and many people came to the place he was staying. He expounded to them from morning to evening, testifying about the kingdom of God and persuading them about Jesus from the Law of Moses and the Prophets."}},"definableWords":["day","people","kingdom","God","law"],"peopleInVerse":["Paul","Jesus","Moses"]},"24":{"text":"And some believed the things which were spoken, and some believed not.","ref":"Acts 28:24","synthesized":"Some of them were convinced by what he said, but others refused to believe.","sources":{"KJV":{"text":"And some believed the things which were spoken, and some believed not."},"BSB":{"text":"Some of them were convinced by what he said, but others refused to believe."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"And when they agreed not among themselves, they departed, after that Paul had spoken one word, Well spake the Holy Ghost by Esaias the prophet unto our fathers,","ref":"Acts 28:25","synthesized":"They disagreed among themselves and began to leave after Paul had made this final statement: “The Holy Spirit was right when He spoke to your fathers through Isaiah the prophet:","sources":{"KJV":{"text":"And when they agreed not among themselves, they departed, after that Paul had spoken one word, Well spake the Holy Ghost by Esaias the prophet unto our fathers,"},"BSB":{"text":"They disagreed among themselves and began to leave after Paul had made this final statement: “The Holy Spirit was right when He spoke to your fathers through Isaiah the prophet:"}},"definableWords":["made","holy","Spirit","fathers","prophet"],"peopleInVerse":["Paul","Isaiah"]},"26":{"text":"Saying, Go unto this people, and say, Hearing ye shall hear, and shall not understand; and seeing ye shall see, and not perceive:","ref":"Acts 28:26","synthesized":"‘Go to this people and say, “You will be ever hearing but never understanding; you will be ever seeing but never perceiving.”","sources":{"KJV":{"text":"Saying, Go unto this people, and say, Hearing ye shall hear, and shall not understand; and seeing ye shall see, and not perceive:"},"BSB":{"text":"‘Go to this people and say, “You will be ever hearing but never understanding; you will be ever seeing but never perceiving.”"}},"definableWords":["people"],"peopleInVerse":[]},"27":{"text":"For the heart of this people is waxed gross, and their ears are dull of hearing, and their eyes have they closed; lest they should see with their eyes, and hear with their ears, and understand with their heart, and should be converted, and I should heal them.","ref":"Acts 28:27","synthesized":"For this people’s heart has grown callous; they hardly hear with their ears, and they have closed their eyes. Otherwise they might see with their eyes, hear with their ears, understand with their hearts, and turn, and I would heal them.’","sources":{"KJV":{"text":"For the heart of this people is waxed gross, and their ears are dull of hearing, and their eyes have they closed; lest they should see with their eyes, and hear with their ears, and understand with their heart, and should be converted, and I should heal them."},"BSB":{"text":"For this people’s heart has grown callous; they hardly hear with their ears, and they have closed their eyes. Otherwise they might see with their eyes, hear with their ears, understand with their hearts, and turn, and I would heal them.’"}},"definableWords":["people","heart","hear","see","heal"],"peopleInVerse":[]},"28":{"text":"Be it known therefore unto you, that the salvation of God is sent unto the Gentiles, and that they will hear it.","ref":"Acts 28:28","synthesized":"Be advised, therefore, that God’s salvation has been sent to the Gentiles, and they will listen!”","sources":{"KJV":{"text":"Be it known therefore unto you, that the salvation of God is sent unto the Gentiles, and that they will hear it."},"BSB":{"text":"Be advised, therefore, that God’s salvation has been sent to the Gentiles, and they will listen!”"}},"definableWords":["God","salvation"],"peopleInVerse":[]},"29":{"text":"And when he had said these words, the Jews departed, and had great reasoning among themselves.","ref":"Acts 28:29","synthesized":"And when he had said these words, the Jews departed, and had great reasoning among themselves.","sources":{"KJV":{"text":"And when he had said these words, the Jews departed, and had great reasoning among themselves."}},"definableWords":["great"],"peopleInVerse":[]},"30":{"text":"And Paul dwelt two whole years in his own hired house, and received all that came in unto him,","ref":"Acts 28:30","synthesized":"Paul stayed there two full years in his own rented house, welcoming all who came to visit him.","sources":{"KJV":{"text":"And Paul dwelt two whole years in his own hired house, and received all that came in unto him,"},"BSB":{"text":"Paul stayed there two full years in his own rented house, welcoming all who came to visit him."}},"definableWords":["years","house"],"peopleInVerse":["Paul"]},"31":{"text":"Preaching the kingdom of God, and teaching those things which concern the Lord Jesus Christ, with all confidence, no man forbidding him.","ref":"Acts 28:31","synthesized":"Boldly and freely he proclaimed the kingdom of God and taught about the Lord Jesus Christ.","sources":{"KJV":{"text":"Preaching the kingdom of God, and teaching those things which concern the Lord Jesus Christ, with all confidence, no man forbidding him."},"BSB":{"text":"Boldly and freely he proclaimed the kingdom of God and taught about the Lord Jesus Christ."}},"definableWords":["kingdom","God","Lord","Christ"],"peopleInVerse":["Jesus"]}}}};